#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val <= k.
            // The number of times is (k - a[i]) / min_val.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << std::endl;
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To maximize the binary number, we want as many '1's as possible, followed by '0's.
    // '1' comes from "one" (o, n, e)
    // '0' comes from "zero" (z, e, r, o)

    // Count how many '1's we can form
    // Each "one" uses one 'o', one 'n', one 'e'.
    int num_ones = count_n; // 'n' is only used by "one"

    // After forming 'num_ones' "one"s, update the counts of 'o' and 'e'
    // 'o' and 'e' are shared with "zero"
    count_o -= num_ones;
    count_e -= num_ones;

    // Count how many '0's we can form
    // Each "zero" uses one 'z', one 'e', one 'r', one 'o'.
    // 'z' and 'r' are only used by "zero".
    // 'o' and 'e' are remaining after forming "one"s.
    int num_zeros = count_z; // 'z' is only used by "zero"

    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // This implies that the remaining counts of 'e', 'r', 'o' will be sufficient for 'num_zeros'.
    // Specifically, count_e >= num_zeros, count_r >= num_zeros, count_o >= num_zeros.

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

