#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // Each coal costs y sticks. So, k coal costs k * y sticks.
        // Total sticks required: k (for crafting) + k * y (for buying coal).
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks.
        // Each stick trade (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick trades needed: ceil((total_sticks_required - 1) / (x - 1))
        long long sticks_to_gain = total_sticks_required - 1;
        long long stick_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = trades for sticks + trades for coal
        // Trades for coal = k (since each coal is 1 trade)
        long long total_trades = stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

