int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // We need to select n numbers.
        // The strategy is to select numbers of the form 2*k where k is odd,
        // and k is greater than n.
        // Specifically, we can pick numbers 2*(n+1), 2*(n+2), ..., 2*(2n).
        // These are 2n+2, 2n+4, ..., 4n.
        // All these numbers are even, so gcd(a,b) >= 2.
        // Also, for any two numbers 2*x and 2*y in this set,
        // if 2*x divides 2*y, then x divides y.
        // If we pick x, y such that n+1 <= x < y <= 2n,
        // then x cannot divide y because y/x < 2.
        // For example, if x divides y, then y = k*x for some integer k.
        // Since x < y, k must be >= 2.
        // But y <= 2n and x >= n+1.
        // So y/x <= 2n / (n+1).
        // For n=1, y/x <= 2/2 = 1. This is not possible as x < y.
        // For n=2, y/x <= 4/3 < 2.
        // For n >= 1, n+1 > n, so 2n/(n+1) < 2.
        // Thus, y/x < 2, which means x cannot divide y if x < y.
        // So, no number in the set {2*(n+1), ..., 2*(2n)} divides another.
        // This set has (2n) - (n+1) + 1 = n numbers.
        // All numbers are distinct and within [1, 4n].
        // The smallest is 2*(n+1) = 2n+2.
        // The largest is 2*(2n) = 4n.
        // This strategy works.

        // However, the example output for n=2 is 6 4.
        // My strategy would give 2*(2+1) = 6, 2*(2+2) = 8. So 6 8.
        // The example output for n=3 is 4 6 10.
        // My strategy would give 2*(3+1)=8, 2*(3+2)=10, 2*(3+3)=12. So 8 10 12.
        // The example output for n=4 is 14 10 12 8.
        // My strategy would give 2*(4+1)=10, 2*(4+2)=12, 2*(4+3)=14, 2*(4+4)=16. So 10 12 14 16.

        // The example output uses numbers that are not necessarily in the range [2n+2, 4n].
        // For n=3, example output is 4 6 10.
        // 4, 6, 10 are all even.
        // gcd(4,6)=2, gcd(4,10)=2, gcd(6,10)=2. No coprime pairs.
        // 4 does not divide 6, 6 does not divide 4.
        // 4 does not divide 10, 10 does not divide 4.
        // 6 does not divide 10, 10 does not divide 6.
        // This works.

        // Let's try a simpler approach: pick numbers from 2n+1 to 4n.
        // No, this includes odd numbers.
        // What if we pick numbers from 2n to 4n, but only even numbers?
        // For n=2, range [1, 8]. We need 2 numbers.
        // Even numbers in [1, 8]: 2, 4, 6, 8.
        // Example output: 6 4.
        // For n=3, range [1, 12]. We need 3 numbers.
        // Even numbers in [1, 12]: 2, 4, 6, 8, 10, 12.
        // Example output: 4 6 10.
        // For n=4, range [1, 16]. We need 4 numbers.
        // Even numbers in [1, 16]: 2, 4, 6, 8, 10, 12, 14, 16.
        // Example output: 14 10 12 8.

        // It seems the example output picks even numbers.
        // And it seems to pick numbers such that no number divides another.
        // The condition "a divides b or b divides a" is the tricky one for even numbers.
        // If we pick numbers x, y such that x < y and y/x < 2, then x cannot divide y.
        // The example output for n=3 is 4, 6, 10.
        // 6/4 = 1.5 < 2.
        // 10/6 = 1.66 < 2.
        // 10/4 = 2.5 > 2. Here 4 divides 10 is false.
        // This is not strictly "y/x < 2".
        // The condition is that for any pair (a,b), a does not divide b AND b does not divide a.

        // Let's try to pick numbers from 2n up to 4n, but only even numbers.
        // And we need to pick n of them.
        // The numbers are 2n, 2n+2, ..., 4n.
        // This sequence has (4n - 2n)/2 + 1 = n + 1 numbers.
        // We need to pick n of them.
        // If we pick all of them except 2n, i.e., 2n+2, 2n+4, ..., 4n. This is my previous strategy.
        // This works.

        // Let's re-examine the example output for n=3: 4 6 10.
        // My strategy: 8 10 12.
        // Both are valid. The problem states "print any of them".
        // My strategy is simpler to implement and prove.

        // Let's stick to the strategy: print 2*(n+1), 2*(n+2), ..., 2*(2n).
        // This is a sequence of n even numbers.
        // Smallest is 2n+2, largest is 4n. All are within [1, 4n].
        // All are even, so gcd(a,b) >= 2.
        // For any two distinct numbers 2x and 2y in this set, assume 2x < 2y.
        // Then n+1 <= x < y <= 2n.
        // If 2x divides 2y, then x divides y.
        // Since x < y, y must be at least 2x.
        // But y <= 2n and x >= n+1.
        // So y/x <= 2n / (n+1).
        // For n=1, y/x <= 2/2 = 1. Not possible as x < y.
        // For n > 1, 2n / (n+1) = (2(n+1) - 2) / (n+1) = 2 - 2/(n+1).
        // Since n >= 1, n+1 >= 2, so 2/(n+1) > 0.
        // Thus, 2 - 2/(n+1) < 2.
        // So y/x < 2.
        // This means y cannot be 2x or more.
        // Therefore, x cannot divide y.
        // This strategy is robust.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

