#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of 'val' to the current_sum.
        // We can think of this as having 'count' number of 'val's.
        // Each 'val' contributes 'val' to the total sum if it's used.
        // We are interested in the sum of numbers that are <= 2048.
        // If we have 2 'val's, they combine to 2*val.
        // If we have 4 'val's, they combine to 2*val, then 2*val, then 4*val.
        // Effectively, we can sum up all numbers less than or equal to 2048.
        // If this sum is >= 2048, we can always form 2048.
        // This is because any power of two can be formed by summing smaller powers of two.
        // For example, to get 2048, we need 1024 + 1024.
        // To get 1024, we need 512 + 512, and so on.
        // If the total sum of numbers <= 2048 is X, and X >= 2048,
        // we can always combine numbers to reach 2048.
        // For example, if we have {1, 1, ..., 1} (2048 times), sum is 2048.
        // We can combine 1s to 2s, 2s to 4s, ..., 1024s to 2048.
        // The only constraint is that we can only combine *equal* numbers.
        // However, since all numbers are powers of two, and the operation
        // 2^k + 2^k = 2^(k+1) effectively means we can always "promote"
        // smaller powers of two to larger ones as long as we have pairs.
        // The total sum of numbers less than or equal to 2048 is conserved
        // in terms of its value, even if the numbers themselves change.
        // For example, {1, 1, 2} -> {2, 2} -> {4}. Sums: 4, 4, 4.
        // So, if the initial sum of numbers <= 2048 is at least 2048,
        // we can always form 2048.
        // Numbers > 2048 are irrelevant as they cannot be used to form 2048.
        // If 2048 is already present, current_sum will eventually include it.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

