#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Update has_pos_one and has_neg_one for elements *before* current index
    // For a[0], these flags are already correctly set based on a[0] itself.
    // For a[k], these flags should reflect if there's a 1 or -1 in a[0...k-1].
    // We iterate from i=1 to n-1.
    // has_pos_one_prefix and has_neg_one_prefix will track if a 1 or -1
    // exists in a[0...i-1].
    bool current_has_pos_one_prefix = (a[0] == 1);
    bool current_has_neg_one_prefix = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (b[i] > a[i]) { // Need to increase a[i]
            if (!current_has_pos_one_prefix) {
                std::cout << "NO\n";
                return;
            }
        } else if (b[i] < a[i]) { // Need to decrease a[i]
            if (!current_has_neg_one_prefix) {
                std::cout << "NO\n";
                return;
            }
        }
        // If b[i] == a[i], no operation is needed for this element,
        // so it doesn't impose a constraint on prefix elements.

        // Update prefix flags for the next iteration (i+1)
        if (a[i] == 1) {
            current_has_pos_one_prefix = true;
        } else if (a[i] == -1) {
            current_has_neg_one_prefix = true;
        }
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration_per_post = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_video_count = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_video_count++;

        if (current_post_sum == target_duration_per_post) {
            s_values.push_back(current_post_video_count);
            current_post_sum = 0;
            current_post_video_count = 0;
            posts_found++;
        } else if (current_post_sum > target_duration_per_post) {
            // Current post sum exceeded target, impossible to form equal sum posts
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_post_sum > target_duration_per_post
        // or if the loop finishes and current_post_sum != 0 (meaning last post incomplete)
        // or if posts_found < k (meaning not enough posts formed)
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (r < 4) { // If r is 2 or 3, the only possible divisor > 1 is 2 (for 2) or 3 (for 3).
                 // If l=2, r=2, ans=2. If l=2, r=3, ans=2 (2 appears once, 3 appears once, 2 is smaller).
                 // If l=3, r=3, ans=3.
                 // In all these cases, l is a valid answer.
        std::cout << l << std::endl;
    } else {
        // For r >= 4, 2 will always be a divisor for at least two numbers (2, 4, 6, ...).
        // The count for 2 is floor(r/2) - ceil(l/2) + 1.
        // The count for any other number x > r/2 can be at most 1 (if x is in [l, r]).
        // For example, if x > r/2, then 2x > r. So there can be at most one multiple of x in [l, r].
        // If x is in [l, r], then x is a multiple of x.
        // If x is not in [l, r], then there are no multiples of x in [l, r].
        // So, for x > r/2, the count is either 0 or 1.
        // Since r >= 4, floor(r/2) >= 2.
        // The count for 2 will be at least 1 (if l=2, r=2) or 2 (if l=2, r=4).
        // Specifically, if l=2, r=3, count for 2 is 1. count for 3 is 1. Output 2.
        // If l=3, r=3, count for 3 is 1. Output 3.
        // If l=3, r=4, count for 2 is 1 (for 4). count for 3 is 1 (for 3). count for 4 is 1 (for 4). Output 2.
        // If l=3, r=5, count for 2 is 2 (for 4). count for 3 is 1 (for 3). count for 4 is 1 (for 4). count for 5 is 1 (for 5). Output 2.
        // If l=3, r=6, count for 2 is 2 (for 4, 6). count for 3 is 2 (for 3, 6). Output 3.
        // The problem states "If there are multiple answers, print any of them."
        // The number 2 is the most frequent divisor for most ranges.
        // The only exception is when a larger prime (like 3) has an equal or higher count.
        // For example, if l=3, r=6, count(2) = 2 (4,6), count(3) = 2 (3,6). Output 3.
        // The problem statement implies that 2 is a good candidate.
        // The maximum count for any number x > r/2 is 1.
        // The maximum count for any number x <= r/2 is at least 1 (if x <= r).
        // For x=2, the count is floor(r/2) - (l+1)/2 + 1.
        // If l=2, r=10^9, count for 2 is approx 10^9/2.
        // If l=3, r=6, count for 2 is floor(6/2) - (3+1)/2 + 1 = 3 - 2 + 1 = 2.
        // If l=3, r=6, count for 3 is floor(6/3) - (3+2)/3 + 1 = 2 - 1 + 1 = 2.
        // In this case, 3 is printed.
        // The problem is asking for *any* of them.
        // The number 2 is almost always the answer or tied for the answer.
        // The only case where 2 might not be the answer is when l is odd and r is small,
        // such that the count for 2 is low, and some other number (like l itself if l is prime)
        // has an equal count.
        // For example, if l=3, r=3, count(3)=1. Output 3.
        // If l=3, r=4, count(2)=1 (for 4), count(3)=1 (for 3). Output 2.
        // If l=3, r=5, count(2)=2 (for 4), count(3)=1 (for 3), count(5)=1 (for 5). Output 2.
        // If l=3, r=6, count(2)=2 (for 4,6), count(3)=2 (for 3,6). Output 3.
        // The example output for 3 6 is 3.
        // This suggests that if 2 and 3 have the same count, 3 is preferred.
        // This implies we should check 2 and 3.
        // Count for 2:
        long long count2 = r / 2 - (l + 1) / 2 + 1;
        // Count for 3:
        long long count3 = r / 3 - (l + 2) / 3 + 1;

        if (count3 > count2) {
            std::cout << 3 << std::endl;
        } else {
            std::cout << 2 << std::endl;
        }
    }

    return 0;
}

