int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // This happens if n is the largest value in the permutation.
    // If n is present in the permutation, it must be assigned to some p[k].
    // For that p[k], max_val_in_row_k will be n-1 (the second largest value in the permutation).
    // If n is not present in p (meaning it was never assigned to any p[i]),
    // it means that the actual value n was never the minimum of any pair.
    // This implies that n was the value of some p[i], and for all j!=i, p[j] < n.
    // In this case, max_val_in_row_i would be max(p[j] for j!=i), which is n-1.
    // So, if n is not found in the initial p, it means one of the p[i] values should be n.
    // The one that should be n is the one that currently has the value n-1,
    // because it was the largest value among all other elements.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found in p, it means one of the p[i] values should be n.
        // This p[i] must be the one whose current value is n-1.
        // We need to find such an index and change its value to n.
        // Since it's guaranteed that a solution exists, there will be exactly one such index.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

