int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_stair_cost = 1; // Cost for n=1 staircase
        long long k = 1; // Represents 2^0 for n=1, 2^1 for n=3, 2^2 for n=7, etc.

        while (true) {
            if (x >= current_stair_cost) {
                x -= current_stair_cost;
                count++;
                k *= 2; // Next k will be 2*k
                current_stair_cost = 2 * k * (k + 1) / 2 + k; // Cost for staircase with 2*k-1 stairs
                                                              // which is (2*k-1)*(2*k)/2 + k = k*(2*k-1) + k = 2*k^2 - k + k = 2*k^2
                                                              // No, this is wrong.
                                                              // The formula for cost of staircase with (2^p - 1) stairs is (2^p - 1) * 2^p / 2 + (2^p - 1)
                                                              // No, the formula is (2^p - 1) * (2^p) / 2 + (2^p - 1)
                                                              // Let's re-derive.
                                                              // For n = 2^p - 1, the cost is n*(n+1)/2.
                                                              // The number of cells for a nice staircase with (2^p - 1) stairs is (2^p - 1) * 2^p / 2.
                                                              // This is the sum of 1 to (2^p - 1).
                                                              // The problem states the cost is (2^p - 1) * 2^p / 2.
                                                              // The sequence of costs is:
                                                              // p=1, n=1: cost = 1*(1+1)/2 = 1
                                                              // p=2, n=3: cost = 3*(3+1)/2 = 6
                                                              // p=3, n=7: cost = 7*(7+1)/2 = 28
                                                              // p=4, n=15: cost = 15*(15+1)/2 = 120
                                                              // The general formula for the cost of a nice staircase with (2^p - 1) stairs is (2^p - 1) * 2^p / 2.
                                                              // Let's use k = 2^p.
                                                              // So, for p=1, k=2. n=1. Cost = (2-1)*2/2 = 1.
                                                              // For p=2, k=4. n=3. Cost = (4-1)*4/2 = 6.
                                                              // For p=3, k=8. n=7. Cost = (8-1)*8/2 = 28.
                                                              // So, if k is the current 2^p, the next k will be 2*k.
                                                              // The current_stair_cost is (k-1)*k/2.
                                                              // The next_stair_cost will be (2*k-1)*(2*k)/2.
                current_stair_cost = (2 * k - 1) * k; // This is (2*k-1)*(2*k)/2 simplified.
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

