#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::vector<bool> used(n + 1, false); // used[x] is true if x is used in p

    // p_1 must be q_1
    p[0] = q[0];
    used[q[0]] = true;

    // For subsequent elements
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used[q[i]]) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But as a safeguard, if q_i was already used, it's impossible.
                // However, q_i > q_{i-1} implies q_i is a new max, so it couldn't have been p_j for j < i.
                // And q_i is guaranteed to be <= n.
                // So this check is mostly for robustness against invalid q inputs not covered by problem constraints.
            }
            used[q[i]] = true;
        } else {
            // If q_i == q_{i-1}, then p_i must be some value x < q_i
            // and x must not have been used yet.
            // To construct *any* valid permutation, we can pick the largest available number
            // that is less than q_i. This strategy is simple and often works.
            // Or, to be more systematic, pick the smallest available number.
            // Let's try to pick the smallest available number.
            // The problem states "any possible suitable permutation".
            // A stack or a set of available numbers would be good.
            // A simple approach: iterate downwards from q[i]-1 to 1 to find the largest unused number.
            // Or, iterate upwards from 1 to find the smallest unused number.
            // Let's use a set of available numbers for efficiency.
        }
    }

    // Collect available numbers
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (!used[i]) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort descending for easy pop_back

    // Fill in the remaining p_i values
    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            // We need to find an unused number x such that x < q[i]
            // The largest available number that is less than q[i] is the best candidate
            // to maximize chances of success, as it leaves smaller numbers for later.
            // However, the problem asks for *any* valid permutation.
            // Let's try to use the largest available number from `available_numbers`
            // as long as it's less than q[i].
            if (available_numbers.empty() || available_numbers.back() >= q[i]) {
                // No suitable number found. Impossible.
                std::cout << -1 << std::endl;
                return;
            }
            p[i] = available_numbers.back();
            available_numbers.pop_back();
        }
    }

    // Final check for validity (optional, but good for debugging)
    // 1. All p_i are distinct and between 1 and n.
    // 2. Prefix maximums match q.
    std::vector<bool> final_used_check(n + 1, false);
    for (int x : p) {
        if (x < 1 || x > n || final_used_check[x]) {
            std::cout << -1 << std::endl; // Should not happen with this construction
            return;
        }
        final_used_check[x] = true;
    }

    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            std::cout << -1 << std::endl; // Should not happen with this construction
            return;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

