void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[k] stores the 0-indexed position of number k

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Update min and max indices to include the number 'm'
        // The number 'm' is at pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the subsegment must be m.
        //    Length = current_max_idx - current_min_idx + 1
        // 2. The maximum value in this subsegment must be m.
        //    (The minimum value is guaranteed to be 1 because we always expand
        //     the range to include 1, and then 2, ..., up to m.
        //     So, 1 is always within [current_min_idx, current_max_idx]
        //     and m is also within this range.
        //     Since we are considering numbers 1 to m, and the range
        //     [current_min_idx, current_max_idx] is the smallest contiguous
        //     range that contains all positions of 1 to m,
        //     the maximum value in this range will be m if and only if
        //     all numbers from 1 to m are present and no number > m is present.
        //     The length check (current_max_idx - current_min_idx + 1 == m)
        //     combined with the fact that all numbers 1 to m are present
        //     in this range implies that no other numbers are present,
        //     and thus the maximum value is indeed m.)
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

