int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int prev_diff_type = 0; // 0: no diff, 1: a[i]=0, b[i]=1, 2: a[i]=1, b[i]=0

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0' && b[i] == '1') { // a[i] is '0', needs to be '1'
                if (prev_diff_type == 2) { // Previous was a[i-1]='1', b[i-1]='0'
                    // We can swap a[i-1] and a[i] with cost 1.
                    // This makes a[i-1] become '0' (correct for b[i-1])
                    // and a[i] become '1' (correct for b[i]).
                    // This is better than two flips (cost 2).
                    cost++;
                    prev_diff_type = 0; // Both issues resolved
                } else {
                    prev_diff_type = 1;
                }
            } else { // a[i] is '1', needs to be '0'
                if (prev_diff_type == 1) { // Previous was a[i-1]='0', b[i-1]='1'
                    // We can swap a[i-1] and a[i] with cost 1.
                    // This makes a[i-1] become '1' (correct for b[i-1])
                    // and a[i] become '0' (correct for b[i]).
                    // This is better than two flips (cost 2).
                    cost++;
                    prev_diff_type = 0; // Both issues resolved
                } else {
                    prev_diff_type = 2;
                }
            }
        } else { // a[i] == b[i]
            if (prev_diff_type != 0) {
                // If there was an unresolved difference at i-1,
                // and current a[i] == b[i], we must flip a[i-1].
                // The cost is 1 for that flip.
                cost++;
                prev_diff_type = 0; // Issue resolved by flip
            }
        }
    }

    // After the loop, if there's any pending difference, it must be resolved by a flip.
    if (prev_diff_type != 0) {
        cost++;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the peak index (first element that breaks non-decreasing from left)
    int peak_idx = -1;
    for (int i = 0; i < m - 1; ++i) {
        if (b[i] > b[i+1]) {
            peak_idx = i;
            break;
        }
    }

    // If the array is already non-decreasing, it's good.
    if (peak_idx == -1) {
        return true;
    }

    // Find the valley index (first element that breaks non-decreasing from right)
    int valley_idx = -1;
    for (int i = m - 1; i > 0; --i) {
        if (b[i] > b[i-1]) {
            valley_idx = i;
            break;
        }
    }

    // If the array is already non-increasing, it's good (by picking from right to left).
    // Example: [5,4,3,2,1] -> c=[1,2,3,4,5]
    if (valley_idx == -1) {
        return true;
    }

    // The "good" property requires that the elements from the left up to some point,
    // and elements from the right up to some point, can be interleaved to form a non-decreasing sequence.
    // This implies that the "middle" part of the array must be non-decreasing.
    // The elements that are *not* picked are those in the middle.
    // If we pick `k` elements from the left and `m-k` elements from the right,
    // the elements `b_1, ..., b_k` and `b_m, ..., b_{k+1}` are picked.
    // The remaining elements are `b_{k+1}, ..., b_{m-k}`. This is not how it works.
    // The elements picked are `b_1, ..., b_L` and `b_R, ..., b_m` for some `L` and `R`.
    // The elements *not* picked are `b_{L+1}, ..., b_{R-1}`.
    // The condition for a good array is that there exists an index `k` (0-indexed)
    // such that `b[0...k]` is non-decreasing and `b[k...m-1]` is non-increasing.
    // This is equivalent to finding a "peak" element.
    // Example: [1,2,3,4,3,2,1] is good. Peak at 3.
    // Example: [1,2,3,4,4,2,1] is good. Peak at 4.
    // Example: [1,2,1,3,2] is NOT good.
    // The condition is that there is some `k` such that `b[0] <= b[1] <= ... <= b[k]`
    // AND `b[k] >= b[k+1] >= ... >= b[m-1]`.
    // This means the array must be "bitonic" (first non-decreasing, then non-increasing).
    // The example `[1, 2, 3, 4, 4, 2, 1]` is bitonic.
    // The example `[4, 5, 2]` is bitonic.
    // The example `[1, 3, 1, 4, 5, 3, 2]` is NOT bitonic.
    // The problem statement's example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // The operations are:
    // 1. take b_1 (1), c=[1], b=[2,3,4,4,2,1]
    // 2. take b_m (1), c=[1,1], b=[2,3,4,4,2]
    // 3. take b_m (2), c=[1,1,2], b=[2,3,4,4]
    // 4. take b_1 (2), c=[1,1,2,2], b=[3,4,4]
    // 5. take b_1 (3), c=[1,1,2,2,3], b=[4,4]
    // 6. take b_m (4), c=[1,1,2,2,3,4], b=[4]
    // 7. take b_1 (4), c=[1,1,2,2,3,4,4], b=[]
    // This strategy picks elements from the ends.
    // The elements picked are `b_1, b_m, b_{m-1}, b_2, b_3, b_{m-2}, b_4`.
    // The elements are `1, 1, 2, 2, 3, 4, 4`.
    // This implies that the elements that are *not* picked yet must always be available at the ends.
    // The key insight is that the elements picked must form a non-decreasing sequence.
    // This means that at any step, if we pick `x` from left and `y` from right,
    // the next element `v` must be `>=` the last element added to `c`.
    // The elements available are `b[x]` and `b[m-1-y]`.
    // The elements that are *not* picked are `b[x+1], ..., b[m-2-y]`.
    // The condition for a good array is that there exists an index `k` (0-indexed)
    // such that `b[0...k]` is non-decreasing and `b[k...m-1]` is non-increasing.
    // This is the definition of a bitonic array.
    // Let's re-check the example `[1, 2, 3, 4, 4, 2, 1]`.
    // It is non-decreasing up to index 4 (value 4).
    // It is non-increasing from index 4 (value 4) to the end.
    // So, it is bitonic.
    // Let's re-check `[4, 5, 2]`.
    // Non-decreasing up to index 1 (value 5).
    // Non-increasing from index 1 (value 5) to the end.
    // So, it is bitonic.
    // Let's re-check `[1, 3, 1, 4, 5, 3, 2]`.
    // Non-decreasing up to index 1 (value 3). Then `b[1] > b[2]` (3 > 1).
    // Non-decreasing up to index 4 (value 5). Then `b[4] > b[5]` (5 > 3).
    // This array is not bitonic.
    // The condition for a good array is that it must be bitonic.
    // An array `b` is good if and only if there exists an index `p` (0 <= p < m) such that
    // `b[0] <= b[1] <= ... <= b[p]` AND `b[p] >= b[p+1] >= ... >= b[m-1]`.
    // This means the array must be non-decreasing up to some peak, and then non-increasing.
    // The peak can be at index 0 (fully non-increasing) or index m-1 (fully non-decreasing).

    // Find the first index `i` where `b[i] > b[i+1]` (start of non-increasing part)
    int i = 0;
    while (i < m - 1 && b[i] <= b[i+1]) {
        i++;
    }
    // Now `b[0...i]` is non-decreasing.
    // Check if `b[i...m-1]` is non-increasing.
    int j = i;
    while (j < m - 1 && b[j] >= b[j+1]) {
        j++;
    }
    // If `j` reached `m-1`, it means the entire array is bitonic.
    return j == m - 1;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that `a[i]` is the start of a potential good suffix.
    // A good suffix must be bitonic.
    // We are looking for the smallest `k` such that `a[k...n-1]` is good.
    // This means we need to find the largest `k` such that `a[k...n-1]` is NOT good.
    // Or, iterate `k` from `n-1` down to `0`.
    // The suffix `a[k...n-1]` must be non-decreasing up to some point, then non-increasing.

    // Find the first index `i` from the right such that `a[i] > a[i+1]`.
    // This marks the end of the non-increasing suffix.
    // Example: [1,3,1,4,5,3,2]
    // n-1=6, a[6]=2
    // i=5, a[5]=3, a[6]=2. a[5] > a[6]. So `i` becomes 5.
    // The suffix `a[5...6]` is `[3,2]`. This is non-increasing.
    // The suffix `a[4...6]` is `[5,3,2]`. This is non-increasing.
    // The suffix `a[3...6]` is `[4,5,3,2]`. `4 <= 5`, `5 > 3`. This is bitonic.
    // The suffix `a[2...6]` is `[1,4,5,3,2]`. `1 <= 4`, `4 <= 5`, `5 > 3`. This is bitonic.
    // The suffix `a[1...6]` is `[3,1,4,5,3,2]`. `3 > 1`. Not non-decreasing from start.
    // The suffix `a[0...6]` is `[1,3,1,4,5,3,2]`. `1 <= 3`, `3 > 1`. Not bitonic from start.

    // Let's find the rightmost index `p` such that `a[p...n-1]` is non-increasing.
    // This means `a[p] >= a[p+1] >= ... >= a[n-1]`.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // Now `a[p...n-1]` is non-increasing.
    // Example: [1,3,1,4,5,3,2]
    // p starts at 6.
    // p=6: a[5]=3, a[6]=2. a[5] >= a[6]. p becomes 5.
    // p=5: a[4]=5, a[5]=3. a[4] >= a[5]. p becomes 4.
    // p=4: a[3]=4, a[4]=5. a[3] < a[4]. Loop stops. p is 4.
    // So `a[4...6]` is `[5,3,2]`, which is non-increasing.

    // Now, from `p`, we need to find the first index `q` to its left
    // such that `a[q] > a[q+1]`.
    // This `q` would be the start of the non-decreasing part.
    // We want `a[q] <= a[q+1] <= ... <= a[p]`.
    // So we need to find the first `q` from `p` going left such that `a[q-1] > a[q]`.
    // The prefix to remove would be `a[0...q-1]`.
    int q = p;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // Now `a[q...p]` is non-decreasing.
    // And `a[p...n-1]` is non-increasing.
    // So `a[q...n-1]` is bitonic.
    // The length of the prefix to remove is `q`.

    // Example: [1,3,1,4,5,3,2]
    // p = 4 (from previous step). `a[4...6]` is `[5,3,2]`.
    // q starts at p=4.
    // q=4: a[3]=4, a[4]=5. a[3] <= a[4]. q becomes 3.
    // q=3: a[2]=1, a[3]=4. a[2] <= a[3]. q becomes 2.
    // q=2: a[1]=3, a[2]=1. a[1] > a[2]. Loop stops. q is 2.
    // So `a[2...4]` is `[1,4,5]`, which is non-decreasing.
    // `a[2...6]` is `[1,4,5,3,2]`. This is bitonic.
    // The length of prefix to remove is `q = 2`.

    std::cout << q << std::endl;
}

