int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost point satisfying x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy x[k] - x[i] <= d.
        // We need to choose two points from this range (i+1 to right_ptr-1).
        // The number of available points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x_j and x_k such that i < j < k.
        // If m < 2, we cannot choose two distinct points.
        // Otherwise, we can choose 2 points from m points in m * (m - 1) / 2 ways.

        // The number of points available to be x_j or x_k (i.e., points strictly after x_i
        // and within the distance d from x_i) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let this quantity be `num_eligible_points`.
        long long num_eligible_points = (long long)right_ptr - 1 - i;

        if (num_eligible_points >= 2) {
            // We need to choose 2 points from `num_eligible_points`.
            // This is a combination C(num_eligible_points, 2).
            count += num_eligible_points * (num_eligible_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
