int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // If a[i] > s for i < median_idx, we must decrease a[i] to s.
    // If a[i] <= s, it's fine, no operations needed for this condition.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // If a[i] < s for i > median_idx, we must increase a[i] to s.
    // If a[i] >= s, it's fine, no operations needed for this condition.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
