// Function to determine if a box can be the special box
// Returns a vector of 4 booleans, one for each box (1-indexed)
std::vector<bool> solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    if (total_toys == 1) {
        return {A > 0, B > 0, C > 0, D > 0};
    }

    // Possible final signs:
    // The final sign depends on the parity of negative numbers multiplied.
    // A toy from Box 1 or Box 2 is negative.
    // Let N_neg be the total count of negative toys (A + B).
    // If N_neg is even, the final product can be positive.
    // If N_neg is odd, the final product can be negative.

    // Possible final magnitudes:
    // Let N_gt1 be the total count of toys with magnitude >= 1 (A + D).
    // Let N_lt1 be the total count of toys with magnitude < 1 (B + C).
    // If all toys have magnitude < 1 (N_gt1 == 0), the final product will have magnitude < 1.
    // If all toys have magnitude >= 1 (N_lt1 == 0), the final product will have magnitude >= 1.
    // If there's a mix (N_gt1 > 0 and N_lt1 > 0), the final product can have magnitude < 1 or >= 1.
    // Exception: if there's a zero, the product is zero. But fun values are non-zero.

    // Let's simplify the state to (can_be_negative, can_be_positive, can_be_gt1, can_be_lt1)
    // Initial state:
    // can_be_negative: A > 0 || B > 0
    // can_be_positive: C > 0 || D > 0
    // can_be_gt1: A > 0 || D > 0
    // can_be_lt1: B > 0 || C > 0

    // The problem is about *possibility*, not certainty.
    // We need to determine if there exists *any* sequence of multiplications and *any* initial fun values
    // within their respective ranges that lead to a final toy in a specific box.

    // Let's analyze the parity of negative numbers.
    long long initial_neg_count = A + B;
    bool can_be_final_positive = (initial_neg_count % 2 == 0);
    bool can_be_final_negative = (initial_neg_count % 2 != 0);

    // However, we can change the parity of negative numbers if we have at least two negative numbers.
    // If we multiply two negative numbers, they become positive. This effectively reduces N_neg by 2.
    // So, if initial_neg_count >= 2, we can achieve both even and odd final negative counts.
    // If initial_neg_count == 0, only even.
    // If initial_neg_count == 1, only odd.

    // More precisely, the final sign depends on the parity of the number of negative toys *that are not paired with another negative toy*.
    // If we have N_neg negative toys, we can pair them up. Each pair becomes positive.
    // If N_neg is even, we can pair all of them, resulting in 0 negative toys (final product positive).
    // If N_neg is odd, we can pair N_neg-1 of them, leaving 1 negative toy (final product negative).
    // So, if N_neg >= 2, we can choose to make the final product positive (by pairing all negatives) OR negative (by leaving one negative unpaired).
    // This means if N_neg >= 2, both positive and negative final products are possible.
    // If N_neg == 0, only positive.
    // If N_neg == 1, only negative.

    bool final_can_be_positive;
    bool final_can_be_negative;

    if (initial_neg_count == 0) {
        final_can_be_positive = true;
        final_can_be_negative = false;
    } else if (initial_neg_count == 1) {
        final_can_be_positive = false;
        final_can_be_negative = true;
    } else { // initial_neg_count >= 2
        final_can_be_positive = true;
        final_can_be_negative = true;
    }

    // Now consider magnitudes.
    // Let N_gt1 = A + D (count of toys with |val| >= 1)
    // Let N_lt1 = B + C (count of toys with |val| < 1)

    // If N_gt1 == 0: All initial toys have magnitude < 1.
    // The product of any number of values all < 1 will always be < 1.
    // So, final magnitude must be < 1.
    bool final_can_be_gt1 = false;
    bool final_can_be_lt1 = true;

    if (A + D > 0) { // There is at least one toy with magnitude >= 1
        // If we have at least one toy with magnitude >= 1, and at least one toy with magnitude < 1,
        // we can potentially achieve both final magnitudes.
        // Example: (2 * 0.1) = 0.2 (<1)
        // Example: (2 * 0.6) = 1.2 (>=1)
        // This means if N_gt1 > 0 and N_lt1 > 0, both are possible.
        if (B + C > 0) { // There is at least one toy with magnitude < 1
            final_can_be_gt1 = true;
            final_can_be_lt1 = true;
        } else { // All toys have magnitude >= 1 (N_lt1 == 0)
            // Product of values all >= 1 will always be >= 1.
            final_can_be_gt1 = true;
            final_can_be_lt1 = false;
        }
    }
    // The case N_gt1 == 0 is handled above.

    // Special case: If there's only one toy with magnitude >= 1, and all others are < 1.
    // e.g., A=1, B=1, C=1, D=0. N_gt1=1, N_lt1=2.
    // If we multiply the A toy with a B toy, it can be <1 or >=1.
    // e.g., -2 * -0.1 = 0.2 (<1)
    // e.g., -2 * -0.6 = 1.2 (>=1)
    // So the logic above (N_gt1 > 0 && N_lt1 > 0 implies both possible) seems correct.

    // Another edge case: What if all toys are in Box 2 or Box 3?
    // e.g., A=0, B=2, C=0, D=0. N_gt1=0, N_lt1=2.
    // Product of two values < 1 is always < 1. So final_can_be_gt1 = false, final_can_be_lt1 = true. Correct.
    // e.g., A=0, B=0, C=2, D=0. N_gt1=0, N_lt1=2.
    // Product of two values < 1 is always < 1. So final_can_be_gt1 = false, final_can_be_lt1 = true. Correct.

    // Final results for each box:
    // Box 1: Negative, magnitude >= 1
    bool box1_possible = final_can_be_negative && final_can_be_gt1;
    // Box 2: Negative, magnitude < 1
    bool box2_possible = final_can_be_negative && final_can_be_lt1;
    // Box 3: Positive, magnitude < 1
    bool box3_possible = final_can_be_positive && final_can_be_lt1;
    // Box 4: Positive, magnitude >= 1
    bool box4_possible = final_can_be_positive && final_can_be_gt1;

    // One final check: if A+D=0, then all toys are in B or C.
    // In this case, the final product will always have magnitude < 1.
    // So, box1_possible and box4_possible must be false.
    // This is covered by `final_can_be_gt1 = false` when `A+D == 0`.

    // What if A+B+C+D = 0? Problem statement says A+B+C+D > 0.

    return {box1_possible, box2_possible, box3_possible, box4_possible};
}

