void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    int distinct_count_prefix = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n) { // Optimization: if an element is too large, it can't be part of any permutation
            break;
        }
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count_prefix++;
        }
        max_val_prefix = std::max(max_val_prefix, a[i]);

        if (distinct_count_prefix == i + 1 && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    int distinct_count_suffix = 0;

    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > n) { // Optimization: if an element is too large, it can't be part of any permutation
            break;
        }
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            distinct_count_suffix++;
        }
        max_val_suffix = std::max(max_val_suffix, a[i]);

        if (distinct_count_suffix == current_len && max_val_suffix == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1;
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }

        if (n == 0) break; // Game ends if no coins left

        // Opponent's turn
        if (n % 2 != 0) { // N is odd
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                n -= 1;
            } else {
                // Opponent will also take N/2 if it's optimal.
                // If N is even, opponent will always take N/2 to maximize their gain.
                // The only exception is if N is a power of 2, where taking 1 might be better for opponent
                // to leave a larger N for Chanek to take N/2 from.
                // However, opponent wants to maximize their own coins.
                // If N is even, taking N/2 gives opponent N/2 coins.
                // If N is even, taking 1 gives opponent 1 coin.
                // N/2 is always >= 1 for N >= 2. So opponent takes N/2.
                n /= 2;
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

