#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        bool prev_won = false;
        int wins_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins_count++;
                if (prev_won) {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
                prev_won = true;
            } else {
                prev_won = false;
            }
        }

        if (wins_count == 0) { // All games are 'L' initially
            if (k > 0) {
                std::cout << 1 + 2 * std::min(k - 1, n - 1) << "\n";
            } else {
                std::cout << 0 << "\n";
            }
            continue;
        }

        // If k is large enough to turn all games into 'W'
        if (wins_count + k >= n) {
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // Find the first and last 'W'
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        std::vector<int> gaps;
        int current_gap = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int score_increase = 0;
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score_increase += 2 * gap_len; // Each 'L' in a gap becomes 'W', connecting two 'W's, adding 2 points per 'L'
            } else {
                break;
            }
        }

        // Remaining k can be used to convert 'L's before first 'W' or after last 'W'
        // Each such conversion adds 1 point (if it's the first 'W' in a new block) or 2 points (if it extends an existing 'W' block)
        // Since we've filled internal gaps, any remaining 'L's are at the ends.
        // Converting an 'L' to 'W' at the ends always adds 1 point for the 'W' itself, and potentially another 1 point if it connects to an existing 'W'.
        // If we convert an 'L' to 'W' adjacent to an existing 'W', it becomes a 2-point win.
        // If we convert an 'L' to 'W' not adjacent to an existing 'W', it becomes a 1-point win.
        // The most efficient use of remaining k is to extend existing 'W' blocks.
        // Each 'L' converted to 'W' at the ends will add 2 points if it connects to an existing 'W' block.
        // Example: LLLWWL -> LLLWWW (1 L changed, score +2)
        // Example: LWWLLL -> LWWWWL (1 L changed, score +2)
        // The initial score calculation already accounts for the 1 point for the first 'W' in a block.
        // When we convert an 'L' to 'W' at the ends, it effectively extends a 'W' block.
        // If we convert an 'L' to 'W' at the beginning (e.g., LWW -> WWWW), the first 'W' becomes 2 points instead of 1.
        // If we convert an 'L' to 'W' at the end (e.g., WWL -> WWWW), the new 'W' gets 2 points.
        // In both cases, each 'L' converted at the ends adds 2 points to the total score.
        // This is because the 'L' becomes a 'W' that is adjacent to another 'W'.
        // The only exception is if we convert an 'L' that is not adjacent to any 'W' (e.g., LLL -> LWL). This would add 1 point.
        // But we prioritize connecting to existing 'W's.
        // The number of 'L's before first_w is `first_w`.
        // The number of 'L's after last_w is `n - 1 - last_w`.

        int available_L_at_ends = first_w + (n - 1 - last_w);
        int num_L_to_convert_at_ends = std::min(k, available_L_at_ends);
        score_increase += 2 * num_L_to_convert_at_ends;

        std::cout << initial_score + score_increase << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b.begin(), b.end(), std::greater<long long>());

    // Create pairs (F(A_i, B_j), original_index_of_A_i)
    // F(n, k) = n / (k+1)
    // We want to maximize sum(A'_i / (B_i + 1))
    // To do this, we pair the largest A_i with the smallest (B_i + 1)
    // which means largest A_i with smallest B_i.
    // Since B is sorted descending, b[0] is largest, b[m-1] is smallest.
    // So we pair a_elements[0] (smallest A) with b[m-1] (smallest B)
    // a_elements[1] with b[m-2], ..., a_elements[m-1] with b[0].
    // This is equivalent to pairing sorted A (ascending) with sorted B (ascending).
    // Or sorted A (ascending) with sorted B (descending) but then reversing the B indices.

    // Let's re-evaluate the pairing.
    // We have A_1 <= A_2 <= ... <= A_m
    // We have B_1 >= B_2 >= ... >= B_m
    // We want to maximize sum(A'_i / (B_i + 1)).
    // This is a rearrangement inequality problem.
    // To maximize sum(x_i * y_i), if x is sorted ascending, y should be sorted ascending.
    // Here, we have A_i and 1/(B_i + 1).
    // A_i is sorted ascending.
    // 1/(B_i + 1) should be sorted ascending.
    // Since B_i is sorted descending, B_i + 1 is sorted descending.
    // Therefore, 1/(B_i + 1) is sorted ascending.
    // So, we should pair A_i (sorted ascending) with 1/(B_i + 1) (sorted ascending).
    // This means a_elements[0] (smallest A) should be paired with b[m-1] (smallest B, largest 1/(B+1)).
    // a_elements[1] with b[m-2], and so on.
    // a_elements[i] should be paired with b[m-1-i].

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        result[a_elements[i].original_index] = a_elements[i].value;
    }

    // The problem asks to output A' which is a permutation of A.
    // The pairing logic is:
    // The smallest A value should be assigned to the B value that makes its F value largest.
    // F(A, B) = A / (B+1).
    // To maximize sum(A'_i / (B_i + 1)), we should pair the largest A_j with the largest 1/(B_k + 1).
    // Largest 1/(B_k + 1) corresponds to smallest B_k.
    // So, sort A ascending: A_1 <= A_2 <= ... <= A_m
    // Sort B ascending: B_1 <= B_2 <= ... <= B_m
    // Then pair A_i with B_i.
    // In our code, A is sorted ascending (a_elements).
    // B is sorted descending.
    // So, a_elements[0] (smallest A) should be paired with b[m-1] (smallest B).
    // a_elements[1] should be paired with b[m-2].
    // ...
    // a_elements[i] should be paired with b[m-1-i].
    // The output array A' should have its elements at positions corresponding to the original B array.
    // The problem asks for A'_1, A'_2, ..., A'_m such that sum F(A'_i, B_i) is maximized.
    // This means we need to find a permutation P of {1, ..., m} such that sum F(A_{P_i}, B_i) is maximized.
    // Let A_sorted be the sorted version of A.
    // Let B_sorted be the sorted version of B.
    // To maximize sum(A_sorted[i] / (B_sorted[i] + 1)), we sort A ascending and B ascending.
    // Our `a_elements` is sorted ascending.
    // Our `b` is sorted descending.
    // So, we need to pair `a_elements[i]` with `b[m-1-i]`.
    // The `result` array should store the `A'` values at their original `B` positions.
    // The `a_elements[i].original_index` tells us where `a_elements[i].value` came from in the original `A`.
    // We need to output `A'` such that `A'_j` is paired with `B_j`.
    // The `j`-th element of the output array `A'` should be `a_elements[k].value` where `a_elements[k]` is paired with `B_j`.
    // This means we need to know the original index of `B_j` after sorting `B`.
    // This is getting complicated. Let's simplify.

    // We have `m` pairs `(A_i, B_i)`. We want to reorder `A` to `A'` to maximize `sum F(A'_i, B_i)`.
    // This is equivalent to finding a permutation `p` of `A` such that `sum A_p[i] / (B_i + 1)` is maximized.
    // Let `X_i = A_i` and `Y_i = 1 / (B_i + 1)`. We want to maximize `sum X_{p[i]} * Y_i`.
    // By rearrangement inequality, this sum is maximized when `X` and `Y` are sorted in the same order.
    // So, we sort `A` in ascending order.
    // We sort `1/(B_i + 1)` in ascending order. This means sorting `B_i + 1` in descending order, or `B_i` in descending order.
    // Let `A_sorted` be `A` sorted ascending.
    // Let `B_desc` be `B` sorted descending.
    // Then the optimal pairing is `A_sorted[i]` with `B_desc[i]`.
    // The problem asks for the output array `A'`.
    // The `i`-th element of the output `A'` should be the `A` value that is paired with the `i`-th element of the *original* `B` array.

    // Let's store original indices for B as well.
    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        b_elements[i].value = b[i];
        b_elements[i].original_index = i;
    }

    // Sort A ascending
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B descending (to get 1/(B+1) ascending)
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Now, a_elements[i].value should be paired with b_elements[i].value.
    // The result array `ans` will store the final permutation of A.
    // `ans[b_elements[i].original_index]` should be `a_elements[i].value`.
    std::vector<long long> ans(m);
    for (int i = 0; i < m; ++i) {
        ans[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << ans[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get 2 * largest available numbers
    // These are the k_ones largest numbers from 'a'.
    // Since w is sorted, w[0]...w[k_ones-1] will be 1s.
    // We assign the largest numbers from 'a' to these friends.
    // The largest numbers are a[n-1], a[n-2], ...
    // Each friend with w_i=1 gets one of these, and their happiness is 2 * that number.
    // So, we add 2 * a[n-1], 2 * a[n-2], etc.
    int a_idx_ptr = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_idx_ptr];
            a_idx_ptr--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here and process the rest.
            break;
        }
    }

    // Friends with w_i > 1: they get max_val + min_val.
    // To maximize this, they should get the largest available numbers as max_val.
    // The remaining largest numbers are a[a_idx_ptr], a[a_idx_ptr-1], ...
    // Each friend with w_i > 1 gets one of these as their max_val.
    // So, we add a[a_idx_ptr], a[a_idx_ptr-1], etc.
    // The w array is sorted, so w[k-1] is the largest, w[k-2] is the second largest, etc.
    // We iterate from the largest w_i down to the smallest w_i > 1.
    // The largest w_i gets the largest remaining number as its max_val.
    // The second largest w_i gets the second largest remaining number as its max_val, and so on.
    // This ensures that the largest numbers are used as max_val for friends with w_i > 1.

    // The smallest numbers from 'a' are a[0], a[1], ...
    // These will be used as min_val for friends with w_i > 1, and to fill the w_i - 2 intermediate slots.
    // We iterate through w in reverse order for friends with w_i > 1.
    // The largest w_i values will consume more of the smallest numbers.
    // This is optimal because a larger w_i means more numbers to pick from,
    // and we want to "hide" the smallest numbers in groups that need many numbers.

    int current_a_min_idx = 0; // Pointer for the smallest available numbers in 'a'

    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            // This friend gets a[a_idx_ptr] as their max_val
            total_happiness += a[a_idx_ptr];
            a_idx_ptr--;

            // This friend also needs a min_val.
            // They will get a[current_a_min_idx] as their min_val.
            total_happiness += a[current_a_min_idx];

            // This friend consumes w[i] numbers in total.
            // One for max_val (a[a_idx_ptr+1]), one for min_val (a[current_a_min_idx]).
            // The remaining w[i] - 2 numbers are intermediate and don't affect happiness.
            // We advance current_a_min_idx by w[i] - 1 (min_val + intermediate numbers).
            current_a_min_idx += (w[i] - 1);
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

