int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_b = 0;
    long long mod = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            count_b = (count_b + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' will interact with all 'b's to its right.
            // Each 'b' to its right will cause one 'ab' -> 'bba' operation.
            // The 'a' effectively moves past the 'b', and the 'b' duplicates.
            // So, if there are 'k' 'b's to its right, this 'a' will cause 'k' operations.
            // After these 'k' operations, the 'a' is gone, and 'k' new 'b's are generated.
            // These new 'b's are added to the existing 'k' 'b's, effectively doubling the 'b' count for future 'a's to the left.
            total_steps = (total_steps + count_b) % mod;
            count_b = (count_b * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all ones

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated from our w
    for (int i = 0; i < n; ++i) {
        // Check if w[i-x] contributes a '1'
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check if w[i+x] contributes a '1'
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

