    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append elements b1, b2, ... such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

        // Strategy: Append two elements.
        // Let the two elements be X and Y.
        // New sum S' = current_sum + X + Y
        // New XOR sum X' = current_xor_sum ^ X ^ Y
        // We want S' = 2 * X'

        // Let's try to make X' = current_xor_sum.
        // This means X ^ Y = 0, which implies X = Y.
        // If we append X and X, then X' = current_xor_sum ^ X ^ X = current_xor_sum.
        // The condition becomes: current_sum + X + X = 2 * current_xor_sum
        // current_sum + 2X = 2 * current_xor_sum
        // 2X = 2 * current_xor_sum - current_sum
        // X = current_xor_sum - current_sum / 2

        // This approach requires current_sum to be even and 2 * current_xor_sum - current_sum to be non-negative and even.
        // However, we know that current_sum and current_xor_sum have the same parity.
        // So, current_sum - 2 * current_xor_sum is always even.
        // Let D = current_sum - 2 * current_xor_sum.
        // We want to find b1, b2 such that
        // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)

        // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        // This is not quite right. The problem states we can append at most 3 elements.
        // A common strategy for these problems is to append two elements:
        // 1. The current XOR sum (X)
        // 2. The current sum + current XOR sum (S + X)
        // Let's verify this.
        // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum

        // New sum: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * current_sum + 2 * current_xor_sum

        // We need S' = 2 * X'
        // Is (2 * current_sum + 2 * current_xor_sum) == 2 * (current_sum + current_xor_sum)?
        // Yes, this is always true.
        // So, appending current_xor_sum and (current_sum + current_xor_sum) always works.
        // The elements are non-negative since current_sum and current_xor_sum are non-negative.
        // The values can be large, up to 10^9 * 10^5 + 10^9 ~ 10^14, which fits in long long.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
}

