#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // For each remainder r from 0 to k-1, all characters s[r], s[r+k], s[r+2k], ... must be the same.
    // We can determine this common character for each remainder group.
    std::vector<char> determined_char(k, '?'); // Stores the determined char for s[i] where i % k == r
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        int r = i % k;
        if (s[i] != '?') {
            if (determined_char[r] == '?') {
                determined_char[r] = s[i];
            } else if (determined_char[r] != s[i]) {
                // Conflict: s[i] requires a different character than already determined for this remainder group
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Fill in '?' based on determined_char
    // And check if the first k characters can form a balanced substring.
    // The first k characters determine the counts of 0s and 1s for all subsequent k-length substrings.
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (determined_char[i] == '0') {
            count0++;
        } else if (determined_char[i] == '1') {
            count1++;
        }
        // If determined_char[i] is '?', it can be either '0' or '1'.
        // We don't need to explicitly fill s[i] here, just check counts.
    }

    // Check if it's possible to make the first k characters balanced.
    // We have '?'s that can be filled.
    // The number of '?'s is k - count0 - count1.
    // We need k/2 zeros and k/2 ones.
    // If count0 > k/2 or count1 > k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means:
    // 1. No direct conflicts in s[i] == s[i+k] constraints.
    // 2. The fixed '0's and '1's in the first k positions (considering determined_char)
    //    do not exceed k/2 for either character.
    // This implies that the remaining '?'s in the first k positions can be filled
    // to satisfy the k/2 zeros and k/2 ones requirement.
    // For example, if we need more '0's, we fill '?'s with '0's until k/2 '0's are met,
    // then fill remaining '?'s with '1's.

    std::cout << "YES\n";
}

