        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // So, if f1=0, the robot must end up at x or to its right.
            // This means X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // So, if f3=0, the robot must end up at x or to its left.
            // This means X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // So, if f4=0, the robot must end up at y or to its top.
            // This means Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // So, if f2=0, the robot must end up at y or to its bottom.
            // This means Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a point exists,
            // one exists with coordinates not exceeding 10^5 by absolute value.
            // We can pick any point within the valid range, e.g., (min_x, min_y).
            // The problem statement implies that the coordinates of the answer
            // should not exceed 10^5 by absolute value.
            // The initial bounds for min_x, max_x, min_y, max_y are set to
            // values far outside the [-10^5, 10^5] range.
            // If min_x or min_y are still at their initial "negative infinity" values,
            // it means no robot restricted them from below. In this case, we can
            // choose -10^5 as a valid coordinate.
            // Similarly for max_x, max_y and 10^5.
            long long final_X = std::max(-100000LL, min_x);
            final_X = std::min(100000LL, final_X);

            long long final_Y = std::max(-100000LL, min_y);
