int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val = (b - 1);
    sum_r_val = (sum_r_val * b) % MOD;

    // We need to divide by 2. Modular inverse of 2 modulo 10^9+7 is (10^9+7+1)/2 = 500000004
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k*b + 1) for k from 1 to a
    // This is sum_k_val
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_val_term1 = (a % MOD);
    long long a_plus_1 = (a + 1) % MOD;
    sum_k_val_term1 = (sum_k_val_term1 * a_plus_1) % MOD;
    sum_k_val_term1 = (sum_k_val_term1 * inv2) % MOD; // (a * (a+1) / 2)
    sum_k_val_term1 = (sum_k_val_term1 * (b % MOD)) % MOD; // b * (a * (a+1) / 2)

    long long sum_k_val_term2 = (a % MOD); // sum_{k=1 to a} 1 = a

    long long sum_k_val = (sum_k_val_term1 + sum_k_val_term2) % MOD;

    // Total sum = (sum_r_val * sum_k_val) % MOD
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> L(n);
    L[0] = 0;
    for (int i = 1; i < n; ++i) {
        L[i] = std::max(0LL, std::min(h[i], L[i - 1] + 1));
    }

    std::vector<long long> R(n);
    R[n - 1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        R[i] = std::max(0LL, std::min(h[i], R[i + 1] + 1));
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(L[i], R[i]));
    }

    long long low = max_k;
    long long high = 2000000000LL; // Max possible answer, roughly max_h / 2 + n / 2
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;

        long long current_max_k_val = 0;
        for (int i = 0; i < n; ++i) {
            current_max_k_val = std::max(current_max_k_val, std::min(h[i] - mid, std::min(L[i], R[i])));
        }

        if (current_max_k_val <= 0) { // All towers are destroyed or reduced to 0 height by mid operations
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

