void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1; // Convert blueberry to -1 for sum calculation
        }
    }

    // Calculate prefix sums for the left segment (jars 1 to n)
    // The prefix sums are calculated from right to left for the left segment
    // s_L[k] = sum of jars n, n-1, ..., n-k+1
    std::vector<int> s_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_L[i + 1] = s_L[i] + a[n - 1 - i];
    }

    // Calculate prefix sums for the right segment (jars n+1 to 2n)
    // The prefix sums are calculated from left to right for the right segment
    // s_R[k] = sum of jars n+1, n+2, ..., n+k
    std::vector<int> s_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_R[i + 1] = s_R[i] + a[n + i];
    }

    // Map to store the minimum number of jars emptied from the left (k_L)
    // for a given sum difference (s_L[k_L])
    std::map<int, int> left_sums;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_sum = s_L[k_L];
        if (left_sums.find(current_sum) == left_sums.end()) {
            left_sums[current_sum] = k_L;
        }
    }

    int min_jars_emptied = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars emptied from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_right_sum = s_R[k_R];
        // We need s_L[k_L] + s_R[k_R] = 0 for the remaining jars to have equal counts.
        // So, we are looking for s_L[k_L] = -current_right_sum.
        int target_left_sum = -current_right_sum;

        if (left_sums.count(target_left_sum)) {
            int k_L = left_sums[target_left_sum];
            min_jars_emptied = std::min(min_jars_emptied, k_L + k_R);
        }
    }

    std::cout << min_jars_emptied << std::endl;
}

