        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long zeros_count = n - m;

        // To minimize substrings of all zeros, distribute zeros as evenly as possible.
        // There are m '1's. These '1's divide the string into m+1 potential blocks for '0's.
        // For example, _1_1_1_ (underscores are blocks of zeros)
        // If we have k zeros, and we want to distribute them into p blocks,
        // we'll have k % p blocks of size (k / p) + 1, and
        // p - (k % p) blocks of size (k / p).

        long long p = m + 1; // Number of blocks for zeros
        long long k = zeros_count; // Total zeros to distribute

        long long num_large_blocks = k % p;
        long long size_large_block = k / p + 1;

        long long num_small_blocks = p - num_large_blocks;
        long long size_small_block = k / p;

        long long substrings_of_zeros = 0;
        substrings_of_zeros += num_large_blocks * (size_large_block * (size_large_block + 1) / 2);
        substrings_of_zeros += num_small_blocks * (size_small_block * (size_small_block + 1) / 2);

        long long result = total_substrings - substrings_of_zeros;
        std::cout << result << "\n";
    }
    return 0;
}

