int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added back"

        active_vertices[k] = true; // Mark k as active

        // Floyd-Warshall update step
        // When vertex k is added, it can serve as an intermediate vertex
        // for paths between any two currently active vertices.
        // It can also be the start or end of a path.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using a large value for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // Also update paths involving k as start/end
        // This is implicitly handled by the above loops if i and j iterate over all n vertices
        // and we only consider active_vertices[i] and active_vertices[j] for the sum.
        // The core Floyd-Warshall update is:
        // dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This needs to be applied for all i, j, using k as an intermediate.
        // The previous loops correctly update dist[i][j] for all active i, j using k.
        // The crucial part is that k itself can be i or j.
        // So, we need to update all pairs (i,j) using k as an intermediate.
        // The loops above do this.

        // After adding k and updating all paths, calculate the sum for currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward order of removal)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

