                // So, we update `min_r_with_3ap[l]` with `end_idx`.
                // Since we want the *minimum* `end_idx` for each `l`, we take `std::min`.
                // We can iterate `l` from `x` down to `0`.
                // This is equivalent to:
                // for (int l_idx = 0; l_idx <= x; ++l_idx) {
                //     min_r_with_3ap[l_idx] = std::min(min_r_with_3ap[l_idx], x + 2 * k);
                // }
                // However, this is O(N^3) in worst case.
                // A more efficient way is to observe that min_r_with_3ap[l] is non-decreasing.
                // If min_r_with_3ap[l] is updated to `val`, then min_r_with_3ap[l-1]
                // can be at most `val`.
                // So, we can update min_r_with_3ap[x] = min(min_r_with_3ap[x], x + 2k).
                // Then, propagate this minimum backwards:
                // min_r_with_3ap[i] = min(min_r_with_3ap[i], min_r_with_3ap[i+1]) for i from x-1 down to 0.
                // This propagation is done after all 3-APs are found.

                // For now, just store the minimum r_prime for each possible starting x.
                // This is min_r_with_3ap[x] = min(min_r_with_3ap[x], x + 2k).
                // This is not quite right. min_r_with_3ap[l] is the minimum r for substring s[l...r].
                // The current 3-AP is s[x...x+2k].
                // So for l=x, the minimum r is x+2k.
                // For l=x-1, the minimum r is also x+2k (if this is the first 3-AP found for l=x-1).
                // So, min_r_with_3ap[l] should be updated for all l <= x.
                // The smallest r for s[l...r] is x+2k.
                // So, min_r_with_3ap[l] = min(min_r_with_3ap[l], x+2k).
                // This is the correct logic.
                // The loop for k can go up to k=7 for N=300000.
                // If k is large, x+2k will be large, so it's less likely to be the minimum r.
                // The maximum k we need to check is small.
                // If k > 7, then 2k > 14.
                // If we have a 3-AP (x, x+k, x+2k) and another (x', x'+k', x'+2k')
                // such that x' <= x and x'+2k' <= x+2k, then the first one is redundant.
                // We are looking for the smallest r for each l.
                // The maximum k we need to consider is 7.
                // If k > 7, then x+2k > x+14.
                // If there is a 3-AP (x, x+k, x+2k) with k > 7,
                // and there is another 3-AP (x', x'+k', x'+2k') with x' <= x and x'+2k' <= x+14,
                // then the (x, k) 3-AP is not the one that determines min_r_with_3ap[l] for l <= x.
                // The problem states $1 \leq k \leq n$.
                // However, if $k$ is large, $x+2k$ will be large.
                // The maximum $k$ that can possibly be relevant for finding the *minimum* $r$ for a given $l$
                // is small.
                // Consider $l$. We are looking for $x, k$ such that $l \le x < x+2k \le r$.
                // We want to find the smallest $r$.
                // This means we want to find the smallest $x+2k$ for any $x \ge l$.
                // If $k$ is large, $x+2k$ will be large.
                // For example, if $k=8$, then $x+2k = x+16$.
                // If there is a 3-AP with $k=1$, $x+2k = x+2$.
                // If there is a 3-AP with $k=2$, $x+2k = x+4$.
                // If there is a 3-AP with $k=3$, $x+2k = x+6$.
                // If there is a 3-AP with $k=4$, $x+2k = x+8$.
                // If there is a 3-AP with $k=5$, $x+2k = x+10$.
                // If there is a 3-AP with $k=6$, $x+2k = x+12$.
                // If there is a 3-AP with $k=7$, $x+2k = x+14$.
                // If $k \ge 8$, then $x+2k \ge x+16$.
                // If we find a 3-AP $(x, k)$ with $k \ge 8$, its end point is $x+2k$.
                // If there is *any* 3-AP $(x', k')$ with $x' \le x$ and $x'+2k' \le x+14$,
                // then $x+2k$ is not the minimum $r$ for $l \le x$.
                // It is known that if a string of length $N$ contains a 3-AP, it must contain one with $k \le \log N$.
                // For $N=300000$, $\log_2 300000 \approx 18$.
                // However, a tighter bound is $k \le 7$.
                // This is a known result for "avoiding 3-APs" in binary strings.
                // If a binary string of length $L$ contains a 3-AP, it must contain one with $k \le 7$.
                // This means we only need to check $k$ from $1$ to $7$.
                // This optimization makes the inner loop constant time.
                if (k > 7) break; // Optimization: only check k up to 7

                int current_r_prime = x + 2 * k;
                // Update min_r_with_3ap[l] for all l from 0 to x.
                // This is done by setting min_r_with_3ap[x] and then propagating.
                min_r_with_3ap[x] = std::min(min_r_with_3ap[x], current_r_prime);
            }
        }
    }

    // Propagate the minimum r_prime backwards.
    // If s[i...r] contains a 3-AP, then s[i-1...r] also contains it.
    // So, min_r_with_3ap[i-1] <= min_r_with_3ap[i].
    // We need to ensure min_r_with_3ap[i-1] is the minimum of its current value
    // and min_r_with_3ap[i].
    for (int i = n - 1; i >= 0; --i) {
        min_r_with_3ap[i] = std::min(min_r_with_3ap[i], min_r_with_3ap[i + 1]);
    }

    // Calculate bad_pairs
    for (int l = 0; l < n; ++l) {
        // For a fixed l, all r such that l <= r < min_r_with_3ap[l]
        // form a bad pair (l, r).
        // The number of such r values is (min_r_with_3ap[l] - 1) - l + 1
        // = min_r_with_3ap[l] - l.
        // If min_r_with_3ap[l] == n, it means no 3-AP was found for this l,
        // so all r from l to n-1 are bad. Number of such r is n - l.
        // The formula min_r_with_3ap[l] - l works for both cases.
        // Example: if min_r_with_3ap[l] = n, then n - l bad pairs.
        // Example: if min_r_with_3ap[l] = 5, l=0, then r=0,1,2,3,4 are bad. 5-0=5 pairs.
        bad_pairs += (min_r_with_3ap[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int i = 0; i < n; ++i) {
        long long head_pos = h[i];
        long long current_head_left_reach = head_pos - T;
        long long current_head_right_reach = head_pos + T;

        // Skip p_j that are already covered by previous heads or are too far left for this head
        while (p_idx < m && p[p_idx] < current_head_left_reach) {
            p_idx++;
        }

        // If this head can cover p[p_idx]
        if (p_idx < m && p[p_idx] <= current_head_right_reach) {
            // This head can cover a segment starting from p[p_idx]
            // We need to find the maximum p_k that this head can cover
            // The head can move to any point X in [head_pos - T, head_pos + T].
            // If it moves to X, it covers [X - (T - abs(X - head_pos)), X + (T - abs(X - head_pos))]
            // This is equivalent to saying it covers [head_pos - T, head_pos + T]
            // and then for any p_j in this range, it can be visited.
            // The crucial part is that if a head covers p[p_idx], it can also cover
            // any p_k such that p_k is within the range [p[p_idx], p[p_idx] + 2*T - (p[p_idx] - current_head_left_reach)]
            // This simplifies to [p[p_idx], current_head_right_reach + T - (p[p_idx] - current_head_left_reach)]
            // No, this is not correct.
            // If a head is at h_i and we have T time, it can reach any point in [h_i - T, h_i + T].
            // If it reaches p[p_idx], it takes abs(p[p_idx] - h_i) time.
            // The remaining time is T - abs(p[p_idx] - h_i).
            // With this remaining time, it can extend its reach from p[p_idx] by this amount in either direction.
            // So, it can cover the range [p[p_idx] - (T - abs(p[p_idx] - h_i)), p[p_idx] + (T - abs(p[p_idx] - h_i))].
            // Let's call this range [L_effective, R_effective].
            // We need to find the maximum p_k such that p_k <= R_effective.
            // The maximum rightmost point a head can reach is h_i + T.
            // The maximum leftmost point a head can reach is h_i - T.
            // If a head covers p[p_idx], it must be that h_i - T <= p[p_idx] <= h_i + T.
            // The head can move to p[p_idx]. This takes `cost = abs(p[p_idx] - h_i)` time.
            // It has `T - cost` time remaining.
            // With this remaining time, it can sweep a range of length `2 * (T - cost)` centered at p[p_idx].
            // So it covers tracks in `[p[p_idx] - (T - cost), p[p_idx] + (T - cost)]`.
            // We want to maximize the rightmost point covered by this head.
            // This is `p[p_idx] + (T - abs(p[p_idx] - h_i))`.
            // Let `max_reach_from_p_idx = p[p_idx] + (T - std::abs(p[p_idx] - h_i))`.
            // This is the furthest right this head can reach *if it starts covering from p[p_idx]*.
            // We need to advance p_idx past all points covered by this head.
            long long current_max_covered_right = p[p_idx] + (T - std::abs(p[p_idx] - h[i]));
            while (p_idx < m && p[p_idx] <= current_max_covered_right) {
                p_idx++;
            }
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between any h_i and p_j is ~10^10.
                               // A head might need to move from 1 to 10^10, taking 10^10 time.
                               // If p_j is 1 and h_i is 10^10, T is 10^10.
                               // If p_j is 1 and h_i is 1, and p_k is 10^10, and h_l is 10^10,
                               // and we need to cover [1, 10^10] with one head, it takes 10^10.
                               // If we need to cover [1, 10^10] with two heads, one at 1, one at 10^10,
                               // and T is the answer, then h_1 covers [1, 1+T] and h_2 covers [10^10-T, 10^10].
                               // If p_1 is 1 and p_m is 10^10, and n=1, h_1=5e9, then T is 5e9.
                               // If p_1 is 1 and p_m is 10^10, and n=1, h_1=1, then T is 10^10.
                               // The maximum possible value for p_m - p_1 is 10^10.
                               // The maximum possible value for p_m - h_1 or h_n - p_1 is 10^10.
                               // So 10^10 is a reasonable upper bound. 2e10 + 7 is safe.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a1 = elements[0].value;
    long long a2 = elements[1].value;
    long long an_1 = elements[n - 2].value;
    long long an = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s).
    // min_f = a1 + a2
    // max_f = an_1 + an
    // goodness = (an_1 + an) - (a1 + a2)
    long long goodness1 = (an_1 + an) - (a1 + a2);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This means f(a_i, a_j) = a_i + a_j + h will occur for some pair.
    // The minimum possible value for f is min(a_i + a_j, a_k + a_l + h).
    // The maximum possible value for f is max(a_i + a_j, a_k + a_l + h).

    // Consider the partition where elements[0] is in one group, and elements[1]...elements[n-1] are in another.
    // Or elements[n-1] is in one group, and elements[0]...elements[n-2] are in another.
    // Or elements[0] and elements[n-1] are in different groups.

    // The critical observation is that if h is small, we want to avoid the +h term.
    // If h is large, we want to make sure the +h term doesn't increase the range too much.

    // Let's analyze the range of values.
    // The smallest possible sum is a1 + a2.
    // The largest possible sum is an_1 + an.

    // If we have elements in both subsequences, then min_f could be a1 + a2 (if a1, a2 are in same group)
    // or a1 + a2 + h (if a1, a2 are in different groups).
    // And max_f could be an_1 + an (if an_1, an are in same group)
    // or an_1 + an + h (if an_1, an are in different groups).

    // The key is to minimize max_f - min_f.
    // The values are in the range [a1+a2, an_1+an] or [a1+a2+h, an_1+an+h] or a mix.

    // Consider the partition where elements[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a2 + a3 (if n >= 3, and a2, a3 are in group 2)
    //   - a1 + a2 + h (a1 in group 1, a2 in group 2)
    //   So, min_f = std::min(a2 + a3 (if n>=3), a1 + a2 + h)
    // max_f:
    //   - an_1 + an (if n >= 3, and an_1, an are in group 2)
    //   - a1 + an + h (a1 in group 1, an in group 2)
    //   So, max_f = std::max(an_1 + an (if n>=3), a1 + an + h)

    // This specific partition strategy (one element in one group, rest in another)
    // is often optimal when h is large.
    // Let's try putting elements[0] in group 1, and all others in group 2.
    // min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value (if n>=3))
    // max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)

    // Let's consider the values that can appear:
    // S_min = a1 + a2
    // S_max = an_1 + an
    // S_min_diff = a1 + a2 + h
    // S_max_diff = an_1 + an + h

    // If we put all elements in one group, range is [S_min, S_max]. Goodness = S_max - S_min.
    // If we put elements[0] in group 1, and elements[1]...elements[n-1] in group 2:
    //   min_f = std::min(a1 + a2 + h, a2 + a3 (if n>=3 else infinity))
    //   max_f = std::max(a1 + an + h, an_1 + an)
    //   Goodness = max_f - min_f

    // Let's analyze the range of values for f.
    // The smallest possible sum is a1 + a2.
    // The largest possible sum is an_1 + an.

    // Option A: All elements in one group (e.g., all 1s).
    // min_f = a1 + a2
    // max_f = an_1 + an
    // Goodness = (an_1 + an) - (a1 + a2)

    // Option B: Partition such that a1 is in group 1, and a2, ..., an are in group 2.
    // min_f:
    //   - a1 + a2 + h (a1 in G1, a2 in G2)
    //   - a2 + a3 (a2, a3 in G2, if n >= 3)
    //   So, min_f = std::min(a1 + a2 + h, (n >= 3 ? a2 + a3 : 2e18 + 7))
    // max_f:
    //   - a1 + an + h (a1 in G1, an in G2)
    //   - an_1 + an (an_1, an in G2)
    //   So, max_f = std::max(a1 + an + h, an_1 + an)
    // Goodness = max_f - min_f

    // Option C: Partition such that a1, ..., an-1 are in group 1, and an is in group 2.
    // min_f:
    //   - a1 + a2 (a1, a2 in G1)
    //   - a1 + an + h (a1 in G1, an in G2)
    //   So, min_f = std::min(a1 + a2, a1 + an + h)
    // max_f:
    //   - an_2 + an_1 (an_2, an_1 in G1, if n >= 3)
    //   - an_1 + an + h (an_1 in G1, an in G2)
    //   So, max_f = std::max((n >= 3 ? an_2 + an_1 : -1), an_1 + an + h)
    // Goodness = max_f - min_f

    // Option D: Partition such that a1 is in group 1, an is in group 2, and a2, ..., an-1 are in group 1.
    // This is equivalent to Option C.

    // Option E: Partition such that a1 is in group 1, an is in group 2, and a2, ..., an-1 are in group 2.
    // min_f:
    //   - a1 + a2 + h (a1 in G1, a2 in G2)
    //   - a2 + a3 (a2, a3 in G2, if n >= 3)
    //   So, min_f = std::min(a1 + a2 + h, (n >= 3 ? a2 + a3 : 2e18 + 7))
    // max_f:
    //   - a1 + an + h (a1 in G1, an in G2)
    //   - an_1 + an (an_1, an in G2)
    //   So, max_f = std::max(a1 + an + h, an_1 + an)
    // Goodness = max_f - min_f
    // This is equivalent to Option B.

    // The crucial cases are:
    // 1. All elements in one group.
    //    min_f = a1 + a2
    //    max_f = an_1 + an
    //    Goodness = (an_1 + an) - (a1 + a2)

    // 2. The smallest element (a1) is in one group, and all other elements are in the other group.
    //    Let's say a1 is in group 1, and a2, ..., an are in group 2.
    //    min_f = std::min(a1 + a2 + h, (n >= 3 ? a2 + a3 : 2000000000000000000LL)) // Use a large number for infinity
    //    max_f = std::max(a1 + an + h, an_1 + an)
    //    Goodness = max_f - min_f

    // 3. The largest element (an) is in one group, and all other elements are in the other group.
    //    Let's say an is in group 2, and a1, ..., an-1 are in group 1.
    //    min_f = std::min(a1 + a2, a1 + an + h)
    //    max_f = std::max((n >= 3 ? an_2 + an_1 : -1LL), an_1 + an + h) // Use a small number for -infinity
    //    Goodness = max_f - min_f

    // 4. The smallest element (a1) and the largest element (an) are in different groups.
    //    Let a1 be in group 1, an in group 2.
    //    The remaining elements a2, ..., an-1 can be distributed.
    //    To minimize the range, we want to make the values as close as possible.
    //    If a2, ..., an-1 are all in group 1:
    //      min_f = std::min(a1 + a2, a1 + an + h)
    //      max_f = std::max(an_2 + an_1, an_1 + an + h)
    //      This is essentially case 3.
    //    If a2, ..., an-1 are all in group 2:
    //      min_f = std::min(a1 + a2 + h, a2 + a3)
    //      max_f = std::max(a1 + an + h, an_1 + an)
    //      This is essentially case 2.

    // What if a1 and an are in different groups, and a2 is in the same group as a1, and an-1 is in the same group as an?
    // This is getting complicated.
    // The problem states that we need to find *a* partition.
    // The minimum possible values for f are `a1 + a2` and `a1 + a2 + h`.
    // The maximum possible values for f are `an_1 + an` and `an_1 + an + h`.

    // Let's consider the four boundary values:
    // V1 = a1 + a2
    // V2 = a1 + a2 + h
    // V3 = an_1 + an
    // V4 = an_1 + an + h

    // If all elements are in one group: min_f = V1, max_f = V3. Goodness = V3 - V1.
    // If a1 is in group 1, and all others in group 2:
    //   min_f = std::min(V2, (n >= 3 ? a2 + a3 : 2000000000000000000LL))
    //   max_f = std::max(a1 + an + h, V3)
    //   Goodness = max_f - min_f

    // If an is in group 2, and all others in group 1:
    //   min_f = std::min(V1, a1 + an + h)
    //   max_f = std::max((n >= 3 ? an_2 + an_1 : -1LL), an_1 + an + h)
    //   Goodness = max_f - min_f

    // The crucial insight for this type of problem is often that the optimal partition
    // involves putting the smallest and/or largest elements strategically.

    // Let's re-evaluate the options for min_goodness.
    // Option 1: All elements in one group.
    //   min_f = a1 + a2
    //   max_f = an_1 + an
    //   current_goodness = (an_1 + an) - (a1 + a2)
    //   best_goodness = current_goodness
    //   best_partition = partition1 (all 1s)

    // Option 2: a1 in group 1, a2...an in group 2.
    //   min_f_val = std::min(a1 + a2 + h, (n >= 3 ? elements[1].value + elements[2].value : 2000000000000000000LL));
    //   max_f_val = std::max(a1 + an + h, an_1 + an);
    //   current_goodness = max_f_val - min_f_val;
    //   If current_goodness < best_goodness:
    //     best_goodness = current_goodness
    //     best_partition: elements[0] is 1, others are 2.

    // Option 3: a1...an-1 in group 1, an in group 2.
    //   min_f_val = std::min(a1 + a2, a1 + an + h);
    //   max_f_val = std::max((n >= 3 ? elements[n-3].value + elements[n-2].value : -1LL), an_1 + an + h);
    //   current_goodness = max_f_val - min_f_val;
    //   If current_goodness < best_goodness:
    //     best_goodness = current_goodness
    //     best_partition: elements[n-1] is 2, others are 1.

    // Let's consider the case where h is very large.
    // In this case, we want to avoid `a_i + a_j + h` if possible, or make sure it doesn't increase the range too much.
    // If h is very large, `a_i + a_j + h` will be much larger than `a_i + a_j`.
    // So, if we have elements in both groups, the min_f will likely be `a_i + a_j` (same group) and max_f will be `a_k + a_l + h` (different groups).
    // This would lead to a large goodness.
    // So, if h is large, the optimal solution is often to put all elements in one group.
    // This is covered by Option 1.

    // What if h is very small (e.g., h=0)?
    // Then f(a_i, a_j) is always a_i + a_j.
    // Goodness is always (an_1 + an) - (a1 + a2).
    // Option 1 is optimal.

    // The only other interesting case is when `a1 + an + h` is close to `an_1 + an`.
    // Or `a1 + a2 + h` is close to `a1 + a2`.

    // Let's consider the values that can be formed:
    // Set S_same = {a_i + a_j | a_i, a_j in same group}
    // Set S_diff = {a_i + a_j + h | a_i, a_j in different groups}
    // The overall set of f values is S_same union S_diff.
    // We want to minimize max(S_same union S_diff) - min(S_same union S_diff).

    // The minimum possible value for any sum is a1 + a2.
    // The maximum possible value for any sum is an_1 + an.

    // Let's define the four critical sums:
    // S_min_same = a1 + a2
    // S_max_same = an_1 + an
    // S_min_diff = a1 + a2 + h
    // S_max_diff = an_1 + an + h

    // If we have a partition where both groups are non-empty:
    // min_f will be at least S_min_same.
    // max_f will be at most S_max_diff.

    // Consider the partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    // min_f = std::min(elements[0].value + elements[1].value + h, (n >= 3 ? elements[1].value + elements[2].value : 2000000000000000000LL));
    // max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    // This is the "one element separated" strategy.

    // Let's try to formalize the candidates for min_goodness.
    // Candidate 1: All elements in one group.
    //   min_f = a1 + a2
    //   max_f = an_1 + an
    //   Goodness = (an_1 + an) - (a1 + a2)
    //   Partition: all 1s.

    // Candidate 2: The smallest element `a1` is in group 1, and all other `n-1` elements are in group 2.
    //   min_f:
    //     - `a1 + a2 + h` (a1 in G1, a2 in G2)
    //     - `a2 + a3` (a2, a3 in G2, if n >= 3)
    //   So, `min_f = std::min(a1 + a2 + h, (n >= 3 ? elements[1].value + elements[2].value : 2000000000000000000LL))`
    //   max_f:
    //     - `a1 + an + h` (a1 in G1, an in G2)
    //     - `an_1 + an` (an_1, an in G2)
    //   So, `max_f = std::max(a1 + an + h, an_1 + an)`
    //   Goodness = `max_f - min_f`
    //   Partition: elements[0] is 1, others are 2.

    // Candidate 3: The largest element `an` is in group 2, and all other `n-1` elements are in group 1.
    //   min_f:
    //     - `a1 + a2` (a1, a2 in G1)
    //     - `a1 + an + h` (a1 in G1, an in G2)
    //   So, `min_f = std::min(a1 + a2, a1 + an + h)`
    //   max_f:
    //     - `an_2 + an_1` (an_2, an_1 in G1, if n >= 3)
    //     - `an_1 + an + h` (an_1 in G1, an in G2)
    //   So, `max_f = std::max((n >= 3 ? elements[n-3].value + elements[n-2].value : -1LL), an_1 + an + h)`
    //   Goodness = `max_f - min_f`
    //   Partition: elements[n-1] is 2, others are 1.

    // Let's calculate these three candidates and pick the best.

    long long best_goodness = -1;
    std::vector<int> result_partition(n);

    // Candidate 1: All in one group
    long long current_min_f_1 = a1 + a2;
    long long current_max_f_1 = an_1 + an;
    long long current_goodness_1 = current_max_f_1 - current_min_f_1;

    best_goodness = current_goodness_1;
    for (int i = 0; i < n; ++i) {
        result_partition[elements[i].original_index] = 1;
    }

    // Candidate 2: elements[0] in group 1, others in group 2
    long long current_min_f_2;
    if (n >= 3) {
        current_min_f_2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    } else { // n=2
        current_min_f_2 = elements[0].value + elements[1].value + h; // Only one pair (a1, a2) and they are in different groups
    }
    long long current_max_f_2 = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    long long current_goodness_2 = current_max_f_2 - current_min_f_2;

    if (current_goodness_2 < best_goodness) {
        best_goodness = current_goodness_2;
        result_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[elements[i].original_index] = 2;
        }
    }

    // Candidate 3: elements[n-1] in group 2, others in group 1
    long long current_min_f_3 = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
    long long current_max_f_3;
    if (n >= 3) {
        current_max_f_3 = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);
    } else { // n=2
        current_max_f_3 = elements[0].value + elements[1].value + h; // Only one pair (a1, a2) and they are in different groups
    }
    long long current_goodness_3 = current_max_f_3 - current_min_f_3;

    if (current_goodness_3 < best_goodness) {
        best_goodness = current_goodness_3;
        result_partition[elements[n-1].original_index] = 2;
        for (int i = 0; i < n - 1; ++i) {
            result_partition[elements[i].original_index] = 1;
        }
    }

    std::cout << best_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

