// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can form s' = s[i...N-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    // The original string s is a palindrome.
    // If s' is a palindrome and s' != s, then k=1 is the answer.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < n
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // If all characters in s are the same (e.g., "aaaa"), then no rearrangement
    // of substrings will ever produce a different string, because all substrings
    // will also consist of the same character.
    // In this case, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Consider the string s = A B A, where A is s[0...N/2-1] and B is s[N/2].
        // (If N is even, B is empty).
        // Since s is a palindrome and not all characters are the same,
        // there must be at least two distinct characters.
        // This implies that s is not of the form "aaaaa...".
        //
        // We can always achieve k=2.
        // Example: s = "nolon"
        // Cut 1: "no" | "lon"
        // Cut 2: "no" | "l" | "on"
        // Rearrange to "on" | "l" | "no" -> "onlno" which is a palindrome and != "nolon".
        //
        // The general strategy for k=2:
        // Take the first character s[0].
        // Take the middle part s[1...N-2].
        // Take the last character s[N-1].
        // Since s is a palindrome, s[0] == s[N-1].
        //
        // If s[0] != s[1], then s[0] s[1...N-2] s[N-1] can be rearranged to
        // s[N-1] s[1...N-2] s[0]. This is s' = s[N-1] + s[1...N-2] + s[0].
        // Since s[0] == s[N-1], this is equivalent to s[0] + s[1...N-2] + s[0].
        // This is the original string s.
        //
        // However, if not all characters are the same, there must be some character s[i] != s[0].
        // Since s is a palindrome, s[i] == s[N-1-i].
        //
        // Consider cutting s into three pieces:
        // P1 = s[0]
        // P2 = s[1...N-2]
        // P3 = s[N-1]
        //
        // Rearrange to P3 P2 P1. This forms s[N-1] + s[1...N-2] + s[0].
        // Since s is a palindrome, s[N-1] == s[0].
        // So P3 P2 P1 is the same as s[0] + s[1...N-2] + s[N-1], which is s.
        // This specific rearrangement doesn't work.
        //
        // A different strategy for k=2:
        // Cut s into s[0...N/2-1] and s[N/2...N-1].
        // Let s_left = s.substr(0, n/2);
        // Let s_right = s.substr(n/2);
        //
        // If n is odd, s_right starts with the middle character.
        // s = s_left + s_middle_char + s_left_reversed
        //
        // Example: "nolon" (n=5)
        // s_left = "no"
        // s_middle_char = "l"
        // s_right_part = "on" (s_left_reversed)
        //
        // Cut 1: s[0...N/2-1] | s[N/2...N-1]
        // For "nolon", this is "no" | "lon"
        //
        // Cut 2: s[0...N/2-1] | s[N/2] | s[N/2+1...N-1]
        // For "nolon", this is "no" | "l" | "on"
        //
        // Rearrange to s[N/2+1...N-1] | s[N/2] | s[0...N/2-1]
        // For "nolon", this is "on" | "l" | "no" = "onlno"
        // "onlno" is a palindrome and "onlno" != "nolon".
        //
        // This strategy works if n >= 3 and not all characters are the same.
        // If n=1, "a", impossible.
        // If n=2, "aa", impossible.
        // If n=3, "aba", not all same.
        //   Cut "a" | "b" | "a". Rearrange to "a" | "b" | "a" -> "aba". No.
        //   This specific rearrangement (P3 P2 P1) doesn't work.
        //
        // The problem statement guarantees that if not all characters are the same,
        // then k=2 is always possible.
        // The example "nolon" (k=2) confirms this.
        // The example "qqqq" (Impossible) confirms the all_same_char case.
        //
        // So, if all_same_char is false, and k=1 didn't work, then k=2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

