#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one/has_neg_one for elements to the left
        // This is only relevant if a[i] itself was 1 or -1.
        // If a[i] was 0, it doesn't affect the flags.
        if (a[i] == 1) {
            has_pos_one = false; // This 1 is now "used up" as a source for future elements
                                 // or it's the current element being modified.
                                 // It cannot be used as a source for elements to its left.
                                 // For elements to its right, it's already processed.
                                 // So, for any i' < i, this a[i] cannot be a source.
                                 // The flag `has_pos_one` tracks if there's any 1 at index < current_i.
        } else if (a[i] == -1) {
            has_neg_one = false;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

