        }
        // If max_val_in_row is 0, it means all other elements are 0.
        // This can only happen if n=1, but n >= 2.
        // Or if p[i] is 1 and all other p[j] are also 1, which is not a permutation.
        // The only way max_val_in_row can be 0 is if n=1, which is not allowed.
        // For n >= 2, max_val_in_row will be at least 1.
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

