#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell visited, or -1 for cell 0.
                             // The distance from last_R_pos to the current 'R' cell is what matters.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we are at cell i+1 (1-indexed) and s[i] is 'R',
                // it means we can jump right from cell i+1.
                // The distance from the previous 'R' cell (or cell 0) to this 'R' cell is (i+1) - (last_R_pos + 1)
                // which simplifies to i - last_R_pos.
                // We need to be able to jump from last_R_pos to i+1.
                // The distance required for this jump is (i+1) - (last_R_pos + 1) = i - last_R_pos.
                // Or, more simply, the distance from the previous safe point (last_R_pos + 1) to the current safe point (i + 1).
                // The actual cells are 0, 1, ..., n, n+1.
                // last_R_pos is 0-indexed.
                // If last_R_pos is -1, it means we are coming from cell 0.
                // The current 'R' is at s[i], which corresponds to cell i+1.
                // The distance from cell 0 to cell i+1 is i+1.
                // If last_R_pos is not -1, it means the previous 'R' was at s[last_R_pos], corresponding to cell last_R_pos+1.
                // The distance from cell last_R_pos+1 to cell i+1 is (i+1) - (last_R_pos+1) = i - last_R_pos.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through all characters, we need to consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's) to cell n+1.
        // The last 'R' was at s[last_R_pos], corresponding to cell last_R_pos+1.
        // The target is cell n+1.
        // The distance is (n+1) - (last_R_pos+1) = n - last_R_pos.
        max_dist = std::max(max_dist, n - last_R_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the cost of the next nice staircase.
            // A nice staircase with k stairs costs k * (k + 1) / 2 cells.
            // The sequence of k for nice staircases is 1, 3, 7, 15, ... which is 2^i - 1.
            // So, the cost for the i-th nice staircase (where k = 2^i - 1) is (2^i - 1) * (2^i) / 2.
            // Let's use the direct formula for the cost of a nice staircase with k stairs.
            // The k here is the number of stairs, not the index i.
            // The sequence of k values for nice staircases is 1, 3, 7, 15, 31, ...
            // This is k_i = 2^(i+1) - 1 for i = 0, 1, 2, ...
            // The cost for a staircase with k stairs is k * (k + 1) / 2.
            // For k=1, cost = 1*(2)/2 = 1.
            // For k=3, cost = 3*(4)/2 = 6.
            // For k=7, cost = 7*(8)/2 = 28.
            // For k=15, cost = 15*(16)/2 = 120.
            // For k=31, cost = 31*(32)/2 = 496.

            long long cost_of_next_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_next_staircase <= x) {
                current_cost += cost_of_next_staircase;
                count++;
                // Update k for the next nice staircase.
                // The next k is 2*k + 1.
                // If current k is 1, next is 3.
                // If current k is 3, next is 7.
                // If current k is 7, next is 15.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

