int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students (no specialization): x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' additional members from the remaining pool.
            // These additional members can be coders, mathematicians, or no-specialization students.
            // The total number of students available for these 'mid' additional slots is:
            // (c - mid) + (m - mid) + x
            // If this sum is >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = n;
    bool use_left = true;

    // Generate k-1 distinct differences using a zigzag pattern
    // This will generate differences: n-1, n-2, ..., n-k+1
    for (int i = 0; i < k; ++i) {
        if (use_left) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
        use_left = !use_left;
    }

    // For the remaining n-k elements, append them in increasing or decreasing order
    // to ensure the differences are small (mostly 1) and don't introduce new distinct differences
    // beyond the k-1 already generated.
    // The last element placed was either 'left-1' or 'right+1'.
    // If the last element was from 'left', then 'left' is the next smallest available.
    // If the last element was from 'right', then 'right' is the next largest available.
    // To keep differences small (1), we just continue with the remaining numbers in order.
    // If use_left is true, it means the last element placed was 'right'. So we should continue with 'left'
    // and then 'left+1', 'left+2', etc.
    // If use_left is false, it means the last element placed was 'left'. So we should continue with 'right'
    // and then 'right-1', 'right-2', etc.

    if (use_left) { // Last element placed was 'right', so 'left' is the next available smallest.
                    // We should append remaining numbers in increasing order.
        for (int i = k; i < n; ++i) {
            p[i] = left;
            left++;
        }
    } else { // Last element placed was 'left', so 'right' is the next available largest.
             // We should append remaining numbers in decreasing order.
        for (int i = k; i < n; ++i) {
            p[i] = right;
            right--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

