    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horz_moves = std::min(counts['L'], counts['R']);
    int vert_moves = std::min(counts['U'], counts['D']);

    std::string result_path = "";
    int total_length = 0;

    if (horz_moves == 0 && vert_moves == 0) {
        // No moves possible
        total_length = 0;
        result_path = "";
    } else if (horz_moves == 0) {
        // Only vertical moves possible, e.g., UUDD.
        // To be valid, it must be U then D, or D then U.
        // If we have only U and D, and we want to return to (0,0),
        // we must have at least one U and one D.
        // The path UUDD is invalid because (0,1) is visited twice.
        // The only valid path with only U/D moves is UD or DU.
        // So, if horz_moves is 0, we can only use 2 moves: UD or DU.
        // This is only possible if vert_moves >= 1.
        total_length = 2;
        result_path = "UD";
    } else if (vert_moves == 0) {
        // Only horizontal moves possible, e.g., LLRR.
        // Similar to vertical, only LR or RL is valid.
        // This is only possible if horz_moves >= 1.
        total_length = 2;
        result_path = "LR";
    } else {
        // Both horizontal and vertical moves are available.
        // We can construct a path like U...UR...RD...DL...L
        // or L...LU...UR...RD...D
        // The structure L...LU...UR...RD...D is valid.
        // Example: L U R D
        // The path will be:
        // horz_moves 'L's
        // vert_moves 'U's
        // horz_moves 'R's
        // vert_moves 'D's
        // This forms a rectangle.
        // The length will be 2 * horz_moves + 2 * vert_moves.
        total_length = 2 * horz_moves + 2 * vert_moves;

        for (int i = 0; i < horz_moves; ++i) result_path += 'L';
        for (int i = 0; i < vert_moves; ++i) result_path += 'U';
        for (int i = 0; i < horz_moves; ++i) result_path += 'R';
        for (int i = 0; i < vert_moves; ++i) result_path += 'D';
    }

    std::cout << total_length << std::endl;
    std::cout << result_path << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result_subsequence.push_back(p[i]);
        }
    }
    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

