#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Found a mismatch at index i
            // Check if there's an adjacent mismatch of the opposite type
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // This means a[i] != b[i] AND a[i+1] != b[i+1]
                // AND a[i] and a[i+1] are different (e.g., '0' and '1')
                // This implies that b[i] and b[i+1] are also different
                // Example: a="01", b="10" or a="10", b="01"
                // In this case, swapping a[i] and a[i+1] makes both match b
                // a[i] becomes a[i+1], which is b[i]
                // a[i+1] becomes a[i], which is b[i+1]
                // Cost is |i - (i+1)| = 1
                cost += 1;
                i += 2; // Both positions i and i+1 are now fixed
            } else {
                // No adjacent mismatch of opposite type, or no adjacent mismatch at all
                // We must flip a[i]
                cost += 1;
                i += 1; // Position i is now fixed
            }
        } else {
            // a[i] == b[i], no operation needed for this position
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each fixed x_i, advance right_ptr to find the largest index 'k'
        // such that x[k] - x[i] <= d.
        // Since x is sorted, x[k] will be <= x[i] + d.
        // The right_ptr only moves forward, making this O(N) overall.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element x[right_ptr]
        // such that x[right_ptr] - x[i] > d, OR right_ptr == n.
        // So, all valid x_k for the current x_i are in the range [i+1, right_ptr-1].

        // The number of points available to choose from (excluding x_i itself)
        // is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let this be 'm'. These are points x_{i+1}, ..., x_{right_ptr-1}.
        // We need to choose 2 points from these 'm' points.
        // The number of ways to choose 2 points from 'm' points is m * (m - 1) / 2.

        long long m = (long long)(right_ptr - 1) - (i + 1) + 1;
        // m = right_ptr - 1 - i;
        // This 'm' is the count of points x_j, x_k such that i < j < k and x_k - x_i <= d.
        // More precisely, 'm' is the number of points in the range (x_i, x_{right_ptr-1}].
        // If m < 2, we cannot choose two distinct points, so we add 0.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // These elements are a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s.
    // Since a is sorted, if a[i] > s, then a[i+1]...a[median_idx-1] are also > s.
    // We only need to consider elements that are currently greater than s.
    // Elements that are already <= s don't need to be changed to satisfy the median property for the left side.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These elements are a[median_idx+1]...a[n-1]
    // If a[i] < s, we must increase it to s.
    // Since a is sorted, if a[i] < s, then a[i-1]...a[median_idx+1] are also < s.
    // We only need to consider elements that are currently smaller than s.
    // Elements that are already >= s don't need to be changed to satisfy the median property for the right side.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

