// Function to determine if a box can be the special box
// A, B, C, D are initial counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box_idx is 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4.
bool can_be_special(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy initially, that toy is the super toy.
    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // Case 1: Final toy is in Box 1 (value <= -1)
    if (target_box_idx == 0) {
        // To get a negative value, there must be an odd number of negative factors.
        // To get magnitude >= 1, there must be at least one factor with magnitude >= 1,
        // or multiple factors with magnitude < 1 that multiply to >= 1 (e.g., 0.5 * 3 = 1.5, 0.5 * 0.5 * 5 = 1.25).
        // However, it's always possible to construct a value >= 1 if there's at least one value >= 1,
        // or if we can combine enough values < 1 to exceed 1.
        // The key is that we can always choose specific values within the ranges.
        // For example, if we need magnitude >= 1, and we have a toy in Box 4 (e.g., 1.5),
        // we can multiply it by any toy in Box 3 (e.g., 0.5) to get 0.75 (Box 3), or by a toy in Box 2 (e.g., -0.5) to get -0.75 (Box 2).
        // If we need magnitude >= 1, and we have a toy in Box 1 (e.g., -1.5),
        // we can multiply it by any toy in Box 3 (e.g., 0.5) to get -0.75 (Box 2), or by a toy in Box 2 (e.g., -0.5) to get 0.75 (Box 3).

        // The crucial observation is that if we have at least one toy in Box 1 or Box 4 (magnitude >= 1),
        // we can always ensure the final magnitude is >= 1 by strategically multiplying.
        // If all initial toys are in Box 2 or Box 3 (magnitude < 1), then the final toy will always have magnitude < 1.
        // So, for Box 1 or Box 4 to be the special box, we must have A+D > 0.
        if (A + D == 0) return false; // All initial toys have magnitude < 1, so final toy will have magnitude < 1.

        // Now we know A+D > 0, so magnitude >= 1 is possible.
        // We need an odd number of negative factors.
        // The number of negative factors is A + B.
        // If A + B is odd, we can end up with a negative value.
        // If A + B is even, we can end up with a positive value.
        // We can always manipulate the sign by pairing up negative numbers.
        // If we have an odd number of negative toys (A+B is odd), we can always end up with a negative result.
        // If we have an even number of negative toys (A+B is even), we can always end up with a positive result.
        // So, for Box 1 (negative, magnitude >= 1), we need A+D > 0 AND (A+B) % 2 == 1.
        return (A + B) % 2 == 1;
    }

    // Case 2: Final toy is in Box 2 (value in (-1, 0))
    if (target_box_idx == 1) {
        // To get a negative value, we need an odd number of negative factors (A+B is odd).
        // To get magnitude < 1, we need A+D == 0 (all initial toys have magnitude < 1).
        // OR, if A+D > 0, we need to be able to make the magnitude < 1.
        // This is always possible if we have at least one toy in Box 2 or Box 3.
        // For example, if we have a toy in Box 4 (e.g., 2) and a toy in Box 2 (e.g., -0.1),
        // we can multiply them to get -0.2 (Box 2).
        // If we have a toy in Box 1 (e.g., -2) and a toy in Box 3 (e.g., 0.1),
        // we can multiply them to get -0.2 (Box 2).
        // The only way we *cannot* get magnitude < 1 is if all initial toys are in Box 1 or Box 4,
        // AND we only have one toy (which would be in Box 1 or Box 4).
        // If total_toys > 1 and A+D > 0, we can always make magnitude < 1 if B+C > 0.
        // If B+C == 0, then all toys are in Box 1 or Box 4.
        // If A+D > 0 and B+C == 0, then all toys have magnitude >= 1.
        // In this scenario, the final toy will always have magnitude >= 1.
        // So, if B+C == 0, Box 2 and Box 3 are impossible.
        if (B + C == 0) return false; // All initial toys have magnitude >= 1, so final toy will have magnitude >= 1.

        // Now we know B+C > 0, so magnitude < 1 is possible.
        // We need an odd number of negative factors (A+B is odd).
        return (A + B) % 2 == 1;
    }

    // Case 3: Final toy is in Box 3 (value in (0, 1))
    if (target_box_idx == 2) {
        // To get a positive value, we need an even number of negative factors (A+B is even).
        // To get magnitude < 1, we need B+C > 0 (similar logic as Box 2).
        if (B + C == 0) return false; // All initial toys have magnitude >= 1, so final toy will have magnitude >= 1.

        // Now we know B+C > 0, so magnitude < 1 is possible.
        // We need an even number of negative factors (A+B is even).
        return (A + B) % 2 == 0;
    }

    // Case 4: Final toy is in Box 4 (value >= 1)
    if (target_box_idx == 3) {
        // To get a positive value, we need an even number of negative factors (A+B is even).
        // To get magnitude >= 1, we need A+D > 0 (similar logic as Box 1).
        if (A + D == 0) return false; // All initial toys have magnitude < 1, so final toy will have magnitude < 1.

        // Now we know A+D > 0, so magnitude >= 1 is possible.
        // We need an even number of negative factors (A+B is even).
        return (A + B) % 2 == 0;
    }

    return false; // Should not be reached
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::string results[4];
        for (int i = 0; i < 4; ++i) {
            if (can_be_special(A, B, C, D, i)) {
                results[i] = "Ya";
            } else {
                results[i] = "Tidak";
            }
        }
        std::cout << results[0] << " " << results[1] << " " << results[2] << " " << results[3] << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementsA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementsB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A_indexed[i].value;
        A_indexed[i].original_index = i;
    }

    std::vector<ElementB> B_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B_indexed[i].value;
        B_indexed[i].original_index = i;
    }

    std::sort(A_indexed.begin(), A_indexed.end(), compareElementsA);
    std::sort(B_indexed.begin(), B_indexed.end(), compareElementsB);

    std::vector<long long> result_A(m);
    for (int i = 0; i < m; ++i) {
        result_A[B_indexed[i].original_index] = A_indexed[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

