void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i was not seen before as a prefix max.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i
            // We need to find the smallest available number that hasn't been used yet
            // and is less than q_i.
            // The largest available number that is less than q_i is q_i - 1.
            // We should pick the smallest available number to maximize chances for later elements.
            // However, the problem asks for *any* valid permutation.
            // A simpler strategy for p_i when q_i == q_{i-1} is to pick the smallest available number
            // that is not yet used and is less than q_i.
            // Let's try to pick the largest available number that is less than q_i.
            // This is because larger numbers are more restrictive.
            // If we pick a smaller number, it leaves larger numbers available for later.
            // The problem states "any possible suitable permutation".
            // Let's try to fill p_i with the smallest available number.
            // This is equivalent to finding the smallest number `x` such that `1 <= x < q_i` and `x` is not in `used_numbers`.
            // We can iterate from 1 up to `q_i - 1` to find such an `x`.
            // Or, we can maintain a set of available numbers.
            // A more efficient way is to use a pointer to the next available number.
            // All numbers from 1 to n are initially available.
            // When a number is used, it's removed from availability.
            // For q_i == q_{i-1}, we need to pick an available number `x` such that `x < q_i`.
            // The smallest such `x` is `1` if available, then `2` if available, etc.
            // Let's use a set of all numbers from 1 to n, and remove used ones.
            // Then for q_i == q_{i-1}, we pick the smallest element from the set that is less than q_i.
            // This is not quite right. We need to pick *any* valid number.
            // The simplest strategy is to pick the largest available number that is less than q_i.
            // This is because if we pick a smaller number, it might be needed later.
            // If we pick the largest available number less than q_i, it's less likely to be needed later.
            // Let's use a set of all numbers from 1 to n, and remove used ones.
            // Then for q_i == q_{i-1}, we pick the largest element from the set that is less than q_i.
            // This is `*used_numbers.rbegin()` if we want to pick the largest available.
            // No, this is not correct. `used_numbers` contains numbers already placed in `p`.
            // We need a set of *unused* numbers.

            // Let's use a boolean array or a set to track unused numbers.
            // A `std::set<int> unused_pool` initialized with `1...n` and then remove `q_i` values.
            // This is too slow if we do it for every test case.
            // A `std::vector<bool> is_used(n + 1, false)` is better.

            // The numbers that are not `q_j` for any `j` are candidates for `p_i` when `q_i == q_{i-1}`.
            // We need to find an unused number `x` such that `x < q_i`.
            // The problem guarantees `q_i <= q_{i+1}`.
            // The numbers `q_j` are always used.
            // So, we need to fill `p_i` with an unused number `x` such that `x < q_i`.
            // Let's maintain a list of available numbers.
            // The numbers `1, ..., n` are available.
            // When `p_j` is set to `val`, `val` becomes unavailable.
            // For `q_i == q_{i-1}`, we need to find an `x` such that `x < q_i` and `x` is available.
            // To make it simple, let's use a `std::set<int> available_nums`.
            // Initialize `available_nums` with `1, ..., n`.
            // When `p_j` is set, remove `p_j` from `available_nums`.
            // For `q_i == q_{i-1}`, we need to find `x = *available_nums.upper_bound(q_i - 1)` (largest less than q_i).
            // Or `x = *available_nums.begin()` (smallest available).
            // The example output for `1 3 4 5 5` is `1 3 4 5 2`.
            // Here `q_4 = 5, q_3 = 4`. `p_4 = 5`.
            // `q_5 = 5, q_4 = 5`. `p_5` must be `< 5` and unused.
            // Used: `1, 3, 4, 5`. Available: `2`. `p_5 = 2`. This works.
            // This suggests picking the smallest available number.

            // Let's try to fill `p_i` with the smallest available number that is less than `q_i`.
            // We can use a `std::set<int> available_pool` to store numbers not yet used.
            // Initialize `available_pool` with `1, ..., n`.
            // For `p_0 = q_0`, remove `q_0` from `available_pool`.
            // For `i > 0`:
            // If `q_i > q_{i-1}`, then `p_i = q_i`. Remove `q_i` from `available_pool`.
            // If `q_i == q_{i-1}`, then `p_i` must be some `x < q_i` and `x` must be in `available_pool`.
            // We need to find such an `x`.
            // The smallest such `x` is `*available_pool.begin()`.
            // The largest such `x` is `*available_pool.rbegin()` if `*available_pool.rbegin() < q_i`.
            // Or `*std::prev(available_pool.upper_bound(q_i))` if `available_pool.upper_bound(q_i)` is not `available_pool.begin()`.
            // Let's try to pick the largest available number that is less than `q_i`.
            // This is `*std::prev(available_pool.lower_bound(q_i))`.
            // If `available_pool.lower_bound(q_i)` is `available_pool.begin()`, then no such number exists.

            // Let's re-evaluate.
            // `p_0 = q_0`.
            // For `i = 1 to n-1`:
            // If `q_i > q_{i-1}`, then `p_i = q_i`.
            // If `q_i == q_{i-1}`, then `p_i` must be some `x` such that `x < q_i` and `x` is not yet used.
            // We need to find *any* such `x`.
            // The simplest way to manage unused numbers is to put all numbers `1..n` into a `std::set<int> available`.
            // Then, for each `p_i` that is determined to be `q_i`, remove `q_i` from `available`.
            // For `p_i` where `q_i == q_{i-1}`, we need to pick an element from `available` that is less than `q_i`.
            // To maximize chances of success, we should pick the largest available number that is less than `q_i`.
            // This is `*std::prev(available.lower_bound(q_i))`.
            // If `available.lower_bound(q_i)` is `available.begin()`, it means all available numbers are `>= q_i`, which is impossible.

            // Let's use a `std::vector<bool> used(n + 1, false)` for efficiency.
            // `p[0] = q[0]`. Mark `used[q[0]] = true`.
            // For `i = 1 to n-1`:
            // If `q[i] > q[i-1]`:
            //   `p[i] = q[i]`.
            //   If `used[q[i]]` is true, then `q[i]` was already used, which is an error.
            //   This implies `q_i` was already `q_j` for some `j < i`, but `q_i > q_{i-1}`.
            //   This means `q_i` must be a new maximum. If `q_i` was already used, it means `q_i` was `p_k` for some `k < i`.
            //   But `p_k` is part of `max(p_1, ..., p_{i-1}) = q_{i-1}`.
            //   So `q_i` would be `<= q_{i-1}`, which contradicts `q_i > q_{i-1}`.
            //   So `used[q[i]]` should always be false here.
            //   Mark `used[q[i]] = true`.
            // Else (`q[i] == q[i-1]`):
            //   We need to find an `x` such that `1 <= x < q[i]` and `used[x]` is false.
            //   To maximize chances, let's pick the largest such `x`.
            //   Iterate `j` from `q[i] - 1` down to `1`.
            //   If `used[j]` is false, then `p[i] = j`. Mark `used[j] = true`. Break.
            //   If no such `j` is found, then it's impossible.

            // This strategy seems robust.
            // Example 1: n=5, q=[1, 3, 4, 5, 5]
            // p = [?, ?, ?, ?, ?], used = [F,F,F,F,F,F] (size n+1)
            // i=0: p[0] = q[0] = 1. used[1]=T. p=[1,?,?,?,?]
            // i=1: q[1]=3, q[0]=1. q[1]>q[0]. p[1]=q[1]=3. used[3]=T. p=[1,3,?,?,?]
            // i=2: q[2]=4, q[1]=3. q[2]>q[1]. p[2]=q[2]=4. used[4]=T. p=[1,3,4,?,?]
            // i=3: q[3]=5, q[2]=4. q[3]>q[2]. p[3]=q[3]=5. used[5]=T. p=[1,3,4,5,?]
            // i=4: q[4]=5, q[3]=5. q[4]==q[3].
            //   Search j from q[4]-1=4 down to 1.
            //   j=4: used[4] is T.
            //   j=3: used[3] is T.
            //   j=2: used[2] is F. p[4]=2. used[2]=T. p=[1,3,4,5,2]. Break.
            // Output: 1 3 4 5 2. Matches example.

            // Example 2: n=4, q=[1, 1, 3, 4]
            // p = [?,?,?,?], used = [F,F,F,F,F]
            // i=0: p[0]=q[0]=1. used[1]=T. p=[1,?,?,?]
            // i=1: q[1]=1, q[0]=1. q[1]==q[0].
            //   Search j from q[1]-1=0 down to 1. (Loop condition j>=1)
            //   No j found. Impossible. Set possible=false. Break.
            // Output: -1. Matches example.

            // Example 3: n=2, q=[2, 2]
            // p = [?,?], used = [F,F,F]
            // i=0: p[0]=q[0]=2. used[2]=T. p=[2,?]
            // i=1: q[1]=2, q[0]=2. q[1]==q[0].
            //   Search j from q[1]-1=1 down to 1.
            //   j=1: used[1] is F. p[1]=1. used[1]=T. p=[2,1]. Break.
            // Output: 2 1. Matches example.

            // This strategy seems correct and covers all cases.
            // The sum of N over all test cases is 10^5.
            // The inner loop for `q[i] == q[i-1]` can iterate up to `N` times.
            // In the worst case, if `q` is `[N, N, ..., N]`, then `p[0]=N`, and for all `i>0`, `q[i]==q[i-1]`.
            // Each `p[i]` would search from `N-1` down to `1`.
            // This would be `O(N^2)` per test case, which is too slow for `N=10^5`.
            // `10^5 * 10^5 = 10^{10}`.

            // We need a faster way to find the largest unused number less than `q[i]`.
            // A `std::set<int> available_numbers` can do this.
            // Initialize `available_numbers` with `1, ..., n`.
            // `p[0] = q[0]`. Remove `q[0]` from `available_numbers`.
            // For `i = 1 to n-1`:
            // If `q[i] > q[i-1]`:
            //   `p[i] = q[i]`. Remove `q[i]` from `available_numbers`.
            // Else (`q[i] == q[i-1]`):
            //   Find `it = available_numbers.lower_bound(q[i])`.
            //   If `it == available_numbers.begin()`, it means all available numbers are `>= q[i]`.
            //   This implies no number less than `q[i]` is available. Impossible.
            //   Else, `it` points to the smallest available number that is `>= q[i]`.
            //   We need the largest available number that is `< q[i]`. This is `*std::prev(it)`.
            //   `p[i] = *std::prev(it)`. Remove `p[i]` from `available_numbers`.

            // Let's trace Example 2 with `std::set<int> available_numbers`:
            // n=4, q=[1, 1, 3, 4]
            // available_numbers = {1, 2, 3, 4}
            // p = [?,?,?,?]
            // i=0: p[0]=q[0]=1. available_numbers.erase(1). available_numbers = {2, 3, 4}. p=[1,?,?,?]
            // i=1: q[1]=1, q[0]=1. q[1]==q[0].
            //   it = available_numbers.lower_bound(q[1]=1). `it` points to 2.
            //   `it != available_numbers.begin()`. So `std::prev(it)` is valid.
            //   `std::prev(it)` would point to an element less than 1, but there are none.
            //   This condition `it == available_numbers.begin()` is crucial.
            //   If `it` points to 2, `std::prev(it)` would be invalid.
            //   `lower_bound(val)` returns an iterator to the first element not less than `val`.
            //   If we want largest element less than `val`, we need `std::prev(available_numbers.lower_bound(val))`.
            //   This is only valid if `available_numbers.lower_bound(val)` is not `available_numbers.begin()`.
            //   In this case, `q[1]=1`. `available_numbers.lower_bound(1)` points to `2`.
            //   `std::prev(available_numbers.lower_bound(1))` would be invalid.
            //   So, `it == available_numbers.begin()` check is correct.
            //   Here, `available_numbers.lower_bound(1)` is `available_numbers.find(2)`.
            //   `available_numbers.begin()` is `available_numbers.find(2)`.
            //   So `it == available_numbers.begin()` is true.
            //   This means no number less than `q[1]=1` is available. Impossible. Set possible=false. Break.
            // Output: -1. Matches example.

            // This `std::set` approach is `O(N log N)` per test case, which is `10^5 log 10^5` total.
            // `log_2(10^5)` is about 17. So `10^5 * 17` operations, which is fine.

    std::set<int> available_numbers;
    for (int k = 1; k <= n; ++k) {
        available_numbers.insert(k);
    }

    p[0] = q[0];
    if (available_numbers.count(q[0])) { // Should always be true if q[0] is valid
        available_numbers.erase(q[0]);
    } else {
        possible = false; // q[0] is out of range 1..n or already used (impossible for p[0])
    }

    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (available_numbers.count(q[i])) {
                available_numbers.erase(q[i]);
            } else {
                // q[i] is either out of range 1..n or already used.
                // If q[i] was already used, it means q[i] was some p_k for k < i.
                // But if q[i] > q[i-1], then q[i] must be the new maximum, so it cannot be p_k for k < i.
                // So this implies q[i] is out of range 1..n.
                possible = false;
            }
        } else { // q[i] == q[i-1]
            // Find the largest available number that is less than q[i]
            auto it = available_numbers.lower_bound(q[i]);
            if (it == available_numbers.begin()) {
                // No available number is less than q[i]
                possible = false;
            } else {
                --it; // Move to the largest available number strictly less than q[i]
                p[i] = *it;
                available_numbers.erase(it);
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

