    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k == 0) { // No wins possible even after k changes
            std::cout << 0 << "\n";
            continue;
        }

        if (initial_wins + k >= n) { // Can make all games wins
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        std::vector<int> gaps;
        int first_W = -1;
        int last_W = -1;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        if (first_W == -1) { // All 'L's initially
            std::cout << 2 * k - 1 << "\n"; // k wins, first is 1, others 2.
            continue;
        }

        // Calculate gaps between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else {
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int score = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                score++;
                if (i > 0 && s[i-1] == 'W') {
                    score++;
                }
            }
        }

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score += 2 * gap_len + 1; // gap_len L's become W's, adding 2*gap_len points, plus 1 for connecting
            } else {
                score += 2 * k; // Use remaining k to turn L's into W's, each adds 2 points (as they are next to existing W's)
                k = 0;
                break;
            }
        }

        // Fill L's at ends
        if (k > 0) {
            // L's before first W
            score += std::min(k, first_W) * 2;
            k -= std::min(k, first_W);

            // L's after last W
            if (k > 0) {
                score += std::min(k, n - 1 - last_W) * 2;
            }
        }

        std::cout << score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
