// Function to check if a prefix of length `len` is a permutation
// `a` is the input array, `len` is the length of the prefix
// `max_val_prefix` is the maximum value encountered in the prefix
// `counts_prefix` stores frequency of elements in the prefix
bool is_prefix_permutation(int len, int max_val_prefix, const std::vector<int>& counts_prefix) {
    if (max_val_prefix != len) {
        return false;
    }
    for (int i = 1; i <= len; ++i) {
        if (counts_prefix[i] != 1) {
            return false;
        }
    }
    return true;
}

// Function to check if a suffix of length `len` is a permutation
// `a` is the input array, `start_idx` is the starting index of the suffix
// `len` is the length of the suffix
// `max_val_suffix` is the maximum value encountered in the suffix
// `counts_suffix` stores frequency of elements in the suffix
bool is_suffix_permutation(int start_idx, int len, int max_val_suffix, const std::vector<int>& counts_suffix) {
    if (max_val_suffix != len) {
        return false;
    }
    for (int i = 1; i <= len; ++i) {
        if (counts_suffix[i] != 1) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_total = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_total) {
            max_val_total = a[i];
        }
    }

    // Precompute prefix properties
    std::vector<int> prefix_max_val(n + 1, 0);
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(n + 1, 0));
    std::vector<bool> is_prefix_valid(n + 1, false);

    int current_max_prefix = 0;
    std::vector<int> current_counts_prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        current_counts_prefix[val]++;
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }

        int len = i + 1;
        prefix_max_val[len] = current_max_prefix;
        prefix_counts[len] = current_counts_prefix; // Copy counts

        if (current_max_prefix == len) {
            bool distinct_and_present = true;
            for (int j = 1; j <= len; ++j) {
                if (current_counts_prefix[j] != 1) {
                    distinct_and_present = false;
                    break;
                }
            }
            is_prefix_valid[len] = distinct_and_present;
        }
    }

    // Precompute suffix properties
    std::vector<int> suffix_max_val(n + 1, 0);
    std::vector<std::vector<int>> suffix_counts(n + 1, std::vector<int>(n + 1, 0));
    std::vector<bool> is_suffix_valid(n + 1, false);

    int current_max_suffix = 0;
    std::vector<int> current_counts_suffix(n + 1, 0);
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        current_counts_suffix[val]++;
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }

        int len = n - i;
        suffix_max_val[len] = current_max_suffix;
        suffix_counts[len] = current_counts_suffix; // Copy counts

        if (current_max_suffix == len) {
            bool distinct_and_present = true;
            for (int j = 1; j <= len; ++j) {
                if (current_counts_suffix[j] != 1) {
                    distinct_and_present = false;
                    break;
                }
            }
            is_suffix_valid[len] = distinct_and_present;
        }
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_valid[l1] && is_suffix_valid[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

