    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long opponent_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets score from N-1.
                // Chanek gets 1 + (total_coins - opponent_score_from_N-1)
                // This is complex because opponent plays optimally.
                // Let's analyze the optimal strategy for even N.
                // If N is even, Chanek can take N/2 or 1.
                // If Chanek takes N/2, remaining N/2.
                // If Chanek takes 1, remaining N-1.
                // The game is symmetric.
                // If N is even, and N is not a power of 2, or N is a power of 2 but N/2 is odd.
                // Example: N=6. Chanek can take 3 or 1.
                // If Chanek takes 3: N=3. Opponent's turn. Opponent takes 1. N=2. Chanek's turn. Chanek takes 1. N=1. Opponent's turn. Opponent takes 1. N=0.
                // Chanek: 3+1 = 4. Opponent: 1+1 = 2.
                // If Chanek takes 1: N=5. Opponent's turn. Opponent takes 1. N=4. Chanek's turn. Chanek takes 2. N=2. Opponent's turn. Opponent takes 1. N=1. Chanek's turn. Chanek takes 1. N=0.
                // Chanek: 1+2+1 = 4. Opponent: 1+1 = 2.
                // In this case, both lead to 4.

                // The key insight for even N:
                // If N is even, and N is not a power of 2, or N is a power of 2 but N/2 is odd:
                // Chanek can take N/2. The remaining N/2 coins will be handled by the opponent.
                // If N is a power of 2 (e.g., 2, 4, 8, 16, ...), taking N/2 is generally good.
                // Example: N=4.
                // Chanek takes 2. N=2. Opponent's turn. Opponent takes 1. N=1. Chanek's turn. Chanek takes 1. N=0.
                // Chanek: 2+1 = 3. Opponent: 1.
                // If Chanek takes 1. N=3. Opponent's turn. Opponent takes 1. N=2. Chanek's turn. Chanek takes 1. N=1. Opponent's turn. Opponent takes 1. N=0.
                // Chanek: 1+1 = 2. Opponent: 1+1 = 2.
                // So for N=4, taking N/2 is better.

                // The only time taking 1 is better for even N is when N is a power of 2, and N/2 is also a power of 2, and so on, until N becomes 2.
                // For example, N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1, Opponent: 1.
                // If Chanek takes N/2=1. N=1. Opponent takes 1. Chanek: 1, Opponent: 1.
                // For N=2, both options yield 1 for Chanek.

                // Consider N=2^k.
                // If Chanek takes N/2, then N becomes 2^(k-1).
                // If Chanek takes 1, then N becomes 2^k - 1 (odd).
                // If N is a power of 2, say N = 2^k.
                // If Chanek takes N/2, he gets N/2. Remaining N/2. Opponent gets score from N/2.
                // If Chanek takes 1, he gets 1. Remaining N-1. Opponent gets score from N-1.
                // The strategy is to take N/2 if N/2 is odd, or if N/2 is even but not a power of 2.
                // If N is a power of 2, say N = 2^k, then N/2 = 2^(k-1).
                // If k=1, N=2. Take 1 or N/2=1. Both give 1.
                // If k > 1, N/2 is even.
                // The optimal strategy for even N is to take N/2 unless N is a power of 2 and taking 1 leads to a better outcome.
                // This happens when N is a power of 2, and taking 1 leaves an odd number, which the opponent will take 1 from, leaving an even number for Chanek.
                // The pattern for powers of 2:
                // N=2: C:1, O:1. (C takes 1 or N/2=1)
                // N=4: C:3, O:1. (C takes N/2=2)
                // N=8: C:5, O:3. (C takes N/2=4)
                // N=16: C:9, O:7. (C takes N/2=8)
                // It seems for N=2^k, Chanek takes N/2.
                // The only exception is when N=2.
                // For N=2, Chanek takes 1.
                // For N > 2 and N is a power of 2, Chanek takes N/2.
                // For N is even and not a power of 2, Chanek takes N/2.

                // Let's re-evaluate the strategy for even N.
                // If N is even:
                // Option A: Take 1. Remaining N-1 (odd).
                // Option B: Take N/2. Remaining N/2.

                // If N/2 is odd (e.g., N=6, N/2=3):
                // Chanek takes N/2. Chanek gets N/2. Remaining N/2.
                // Opponent's turn, N/2 is odd. Opponent takes 1. Remaining N/2-1.
                // This seems good for Chanek.
                // If N/2 is odd, Chanek takes N/2.
                // Example N=6: Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.

                // If N/2 is even (e.g., N=4, N/2=2; N=8, N/2=4):
                // This means N is a multiple of 4.
                // Chanek can take N/2. Chanek gets N/2. Remaining N/2.
                // Or Chanek can take 1. Chanek gets 1. Remaining N-1 (odd).
                // If N is a power of 2 (N=2^k, k>=2), then N/2 is also a power of 2.
                // In this case, taking N/2 is always optimal for Chanek.
                // Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.

                // The only special case is N=2.
                // If N=2, Chanek takes 1.
                // If N > 2 and N is even: Chanek takes N/2.
                // This covers all cases.

                if (n == 2) {
                    chanek_score += 1;
                    n -= 1;
                } else {
                    chanek_score += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                opponent_score += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    opponent_score += 1;
                    n -= 1;
                } else {
                    opponent_score += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

