// Function to find prime factors of a number
std::set<long long> get_prime_factors(long long n) {
    std::set<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.insert(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.insert(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to remove some prime factors from p such that the resulting number x
        // is no longer divisible by q, but we remove as few as possible (or rather, we want x to be as large as possible).

        // Find all unique prime factors of q.
        std::set<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        // For each prime factor f of q, consider dividing p by f until it's no longer divisible by q.
        // The resulting number will be a candidate for x.
        // We take the maximum among all such candidates.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // This means we divide by f until the count of f in current_p is less than the count of f in q.
            // Or more simply, divide by f until current_p is no longer divisible by q.
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

