#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> fixed_val(k, -1); // -1 for unknown, 0 for '0', 1 for '1'
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        int current_char_val;
        if (s[i] == '0') {
            current_char_val = 0;
        } else if (s[i] == '1') {
            current_char_val = 1;
        } else { // s[i] == '?'
            current_char_val = -1;
        }

        int remainder = i % k;
        if (fixed_val[remainder] == -1) {
            fixed_val[remainder] = current_char_val;
        } else if (current_char_val != -1 && fixed_val[remainder] != current_char_val) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int zeros_count = 0;
    int ones_count = 0;
    int unknown_count = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_val[i] == 0) {
            zeros_count++;
        } else if (fixed_val[i] == 1) {
            ones_count++;
        } else { // fixed_val[i] == -1
            unknown_count++;
        }
    }

    if (zeros_count > k / 2 || ones_count > k / 2) {
        possible = false;
    } else {
        // We need to fill (k/2 - zeros_count) '0's and (k/2 - ones_count) '1's
        // using the 'unknown_count' '?' positions.
        // The sum of these needed counts must be equal to unknown_count.
        // (k/2 - zeros_count) + (k/2 - ones_count) = k - (zeros_count + ones_count)
        // This is exactly unknown_count.
        // So, if zeros_count <= k/2 and ones_count <= k/2, it's always possible to fill the '?'s.
        // The remaining '?'s can be filled to satisfy the k/2 condition.
        // For example, if we need more zeros, fill '?' with '0' until k/2 zeros are met.
        // Then fill remaining '?' with '1' until k/2 ones are met.
        // This is always possible if the initial counts don't exceed k/2.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

