    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = a[i] % n;
        long long to_add = (remainder == 0) ? 0 : (n - remainder);
        a[i] += to_add;
        std::cout << to_add << (i == n - 2 ? "" : " ");
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n
    // Segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = a[n - 1] % n;
    long long to_add_n_minus_1 = (remainder_n_minus_1 == 0) ? 0 : (n - remainder_n_minus_1);
    a[n - 1] += to_add_n_minus_1;
    std::cout << to_add_n_minus_1 << "\n";

    // Operation 3: Make all elements zero
    // Segment [1, n] (0-indexed: [0, n-1])
    // Length is n
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        // At this point, all a[i] are multiples of n.
        // We need to add -a[i] to make them zero.
        // -a[i] is also a multiple of n.
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

