        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k is less than the minimum number of moves (abs_n)
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k and abs_n have different parities
        // This means (k - abs_n) is odd.
        // If (k - abs_n) is odd, then (k - abs_m) must also be odd.
        // If (abs_n - abs_m) is even, then (k - abs_n) and (k - abs_m) have same parity.
        // If (abs_n - abs_m) is odd, then (k - abs_n) and (k - abs_m) have different parity.
        // The parity of the final coordinates (abs_n, abs_m) must match the parity of k.
        // Specifically, (abs_n % 2) == (k % 2) and (abs_m % 2) == (k % 2) is not strictly required.
        // What is required is that (abs_n + abs_m) % 2 == (k % 2) if we only consider moves that change parity.
        // However, we can always make two moves that cancel out parity changes (e.g., (0,0)->(1,0)->(0,0)).
        // The key is that each move changes the parity of (x+y) by 1 or -1.
        // So, (x_final + y_final) % 2 must be equal to (k % 2).
        // (abs_n + abs_m) % 2 must be equal to (k % 2).
        // This is equivalent to (abs_n % 2) == (k % 2) if and only if (abs_m % 2) == 0.
        // Or (abs_n % 2) != (k % 2) if and only if (abs_m % 2) == 1.
        // A simpler way: (k - abs_n) must be even if (abs_n - abs_m) is even.
        // (k - abs_n) must be odd if (abs_n - abs_m) is odd.
        // This is equivalent to (k - abs_n) % 2 == (abs_n - abs_m) % 2.
        // Which simplifies to k % 2 == abs_m % 2.
        // Or, (k - abs_n) % 2 == 0 if (abs_n % 2) == (abs_m % 2)
        // And (k - abs_n) % 2 == 1 if (abs_n % 2) != (abs_m % 2)

        // Let's re-evaluate the parity condition.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // The parity of (x+y) changes by 0 or 1.
        // A diagonal move changes (x+y) by 2, 0, or -2. Parity of (x+y) does not change.
        // A non-diagonal move changes (x+y) by 1 or -1. Parity of (x+y) changes.
        // Let D be diagonal moves, ND be non-diagonal moves.
        // (abs_n + abs_m) % 2 must be equal to (ND % 2).
        // Since ND = k - D, (abs_n + abs_m) % 2 must be equal to (k - D) % 2.
        // This means (abs_n + abs_m) % 2 == (k % 2) if D is even.
        // And (abs_n + abs_m) % 2 != (k % 2) if D is odd.
        // This is not simple enough.

        // A simpler parity check:
        // The parity of the final coordinates (n, m) must match the parity of k.
        // If n and m have the same parity (n%2 == m%2), then (n+m) is even.
        // To reach (n,m) in k moves, (k - n) must be even and (k - m) must be even.
        // This means k must have the same parity as n (and m).
        // If n and m have different parities (n%2 != m%2), then (n+m) is odd.
        // To reach (n,m) in k moves, (k - n) must be odd and (k - m) must be odd.
        // This means k must have a different parity than n (and m).
        // This is incorrect. Consider (1,0) in 1 move. k=1, n=1, m=0. n%2 != m%2. k%2 == n%2.
        // Consider (2,0) in 2 moves. k=2, n=2, m=0. n%2 == m%2. k%2 == n%2.
        // Consider (1,1) in 1 move. k=1, n=1, m=1. n%2 == m%2. k%2 != n%2.
        // The correct parity condition is:
        // If (abs_n % 2) == (abs_m % 2):
        //   Then k must have the same parity as abs_n (and abs_m).
        //   i.e., (k % 2) == (abs_n % 2).
        // If (abs_n % 2) != (abs_m % 2):
        //   Then k must have a different parity than abs_n (and abs_m).
        //   i.e., (k % 2) != (abs_n % 2).
        // This can be combined: (k % 2) == ((abs_n + abs_m) % 2).
        // No, this is also wrong.
        // The correct parity condition is:
        // If (abs_n % 2) == (abs_m % 2):
        //   Then k must have the same parity as abs_n (and abs_m).
        //   (k % 2) == (abs_n % 2)
        // If (abs_n % 2) != (abs_m % 2):
        //   Then k must have a different parity than abs_n (and abs_m).
        //   (k % 2) != (abs_n % 2)
        // This is equivalent to: (k - abs_n) % 2 == 0 if (abs_n % 2) == (abs_m % 2)
        // And (k - abs_n) % 2 == 1 if (abs_n % 2) != (abs_m % 2)
        // This is equivalent to: (k - abs_n) % 2 == (abs_n - abs_m) % 2.
        // Which simplifies to: (k % 2) == (abs_m % 2).
        // Let's test this:
        // (2,2,3) -> abs_n=2, abs_m=2, k=3. (k%2) = 1, (abs_m%2) = 0. Not equal. Output 1.
        // My condition says it should be -1. Example output is 1. So my condition is wrong.

        // Let's re-think the parity.
        // Each move changes x by dx, y by dy.
        // (x_final, y_final) = (sum(dx_i), sum(dy_i))
        // k moves.
        // The minimum number of moves to reach (abs_n, abs_m) is abs_n (assuming abs_n >= abs_m).
        // This involves abs_m diagonal moves and (abs_n - abs_m) non-diagonal moves.
        // Total min_moves = abs_m + (abs_n - abs_m) = abs_n.
        // If k > abs_n, we have (k - abs_n) extra moves.
        // Each extra move must be paired with a "return" move to cancel out displacement.
        // E.g., (0,0) -> (1,0) -> (0,0). This uses 2 moves, changes (x,y) by (0,0).
        // (0,0) -> (1,1) -> (0,0). This uses 2 moves, changes (x,y) by (0,0).
        // Each pair of such moves adds 2 to k, but doesn't change (abs_n, abs_m).
        // So, (k - abs_n) must be an even number.
        // If (k - abs_n) is odd, it's impossible.
        // This is the standard Manhattan distance + parity argument for grid problems.
        // (k - abs_n) % 2 != 0 implies impossible.

        if ((k - abs_n) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible.
        // We want to maximize diagonal moves.
        // We make abs_m diagonal moves to reach (abs_m, abs_m).
        // We make (abs_n - abs_m) non-diagonal moves to reach (abs_n, abs_m).
        // This uses abs_n moves.
        // We have (k - abs_n) remaining moves. This quantity is even.
        // We can use these remaining moves in pairs.
        // Each pair can be:
        // 1. (1,0) then (-1,0) - 0 diagonal moves.
        // 2. (1,1) then (-1,-1) - 2 diagonal moves.
        // 3. (1,0) then (0,1) then (-1,0) then (0,-1) - 0 diagonal moves. (4 moves)
        // To maximize diagonal moves, we should use pairs of (1,1) and (-1,-1).
        // Each such pair adds 2 to the total diagonal moves and 2 to k.
        // So, we can add (k - abs_n) / 2 * 2 = (k - abs_n) diagonal moves.
        // Total diagonal moves = abs_m (initial diagonal moves) + (k - abs_n) (from extra pairs).

        long long max_diag_moves = abs_m + (k - abs_n);

        std::cout << max_diag_moves << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track its state if input bit is 0 and if input bit is 1.
    // state_if_0[bit_idx] = final value of bit_idx if input bit_idx was 0
    // state_if_1[bit_idx] = final value of bit_idx if input bit_idx was 1
    std::vector<int> state_if_0(10); // Initially, if input bit is 0, output bit is 0
    std::vector<int> state_if_1(10); // Initially, if input bit is 1, output bit is 1

    // Initialize states: for each bit j, if input bit j is 0, output bit j is 0.
    // If input bit j is 1, output bit j is 1.
    // This means state_if_0[j] = 0 and state_if_1[j] = 1 for all j.
    std::iota(state_if_1.begin(), state_if_1.end(), 0); // Not really, this sets to 0,1,2...
    // Correct initialization:
    for (int i = 0; i < 10; ++i) {
        state_if_0[i] = 0;
        state_if_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant 'val'

            if (op_char == '&') {
                state_if_0[i] &= bit_val;
                state_if_1[i] &= bit_val;
            } else if (op_char == '|') {
                state_if_0[i] |= bit_val;
                state_if_1[i] |= bit_val;
            } else if (op_char == '^') {
                state_if_0[i] ^= bit_val;
                state_if_1[i] ^= bit_val;
            }
        }
    }

    // Now, determine the equivalent operations.
    // We need to find A_AND, A_OR, A_XOR such that:
    // ( ( (x & A_AND) | A_OR ) ^ A_XOR )
    // produces the same result for all x from 0 to 1023.

    // Let's find the combined effect for each bit.
    // For each bit 'i':
    // If input bit 'i' is 0, output bit 'i' is state_if_0[i].
    // If input bit 'i' is 1, output bit 'i' is state_if_1[i].

    // We can represent the final transformation for each bit 'i' as:
    // ( ( (x_i & and_mask_i) | or_mask_i ) ^ xor_mask_i )
    // where x_i is the i-th bit of the input.

    // Let's try to find the combined AND, OR, XOR constants.
    // Initialize combined constants:
    // Start with an identity transformation: x & 1023 | 0 ^ 0
    int final_and_const = 1023; // All bits are 1
    int final_or_const = 0;     // All bits are 0
    int final_xor_const = 0;    // All bits are 0

    for (int i = 0; i < 10; ++i) {
        // For bit 'i':
        // If input bit is 0, output should be state_if_0[i].
        // If input bit is 1, output should be state_if_1[i].

        // Case 1: state_if_0[i] = 0, state_if_1[i] = 0
        // This means the bit is always 0, regardless of input.
        // To achieve this: (x_i & 0) | 0 ^ 0 = 0
        // Or: (x_i & 1) | 0 ^ 1 = 1 (if x_i=0) or 0 (if x_i=1) -- no
        // (x_i & 0) makes it 0.
        // So, set i-th bit of final_and_const to 0.
        if (state_if_0[i] == 0 && state_if_1[i] == 0) {
            final_and_const &= ~(1 << i); // Set i-th bit to 0
            final_or_const &= ~(1 << i);  // Set i-th bit to 0
            final_xor_const &= ~(1 << i); // Set i-th bit to 0
        }
        // Case 2: state_if_0[i] = 0, state_if_1[i] = 1
        // This means the bit is unchanged (x_i).
        // To achieve this: (x_i & 1) | 0 ^ 0 = x_i
        // So, set i-th bit of final_and_const to 1.
        // i-th bit of final_or_const to 0.
        // i-th bit of final_xor_const to 0.
        else if (state_if_0[i] == 0 && state_if_1[i] == 1) {
            final_and_const |= (1 << i); // Set i-th bit to 1
            final_or_const &= ~(1 << i); // Set i-th bit to 0
            final_xor_const &= ~(1 << i); // Set i-th bit to 0
        }
        // Case 3: state_if_0[i] = 1, state_if_1[i] = 0
        // This means the bit is inverted (~x_i).
        // To achieve this: (x_i & 1) | 0 ^ 1 = ~x_i
        // So, set i-th bit of final_and_const to 1.
        // i-th bit of final_or_const to 0.
        // i-th bit of final_xor_const to 1.
        else if (state_if_0[i] == 1 && state_if_1[i] == 0) {
            final_and_const |= (1 << i); // Set i-th bit to 1
            final_or_const &= ~(1 << i); // Set i-th bit to 0
            final_xor_const |= (1 << i); // Set i-th bit to 1
        }
        // Case 4: state_if_0[i] = 1, state_if_1[i] = 1
        // This means the bit is always 1, regardless of input.
        // To achieve this: (x_i & 0) | 1 ^ 0 = 1
        // Or: (x_i & 1) | 1 ^ 0 = 1
        // So, set i-th bit of final_or_const to 1.
        // i-th bit of final_and_const to 0.
        // i-th bit of final_xor_const to 0.
        else if (state_if_0[i] == 1 && state_if_1[i] == 1) {
            final_and_const &= ~(1 << i); // Set i-th bit to 0
            final_or_const |= (1 << i);   // Set i-th bit to 1
            final_xor_const &= ~(1 << i); // Set i-th bit to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If AND mask is not all 1s
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If OR mask is not all 0s
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If XOR mask is not all 0s
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int target_diff = initial_s - initial_b;

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_left[k] = (S_count - B_count) for jars 1 to k
    std::vector<int> diff_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_right[k] = (S_count - B_count) for jars 2n-k+1 to 2n
    std::vector<int> diff_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left to achieve a certain diff
    // key: diff_left[k], value: k (jars eaten from left)
    std::map<int, int> left_diff_to_k;
    for (int k = 0; k <= n; ++k) {
        if (left_diff_to_k.find(diff_left[k]) == left_diff_to_k.end()) {
            left_diff_to_k[diff_left[k]] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars eaten from the right (j)
    // For each j, calculate the required diff from the left (diff_left[i])
    // and check if it exists in the map.
    for (int j = 0; j <= n; ++j) {
        int current_right_diff = diff_right[j];
        int required_left_diff = target_diff - current_right_diff;

        if (left_diff_to_k.count(required_left_diff)) {
            int i = left_diff_to_k[required_left_diff];
            min_jars_eaten = std::min(min_jars_eaten, i + j);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;

        // If m ones, there are m+1 possible blocks of zeros.
        // Distribute num_zeros among m+1 blocks as evenly as possible.
        // Let k be the number of zeros in each block.
        // There will be (m+1) blocks.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.

        long long num_blocks = m + 1;

        long long k_small = num_zeros / num_blocks;
        long long count_large_blocks = num_zeros % num_blocks;
        long long count_small_blocks = num_blocks - count_large_blocks;

        long long k_large = k_small + 1;

        long long substrings_of_zeros = 0;

        // Substrings from small blocks
        substrings_of_zeros += count_small_blocks * (k_small * (k_small + 1) / 2);

        // Substrings from large blocks
        substrings_of_zeros += count_large_blocks * (k_large * (k_large + 1) / 2);

        long long result = total_substrings - substrings_of_zeros;

        std::cout << result << "\n";
    }
    return 0;
}

