int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then increment by d for new blocks

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, (1LL << k) <= X + 1

        // A more direct way: find the highest set bit in X+1, its position is k.
        // Or iterate k from 60 down to 0.
        for (int i = 60; i >= 0; --i) {
            if (((1LL << (i + 1)) - 1) <= X) {
                k = i + 1;
                break;
            }
        }
        if (k == 0) { // If X is 1, then (1LL << 1) - 1 = 1 <= X, so k=1. This case should not be reached.
                      // If X is 0, loop won't run.
            k = 1; // For X=1, k should be 1. (1LL << 1) - 1 = 1.
        }

        // Add k elements of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        X -= ((1LL << k) - 1); // Subtract the count of subsequences generated by these k elements

        if (X > 0) {
            current_val += d; // Increment current_val by d for the next block
            // Ensure current_val doesn't exceed 10^18
            if (current_val >= 1000000000000000000LL) {
                // This case should ideally not be reached given X, d constraints and N limit.
                // But as a safeguard.
                std::cout << -1 << std::endl;
                return 0;
            }
        }
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(std::vector<int>& current_seq, std::vector<int>& next_seq) {
    int n = current_seq.size();
    bool changed = false;

    next_seq[0] = current_seq[0];
    next_seq[n - 1] = current_seq[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = current_seq[i - 1] + current_seq[i] + current_seq[i + 1];
        next_seq[i] = (sum >= 2) ? 1 : 0;
    }

    if (current_seq != next_seq) {
        changed = true;
        current_seq.swap(next_seq); // Efficiently update current_seq
    }
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (no internal elements to smooth)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    std::vector<int> next_seq(n);
    int steps = 0;

    // Find the first 0-1 or 1-0 transition
    int first_transition_idx = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] != current_seq[i+1]) {
            first_transition_idx = i;
            break;
        }
    }

    // If no transitions, sequence is all 0s or all 1s, already stable
    if (first_transition_idx == -1) {
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the last 0-1 or 1-0 transition
    int last_transition_idx = -1;
    for (int i = n - 2; i >= 0; --i) {
        if (current_seq[i] != current_seq[i+1]) {
            last_transition_idx = i;
            break;
        }
    }

    // Calculate max_steps based on the transitions
    // The number of steps is limited by the distance from the ends to the nearest transition
    // or half the distance between the first and last transition.
    // Specifically, it's ceil( (last_transition_idx - first_transition_idx) / 2.0 )
    // plus 1 if the first/last elements are different from their neighbors.
    // A simpler bound is (n-1)/2, but we can be more precise.
    // The maximum number of steps for a sequence of length N is roughly N/2.
    // For N=500,000, this is 250,000.
    // We can use a more precise bound: max_steps = max(first_transition_idx, n - 1 - (last_transition_idx + 1))
    // This is the distance from an end to the nearest "stable" block.
    // Or, more simply, the maximum number of steps is bounded by n/2.
    // The actual number of steps is related to the "width" of the changing region.
    // The number of steps is at most (last_transition_idx - first_transition_idx + 1) / 2.
    // Let's use a generous bound like n to be safe, or even n/2.
    // The maximum number of steps is actually (last_transition_idx - first_transition_idx + 1) / 2.
    // Example: 01010 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2. Correct.
    // Example: 0011 (n=4). first_trans=1, last_trans=1. (1-1+1)/2 = 0. Correct.
    // Example: 000111 (n=6). first_trans=2, last_trans=2. (2-2+1)/2 = 0. Correct.
    // Example: 01110 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // 01110 -> 01110 (stable) -> 0 steps.
    // My formula is for the "width" of the unstable region.
    // The actual number of steps is the maximum of:
    // 1. The number of steps for the first block to stabilize: first_transition_idx + 1 if a[0] != a[first_transition_idx+1]
    // 2. The number of steps for the last block to stabilize: n - (last_transition_idx + 1) if a[n-1] != a[last_transition_idx]
    // 3. The number of steps for the middle part to stabilize.
    // The maximum number of steps is actually `(last_transition_idx - first_transition_idx + 1) / 2`
    // if the sequence is of the form 0...01...10...0 or 1...10...01...1.
    // For 01010, first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // For 01110, first_trans=0, last_trans=3. (3-0+1)/2 = 2. But it's 0 steps.
    // The formula is for the maximum possible steps for a sequence of alternating values.
    // The actual number of steps is bounded by `n/2`. Let's use `n` as a safe upper bound for the loop.
    // The problem statement guarantees that if it stabilizes, it does so in a finite number of steps.
    // The maximum number of steps is actually `(n-1)/2`.
    // For N=500,000, this is 249,999.
    // A loop for `n` iterations is fine.

    for (int k = 0; k < n; ++k) { // Max steps is bounded by n/2, so n iterations is safe.
        if (!apply_median_smoothing(current_seq, next_seq)) {
            break; // Sequence became stable
        }
        steps++;
    }

    // Check for non-stability (oscillating sequences)
    // An oscillating sequence would be something like 010101...
    // However, for 0s and 1s, the median filter tends to "flatten" sequences.
    // It's known that for 0/1 sequences, the median filter always converges to a stable state.
    // The only stable sequences are blocks of 0s and 1s, e.g., 000111, 00000, 11111.
    // A sequence like 010101... will eventually become 000000... or 111111...
    // The problem statement implies that it *might* not become stable, but for 0/1 sequences, it always does.
    // So, we don't need to output -1. The loop will always break.

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

