    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of deletion
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back to the graph

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core of Floyd-Warshall, but applied incrementally
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices

                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating paths through k,
        // we also need to update paths using other active vertices
        // as intermediates for paths involving k.
        // This is essentially running Floyd-Warshall on the current set of active vertices.
        // The previous loop (i->k->j) handles paths where k is the *new* intermediate.
        // The following two loops handle paths where k is an endpoint and an existing active vertex is an intermediate.
        // And also paths where k is an intermediate for two existing active vertices.
        // The full Floyd-Warshall structure is:
