        //     }
        // }
        // This updates all pairs `(i, j)` using `k_node` as an intermediate.
        // This is the correct step for adding `k_node` to the set of allowed intermediates.
        //
        // After this, `dist` matrix contains shortest paths between *all* pairs `(i, j)`
        // using only intermediate vertices from the set `{x[n-1], x[n-2], ..., x[k_idx]}`.
        //
        // So, the first triple loop should be:
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // This updates all paths using `k` as an intermediate.
        // This is the standard Floyd-Warshall step for `k`.
        //
        // Now, calculate the sum for *only* the currently active vertices.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
    long long max_val_at_op_time; // For type 2, this is the m_i
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n);
    std::vector<long long> current_delta(n, 0);

    // Step 1: Determine upper bounds for a[i]
    // For each type 2 operation (2 l r m), it implies a[j] + delta[j] <= m for l <= j <= r.
    // This means a[j] <= m - delta[j].
    // We want to find the largest possible a[j] that satisfies all constraints.
    // So, a[j] must be <= min(m - delta[j]) over all relevant type 2 operations.
    // Initialize a[i] to a very large value (effectively infinity)
    for (int i = 0; i < n; ++i) {
        a[i] = std::numeric_limits<long long>::max();
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] = std::min(a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Step 2: Verify the solution and adjust a[i] if necessary
    // After step 1, a[i] contains the maximum possible initial value for each index
    // that satisfies all type 2 upper bound constraints.
    // Now, we need to check if these values actually work.
    // For each type 2 operation (2 l r m), we must have max(a[j] + delta[j]) = m.
    // If max(a[j] + delta[j]) < m, then no solution exists.
    // If max(a[j] + delta[j]) > m, then our a[j] values are too high, which contradicts
    // how we derived them (they are already the maximum possible). This case should not happen
    // if the problem is well-posed and a solution exists.

    // Reset current_delta for verification
    std::fill(current_delta.begin(), current_delta.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long current_max = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_max = std::max(current_max, a[j] + current_delta[j]);
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array elements
    for (int i = 0; i < n; ++i) {
        if (std::abs(a[i]) > 1000000000LL) {
            // This case should ideally be caught by the current_max != ops[i].val check
            // if the problem guarantees a solution within bounds.
            // However, if a[i] was initialized to max_long_long and never constrained,
            // it might remain too large.
            // The problem statement says "Levko clearly remembers that all numbers in his array didn't exceed 10^9 in their absolute value"
            // This implies that if a solution exists, it must satisfy this.
            // Our construction finds the largest possible a[i]. If this largest possible a[i]
            // is out of bounds, then no solution exists within bounds.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
