int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_input(n); // a_input[0] is unused, a_input[1]...a_input[n-1] are a_2...a_n
    for (int i = 1; i < n; ++i) {
        std::cin >> a_input[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop, >=0: final y
    std::vector<int> dp_x(n + 1, 0);     // 0: uncomputed, -1: infinite loop, >=1: final x

    // Compute DP for a_x where x is from 2 to n
    // dp_y[k] stores the final y value if we start at x=k, y=0 and a_k is the first step.
    // dp_x[k] stores the final x value if we start at x=k, y=0 and a_k is the first step.
    // This is for the "second half" of the jump: x = x - a_x, y = y + a_x
    // The actual values stored are for the state *after* the first step (x+a_x, y+a_x)
    // and *before* the second step (x-a_x, y+a_x+a_x).
    // Let's rephrase: dp_y[k] is the total y accumulated and dp_x[k] is the final x
    // if we start at x=k, y=0 and perform the sequence:
    // 1. x_new = k + a_k, y_new = 0 + a_k
    // 2. x_final = x_new - a_k, y_final = y_new + a_k
    // This is equivalent to starting at x=k, y=0, then jumping to x=k, y=2*a_k.
    // Then from (k, 2*a_k) we need to find the result.
    // The DP state should be: if we are at (x_curr, y_curr) and the next step is x_curr + a_x_curr,
    // what is the final y and x?

    // Let's define dp_y[k] as the final y value and dp_x[k] as the final x value
    // if we start the *cycle* at x=k, y=0.
    // A cycle is: (x,y) -> (x+a_x, y+a_x) -> (x+a_x-a_x, y+a_x+a_x) = (x, y+2*a_x)
    // This is not quite right. The problem states:
    // 1. x = x + a_x, y = y + a_x
    // 2. y = y + a_x, x = x - a_x
    // So if we are at (x_curr, y_curr), the next state is (x_curr + a_x_curr, y_curr + a_x_curr).
    // Let's call this (x_prime, y_prime).
    // Then from (x_prime, y_prime), the next state is (x_prime - a_x_prime, y_prime + a_x_prime).
    // Let's call this (x_double_prime, y_double_prime).
    // The DP should store the result of starting from (x_prime, y_prime).

    // dp_y[k] = final y if we start at x=k, y=0 and perform step 2 then step 3.
    // dp_x[k] = final x if we start at x=k, y=0 and perform step 2 then step 3.
    // This means:
    // current_x = k, current_y = 0
    // x_step2 = k + a_k, y_step2 = 0 + a_k
    // If x_step2 <= 0 or x_step2 > n, then dp_x[k] = x_step2, dp_y[k] = y_step2.
    // Else:
    // x_step3 = x_step2 - a_x_step2, y_step3 = y_step2 + a_x_step2
    // If x_step3 <= 0 or x_step3 > n, then dp_x[k] = x_step3, dp_y[k] = y_step3.
    // Else:
    // We need to find the result from (x_step3, y_step3).
    // This is a recursive definition.

    // Let's use a different DP state:
    // dp_y[k] = total y accumulated *from this point onwards* if we are at x=k.
    // dp_x[k] = final x value *from this point onwards* if we are at x=k.
    // This means, if we are at x=k, y=Y_current, and we want to find the final Y and X.
    // The first operation is x = k + a_k, y = Y_current + a_k.
    // Let x_next = k + a_k.
    // If x_next <= 0 or x_next > n:
    //   dp_y[k] = a_k
    //   dp_x[k] = x_next
    // Else:
    //   The second operation is y = (Y_current + a_k) + a_x_next, x = x_next - a_x_next.
    //   Let x_final_in_this_step = x_next - a_x_next.
    //   If x_final_in_this_step <= 0 or x_final_in_this_step > n:
    //     dp_y[k] = a_k + a_x_next
    //     dp_x[k] = x_final_in_this_step
    //   Else:
    //     dp_y[k] = a_k + a_x_next + dp_y[x_final_in_this_step]
    //     dp_x[k] = dp_x[x_final_in_this_step]
    // This is a recursive definition that can be solved with memoization.
    // The values a_k are from a_input.
    // For a_1, we iterate i from 1 to n-1.

    // The values a_k are 1-indexed in the problem, but a_input is 0-indexed.
    // a_input[0] is unused. a_input[k] corresponds to a_{k+1} in the problem.
    // So a_input[k-1] corresponds to a_k.
    // For a_k, we use a_input[k-1] if k > 1.
    // For a_1, we use the current 'i' from the outer loop.

    // Let's define a helper function or use a loop for DP.
    // We need to compute dp_y[k] and dp_x[k] for k from n down to 2.
    // For k=1, it's a special case for each i.

    // dp_y[k] and dp_x[k] will store the result of starting a *full cycle* at x=k.
    // A full cycle: (x, y) -> (x+a_x, y+a_x) -> (x+a_x-a_{x+a_x}, y+a_x+a_{x+a_x})
    // Let's use a_val[k] for a_k.
    // For k from n down to 2:
    //   Let current_a_val = a_input[k-1].
    //   x_after_step2 = k + current_a_val
    //   y_after_step2 = current_a_val
    //   If x_after_step2 <= 0 or x_after_step2 > n:
    //     dp_x[k] = x_after_step2
    //     dp_y[k] = y_after_step2
    //   Else:
    //     x_after_step3 = x_after_step2 - a_input[x_after_step2-1]
    //     y_after_step3 = y_after_step2 + a_input[x_after_step2-1]
    //     If x_after_step3 <= 0 or x_after_step3 > n:
    //       dp_x[k] = x_after_step3
    //       dp_y[k] = y_after_step3
    //     Else:
    //       If dp_x[x_after_step3] == -1: // Infinite loop detected
    //         dp_x[k] = -1
    //         dp_y[k] = -1
    //       Else:
    //         dp_x[k] = dp_x[x_after_step3]
    //         dp_y[k] = y_after_step3 + dp_y[x_after_step3]

    // This DP approach is for a fixed 'a' array.
    // The problem is that a_1 changes for each query.
    // So, for each i (1 to n-1), a_1 = i.
    // The values a_2, ..., a_n are fixed.
    // This means dp_x[k] and dp_y[k] for k >= 2 can be precomputed.
    // For k=1, we need to compute it for each i.

    // Let's define dp_x[k] and dp_y[k] for k from 2 to n.
    // dp_x[k] = final x if we start at x=k, y=0 and perform the sequence of operations.
    // dp_y[k] = final y if we start at x=k, y=0 and perform the sequence of operations.
    // The sequence of operations is:
    // 1. x_new = k + a_k, y_new = a_k
    // 2. x_final = x_new - a_x_new, y_final = y_new + a_x_new
    // If x_new or x_final is out of bounds, we terminate.
    // Otherwise, we continue from (x_final, y_final).

    // To handle cycles, we can use a 'visiting' state.
    // -2: uncomputed
    // -1: currently visiting (part of a cycle)
    // 0: computed (final x/y stored)

    std::vector<long long> memo_y(n + 1, -2); // -2: uncomputed, -1: infinite loop, >=0: final y
    std::vector<int> memo_x(n + 1, -2);     // -2: uncomputed, -1: infinite loop, >=0: final x (or out of bounds)
    std::vector<int> visiting(n + 1, 0); // 0: not visiting, 1: visiting

    // Function to compute memo_x[start_x] and memo_y[start_x]
    // This function computes the result of starting a *full program execution* from x=start_x, y=0.
    // It uses a_input for a_2...a_n.
    auto solve = [&](int start_x, long long a_val_for_start_x, auto& self) -> void {
        if (start_x <= 0 || start_x > n) {
            memo_x[start_x] = start_x;
            memo_y[start_x] = 0; // No operations performed, y remains 0
            return;
        }
        if (memo_x[start_x] != -2) { // Already computed or in a cycle
            return;
        }
        if (visiting[start_x] == 1) { // Cycle detected
            memo_x[start_x] = -1;
            memo_y[start_x] = -1;
            return;
        }

        visiting[start_x] = 1;

        long long current_a_val = (start_x == 1) ? a_val_for_start_x : a_input[start_x - 1];

        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = start_x + current_a_val;
        long long y_after_step2 = current_a_val;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            memo_x[start_x] = x_after_step2;
            memo_y[start_x] = y_after_step2;
            visiting[start_x] = 0;
            return;
        }

        // Step 3: y = y + a_x, x = x - a_x
        long long a_val_for_x_after_step2 = (x_after_step2 == 1) ? a_val_for_start_x : a_input[x_after_step2 - 1];
        long long x_after_step3 = x_after_step2 - a_val_for_x_after_step2;
        long long y_after_step3 = y_after_step2 + a_val_for_x_after_step2;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            memo_x[start_x] = x_after_step3;
            memo_y[start_x] = y_after_step3;
            visiting[start_x] = 0;
            return;
        }

        // Continue from x_after_step3
        self(x_after_step3, a_val_for_start_x, self); // Note: a_val_for_start_x is only relevant if x_after_step3 == 1

        if (memo_x[x_after_step3] == -1) { // Infinite loop
            memo_x[start_x] = -1;
            memo_y[start_x] = -1;
        } else {
            memo_x[start_x] = memo_x[x_after_step3];
            memo_y[start_x] = y_after_step3 + memo_y[x_after_step3];
        }
        visiting[start_x] = 0;
    };

    // Precompute for x from 2 to n
    // For these, a_1 is not involved in their calculation.
    // We can pass a dummy value for a_val_for_start_x since start_x != 1.
    for (int k = 2; k <= n; ++k) {
        solve(k, 0, solve); // 0 is a dummy value for a_1
    }

    // Now, for each i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        // Reset memoization and visiting for x=1
        // Other memo_x/y values (for k >= 2) are already computed and valid.
        memo_x[1] = -2;
        memo_y[1] = -2;
        visiting[1] = 0;

        solve(1, i, solve);
        std::cout << memo_y[1] << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v;
    long long d;
    long long p;
    int original_idx;
    bool active; // To mark if child is still in line

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), active(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data;
    children_data.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_data.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children_data[i].active) {
            continue; // This child has already left
        }

        // Child i goes to the dentist
        treated_children_indices.push_back(children_data[i].original_idx);
        children_data[i].active = false; // Mark as treated

        long long current_v_cry = children_data[i].v;
        long long cumulative_d_cry = 0;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (!children_data[j].active) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children_data[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply cumulative cry from children who left earlier in this chain reaction
            children_data[j].p -= cumulative_d_cry;
        }

        // Chain reaction loop
        bool chain_reaction_happened;
        do {
            chain_reaction_happened = false;
            for (int j = i + 1; j < n; ++j) {
                if (children_data[j].active && children_data[j].p < 0) {
                    children_data[j].active = false; // Child j leaves
                    cumulative_d_cry += children_data[j].d; // Add to cumulative cry
                    chain_reaction_happened = true;

                    // Apply this child's d_cry to all subsequent active children
                    for (int k = j + 1; k < n; ++k) {
                        if (children_data[k].active) {
                            children_data[k].p -= children_data[j].d;
                        }
                    }
                }
            }
        } while (chain_reaction_happened);
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_balance++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_balance > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // s = s1s2. New string s' = s2s1.
    // s' must be a palindrome and s' != s.
    // This is possible if s is not a "half-palindrome" (e.g., "abccba" is, "otto" is not)
    // and s2s1 is a palindrome.
    // For s2s1 to be a palindrome, s1 must be the reverse of s2.
    // Since s is already a palindrome, s = s_rev.
    // If s1 = s2_rev, then s = s2_rev s2.
    // Then s_rev = s2_rev s2_rev_rev = s2_rev s2.
    // This means s is of the form X X_rev.
    // Example: "otto". s1="ot", s2="to". s2s1="toot". "toot" is palindrome. "toot" != "otto". k=1.
    // Example: "kinnikkinnik". s1="kinnik", s2="kinnik". s2s1="kinnikkinnik". s2s1 == s. Not valid.
    // Example: "nolon". s1="no", s2="lon". s2s1="lonno". Not palindrome.
    // Example: "abccba". s1="abc", s2="cba". s2s1="cbaabc". Palindrome. s2s1 != s. k=1.

    // A simpler check for k=1:
    // If s can be cut into s_prefix and s_suffix such that s_suffix + s_prefix is a palindrome
    // AND s_suffix + s_prefix != s.
    // This is true if there exists *any* cut point i (1 <= i < n) such that s[i...n-1] + s[0...i-1] is a palindrome
    // AND s[i...n-1] + s[0...i-1] != s.
    // Since s is a palindrome, s[0...i-1] is the reverse of s[n-i...n-1].
    // And s[i...n-1] is the reverse of s[0...n-i-1].
    // So s_suffix + s_prefix is a palindrome if and only if s_prefix is the reverse of s_suffix.
    // This means s = s_prefix s_suffix where s_prefix = reverse(s_suffix).
    // Example: "otto". s_prefix="ot", s_suffix="to". reverse("to")="ot". So s_prefix = reverse(s_suffix).
    // Then s_suffix + s_prefix = "to" + "ot" = "toot", which is a palindrome and != "otto". So k=1.
    // Example: "abccba". s_prefix="abc", s_suffix="cba". reverse("cba")="abc". So s_prefix = reverse(s_suffix).
    // Then s_suffix + s_prefix = "cba" + "abc" = "cbaabc", which is a palindrome and != "abccba". So k=1.
    // This condition is equivalent to checking if s is of the form X X_rev.
    // If s is of the form X X_rev, then s_suffix + s_prefix = X_rev X.
    // This is a palindrome. We just need to check if X_rev X != X X_rev.
    // This is true if X != X_rev.
    // If X = X_rev, then s = X X.
    // Example: "kinnikkinnik". X="kinnik". X is not a palindrome. X_rev="kinnik_rev".
    // s_prefix="kinnik", s_suffix="kinnik". s_suffix + s_prefix = "kinnikkinnik" == s. Not valid.
    // The condition for k=1 is that there exists a cut point `i` such that `s.substr(i) + s.substr(0, i)` is a palindrome AND is not equal to `s`.
    // We can iterate through all possible cut points.
    bool found_k1 = false;
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            found_k1 = true;
            break;
        }
    }
    if (found_k1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    // Check for k=2
    // This means 3 pieces: s = p0 p1 p2.
    // We can rearrange them.
    // The problem statement gives an example: "nolon" -> "no|l|on" -> "on|l|no".
    // "onlno" is a palindrome and != "nolon".
    // This implies that if we can't do it with k=1, we might be able to do it with k=2.
    // The only case where k=2 might be impossible is if all characters in s are the same.
    // If all characters are the same, e.g., "aaaa", "qqqq".
    // Any permutation of substrings will result in the same string "aaaa".
    // So, if all characters are the same, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider s = "nolon". n=5.
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
    // Since s is a palindrome, s[i] == s[n-1-i].
    // If not all characters are the same, there must be at least two distinct characters.
    // Since s is a palindrome, if s[0] != s[1], then s[n-1] != s[n-2].
    // If s[0] != s[1], then s[0] != s[n-2] (since s[1] == s[n-2]).
    // If s[0] != s[1], then s[0] != s[n-1] (since s[0] == s[n-1]).
    // If s[0] != s[1], then s[0] != s[n-2].
    // Consider the string s' formed by taking s[1...n-2] and putting s[0] at the end and s[n-1] at the beginning.
    // s' = s[n-1] + s[1...n-2] + s[0].
    // Since s is a palindrome, s[n-1] == s[0].
    // So s' = s[0] + s[1...n-2] + s[0]. This is just s.
    // This doesn't work.

    // Let's use the example "nolon".
    // s = "nolon".
    // Cut: "no" | "l" | "on". Pieces: p0="no", p1="l", p2="on".
    // Rearrange: p2 | p1 | p0 = "on" | "l" | "no" = "onlno".
    // "onlno" is a palindrome. "onlno" != "nolon".
    // This is a k=2 solution.

    // Why is k=2 always possible if not all characters are the same?
    // If not all characters are the same, then there exists some `i` such that `s[i] != s[0]`.
    // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
    // If `s[i] != s[0]`, then `s[n-1-i] != s[0]`.
    // This means `s` is not of the form `c c ... c`.
    // Consider the string `s_middle = s.substr(1, n-2)`.
    // `s_middle` is also a palindrome.
    // If `s_middle` is not empty (i.e., `n > 2`), we can form `s[n-1] + s_middle + s[0]`.
    // Since `s[n-1] == s[0]`, this is `s[0] + s_middle + s[0]`, which is `s`.
    // This is not a new string.

    // The key insight for k=2 is that if not all characters are the same,
    // then there must be at least one character `c` such that `s[0] != c` and `c` appears in `s`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // If `n` is odd, `n = 2m+1`. `s = s_0 s_1 ... s_m ... s_1 s_0`.
    // If `n` is even, `n = 2m`. `s = s_0 s_1 ... s_{m-1} s_{m-1} ... s_1 s_0`.
    // Consider the string `s_prefix = s.substr(0, n/2)`.
    // If `s_prefix` is not all the same character, then there exists `j < n/2` such that `s[j] != s[0]`.
    // If `s_prefix` is all the same character, then `s = s[0]...s[0]s[0]...s[0]`.
    // This means all characters in `s` are the same, which we've already handled.
    // So, if not all characters are the same, then `s_prefix` must contain at least two distinct characters.
    // This means there is some `j < n/2` such that `s[j] != s[0]`.
    // Since `s` is a palindrome, `s[j] == s[n-1-j]`.
    // So `s[n-1-j] != s[0]`.
    // This means `s` has at least two distinct characters, and these distinct characters are not just at the ends.
    // For example, "abacaba". `s[0]='a'`, `s[1]='b'`. `s[1] != s[0]`.
    // Cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // Pieces: `s[0]`, `s.substr(1, n-2)`, `s[n-1]`.
    // Rearrange to `s[n-1] + s.substr(1, n-2) + s[0]`.
    // This is `s[0] + s.substr(1, n-2) + s[0]`, which is `s`. This doesn't work.

    // The example "nolon" -> "onlno" uses cuts `no|l|on`.
    // This is `s[0...1] | s[2] | s[3...4]`.
    // Pieces: `s[0...1]`, `s[2]`, `s[3...4]`.
    // Rearranged: `s[3...4] + s[2] + s[0...1]`.
    // `s[3...4]` is `on`. `s[2]` is `l`. `s[0...1]` is `no`.
    // Result: `onlno`. This is a palindrome.
    // This is a specific type of cut: `s[0...i-1] | s[i...n-1-i] | s[n-i...n-1]`.
    // And then rearrange to `s[n-i...n-1] | s[i...n-1-i] | s[0...i-1]`.
    // Let `P1 = s[0...i-1]`, `P2 = s[i...n-1-i]`, `P3 = s[n-i...n-1]`.
    // Since `s` is a palindrome, `P1` is the reverse of `P3`.
    // So `P3 + P2 + P1` is `reverse(P1) + P2 + P1`.
    // For this to be a palindrome, `reverse(P1) + P2 + P1` must be equal to `reverse(P1) + reverse(P2) + reverse(reverse(P1))`.
    // Which means `reverse(P1) + P2 + P1` must be equal to `reverse(P1) + reverse(P2) + P1`.
    // This implies `P2` must be a palindrome.
    // In the "nolon" example: `i=2`. `P1="no"`, `P2="l"`, `P3="on"`.
    // `P2="l"` is a palindrome. `P3+P2+P1 = "onlno"`. This is a palindrome.
    // And "onlno" != "nolon".
    // This works if `P2` is a palindrome and `P3+P2+P1 != s`.
    // `P3+P2+P1 = reverse(P1) + P2 + P1`.
    // `s = P1 + P2 + P3 = P1 + P2 + reverse(P1)`.
    // We need `reverse(P1) + P2 + P1 != P1 + P2 + reverse(P1)`.
    // This is true if `P1 != reverse(P1)`.
    // If `P1` is not a palindrome, then `P1 != reverse(P1)`.
    // If `P1` is a palindrome, then `P1 = reverse(P1)`.
    // Then `reverse(P1) + P2 + P1 = P1 + P2 + P1`.
    // And `P1 + P2 + reverse(P1) = P1 + P2 + P1`.
    // In this case, the new string is equal to the original string.
    // So, this strategy works if we can find an `i` such that:
    // 1. `P2 = s.substr(i, n-2*i)` is a palindrome.
    // 2. `P1 = s.substr(0, i)` is NOT a palindrome.
    // This requires `n-2*i >= 0`, so `i <= n/2`.
    // We need to find such an `i` where `1 <= i <= n/2`.
    // If `n` is odd, `n=2m+1`. `i` can go up to `m`. `P2` would be `s.substr(m, 1)`.
    // If `n` is even, `n=2m`. `i` can go up to `m-1`. `P2` would be `s.substr(m-1, 2)`.
    // The middle part `P2` is always a palindrome because `s` is a palindrome.
    // `s.substr(i, n-2*i)` is a substring of a palindrome, symmetric around the center of `s`.
    // So `s.substr(i, n-2*i)` is always a palindrome.
    // Thus, we just need to find an `i` such that `1 <= i <= n/2` and `s.substr(0, i)` is NOT a palindrome.
    // If such an `i` exists, then `k=2` is possible.
    // If for all `i` from `1` to `n/2`, `s.substr(0, i)` IS a palindrome,
    // then `s[0...0]` is a palindrome (always true).
    // `s[0...1]` is a palindrome.
    // `s[0...2]` is a palindrome.
    // ...
    // `s[0...n/2-1]` is a palindrome.
    // This implies that `s[0] == s[1] == s[2] == ... == s[n/2-1]`.
    // Because if `s[0...j]` is a palindrome, then `s[0] == s[j]`.
    // If `s[0...j+1]` is a palindrome, then `s[0] == s[j+1]`.
    // So if all prefixes `s[0...i-1]` for `1 <= i <= n/2` are palindromes,
    // then `s[0] == s[1] == ... == s[n/2-1]`.
    // Since `s` itself is a palindrome, `s[j] == s[n-1-j]`.
    // This means `s[0] == s[1] == ... == s[n-1]`.
    // So, if all characters are the same, then `s.substr(0, i)` is always a palindrome.
    // If not all characters are the same, then there must be some `j` such that `s[j] != s[0]`.
    // Let `j_min` be the smallest such `j`.
    // Then `s.substr(0, j_min+1)` is not a palindrome (because `s[0] != s[j_min]`).
    // If `j_min < n/2`, then we can pick `i = j_min+1`.
    // Then `s.substr(0, i)` is not a palindrome.
    // This means `k=2` is possible.
    // The only case where `j_min >= n/2` is if `s[0] == s[1] == ... == s[n/2-1]`.
    // But if `s` is not all same characters, then there must be some `j` such that `s[j] != s[0]`.
    // If `j >= n/2`, then `s[n-1-j]` is also not equal to `s[0]`.
    // And `n-1-j < n/2`. This contradicts `j_min >= n/2`.
    // Therefore, if not all characters are the same, there must exist `j_min < n/2` such that `s[j_min] != s[0]`.
    // This implies that `s.substr(0, j_min+1)` is not a palindrome.
    // So we can always find such an `i` (namely `j_min+1`).
    // Thus, if not all characters are the same, `k=2` is always possible.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_a = a[0].value;
    long long max_a = a[n - 1].value;
    long long min_a2 = a[1].value; // Second smallest
    long long max_a2 = a[n - 2].value; // Second largest

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = min_a + min_a2
    // max_f = max_a + max_a2
    // Goodness = (max_a + max_a2) - (min_a + min_a2)
    long long goodness1 = (max_a + max_a2) - (min_a + min_a2);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This means there will be values of type a_i + a_j + h.
    // The minimum possible value of f is min_a + min_a2 (if min_a and min_a2 are in the same subsequence).
    // The minimum possible value of f is min_a + a[k].value + h (if min_a and some a[k] are in different subsequences).
    // The maximum possible value of f is max_a + max_a2 + h (if max_a and max_a2 are in different subsequences).
    // The maximum possible value of f is max_a + max_a2 (if max_a and max_a2 are in the same subsequence).

    // Consider a partition where a[0] is in S1 and a[1]...a[n-1] are in S2.
    // Or a[0]...a[n-2] in S1 and a[n-1] in S2.
    // Or a[0] in S1, a[n-1] in S2, and others in S1 or S2.

    // Let's analyze the bounds for f values.
    // min_f_overall = min(min_a + min_a2, min_a + a[k].value + h)
    // max_f_overall = max(max_a + max_a2, max_a + a[k].value + h)

    // The smallest possible sum of two elements is a[0] + a[1].
    // The largest possible sum of two elements is a[n-1] + a[n-2].

    // If we put a[0] in S1 and all other elements in S2:
    // Values of type a_i + a_j:
    //   - a[k] + a[l] for k,l >= 1. Min: a[1] + a[2]. Max: a[n-1] + a[n-2].
    // Values of type a_i + a_j + h:
    //   - a[0] + a[k] + h for k >= 1. Min: a[0] + a[1] + h. Max: a[0] + a[n-1] + h.

    // The overall minimum f value will be min(a[1] + a[2], a[0] + a[1] + h).
    // The overall maximum f value will be max(a[n-1] + a[n-2], a[0] + a[n-1] + h).
    // This partition strategy is: a[0] in S1, a[1...n-1] in S2.
    // This is one of the "extreme" partitions.

    // Let's consider the partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n >= 3)
    // If n=2, min_f = a[0].value + a[1].value + h (only cross-subsequence pairs)
    // max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) (if n >= 3)
    // If n=2, max_f = a[0].value + a[1].value + h

    // For n=2, the only partition with elements in both subsequences is a[0] in S1, a[1] in S2.
    // f(a[0], a[1]) = a[0] + a[1] + h. min_f = max_f = a[0] + a[1] + h. Goodness = 0.
    // For n=2, Case 1 goodness is (a[0]+a[1]) - (a[0]+a[1]) = 0.
    // So for n=2, goodness is always 0.
    if (n == 2) {
        std::cout << 0 << "\n";
        std::cout << "1 2\n";
        return 0;
    }

    // Consider the partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // min_f_val = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // max_f_val = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    // Goodness for this partition: max_f_val - min_f_val
    long long goodness2_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long goodness2_max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    long long goodness2 = goodness2_max_f - goodness2_min_f;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Consider the partition where a[n-1] is in S1, and a[0]...a[n-2] are in S2.
    // This is symmetric to the previous case.
    // min_f_val = min(a[0].value + a[1].value, a[n-1].value + a[0].value + h)
    // max_f_val = max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h)
    // Goodness for this partition: max_f_val - min_f_val
    long long goodness3_min_f = std::min(a[0].value + a[1].value, a[n-1].value + a[0].value + h);
    long long goodness3_max_f = std::max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h);
    long long goodness3 = goodness3_max_f - goodness3_min_f;
    std::vector<int> partition3(n);
    partition3[a[n-1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition3[a[i].original_index] = 2;
    }

    // Consider the partition where a[0] and a[n-1] are in S1, and a[1]...a[n-2] are in S2.
    // This is a common strategy to minimize the range.
    // Values of type a_i + a_j:
    //   - a[0] + a[n-1] (in S1)
    //   - a[k] + a[l] for 1 <= k,l <= n-2. Min: a[1] + a[2]. Max: a[n-2] + a[n-3].
    // Values of type a_i + a_j + h:
    //   - a[0] + a[k] + h for 1 <= k <= n-2. Min: a[0] + a[1] + h. Max: a[0] + a[n-2] + h.
    //   - a[n-1] + a[k] + h for 1 <= k <= n-2. Min: a[n-1] + a[1] + h. Max: a[n-1] + a[n-2] + h.

    // Overall min_f:
    // min_f_val = min(a[0].value + a[n-1].value, a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max_f:
    // max_f_val = max(a[0].value + a[n-1].value, a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h)

    // This partition is only relevant if n >= 4 (to have at least two elements in S2).
    // If n=3, a[0] in S1, a[2] in S1, a[1] in S2.
    // f values: a[0]+a[2] (same), a[0]+a[1]+h (diff), a[2]+a[1]+h (diff).
    // min_f = min(a[0]+a[2], a[0]+a[1]+h)
    // max_f = max(a[0]+a[2], a[2]+a[1]+h)
    // Goodness = max_f - min_f
    long long goodness4 = std::numeric_limits<long long>::max();
    std::vector<int> partition4(n);
    if (n >= 3) {
        long long current_min_f = std::numeric_limits<long long>::max();
        long long current_max_f = std::numeric_limits<long long>::min();

        // a[0] and a[n-1] in S1, others in S2
        current_min_f = std::min(a[0].value + a[n-1].value, a[0].value + a[1].value + h);
        current_max_f = std::max(a[0].value + a[n-1].value, a[n-1].value + a[n-2].value + h);

        if (n >= 4) { // If S2 has at least two elements
            current_min_f = std::min(current_min_f, a[1].value + a[2].value);
            current_max_f = std::max(current_max_f, a[n-2].value + a[n-3].value);
        } else { // n=3, S2 has only a[1]
            // No a[k]+a[l] for k,l in S2
        }

        goodness4 = current_max_f - current_min_f;

        partition4[a[0].original_index] = 1;
        partition4[a[n-1].original_index] = 1;
        for (int i = 1; i < n - 1; ++i) {
            partition4[a[i].original_index] = 2;
        }
    }

    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition = partition2;
    }
    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition = partition3;
    }
    if (n >= 3 && goodness4 < min_goodness) {
        min_goodness = goodness4;
        best_partition = partition4;
    }

    // One more case: if h is very large, it's always better to put all elements in one subsequence.
    // This is covered by goodness1.
    // If h is small, it might be better to split.

    // The key observation is that the minimum and maximum values of f will always involve
    // the smallest and largest elements of the sequence.
    // Specifically, min_f will be either a[0]+a[1] or a[0]+a[k]+h.
    // And max_f will be either a[n-1]+a[n-2] or a[n-1]+a[k]+h.

    // Let's consider the four critical values:
    // v1 = a[0] + a[1]
    // v2 = a[n-1] + a[n-2]
    // v3 = a[0] + a[n-1] + h
    // v4 = a[0] + a[1] + h (if a[0] and a[1] are in different subsequences)
    // v5 = a[n-1] + a[n-2] + h (if a[n-1] and a[n-2] are in different subsequences)

    // The minimum possible value of f is always a[0] + a[1] (if they are in the same subsequence)
    // or a[0] + a[k] + h (if a[0] is in S1 and a[k] in S2).
    // The smallest possible cross-subsequence sum is a[0] + a[1] + h.
    // So, min_f is either a[0] + a[1] or a[0] + a[1] + h.
    // The maximum possible value of f is always a[n-1] + a[n-2] (if they are in the same subsequence)
    // or a[n-1] + a[k] + h (if a[n-1] is in S1 and a[k] in S2).
    // The largest possible cross-subsequence sum is a[n-1] + a[n-2] + h.
    // So, max_f is either a[n-1] + a[n-2] or a[n-1] + a[n-2] + h.

    // The crucial observation is that the minimum and maximum values of f will always be formed by
    // the smallest and largest elements.
    // Specifically, the minimum f value will be one of:
    //   - a[0] + a[1] (if a[0] and a[1] are in the same subsequence)
    //   - a[0] + a[k] + h (if a[0] is in S1 and a[k] in S2, for some k)
    // The smallest possible a[0] + a[k] + h is a[0] + a[1] + h.
    // So, min_f is either a[0] + a[1] or a[0] + a[1] + h.

    // The maximum f value will be one of:
    //   - a[n-1] + a[n-2] (if a[n-1] and a[n-2] are in the same subsequence)
    //   - a[n-1] + a[k] + h (if a[n-1] is in S1 and a[k] in S2, for some k)
    // The largest possible a[n-1] + a[k] + h is a[n-1] + a[n-2] + h.
    // So, max_f is either a[n-1] + a[n-2] or a[n-1] + a[n-2] + h.

    // Let's consider the four possible scenarios for min_f and max_f:
    // 1. min_f = a[0]+a[1], max_f = a[n-1]+a[n-2]
    //    This happens if all elements are in one subsequence. Goodness = (a[n-1]+a[n-2]) - (a[0]+a[1]). (This is goodness1)
    // 2. min_f = a[0]+a[1], max_f = a[n-1]+a[k]+h
    //    This happens if a[0], a[1] are in S1, and a[n-1] is in S2.
    //    The largest cross-subsequence sum is a[n-1] + a[k] + h.
    //    If a[n-1] is in S2, and a[0] is in S1, then a[n-1]+a[0]+h is a candidate for max_f.
    //    If a[n-1] is in S2, and a[n-2] is in S1, then a[n-1]+a[n-2]+h is a candidate for max_f.
    //    The largest possible cross-subsequence sum is a[n-1] + a[0] + h.
    //    So, max_f = a[n-1] + a[0] + h.
    //    Goodness = (a[n-1]+a[0]+h) - (a[0]+a[1]) = a[n-1] - a[1] + h.
    //    This partition is: a[0] in S1, a[1] in S1, ..., a[n-2] in S1, a[n-1] in S2.
    //    Or a[0] in S1, a[1] in S2, a[2] in S2, ..., a[n-1] in S2. (This is goodness2)
    //    The partition for (a[n-1]+a[0]+h) - (a[0]+a[1]) is: a[0] in S1, a[1] in S1, ..., a[n-2] in S1, a[n-1] in S2.
    //    min_f = a[0]+a[1]. max_f = max(a[n-2]+a[n-3], a[n-1]+a[0]+h).
    //    Goodness = max(a[n-2]+a[n-3], a[n-1]+a[0]+h) - (a[0]+a[1]).
    //    This is covered by goodness3 (symmetric to goodness2).

    // 3. min_f = a[0]+a[k]+h, max_f = a[n-1]+a[n-2]
    //    This happens if a[0] is in S1, a[k] is in S2, and a[n-1], a[n-2] are in S2.
    //    The smallest cross-subsequence sum is a[0] + a[1] + h.
    //    So, min_f = a[0] + a[1] + h.
    //    Goodness = (a[n-1]+a[n-2]) - (a[0]+a[1]+h).
    //    This partition is: a[0] in S1, a[1] in S2, ..., a[n-1] in S2. (This is goodness2)

    // 4. min_f = a[0]+a[k]+h, max_f = a[n-1]+a[l]+h
    //    This happens if a[0] is in S1, a[1] is in S2, a[n-1] is in S2, a[n-2] is in S1.
    //    min_f = a[0]+a[1]+h. max_f = a[n-1]+a[n-2]+h.
    //    Goodness = (a[n-1]+a[n-2]+h) - (a[0]+a[1]+h) = (a[n-1]+a[n-2]) - (a[0]+a[1]).
    //    This is the same goodness as Case 1.
    //    This partition is: a[0] in S1, a[n-1] in S2, and others split.
    //    For example, a[0] in S1, a[1]...a[n-1] in S2.
    //    min_f = a[0]+a[1]+h. max_f = a[0]+a[n-1]+h.
    //    Goodness = (a[0]+a[n-1]+h) - (a[0]+a[1]+h) = a[n-1] - a[1].
    //    This is a candidate for minimal goodness.
    //    This partition is: a[0] in S1, a[1]...a[n-1] in S2.
    //    The min_f is a[0]+a[1]+h. The max_f is a[0]+a[n-1]+h.
    //    The goodness is (a[0]+a[n-1]+h) - (a[0]+a[1]+h) = a[n-1] - a[1].
    //    This is a very simple partition.
    long long goodness_simple_split = a[n-1].value - a[1].value;
    std::vector<int> partition_simple_split(n);
    partition_simple_split[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_simple_split[a[i].original_index] = 2;
    }

    if (goodness_simple_split < min_goodness) {
        min_goodness = goodness_simple_split;
        best_partition = partition_simple_split;
    }

    // The problem states that one subsequence can be empty.
    // Case 1: All elements in S1. Goodness = (max_a + max_a2) - (min_a + min_a2).
    // Case 2: S1 has a[0], S2 has a[1]...a[n-1].
    //   min_f = min(a[1]+a[2], a[0]+a[1]+h)
    //   max_f = max(a[n-1]+a[n-2], a[0]+a[n-1]+h)
    //   Goodness = max_f - min_f
    // Case 3: S1 has a[n-1], S2 has a[0]...a[n-2].
    //   min_f = min(a[0]+a[1], a[n-1]+a[0]+h)
    //   max_f = max(a[n-2]+a[n-3], a[n-1]+a[n-2]+h)
    //   Goodness = max_f - min_f
    // Case 4: S1 has a[0], S2 has a[n-1], and others are split.
    //   This is the case where min_f = a[0]+a[1]+h and max_f = a[n-1]+a[n-2]+h.
    //   Goodness = (a[n-1]+a[n-2]) - (a[0]+a[1]).
    //   This is the same as Case 1.
    //   The partition for this is a[0] in S1, a[1] in S2, a[n-1] in S2, a[n-2] in S1.
    //   This is not necessarily the partition that gives this goodness.
    //   The partition that gives (a[n-1]+a[n-2]) - (a[0]+a[1]) is simply all in one group.

    // The critical partitions are:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = a[0]+a[1], max_f = a[n-1]+a[n-2]. Goodness = (a[n-1]+a[n-2]) - (a[0]+a[1]).
    // 2. a[0] in group 1, all others in group 2.
    //    min_f = min(a[1]+a[2], a[0]+a[1]+h)
    //    max_f = max(a[n-1]+a[n-2], a[0]+a[n-1]+h)
    //    Goodness = max_f - min_f
    // 3. a[n-1] in group 1, all others in group 2.
    //    min_f = min(a[0]+a[1], a[n-1]+a[0]+h)
    //    max_f = max(a[n-2]+a[n-3], a[n-1]+a[n-2]+h)
    //    Goodness = max_f - min_f

    // The logic for goodness_simple_split (a[n-1] - a[1]) is derived from:
    // Partition: a[0] in S1, a[1...n-1] in S2.
    // min_f = a[0]+a[1]+h (from S1-S2 pair)
    // max_f = a[0]+a[n-1]+h (from S1-S2 pair)
    // This assumes that all same-subsequence pairs (a[i]+a[j] for i,j >= 1)
    // are within this range [a[0]+a[1]+h, a[0]+a[n-1]+h].
    // This is not necessarily true. For example, a[1]+a[2] could be smaller than a[0]+a[1]+h.
    // Or a[n-1]+a[n-2] could be larger than a[0]+a[n-1]+h.
    // So, goodness_simple_split is not a complete calculation.

    // The three cases (all in one, a[0] separate, a[n-1] separate) are the most promising.
    // The goodness4 calculation (a[0] and a[n-1] in S1, others in S2) is also important.
    // Let's re-evaluate goodness4 for n=3:
    // a[0] in S1, a[2] in S1, a[1] in S2.
    // f values:
    //   Same: a[0]+a[2]
    //   Diff: a[0]+a[1]+h, a[2]+a[1]+h
    // min_f = min(a[0]+a[2], a[0]+a[1]+h)
    // max_f = max(a[0]+a[2], a[2]+a[1]+h)
    // Goodness = max_f - min_f
    // This is exactly what goodness4 calculates.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // min_r[i] stores the minimum r such that the substring s[i...r] contains a valid triplet.
    // If no such r exists for a given i, min_r[i] will remain n+1.
    std::vector<int> min_r(n, n + 1);

    // Iterate through all possible starting positions x for a triplet (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible common differences k
        // The condition is x + 2k < n, so 2k < n - x, k < (n - x) / 2
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a valid triplet (x, x+k, x+2k)
                // The rightmost index of this triplet is x + 2k.
                // For any l <= x, the minimum r required to contain this triplet is x + 2k.
                // We want to find the minimum r for each l.
                // So, for l = x, the minimum r is x + 2k.
                // For l = x-1, the minimum r is also x + 2k (if x-1 is valid).
                // This means min_r[l] should be updated with min(min_r[l], x + 2k) for all l <= x.
                // However, we only need to update min_r[x] because we are iterating x from 0 to n-1.
                // The final min_r[l] will be min(min_r[l], min_r[l+1]) after this loop.
                min_r[x] = std::min(min_r[x], x + 2 * k);
                // Optimization: If k is small, we might find a triplet quickly.
