#include <numeric> // For std::gcd in C++17, not strictly needed here but good practice for math

// Using long long for all calculations involving x, y, k to prevent overflow
// as k, y can be up to 10^9, so k*y can be 10^18.

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is a common competitive programming optimization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k; // Read x, y, k for each test case

        // To craft k torches, we need k coal and k sticks.
        // Each coal costs y sticks. So, k coal costs k * y sticks.
        // Total sticks required for both coal and the torches themselves:
        // (k * y) sticks for coal + k sticks for torches = k * y + k sticks.
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using the first trade offer.
        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Let 'trades_for_stick_gain' be the number of times we use the first trade offer.
        // We need to find the smallest 'trades_for_stick_gain' such that:
        // trades_for_stick_gain * (x - 1) >= (total_sticks_needed - 1)
        //
        // Using integer division for ceiling: (A + B - 1) / B for ceil(A/B)
        long long trades_for_stick_gain = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // The total number of trades is:
        // trades_for_stick_gain (for acquiring enough sticks)
        // + k (for exchanging sticks for k coal, each coal is 1 trade)
        long long total_trades = trades_for_stick_gain + k;

        std::cout << total_trades << "\n"; // Print the result followed by a newline
    }

    return 0; // Indicate successful execution
}

