#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                if (a[i][j] > max_val_in_row) {
                    max_val_in_row = a[i][j];
                }
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is missing from 1 to n.
    // This happens if n is not present in any row's max_val_in_row.
    // If n is missing, it means the actual value for some p[i] should be n,
    // but its row max was n-1 (because all other elements were smaller than n).
    // In this case, the element whose row max was n-1 must be n.

    std::vector<bool> seen(n + 1, false);
    for (int val : p) {
        if (val >= 1 && val <= n) {
            seen[val] = true;
        }
    }

    bool n_is_missing = true;
    for (int i = 1; i <= n; ++i) {
        if (seen[i]) {
            if (i == n) {
                n_is_missing = false;
            }
        }
    }

    if (n_is_missing) {
        // Find the element that has max_val_in_row = n-1.
        // This element must be n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) { // If there's only one day or no days, no price can be "bad"
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // This variable will store the minimum price encountered so far
        // when iterating from right to left.
        int min_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day 'i', we compare its price 'a[i]' with 'min_suffix',
        // which holds the minimum price from days 'i+1' to 'n-1'.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price 'a[i]' is greater than 'min_suffix',
                // it means there was a lower price later, so 'a[i]' is a bad price.
                bad_prices_count++;
            } else {
                // If 'a[i]' is not greater than 'min_suffix', it means 'a[i]'
                // is either equal to or less than the minimum price found so far
                // to its right. In this case, 'a[i]' itself becomes a new
                // potential minimum for elements further to its left.
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

