int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_consecutive_L = 0;
        int current_consecutive_L = 0;

        // Add an implicit 'R' at the beginning (cell 0)
        // and an implicit 'R' at the end (cell n+1)
        // This simplifies the logic: we only care about 'R's.
        // The distance between consecutive 'R's (including 0 and n+1)
        // determines the minimum d.

        // The positions of 'R's are 0 (start), then indices i where s[i-1] == 'R', then n+1 (end).
        // Let's find the indices of 'R's.
        // The first 'R' is effectively at index 0.
        // The last 'R' is effectively at index n+1.

        // We need to find the maximum distance between any two consecutive 'R's.
        // If the frog is at position `prev_R_pos` (which is an 'R' cell or 0),
        // it needs to jump to the next 'R' cell at `current_R_pos`.
        // The jump distance required is `current_R_pos - prev_R_pos`.
        // `d` must be at least this value.

        int last_r_pos = 0; // Represents cell 0
        int max_dist = 0;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After the loop, consider the jump from the last 'R' found (or 0 if no 'R's)
        // to the target cell n+1.
        max_dist = std::max(max_dist, (n + 1) - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

