#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by the minimum of coders and mathematicians.
        // It's also limited by the total number of students divided by 3.
        // So, a first upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual maximum number of teams can be at most min(c, m) because each team needs at least one coder and one mathematician.
        // So, the search space for 'k' (number of teams) is from 0 to min(c, m).

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        // Binary search for the maximum number of teams 'k'
        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and 'x' no-specialization students.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // Each team needs 3 members. We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more students to fill the third slot in each of the 'mid' teams.
            // These 'mid' students can come from the remaining coders, mathematicians, or no-specialization students.

