#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(p[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(p[i])) {
                // This should not happen if q is valid, as q_i is distinct from q_{i-1}
                // and q_i is the new max, so it wasn't in p_1...p_{i-1}
                // But as a safety check for permutation validity.
                possible = false;
                break;
            }
            used_numbers.insert(p[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number not yet used, and less than q_i
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // The smallest available number is 1, then 2, etc.
            // We need to find the smallest number `x` such that `x` is not in `used_numbers`
            // and `x < q_i`.
            // Since we are filling `p_i` with `q_i` when `q_i > q_{i-1}`,
            // the numbers `1, ..., q_i-1` are candidates for `p_i` when `q_i == q_{i-1}`.
            // We need to find the smallest `x` in `[1, n]` that is not in `used_numbers`.
            // This can be done by iterating from 1.
            int candidate = 1;
            while (used_numbers.count(candidate)) {
                candidate++;
            }

            if (candidate >= q[i]) { // If the smallest available number is >= q_i, no valid p_i exists
                possible = false;
                break;
            }
            p[i] = candidate;
            used_numbers.insert(p[i]);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences using numbers from 1 to k+1
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining n - (k+1) elements
    // These elements should not introduce new distinct differences.
    // The simplest way is to continue with an increasing sequence.
    // The last number placed was either `left-1` or `right+1`.
    // If `k` is even, the last number placed was `right+1`. `left` is `k/2 + 1`. `right` is `k/2 + 2`.
    // If `k` is odd, the last number placed was `left-1`. `left` is `(k+1)/2 + 1`. `right` is `(k+1)/2 + 1`.
    // In both cases, `left` holds the next available smallest number.
    // So, we can just append `left, left+1, left+2, ...`
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

