#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    int countL = 0;
    int countR = 0;
    int countU = 0;
    int countD = 0;

    for (char c : s) {
        if (c == 'L') {
            countL++;
        } else if (c == 'R') {
            countR++;
        } else if (c == 'U') {
            countU++;
        } else if (c == 'D') {
            countD++;
        }
    }

    int horizontal_moves = std::min(countL, countR);
    int vertical_moves = std::min(countU, countD);

    if (horizontal_moves == 0 && vertical_moves == 0) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else if (horizontal_moves == 0) { // Only vertical moves possible
        // If only vertical moves, we can only do UD or DU. Max length 2.
        // If vertical_moves > 0, we can always form "UD" or "DU".
        std::cout << 2 << std::endl;
        std::cout << "UD" << std::endl;
    } else if (vertical_moves == 0) { // Only horizontal moves possible
        // If only horizontal moves, we can only do LR or RL. Max length 2.
        // If horizontal_moves > 0, we can always form "LR" or "RL".
        std::cout << 2 << std::endl;
        std::cout << "LR" << std::endl;
    } else {
        // Both horizontal and vertical moves are available.
        // We can form a path like U...UR...RD...DL...L
        // The maximum length is 2 * horizontal_moves + 2 * vertical_moves
        std::cout << 2 * horizontal_moves + 2 * vertical_moves << std::endl;
        std::string result = "";
        for (int i = 0; i < vertical_moves; ++i) {
            result += 'U';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'R';
        }
        for (int i = 0; i < vertical_moves; ++i) {
            result += 'D';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'L';
        }
        std::cout << result << std::endl;
    }
}

