#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1], which is always a permutation of {1}.
        // min_idx and max_idx are already initialized to pos[1].
        // The length of the segment is max_idx - min_idx + 1 = pos[1] - pos[1] + 1 = 1.
        // This matches m=1. So 1 is beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The current segment [min_idx, max_idx] contains numbers 1 to m-1.
        // To include 'm', we need to update min_idx and max_idx to cover pos[m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A number 'm' is beautiful if the segment [min_idx, max_idx]
        // (which now contains all numbers from 1 to m)
        // has a length exactly equal to 'm'.
        // If the length is 'm', it means all numbers from 1 to m are present
        // and no other numbers are present in this segment.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

