void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i-1] < p[i] && p[i] > p[i+1]  (peak)
        // p[i-1] > p[i] && p[i] < p[i+1]  (valley)
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << std::endl;
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

