                    //     This is equivalent to `sum(min(|i_p - j_p|, 2))`.
                    //     This means for each pair of opposite mismatches, we pay 1 if they are adjacent, or 2 if not.
                    //     The remaining mismatches (if `zeros_to_ones != ones_to_zeros`) must be resolved by flips.

                    // This suggests a greedy approach:
                    // Iterate through the string.
                    // Maintain `count_01` (number of '0'->'1' mismatches encountered so far)
                    // and `count_10` (number of '1'->'0' mismatches encountered so far).
                    // When `a[i] != b[i]`:
                    //   If `a[i] == '0'` and `b[i] == '1'`:
                    //     If `count_10 > 0`: // We have a pending '1'->'0' mismatch
                    //       // We can resolve this '0'->'1' with a pending '1'->'0'.
                    //       // This costs 1 if they are adjacent, 2 otherwise.
                    //       // The problem is that we don't know if the pending '1'->'0' is at i-1.
                    //       // The optimal strategy is to always pair up adjacent opposite mismatches.
                    //       // If a[i] = '0', b[i] = '1' and a[i-1] = '1', b[i-1] = '0',
                    //       // we can swap a[i] and a[i-1] for cost 1.
                    //       // This means we decrement both counts and add 1 to cost.
                    //       // If they are not adjacent, we just increment the count for the current type of mismatch.
                    //       // The total cost will be the sum of all such adjacent swaps (cost 1 each)
                    //       // plus the number of remaining mismatches (cost 1 each for flip).

                    // Let's try the logic from a common competitive programming solution for this type of problem:
                    // Iterate through the string.
                    // If a[i] != b[i]:
                    //   If a[i] == '0' and b[i] == '1':
                    //     If count_10 > 0: // Found a '0'->'1' and there's a pending '1'->'0'
                    //       cost += 1; // Resolve them with a swap (cost 1 if adjacent) or two flips (cost 2).
                    //                   // The key is that we can always resolve a pair of opposite mismatches for cost 1.
                    //                   // This is because if they are adjacent, cost is 1.
                    //                   // If they are not adjacent, cost is 2 (two flips).
                    //                   // The problem is that we are trying to minimize cost.
                    //                   // If we have a '0' at i and a '1' at j, and both need to be flipped,
                    //                   // we can swap them. The cost is |i-j|.
                    //                   // If |i-j| = 1, cost is 1. This is better than 2 flips.
                    //                   // If |i-j| > 1, cost is |i-j|. This is worse than 2 flips.
                    //                   // So, we only use swaps if |i-j|=1.
                    //                   // This means we only care about adjacent differing bits of opposite types.

                    // The correct logic is simpler:
                    // Iterate `i` from `0` to `n-1`.
                    // If `a[i] != b[i]`:
                    //   If `a[i] == '0'` and `b[i] == '1'`:
                    //     `count_01++`;
                    //   Else (`a[i] == '1'` and `b[i] == '0'`):
                    //     `count_10++`;
                    //
                    // Now, we have `count_01` mismatches of type '0'->'1' and `count_10` mismatches of type '1'->'0'.
                    // We can pair up `min(count_01, count_10)` pairs.
                    // Each such pair can be resolved by a swap.
                    // If the two positions are adjacent, cost is 1.
                    // If the two positions are not adjacent, cost is > 1. In this case, it's better to flip both (cost 2).
                    // So, for each pair of opposite mismatches, we pay 1 if they are adjacent, or 2 if not.
                    // This is not quite right. The problem is that we don't know which specific indices are paired.

                    // Let's consider the state at each index `i`.
                    // We are looking for `a[i] != b[i]`.
                    // If `a[i] == '0'` and `b[i] == '1'`:
                    //   If `count_10 > 0`: // There's a pending '1'->'0' mismatch from a previous index.
                    //     // We can resolve this '0'->'1' with one of the pending '1'->'0' mismatches.
                    //     // This costs 1. This is because we can always find an adjacent pair if we are careful.
                    //     // No, this is not true.
                    //     // The optimal strategy is to resolve adjacent opposite mismatches first.
                    //     // Then resolve remaining mismatches by flipping.

                    // Let's use the logic that passed similar problems:
                    // Iterate `i` from `0` to `n-1`.
                    // If `a[i] != b[i]`:
                    //   If `a[i] == '0'` and `b[i] == '1'`: // Current is '0' needs '1'
                    //     If `count_10 > 0`: // There's a pending '1' needs '0'
                    //       // We can resolve this '0'->'1' with one of the pending '1'->'0'.
                    //       // This costs 1. This is because we can always find an adjacent pair if we are careful.
                    //       // No, this is not true.
                    //       // The optimal strategy is to resolve adjacent opposite mismatches first.
                    //       // Then resolve remaining mismatches by flipping.
                    //       // The cost is 1 for a swap if |i-j|=1.
                    //       // The cost is 2 for two flips if |i-j|>1.
                    //       // So, if we have a '0' at i and a '1' at i-1, and both are mismatches of opposite types,
                    //       // we swap them for cost 1.
                    //       // Otherwise, we flip the current bit for cost 1.

                    // This is the correct logic:
                    // Iterate `i` from `0` to `n-1`.
                    // If `a[i] != b[i]`:
                    //   If `i + 1 < n` and `a[i+1] != b[i+1]` and `a[i] != a[i+1]`:
                    //     // This means `a[i]` and `a[i+1]` are different, and both are mismatches.
                    //     // Example: a="01", b="10". Here a[i]='0', b[i]='1' and a[i+1]='1', b[i+1]='0'.
                    //     // These are adjacent and opposite types of mismatches.
                    //     // We can swap a[i] and a[i+1]. Cost is |i - (i+1)| = 1.
                    //     // This fixes both positions.
                    //     cost += 1;
                    //     i++; // Skip next character as it's already handled.
                    //   Else:
                    //     // This mismatch cannot be resolved by an adjacent swap.
                    //     // It must be resolved by a flip. Cost is 1.
                    //     cost += 1;
                    //
                    // Let's trace Example 1:
                    // n=3, a="100", b="001"
                    // cost = 0
                    // i=0: a[0]='1', b[0]='0'. Mismatch.
                    //   i+1=1 < 3. a[1]='0', b[1]='0'. Match.
                    //   So, the `if` condition `a[i+1] != b[i+1]` is false.
                    //   Else branch: cost += 1. cost = 1.
                    // i=1: a[1]='0', b[1]='0'. Match. Loop continues.
                    // i=2: a[2]='0', b[2]='1'. Mismatch.
                    //   i+1=3. Not < 3.
                    //   Else branch: cost += 1. cost = 1 + 1 = 2.
                    // Total cost = 2. Matches example.

                    // Let's trace Example 2:
                    // n=4, a="0101", b="0011"
                    // cost = 0
                    // i=0: a[0]='0', b[0]='0'. Match. Loop continues.
                    // i=1: a[1]='1', b[1]='0'. Mismatch.
                    //   i+1=2 < 4. a[2]='0', b[2]='1'. Mismatch.
                    //   a[1]='1', a[2]='0'. They are different.
                    //   All conditions met: `a[i] != b[i]`, `a[i+1] != b[i+1]`, `a[i] != a[i+1]`.
                    //   cost += 1. cost = 1.
                    //   i++. i becomes 2. Loop will increment it to 3.
                    // i=3: a[3]='1', b[3]='1'. Match. Loop continues.
                    // Total cost = 1. Matches example.

                    // This logic seems correct and covers all cases.
                    // The key is that a swap is only beneficial over two flips if the cost |i-j| is 1.
                    // If |i-j| > 1, two flips (cost 2) are always better or equal.
                    // So we only look for adjacent swaps.

                    // Final check on the logic:
                    // We iterate through the string.
                    // If `a[i]` needs to be changed:
                    //   Check if `a[i+1]` also needs to be changed, AND `a[i]` and `a[i+1]` are different.
                    //   This means `a[i]` is '0' and `b[i]` is '1', AND `a[i+1]` is '1' and `b[i+1]` is '0'.
                    //   OR `a[i]` is '1' and `b[i]` is '0', AND `a[i+1]` is '0' and `b[i+1]` is '1'.
                    //   In both cases, `a[i] != a[i+1]`.
                    //   If this condition holds, we can swap `a[i]` and `a[i+1]` for cost 1.
                    //   This fixes both positions. We increment `i` to skip `i+1`.
                    //   If this condition does not hold, it means `a[i]` needs to be changed, but either:
                    //     - `i+1` is out of bounds.
                    //     - `a[i+1]` does not need to be changed.
                    //     - `a[i+1]` needs to be changed, but `a[i]` and `a[i+1]` are the same (e.g., `a="00", b="11"`).
                    //   In these cases, we must flip `a[i]`. Cost 1.

                    // This logic is sound.

                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Found adjacent differing bits that are also mismatches of opposite types
                // e.g., a[i]='0', b[i]='1' and a[i+1]='1', b[i+1]='0'
                // or a[i]='1', b[i]='0' and a[i+1]='0', b[i+1]='1'
                // In both cases, a[i] != a[i+1]
                cost += 1; // Swap them for cost 1
                i++;       // Skip the next character as it's also resolved
            } else {
                // This mismatch cannot be resolved by an adjacent swap
                // (either no next char, or next char matches, or next char is same as current char but also mismatch)
                // Must flip current bit for cost 1
                cost += 1;
            }
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // Pointer for the rightmost point that satisfies the distance condition

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] is the rightmost point such that x[right_ptr] - x[i] <= d
        // or right_ptr reaches the end of the array.
        // Since x is sorted, x[right_ptr] <= x[i] + d is equivalent to x[right_ptr] - x[i] <= d.
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy x[k] - x[i] <= d.
        // We need to choose two distinct points from this range (i+1 to right_ptr-1).
        // The number of points available to choose from is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let k = right_ptr - 1 - i.
        // If k < 2, we cannot choose two points, so we skip.
        // Otherwise, we can choose 2 points from k points in C(k, 2) ways.
        // C(k, 2) = k * (k - 1) / 2.

        long long k = right_ptr - 1 - i;
        if (k >= 2) {
            count += k * (k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it for subsequent checks

    // Step 2: Ensure elements to the left of median are <= s
    // These elements are a[0]...a[median_idx-1]
    // Since the array is sorted, we only need to check elements that are currently > s.
    // If a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // No need to actually change it, just count operations
        }
    }

    // Step 3: Ensure elements to the right of median are >= s
    // These elements are a[median_idx+1]...a[n-1]
    // Since the array is sorted, we only need to check elements that are currently < s.
    // If a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // No need to actually change it, just count operations
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElementA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareElementB);

    // Create the result array
    std::vector<long long> result(m);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // However, we need to output the rearranged A' in the original order of B.
    // So, if B[k] (sorted) was originally at index B[k].original_index,
    // then result[B[k].original_index] should be A[k].value (sorted).
    for (int i = 0; i < m; ++i) {
        result[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

