#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        int wins_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins_count++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (wins_count == 0) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 2 * k - 1 << "\n";
            }
            continue;
        }

        // Case 1: Fill gaps between existing 'W' segments
        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else {
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap before last_W
            gap_lengths.push_back(current_gap);
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        for (int gap_len : gap_lengths) {
            if (k >= gap_len) {
                current_score += 2 * gap_len + 1; // Each L becomes W, connects two Ws, adds 2*L + 1 for the connection
                k -= gap_len;
            } else {
                current_score += 2 * k; // Can only fill part of the gap, each adds 2 points
                k = 0;
                break;
            }
        }

        // Case 2: Convert remaining 'L's at ends or if k is still available
        if (k > 0) {
            // Convert 'L's before first_W
            int L_before_first_W = first_W;
            long long convert_before = std::min((long long)L_before_first_W, k);
            current_score += 2 * convert_before;
            k -= convert_before;

            if (k > 0) {
                // Convert 'L's after last_W
                int L_after_last_W = n - 1 - last_W;
                long long convert_after = std::min((long long)L_after_last_W, k);
                current_score += 2 * convert_after;
                k -= convert_after;
            }
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to max_val are present exactly once.
// max_val is the expected length of the permutation.
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len <= 0) {
        return false; // A permutation must have positive length
    }
    if (end_idx - start_idx + 1 != expected_len) {
        return false; // Length mismatch
    }

    std::vector<bool> seen(expected_len + 1, false);
    int current_max = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        int val = arr[i];
        if (val <= 0 || val > expected_len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }

    // After iterating, current_max must be equal to expected_len
    // and all numbers from 1 to expected_len must have been seen.
    // The `seen` array check already covers this if `current_max` is `expected_len`.
    // If `current_max` is less than `expected_len`, it means some numbers are missing.
    return current_max == expected_len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max prefix and max suffix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i-1], a[i]);
    }

    std::vector<int> max_suffix(n);
    max_suffix[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i+1], a[i]);
    }

    // Use sets to check for duplicates and missing numbers efficiently
    std::set<int> p1_elements;
    int p1_max_val = 0;

    for (int l1 = 1; l1 < n; ++l1) { // l1 is the length of p1, so it goes from 1 to n-1
        int current_val = a[l1-1];

        // Update p1_elements and p1_max_val for the current prefix
        if (p1_elements.count(current_val)) {
            // Duplicate found in p1, so no further prefixes starting with this can be permutations
            break; 
        }
        p1_elements.insert(current_val);
        if (current_val > p1_max_val) {
            p1_max_val = current_val;
        }

        // Check if the current prefix a[0...l1-1] is a permutation of length l1
        // Conditions:
        // 1. All elements from 1 to l1 are present exactly once.
        //    - `p1_elements.size() == l1` checks if all elements are unique and count matches length.
        //    - `p1_max_val == l1` checks if the maximum element is equal to the length,
        //      which implies all numbers from 1 to l1 must be present if `p1_elements.size() == l1`.
        // 2. The maximum value in the prefix must be equal to its length.
        if (p1_elements.size() == l1 && p1_max_val == l1) {
            // Now check if the suffix a[l1...n-1] is a permutation of length l2 = n - l1
            int l2 = n - l1;

            // The maximum value in the suffix must be equal to its length.
            // This is a necessary condition for it to be a permutation.
            if (max_suffix[l1] == l2) {
                // If this condition holds, we need to perform a full check for the suffix.
                // This is the most expensive part, so we do it only if necessary.
                if (is_permutation(a, l1, n - 1, l2)) {
                    results.push_back({l1, l2});
                }
            }
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_coins += 1;
                n = 0;
            } else if (n == 2) {
                chanek_coins += 1; // Take 1, N becomes 1. Opponent takes 1. Chanek gets 1.
                n = 0; // Game ends after this turn for Chanek's perspective.
            } else if (n == 3) {
                chanek_coins += 1; // Take 1, N becomes 2. Opponent takes 1. Chanek takes 1.
                n = 0; // Game ends after this turn for Chanek's perspective.
            } else if (n % 2 == 1) { // N is odd and > 3
                chanek_coins += 1;
                n -= 1;
            } else { // N is even and > 3
                // Chanek has two choices: take 1 or take N/2.
                // If Chanek takes 1: N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                // If Chanek takes N/2: N becomes N/2 (can be even or odd).

                // Strategy: If N is even, and N/2 is odd, taking N/2 leaves an odd number for opponent.
                // If N is even, and N/2 is even, taking N/2 leaves an even number for opponent.

                // Consider taking N/2.
                // If N/2 is odd, opponent takes 1. N becomes N/2 - 1 (even).
                // If N/2 is even, opponent takes N/4. N becomes N/4 (even).

                // The optimal strategy for Chanek when N is even is to take N/2 if N/2 is odd.
                // This forces the opponent to take 1, leaving an even number for Chanek.
                // If N/2 is even, taking N/2 leaves an even number for the opponent, who will then take N/4.
                // This seems to be a greedy approach.

                // Let's analyze the pattern:
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * (odd number), N is even but not divisible by 4):
                //     Chanek takes N/2. N becomes N/2 (odd).
                //     Opponent takes 1. N becomes N/2 - 1 (even).
                //     Chanek gets N/2.
                //   If N/2 is even (i.e., N = 4 * (any number), N is divisible by 4):
                //     Chanek takes N/2. N becomes N/2 (even).
                //     Opponent takes N/4. N becomes N/4 (even).
                //     Chanek gets N/2.

                // The strategy is always to take N/2 if N is even.
                // This is because taking N/2 gives Chanek more coins immediately than taking 1.
                // And it leaves a smaller number for the opponent.
                // The only exception is when N is small (like 2, 3) where taking 1 might be better to ensure a win.
                // But for N > 3, taking N/2 is always better if N is even.

                chanek_coins += n / 2;
                n /= 2;
            }
        } else { // Opponent's turn
            if (n == 1) {
                opponent_coins += 1;
                n = 0;
            } else if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally. They will take N/2.
                opponent_coins += n / 2;
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

