int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends who get w_i = 1.
        // These friends should get the largest available numbers,
        // as their happiness is 2 * number.
        // Since w is sorted, these are at the beginning of w.
        for (int i = 0; i < k; ++i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // All remaining w_i will be > 1 because w is sorted.
                // Break and handle them in the next loop.
                // These friends will get the largest available numbers as their max.
                // These friends will get the smallest available numbers as their min.
                break;
            }
        }

        // Now, handle friends who get w_i > 1.
        // These friends are at the end of the sorted w array.
        // They should get the largest remaining numbers as their max.
        // They should get the smallest remaining numbers as their min.
        // Iterate w in reverse for w_i > 1.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                // Max element for this friend
                total_happiness += a[a_ptr_right];
                a_ptr_right--;

                // Min element for this friend
                // This friend needs w[i] - 1 additional elements.
                // These elements should be the smallest available.
                total_happiness += a[a_ptr_left];
                a_ptr_left += (w[i] - 1);
            }
        }
        std::cout << total_happiness << "\n";
    }
    return 0;
}

