int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // Condition: current_sum = 2 * current_xor_sum
        // If current_sum == 2 * current_xor_sum, array is already good.
        // Otherwise, we need to append elements.

        // We want to find b1, b2, b3 such that
        // (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)

        // Let's try to append at most 2 elements.
        // We need to find b1, b2 such that
        // current_sum + b1 + b2 = 2 * (current_xor_sum ^ b1 ^ b2)

        // A simple strategy is to append two elements:
        // 1. Append current_xor_sum.
        //    New XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
        //    New sum becomes current_sum + current_xor_sum.
        //    Now we need (current_sum + current_xor_sum) = 2 * 0, which means current_sum + current_xor_sum = 0.
        //    This is only true if all elements are 0, which is a trivial case.
        //    So, this single append is not enough in general.

        // 2. Append current_xor_sum and then current_sum + current_xor_sum.
        //    Let X = current_xor_sum
        //    Let S = current_sum
        //    Append b1 = X.
        //    New XOR sum: X' = X ^ X = 0.
        //    New sum: S' = S + X.
        //    Now we need S' = 2 * X'.
        //    S + X = 2 * 0 => S + X = 0. This is generally not true.

        //    We need to make the final XOR sum be some value Y, and final sum be 2Y.
        //    Consider appending two elements: X and S+X.
        //    Let b1 = X.
        //    Let b2 = S + X.
        //    New XOR sum: X_new = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X.
        //    New sum: S_new = S + b1 + b2 = S + X + (S + X) = 2S + 2X.
        //    We need S_new = 2 * X_new.
        //    2S + 2X = 2 * (S + X).
        //    This equation is always true!
        //    So, appending X and S+X always works.
        //    The number of appended elements is 2.
        //    The elements are current_xor_sum and current_sum + current_xor_sum.

        // This strategy always works and appends exactly 2 elements.
        // The problem statement says "you don't have to minimize the number of added elements!".
        // So, even if the array is already good, we can still append these two elements.
        // However, the example output for an already good array is 0 elements.
        // Let's follow the example and output 0 if already good.

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
    }
    return 0;
}

