    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // Each 'a' at this position will interact with all 'b's to its right.
            // The number of steps for this 'a' is equal to the current b_count.
            // After this 'a' interacts, it effectively creates a new 'b' for each 'b' it interacted with.
            // So, the number of 'b's available for 'a's further to the left doubles.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

