#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_good(const std::vector<int>& b) {
    if (b.empty()) {
        return true;
    }
    int m = b.size();
    std::vector<int> c(m);
    int left = 0;
    int right = m - 1;
    int c_idx = m - 1; // Fill c from right to left to get the final non-decreasing sequence

    while (left <= right) {
        if (b[left] < b[right]) {
            c[c_idx--] = b[right--];
        } else if (b[right] < b[left]) {
            c[c_idx--] = b[left++];
        } else { // b[left] == b[right]
            // Find the first differing pair from left and right
            int l_ptr = left + 1;
            int r_ptr = right - 1;
            bool found_diff = false;
            while (l_ptr <= r_ptr) {
                if (b[l_ptr] != b[r_ptr]) {
                    found_diff = true;
                    break;
                }
                l_ptr++;
                r_ptr--;
            }

            if (!found_diff) { // All elements between left and right (inclusive) are equal
                // We can pick either, doesn't matter. Pick from right for consistency.
                c[c_idx--] = b[right--];
            } else {
                if (b[l_ptr] < b[r_ptr]) {
                    c[c_idx--] = b[right--];
                } else { // b[r_ptr] < b[l_ptr]
                    c[c_idx--] = b[left++];
                }
            }
        }
    }

    for (int i = 0; i < m - 1; ++i) {
        if (c[i] > c[i+1]) {
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        // Find the longest suffix that is non-increasing
        int p = n - 1;
        while (p > 0 && a[p-1] >= a[p]) {
            p--;
        }
        // Now a[p...n-1] is non-increasing.
        // We need to find the first element from the left of this suffix
        // that breaks the non-decreasing property if we were to pick elements
        // from both ends.
        // The elements a[p...n-1] are candidates for the right side of the "valley".
        // The elements a[0...p-1] are candidates for the left side of the "valley".

        // Find the first index `i` from the right such that `a[i] < a[i+1]`
        // This `i` marks the end of the non-decreasing suffix from the right.
        int suffix_start_idx = n - 1;
        while (suffix_start_idx > 0 && a[suffix_start_idx - 1] >= a[suffix_start_idx]) {
            suffix_start_idx--;
        }
        // Now a[suffix_start_idx ... n-1] is non-decreasing.
        // Example: [1, 2, 3, 4, 4, 2, 1]
        // n=7
        // suffix_start_idx = 6 (a[6]=1)
        // a[5]=2 >= a[6]=1 -> suffix_start_idx = 5 (a[5]=2)
        // a[4]=4 >= a[5]=2 -> suffix_start_idx = 4 (a[4]=4)
        // a[3]=4 >= a[4]=4 -> suffix_start_idx = 3 (a[3]=4)
        // a[2]=3 < a[3]=4 -> stop. suffix_start_idx = 3.
        // So [4, 4, 2, 1] is the non-increasing suffix.

        // Now find the first index `j` from the right (starting from `suffix_start_idx - 1`)
        // such that `a[j] > a[j+1]`. This `j` marks the end of the non-increasing prefix
        // that we must remove.
        // Example: [1, 2, 3, 4, 4, 2, 1]
        // suffix_start_idx = 3 (a[3]=4)
        // j = 2 (a[2]=3)
        // a[2]=3 < a[3]=4 -> stop. j = 2.
        // So the "valley" is at index 2. The elements from index 0 to 2 are [1, 2, 3].
        // The elements from index 3 to 6 are [4, 4, 2, 1].
        // The "good" array must be formed by elements from a single "peak".
        // The elements from `a[0]` to `a[suffix_start_idx-1]` form the left part of the array.
        // The elements from `a[suffix_start_idx]` to `a[n-1]` form the right part of the array.
        // We need to find the point where the array stops being non-decreasing from the right.
        // This is `suffix_start_idx`.
        // Then we need to find the point where the array stops being non-increasing from the right,
        // starting from `suffix_start_idx - 1`.

        int peak_idx = suffix_start_idx;
        while (peak_idx > 0 && a[peak_idx - 1] <= a[peak_idx]) {
            peak_idx--;
        }
        // Now a[peak_idx ... n-1] is a "mountain" shape (non-decreasing then non-increasing).
        // The elements from a[0] to a[peak_idx-1] must be removed.
        // The length of the prefix to remove is `peak_idx`.

        std::cout << peak_idx << "\n";
    }
    return 0;
}

#include <iostream>
