int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequence_segments = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (m_i >= 1)

        int prev_doll;
        std::cin >> prev_doll; // First doll in the chain

        // Check if the first doll is '1'
        if (prev_doll == 1) {
            correct_sequence_segments++; // This chain starts with 1, potentially contributing to the 1->2->... sequence
            // Check for consecutive sequence 1 -> 2 -> 3 ...
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll;
                if (current_doll == prev_doll + 1) {
                    correct_sequence_segments++;
                    prev_doll = current_doll;
                } else {
                    // Sequence broken, remaining dolls in this chain need to be disassembled
                    // and reassembled.
                    // Each remaining doll (including current_doll) needs to be taken out.
                    // Number of remaining dolls: m - (j+1) + 1 = m - j
                    // Number of existing nestings to break: m - j
                    total_operations += (m - j) * 2; // 1 to take out, 1 to put in later
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> current_doll; // Consume remaining input for this chain
                    }
                    break; // Move to the next chain
                }
            }
        } else {
            // This chain does not start with '1'. All its nestings must be broken.
            // Each doll (except the outermost) needs to be taken out.
            // Number of nestings to break: m - 1
            total_operations += (m - 1) * 2; // 1 to take out, 1 to put in later
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll; // Consume remaining input for this chain
            }
        }
    }

    // Total operations:
    // (n - 1) operations to form the final chain 1->2->...->n
    // - correct_sequence_segments operations that are already in place
    // = (n - 1 - correct_sequence_segments) operations that need to be performed.
    // Each of these operations requires one 'put in' action.
    //
    // Additionally, for each 'put in' operation that is not part of the initial correct sequence,
    // we might have had to 'take out' a doll first.
    //
    // Let's re-evaluate:
    // Total 'put in' operations needed for the final chain: n - 1.
    // Number of 'put in' operations already existing and correct: correct_sequence_segments - 1 (if 1 is present, it's 1->2, 2->3, etc.)
    // No, correct_sequence_segments is the count of dolls in the 1->2->... sequence.
    // So, correct_sequence_segments - 1 is the number of *correct nestings* starting from 1.
    //
    // Example: 1->2->3. correct_sequence_segments = 3. Correct nestings = 2.
    //
    // The total number of 'put in' operations required is (n - 1).
    // The number of 'put in' operations that are already correctly formed is (correct_sequence_segments - 1).
    // So, (n - 1) - (correct_sequence_segments - 1) = n - correct_sequence_segments new 'put in' operations are needed.
    // Each of these new 'put in' operations costs 1 second.
    //
    // The total_operations variable already accounts for 'take out' operations for incorrect nestings.
    // Each 'take out' operation costs 1 second.
    // Each 'put in' operation costs 1 second.
    //
    // The total number of 'take out' operations is `total_operations / 2`.
    // The total number of 'put in' operations for new connections is `n - correct_sequence_segments`.
    //
    // So, total time = (total_operations / 2) + (n - correct_sequence_segments).
    //
    // Let's trace the example 7 3, 3 1 3 7, 2 2 5, 2 4 6
    // n=7, k=3
    //
    // Chain 1: 3 1 3 7
    // prev_doll = 1. correct_sequence_segments = 1.
    // j=1: current_doll = 3. Not prev_doll+1 (1+1=2). Sequence broken.
    // Remaining dolls: 3, 7. Number of remaining dolls = 2.
    // Number of existing nestings to break: 2. (1->3, 3->7 are not target)
    // total_operations += (2 * 2) = 4.
    // (This means 2 'take out' operations and 2 'put in' operations for these dolls later)
    //
    // Chain 2: 2 2 5
    // prev_doll = 2. Not 1.
    // Number of nestings to break: m-1 = 2-1 = 1. (2->5)
    // total_operations += (1 * 2) = 2.
    //
    // Chain 3: 2 4 6
    // prev_doll = 4. Not 1.
    // Number of nestings to break: m-1 = 2-1 = 1. (4->6)
    // total_operations += (1 * 2) = 2.
    //
    // After loop:
    // correct_sequence_segments = 1
    // total_operations = 4 + 2 + 2 = 8.
    //
    // Final calculation:
    // Time = (total_operations / 2) + (n - correct_sequence_segments)
    // Time = (8 / 2) + (7 - 1)
    // Time = 4 + 6 = 10. This matches the example output.

    // Let's trace example 1: 3 2, 2 1 2, 1 3
    // n=3, k=2
    //
    // Chain 1: 2 1 2
    // prev_doll = 1. correct_sequence_segments = 1.
    // j=1: current_doll = 2. Is prev_doll+1 (1+1=2).
    // correct_sequence_segments = 2. prev_doll = 2.
    // Loop ends.
    //
    // Chain 2: 1 3
    // prev_doll = 3. Not 1.
    // Number of nestings to break: m-1 = 1-1 = 0.
    // total_operations += (0 * 2) = 0.
    //
    // After loop:
    // correct_sequence_segments = 2
    // total_operations = 0.
    //
    // Final calculation:
    // Time = (total_operations / 2) + (n - correct_sequence_segments)
    // Time = (0 / 2) + (3 - 2)
    // Time = 0 + 1 = 1. This matches the example output.

    // The logic seems correct.
    // total_operations accumulates 2 for each nesting that needs to be broken and re-established.
    // This means `total_operations / 2` is the count of 'take out' operations.
    // The number of 'put in' operations needed is `n - correct_sequence_segments`.
    // This is because `n-1` total nestings are needed. `correct_sequence_segments - 1` are already in place.
    // So `(n-1) - (correct_sequence_segments - 1) = n - correct_sequence_segments` new 'put in' operations are needed.
    //
    // Total time = (number of 'take out' operations) + (number of 'put in' operations)
    // Total time = (total_operations / 2) + (n - correct_sequence_segments)

    std::cout << (total_operations / 2) + (n - correct_sequence_segments) << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::vector<std::string> result(4);

    long long total_toys = A + B + C + D;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        result[0] = (A == 1) ? "Ya" : "Tidak";
        result[1] = (B == 1) ? "Ya" : "Tidak";
        result[2] = (C == 1) ? "Ya" : "Tidak";
        result[3] = (D == 1) ? "Ya" : "Tidak";
    } else {
        // Box 1: (-inf, -1]
        // Final toy can be in Box 1 if:
        // 1. The final sign is negative.
        // 2. The final magnitude is >= 1.

        // Sign:
        // The number of negative toys (A+B) determines the parity of negative signs.
        // If (A+B) is odd, the final sign can be negative.
        // If (A+B) is even, the final sign can be positive.
        // Exception: If there are no negative toys (A+B=0), the final sign must be positive.
        // If there are negative toys, we can always make the final sign negative by pairing up negatives until one is left, or by pairing a negative with a positive.
        // If A+B is odd, it's possible to have a negative final sign.
        // If A+B is even and A+B > 0, it's possible to have a positive final sign.
        // If A+B is even and A+B > 0, it's also possible to have a negative final sign if there's at least one positive toy (C+D > 0) to multiply with an odd number of negatives.
        // This logic is tricky. Let's simplify:
        // The final sign is negative if and only if an odd number of negative toys are involved in the final product.
        // If A+B is odd, it's possible to have an odd number of negatives in the product.
        // If A+B is even, it's possible to have an even number of negatives in the product.
        // So, if A+B is odd, a negative final product is possible.
        // If A+B is even, a positive final product is possible.
        // Can an even number of negative toys result in a negative product? No.
        // Can an odd number of negative toys result in a positive product? No.
        // So, the final sign is negative if and only if the initial count of negative toys (A+B) is odd.

        bool can_be_negative_final_sign = ((A + B) % 2 != 0);
        bool can_be_positive_final_sign = ((A + B) % 2 == 0);

        // Magnitude >= 1:
        // This requires at least one toy with magnitude >= 1 (from A or D) to "dominate" the product,
        // OR, if all toys have magnitude < 1 (B+C > 0, A=D=0), it's impossible to get >= 1.
        // If A+D > 0, it's possible to get magnitude >= 1.
        // If A+D == 0, then all toys are in B or C. All have magnitude < 1. Product will always be < 1.
        bool can_be_magnitude_ge_1 = (A + D > 0);

        // Box 1: Negative and magnitude >= 1
        if (can_be_negative_final_sign && can_be_magnitude_ge_1) {
            result[0] = "Ya";
        } else {
            result[0] = "Tidak";
        }

        // Box 2: (-1, 0)
        // Final toy can be in Box 2 if:
        // 1. The final sign is negative.
        // 2. The final magnitude is < 1.

        // Magnitude < 1:
        // This is always possible if there are at least two toys (total_toys > 1).
        // We can always pick two toys, say x1 and x2, and if we want magnitude < 1, we can pick x1 from B or C, and x2 from B or C.
        // If A+D > 0, we can still make it < 1 by multiplying a large number by many small numbers.
        // Example: 10 * 0.1 * 0.1 = 0.1.
        // The only case where magnitude < 1 is impossible is if all toys have magnitude >= 1 (A+D == total_toys) AND total_toys > 0.
        // But if total_toys > 1, and A+D == total_toys, then all toys are >= 1 or <= -1.
        // In this case, the product will always have magnitude >= 1.
        bool can_be_magnitude_lt_1;
        if (A + D == total_toys) { // All toys have magnitude >= 1
            can_be_magnitude_lt_1 = false;
        } else { // At least one toy has magnitude < 1 (from B or C)
            can_be_magnitude_lt_1 = true;
        }

        if (can_be_negative_final_sign && can_be_magnitude_lt_1) {
            result[1] = "Ya";
        } else {
            result[1] = "Tidak";
        }

        // Box 3: (0, 1)
        // Final toy can be in Box 3 if:
        // 1. The final sign is positive.
        // 2. The final magnitude is < 1.
        if (can_be_positive_final_sign && can_be_magnitude_lt_1) {
            result[2] = "Ya";
        } else {
            result[2] = "Tidak";
        }

        // Box 4: [1, inf)
        // Final toy can be in Box 4 if:
        // 1. The final sign is positive.
        // 2. The final magnitude is >= 1.
        if (can_be_positive_final_sign && can_be_magnitude_ge_1) {
            result[3] = "Ya";
        } else {
            result[3] = "Tidak";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

