#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // For each i from 0 to n-k-1, s[i] must be equal to s[i+k]
    // This means s[i], s[i+k], s[i+2k], ... must all be the same character.
    // We can iterate through the first k characters and propagate their values.
    for (int i = 0; i < k; ++i) {
        char fixed_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[j];
                } else if (fixed_char != s[j]) {
                    // Conflict: s[j] is '0' but fixed_char is '1', or vice versa.
                    // This means it's impossible to form a k-balanced string.
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a fixed_char was found, apply it to all positions in this "k-chain"
        if (fixed_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = fixed_char;
            }
        }
    }

    // Step 2: Check if the first k characters can form a k-balanced prefix.
    // After propagation, the first k characters s[0...k-1] are either '0', '1', or '?'.
    // We need to count the number of '0's, '1's, and '?'s in s[0...k-1].
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;
    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else {
            count_q++;
        }
    }

    // If the number of '0's or '1's already exceeds k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // We need to fill the '?'s such that the total '0's and '1's are k/2 each.
    // The remaining '?'s must be filled to reach k/2 for both '0's and '1's.
    // Number of '0's needed: k/2 - count0
    // Number of '1's needed: k/2 - count1
    // The sum of these needed counts must be equal to count_q.
    // (k/2 - count0) + (k/2 - count1) = k - count0 - count1 = count_q.
    // This is guaranteed if count0 + count1 + count_q = k, which is true.
    // So, if we passed the previous check (count0 <= k/2 and count1 <= k/2),
    // it's always possible to fill the '?'s in the first k characters to make it k-balanced.

    // Since s[i] == s[i+k] for all i, if s[0...k-1] can be made k-balanced,
    // then all subsequent k-length substrings will also be k-balanced.
    // For example, s[k...2k-1] will have the same character counts as s[0...k-1]
    // because s[k] = s[0], s[k+1] = s[1], ..., s[2k-1] = s[k-1].

    std::cout << "YES\n";
}

