    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            if (f1 == 0) { // Cannot move left (x-1), so target X must be >= current x
                min_x = std::max(min_x, x);
            }
            if (f2 == 0) { // Cannot move up (y+1), so target Y must be <= current y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right (x+1), so target X must be <= current x
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down (y-1), so target Y must be >= current y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where one class has size 1 and the other has size 2n-1.
        // The median of a class of size 1 is its single element.
        // The median of a class of size 2n-1 is its n-th element (0-indexed).
        //
        // If we pick a_0 for the first class (size 1), its median is a_0.
        // The remaining 2n-1 elements are a_1, ..., a_{2n-1}.
        // The median of these 2n-1 elements is a_1 + (n-1) = a_n.
        // The difference would be |a_n - a_0|.
        //
        // If we pick a_i for the first class (size 1), its median is a_i.
        // The remaining 2n-1 elements are all other elements.
        // This becomes complicated because the median of the remaining elements depends on which element a_i was.
        //
        // However, a key observation for this type of problem is often related to the sorted array.
        //
        // Let the two classes be $C_1$ and $C_2$.
        // Let their sizes be $S_1$ and $S_2$, where $S_1, S_2$ are odd and $S_1 + S_2 = 2n$.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // We want to minimize $|m_1 - m_2|$.
        //
        // Consider the specific partition where the first class consists of the first $n$ elements
        // and the second class consists of the last $n$ elements.
        // This is not allowed because $n$ can be even, and class sizes must be odd.
        //
        // The problem statement implies that we can choose any odd sizes $S_1, S_2$ such that $S_1+S_2=2n$.
        //
        // Let's consider the elements $a_0, a_1, \dots, a_{2n-1}$ after sorting.
        //
        // If we want to minimize the difference between two medians, it's intuitive that the medians
        // should be "close" in the sorted array.
        //
        // Consider the partition where one class takes the elements $a_0, \dots, a_{n-1}$ and the other takes $a_n, \dots, a_{2n-1}$.
        // This is not a valid partition because $n$ can be even.
        //
        // The crucial insight for this problem is that the minimum difference is always achieved
        // when the two medians are $a_{n-1}$ and $a_n$.
        //
        // Let's try to prove this or at least understand why it's true.
        // Suppose we have two classes $C_1$ and $C_2$ with medians $m_1$ and $m_2$.
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // For $m_1$ to be the median of $C_1$ (size $S_1 = 2k_1+1$), there must be $k_1$ elements in $C_1$ less than or equal to $m_1$,
        // and $k_1$ elements in $C_1$ greater than or equal to $m_1$.
        // Similarly for $m_2$ (size $S_2 = 2k_2+1$).
        //
        // The total number of elements is $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The minimum possible difference is always $a_n - a_{n-1}$.
        // This can be achieved by forming two classes:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$
        //
        // This is not a valid partition because the sizes are $n$ and $n$.
        // If $n$ is odd, then this is a valid partition. The median of the first class is $a_{(n-1)/2}$.
        // The median of the second class is $a_{n + (n-1)/2} = a_{(3n-1)/2}$.
        // This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler than that.
        // The minimum difference is always $a_n - a_{n-1}$.
        //
        // Let's verify this with the examples.
        // n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // a_0=1, a_1=1. n=1. a_n = a_1 = 1. a_{n-1} = a_0 = 1.
        // Difference = a_1 - a_0 = 1 - 1 = 0. Correct.
        //
        // n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6. n=3.
        // a_n = a_3 = 4. a_{n-1} = a_2 = 3.
        // Difference = a_3 - a_2 = 4 - 3 = 1. Correct.
        //
        // n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // a_0=2, a_1=3, a_2=4, a_3=5, a_4=8, a_5=13, a_6=13, a_7=16, a_8=17, a_9=20. n=5.
        // a_n = a_5 = 13. a_{n-1} = a_4 = 8.
        // Difference = a_5 - a_4 = 13 - 8 = 5. Correct.
        //
        // The pattern holds for all examples.
        //
        // Why is this always the minimum?
        // Consider any partition into two classes $C_1$ and $C_2$ with odd sizes $S_1, S_2$.
        // Let $m_1$ and $m_2$ be their medians.
        //
        // The median of a set of $2k+1$ elements is the $(k+1)$-th element.
        // This means there are $k$ elements less than or equal to the median, and $k$ elements greater than or equal to the median.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // For $m_1$ to be the median of $C_1$ (size $S_1 = 2k_1+1$), there must be at least $k_1$ elements in $C_1$ that are $\le m_1$.
        // For $m_2$ to be the median of $C_2$ (size $S_2 = 2k_2+1$), there must be at least $k_2+1$ elements in $C_2$ that are $\le m_2$.
        //
        // Total elements $\le m_1$ in $C_1$ is $k_1+1$.
        // Total elements $\le m_2$ in $C_2$ is $k_2+1$.
        //
        // The total number of elements is $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // Suppose $m_1 < a_{n-1}$ and $m_2 > a_n$.
        // This would mean $m_2 - m_1 > a_n - a_{n-1}$.
        //
        // Let's try a proof by contradiction.
        // Assume there exists a partition such that $|m_1 - m_2| < a_n - a_{n-1}$.
        // This implies $m_1$ and $m_2$ must both lie within the interval $[a_{n-1}, a_n]$ or one of them is $a_{n-1}$ and the other is $a_n$.
        // More precisely, if $m_1 \le m_2$, then $m_1$ must be greater than or equal to $a_{n-1}$ and $m_2$ must be less than or equal to $a_n$.
        // If $m_1 < a_{n-1}$ or $m_2 > a_n$, then $|m_1 - m_2| \ge a_n - a_{n-1}$ (if $m_1 \le m_2$).
        //
        // So, we must have $a_{n-1} \le m_1 \le m_2 \le a_n$.
        //
        // For $m_1$ to be the median of $C_1$ (size $2k_1+1$), there are $k_1$ elements in $C_1$ that are $\le m_1$.
        // For $m_2$ to be the median of $C_2$ (size $2k_2+1$), there are $k_2$ elements in $C_2$ that are $\ge m_2$.
        //
        // The total number of elements less than or equal to $m_1$ is at least $k_1+1$.
        // The total number of elements greater than or equal to $m_2$ is at least $k_2+1$.
        //
        // Since $m_1 \le m_2$, all elements $\le m_1$ are also $\le m_2$.
        // All elements $\ge m_2$ are also $\ge m_1$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // If $m_1 \le m_2$, then $m_1$ must be one of $a_i$ and $m_2$ must be one of $a_j$.
        //
        // The number of elements in the entire array that are $\le m_1$ is at most $n-1$ (if $m_1 < a_n$).
        // The number of elements in the entire array that are $\ge m_2$ is at most $n$ (if $m_2 \ge a_n$).
        //
        // Let's consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        // This means there are $k$ elements smaller than or equal to it, and $k$ elements larger than or equal to it.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // The number of elements in $C_1$ that are $\le m_1$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\le m_2$ is $k_2+1$.
        //
        // The total number of elements in $A$ that are $\le m_1$ is at least $k_1+1$.
        // The total number of elements in $A$ that are $\ge m_2$ is at least $k_2+1$.
        //
        // The total number of elements in $A$ is $2n$.
        //
        // The number of elements in $A$ that are $\le m_1$ is at most $n-1$ if $m_1 < a_n$.
        // The number of elements in $A$ that are $\ge m_2$ is at most $n$ if $m_2 \ge a_n$.
        //
        // This is a known result. For any partition of $2n$ elements into two sets of odd sizes,
        // the median of one set must be $\le a_{n-1}$ and the median of the other set must be $\ge a_n$.
        // Or, more generally, one median is $\le a_{n-1}$ and the other is $\ge a_n$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Suppose $m_1 \le m_2$.
        //
        // There are $k_1+1$ elements in $C_1$ that are $\le m_1$.
        // There are $k_2+1$ elements in $C_2$ that are $\le m_2$.
        //
        // The total number of elements in $A$ that are $\le m_1$ is at least $k_1+1$.
        // The total number of elements in $A$ that are $\ge m_2$ is at least $k_2+1$.
        //
        // The sum of elements in $A$ that are $\le m_1$ and elements in $A$ that are $\ge m_2$
        // is at least $(k_1+1) + (k_2+1) = k_1+k_2+2$.
        //
        // We know $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $S_1+S_2 = 2k_1+1+2k_2+1 = 2(k_1+k_2+1) = 2n$.
        // So $k_1+k_2+1 = n$.
        //
        // Thus, the sum of elements in $A$ that are $\le m_1$ and elements in $A$ that are $\ge m_2$
        // is at least $n+1$.
        //
        // If $m_1$ and $m_2$ are such that $m_1 \ge a_n$ or $m_2 \le a_{n-1}$, then the difference could be smaller.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ elements.
        //
        // If $m_1 \le a_{n-1}$ and $m_2 \ge a_n$, then $|m_1 - m_2| \ge a_n - a_{n-1}$.
        //
        // What if $m_1 > a_{n-1}$? Then $m_1$ must be one of $a_n, \dots, a_{2n-1}$.
        // What if $m_2 < a_n$? Then $m_2$ must be one of $a_0, \dots, a_{n-1}$.
        //
        // This is a standard result from competitive programming.
        // The minimum difference is always $a_n - a_{n-1}$.
        //
        // To achieve this, we can construct the classes as follows:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ elements.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ elements.
        // This is not valid if $n$ is even.
        //
        // The problem states that each class has an odd number of students.
        //
        // Let's consider the partition:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$ (size $n$)
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$ (size $n$)
        //
        // If $n$ is odd:
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The solution is simply $a_n - a_{n-1}$.
        // The proof for this is usually based on the fact that if you have $2n$ numbers,
        // and you split them into two sets of odd sizes, say $S_1$ and $S_2$,
        // then the median of one set must be $\le a_{n-1}$ and the median of the other set must be $\ge a_n$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // $C_1$ has $S_1 = 2k_1+1$ elements. $m_1$ is the $(k_1+1)$-th element.
        // So there are $k_1$ elements in $C_1$ that are $\le m_1$ (excluding $m_1$ itself).
        // And $k_1$ elements in $C_1$ that are $\ge m_1$ (excluding $m_1$ itself).
        //
        // $C_2$ has $S_2 = 2k_2+1$ elements. $m_2$ is the $(k_2+1)$-th element.
        // So there are $k_2$ elements in $C_2$ that are $\le m_2$ (excluding $m_2$ itself).
        // And $k_2$ elements in $C_2$ that are $\ge m_2$ (excluding $m_2$ itself).
        //
        // Total elements $2n = S_1+S_2 = 2k_1+1+2k_2+1 = 2(k_1+k_2+1)$.
        // So $n = k_1+k_2+1$.
        //
        // Consider the set of all elements $A = \{a_0, \dots, a_{2n-1}\}$.
        //
        // The number of elements in $A$ that are $\le m_1$ is at least $k_1+1$.
        // The number of elements in $A$ that are $\ge m_2$ is at least $k_2+1$.
        //
        // If $m_1 > a_{n-1}$, then there are at least $n$ elements in $A$ that are $\le m_1$.
        // If $m_2 < a_n$, then there are at least $n$ elements in $A$ that are $\ge m_2$.
        //
        // Suppose $m_1 \le a_{n-1}$ and $m_2 \ge a_n$. Then $|m_1 - m_2| \ge a_n - a_{n-1}$.
        //
        // Suppose $m_1 > a_{n-1}$. Then $m_1 \ge a_n$.
        // In this case, all $k_1+1$ elements of $C_1$ that are $\le m_1$ must be $\ge a_n$.
        // This means $C_1$ must contain at least $k_1+1$ elements from $\{a_n, \dots, a_{2n-1}\}$.
