            }
            max_x = std::max(max_x, current_candidate_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are present, they divide the zeros into at most m+1 blocks.
        // To minimize substrings of only zeros, we want to distribute the zeros
        // as evenly as possible among these blocks.
        // The optimal configuration is to have 'm' ones separating 'm+1' blocks of zeros.
        // For example, 101010...101
        // The number of blocks of zeros is m+1.
        // The number of zeros is n-m.
        // Let k be the number of zeros in each block.
        // We distribute num_zeros among m+1 blocks.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.

        long long num_blocks = m + 1;

        long long k_floor = num_zeros / num_blocks;
        long long k_ceil = k_floor + 1;

        // Number of blocks with k_ceil zeros
        long long num_blocks_ceil = num_zeros % num_blocks;
        // Number of blocks with k_floor zeros
        long long num_blocks_floor = num_blocks - num_blocks_ceil;

        // Calculate substrings of only zeros from these blocks
        long long substrings_only_zeros = 0;
        if (k_floor > 0) {
            substrings_only_zeros += num_blocks_floor * (k_floor * (k_floor + 1) / 2);
        }
        if (k_ceil > 0) {
            substrings_only_zeros += num_blocks_ceil * (k_ceil * (k_ceil + 1) / 2);
        }

        // The maximum f(s) is total_substrings - minimum_substrings_only_zeros
        long long max_f_s = total_substrings - substrings_only_zeros;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }

        // Calculate initial balance for the entire 2n jars
        int initial_balance = 0;
        for (int x : a) {
            if (x == 1) {
                initial_balance++;
            } else {
                initial_balance--;
            }
        }

        // If already balanced, 0 jars need to be emptied
        if (initial_balance == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate prefix sums for the left side (jars 1 to n)
        // balance_left[k] = balance of jars 1 to k
        std::vector<int> balance_left(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            balance_left[i + 1] = balance_left[i] + (a[i] == 1 ? 1 : -1);
        }

        // Calculate suffix sums for the right side (jars n+1 to 2n)
        // balance_right[k] = balance of jars k to 2n
        std::vector<int> balance_right(n + 1, 0); // balance_right[k] stores balance of jars 2n-k+1 to 2n
        for (int i = 0; i < n; ++i) {
            balance_right[i + 1] = balance_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
        }

        // Map to store the minimum number of jars removed from the left side
        // to achieve a certain balance for the remaining jars (1 to n-i)
        // key: balance, value: number of jars removed (i)
        std::map<int, int> left_balance_to_removed_count;
        // Iterate through all possible 'i' jars removed from the left (0 to n)
        // If 'i' jars are removed, jars 1 to n-i remain.
        // The balance of these remaining jars is balance_left[n-i].
        // The number of jars removed is 'i'.
        for (int i = 0; i <= n; ++i) {
            int current_balance = balance_left[n - i];
            if (left_balance_to_removed_count.find(current_balance) == left_balance_to_removed_count.end()) {
                left_balance_to_removed_count[current_balance] = i;
            } else {
                left_balance_to_removed_count[current_balance] = std::min(left_balance_to_removed_count[current_balance], i);
            }
        }

        int min_removed_jars = 2 * n; // Initialize with max possible

        // Iterate through all possible 'j' jars removed from the right (0 to n)
        // If 'j' jars are removed, jars n+j+1 to 2n remain.
        // The balance of these remaining jars is balance_right[n-j].
        // The number of jars removed is 'j'.
        for (int j = 0; j <= n; ++j) {
            int current_right_balance = balance_right[n - j];
            // We need the total balance of remaining jars to be 0.
            // This means balance_left[n-i] + balance_right[n-j] = 0.
            // So, balance_left[n-i] must be -current_right_balance.
            int target_left_balance = -current_right_balance;

            if (left_balance_to_removed_count.count(target_left_balance)) {
                int i = left_balance_to_removed_count[target_left_balance];
                min_removed_jars = std::min(min_removed_jars, i + j);
            }
        }

        std::cout << min_removed_jars << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two numbers:
    // `all_zero` represents the state of bits if the input was 0.
    // `all_one` represents the state of bits if the input was 1023 (all 1s for 0-9 bits).
    // We only care about bits 0-9, as constants are <= 1023.
    int all_zero = 0;
    int all_one = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            all_zero &= x;
            all_one &= x;
        } else if (op_char == '|') {
            all_zero |= x;
            all_one |= x;
        } else if (op_char == '^') {
            all_zero ^= x;
            all_one ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // Let x_j be the j-th bit of the input.
    // Let z_j be the j-th bit of all_zero.
    // Let o_j be the j-th bit of all_one.
    //
    // If x_j = 0, the final bit is z_j.
    // If x_j = 1, the final bit is o_j.
    //
    // We need to find a minimal set of operations to achieve this transformation.
    //
    // Case 1: z_j = 0, o_j = 0  =>  final bit is always 0.
    // Case 2: z_j = 1, o_j = 1  =>  final bit is always 1.
    // Case 3: z_j = 0, o_j = 1  =>  final bit is x_j (identity).
    // Case 4: z_j = 1, o_j = 0  =>  final bit is 1 - x_j (flip).

    int final_and_mask = 1023; // Bits that become 0 if input is 0, or 1 if input is 1
    int final_or_mask = 0;     // Bits that become 1 if input is 0, or 0 if input is 1
    int final_xor_mask = 0;    // Bits that flip the input bit

    for (int j = 0; j < 10; ++j) {
        int z_j = (all_zero >> j) & 1;
        int o_j = (all_one >> j) & 1;

        if (z_j == 0 && o_j == 0) {
            // Case 1: final bit is always 0.
            // This means we need to AND with 0 at this bit position.
            final_and_mask &= ~(1 << j);
        } else if (z_j == 1 && o_j == 1) {
            // Case 2: final bit is always 1.
            // This means we need to OR with 1 at this bit position.
            final_or_mask |= (1 << j);
        } else if (z_j == 0 && o_j == 1) {
            // Case 3: final bit is x_j (identity).
            // No change needed for this bit from AND/OR/XOR masks.
        } else if (z_j == 1 && o_j == 0) {
            // Case 4: final bit is 1 - x_j (flip).
            // This means we need to XOR with 1 at this bit position.
            final_xor_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters.
    // A common simplification is: (x & A) | B ^ C
    // This can be rewritten as:
    // x' = x ^ C
    // x'' = x' & A
    // x''' = x'' | B
    //
    // Let's try to construct the operations in a way that matches the derived masks.
    // The final state of a bit `j` is `((x_j ^ final_xor_mask_j) & final_and_mask_j) | final_or_mask_j`.
    //
    // However, the problem states "no more than 5 lines".
    // The standard simplification for any sequence of bitwise operations is at most 3 operations:
    // `(x & A) | B ^ C`
    //
    // Let's derive A, B, C from `final_and_mask`, `final_or_mask`, `final_xor_mask`.
    //
    // If we apply `^ C` first: `x_new = x ^ C`
    // Then `& A`: `x_new_2 = x_new & A`
    // Then `| B`: `x_final = x_new_2 | B`
    //
    // Let's consider the effect on `all_zero` and `all_one` for these three operations.
    // Initial: `all_zero = 0`, `all_one = 1023`
    //
    // After `^ C`:
    // `all_zero_1 = 0 ^ C = C`
    // `all_one_1 = 1023 ^ C`
    //
    // After `& A`:
    // `all_zero_2 = C & A`
    // `all_one_2 = (1023 ^ C) & A`
    //
    // After `| B`:
    // `all_zero_3 = (C & A) | B`
    // `all_one_3 = ((1023 ^ C) & A) | B`
    //
    // We want `all_zero_3` to be our calculated `all_zero` and `all_one_3` to be our calculated `all_one`.
    //
    // Let's try to find A, B, C.
    //
    // For each bit `j`:
    // `z_j = ((C_j & A_j) | B_j)`
    // `o_j = (((1 ^ C_j) & A_j) | B_j)`
    //
    // This is a system of equations for each bit.
    //
    // If `final_and_mask` is not 1023, we need an `&` operation.
    // If `final_or_mask` is not 0, we need an `|` operation.
    // If `final_xor_mask` is not 0, we need an `^` operation.
    //
    // The problem states "no more than 5 lines". The standard simplification is 3 operations.
    // Let's try to construct the 3 operations: `& A`, `| B`, `^ C`.
    //
    // The final state of bit `j` is `y_j`.
    // `y_j = (x_j & A_j) | B_j ^ C_j` is not the standard form.
    // The standard form is `((x ^ C) & A) | B`.
    //
    // Let's re-evaluate the `final_and_mask`, `final_or_mask`, `final_xor_mask` based on the 3-op form.
    //
    // Let `A_val = 1023`, `B_val = 0`, `C_val = 0`.
    //
    // For each bit `j`:
    // `z_j` is the target output for input `0`.
    // `o_j` is the target output for input `1`.
    //
    // If `z_j == 0 && o_j == 0`:
    //   Output is always 0. This means `A_j` must be 0.
    //   `A_val &= ~(1 << j);`
    //   `B_val &= ~(1 << j);` (if `B_j` was 1, output would be 1)
    //   `C_val` doesn't matter for this bit if `A_j` is 0.
    //
    // If `z_j == 1 && o_j == 1`:
    //   Output is always 1. This means `B_j` must be 1.
    //   `B_val |= (1 << j);`
    //   `A_val` doesn't matter for this bit if `B_j` is 1.
    //   `C_val` doesn't matter for this bit if `B_j` is 1.
    //
    // If `z_j == 0 && o_j == 1`:
    //   Output is `x_j`. This means `A_j` must be 1, `B_j` must be 0, `C_j` must be 0.
    //   `A_val |= (1 << j);` (already 1023)
    //   `B_val &= ~(1 << j);` (already 0)
    //   `C_val &= ~(1 << j);` (already 0)
    //
    // If `z_j == 1 && o_j == 0`:
    //   Output is `1 - x_j`. This means `A_j` must be 1, `B_j` must be 0, `C_j` must be 1.
    //   `A_val |= (1 << j);` (already 1023)
    //   `B_val &= ~(1 << j);` (already 0)
    //   `C_val |= (1 << j);`
    //
    // Let's refine this.
    // We want to find `A`, `B`, `C` such that for any input `x`,
    // `((x ^ C) & A) | B` is the desired output.
    //
    // Let's determine `A`, `B`, `C` bit by bit.
    // For bit `j`:
    // `z_j = ((0 ^ C_j) & A_j) | B_j`
    // `o_j = ((1 ^ C_j) & A_j) | B_j`
    //
    // Case 1: `z_j = 0, o_j = 0` (output always 0)
    //   This implies `B_j = 0`.
    //   Then `(0 ^ C_j) & A_j = 0` and `(1 ^ C_j) & A_j = 0`.
    //   This means `A_j` must be 0.
    //   So, `A_j = 0, B_j = 0`. `C_j` can be anything, let's say 0.
    //
    // Case 2: `z_j = 1, o_j = 1` (output always 1)
    //   This implies `B_j = 1`.
    //   Then `A_j` and `C_j` don't matter. Let's say `A_j = 1, C_j = 0`.
    //
    // Case 3: `z_j = 0, o_j = 1` (output is `x_j`)
    //   This implies `B_j = 0`.
    //   Then `(0 ^ C_j) & A_j = 0` and `(1 ^ C_j) & A_j = 1`.
    //   If `C_j = 0`: `(0 & A_j) = 0` and `(1 & A_j) = 1`. This means `A_j = 1`.
    //   So, `A_j = 1, B_j = 0, C_j = 0`.
    //   If `C_j = 1`: `(1 & A_j) = 0` and `(0 & A_j) = 1`. This is impossible.
    //   So, `C_j` must be 0.
    //
    // Case 4: `z_j = 1, o_j = 0` (output is `1 - x_j`)
    //   This implies `B_j = 0`.
    //   Then `(0 ^ C_j) & A_j = 1` and `(1 ^ C_j) & A_j = 0`.
    //   If `C_j = 0`: `(0 & A_j) = 1` (impossible).
    //   If `C_j = 1`: `(1 & A_j) = 1` and `(0 & A_j) = 0`. This means `A_j = 1`.
    //   So, `A_j = 1, B_j = 0, C_j = 1`.

    int A = 0; // Mask for AND operation
    int B = 0; // Mask for OR operation
    int C = 0; // Mask for XOR operation

    for (int j = 0; j < 10; ++j) {
        int z_j = (all_zero >> j) & 1;
        int o_j = (all_one >> j) & 1;

        if (z_j == 0 && o_j == 0) { // Output always 0
            // A_j = 0, B_j = 0, C_j = 0 (or 1, doesn't matter for A_j=0)
            // A remains 0 for this bit, B remains 0 for this bit.
        } else if (z_j == 1 && o_j == 1) { // Output always 1
            // A_j = 1, B_j = 1, C_j = 0 (or 1, doesn't matter for B_j=1)
            A |= (1 << j); // A_j must be 1 for this bit to pass through to B_j
            B |= (1 << j);
        } else if (z_j == 0 && o_j == 1) { // Output is x_j
            // A_j = 1, B_j = 0, C_j = 0
            A |= (1 << j);
        } else if (z_j == 1 && o_j == 0) { // Output is 1 - x_j
            // A_j = 1, B_j = 0, C_j = 1
            A |= (1 << j);
            C |= (1 << j);
        }
    }

    // Add operations if their masks are non-trivial
    if (C != 0) {
        result_ops.push_back({'^', C});
    }
    if (A != 1023) { // If A is not all ones, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not all zeros, we need an OR operation
        result_ops.push_back({'|', B});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal
    for (int step = n - 1; step >= 0; --step) {
        int k_idx = x[step]; // The vertex being added back to the graph
        active[k_idx] = true;

        // Update shortest paths using k_idx as an intermediate vertex
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices
                if (dist[i][k_idx] + dist[k_idx][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k_idx] + dist[k_idx][j];
                }
            }
        }

        // After adding k_idx and updating paths through it,
        // we also need to update paths between existing active vertices
        // using k_idx as an endpoint or starting point.
        // This is implicitly handled by the triple loop above, but
        // to be explicit about the order of operations for Floyd-Warshall:
        // When k_idx is added, it can be an intermediate vertex for any pair (i,j)
        // where i, j are already active.
        // It can also be an endpoint for paths from/to other active vertices.
        // The triple loop (i, j, k_idx) correctly updates all these.
        // The order of loops (i, j, k) is important for Floyd-Warshall.
        // Here, k_idx is the 'k' in Floyd-Warshall.
        // The loops for i and j must iterate over all currently active vertices.

        // Calculate the sum of shortest paths for all pairs of currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    std::deque<std::pair<long long, int>> q; // {height, index}

    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n); // d[i] = min_dist_to_boundary for tower i

    // Calculate min_dist_to_boundary from left
    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long current_d = 0;

        // Remove towers from queue that are shorter than or equal to current_h - current_d
        // and are further away (smaller index)
        while (!q.empty() && q.front().first <= current_h - current_d) {
            q.pop_front();
        }

        // If queue is not empty, it means there's a taller tower to the left
        // The distance to boundary for current tower is 1 + distance to that taller tower
        // The distance to that taller tower is its height minus current_h + current_d
        // No, it's simpler: the distance is 1 + the distance of the previous tower.
        // The actual distance is min(current_h, 1 + d[i-1])
        // But we need to consider the "valley" effect.
        // The distance from the left boundary is `i`.
        // The distance from the right boundary is `n-1-i`.
        // The distance from the top boundary is `h[i]-1`.
        // The distance from an adjacent shorter tower is `h[i] - h[j]`.

        // Let's re-evaluate d[i] as the maximum possible height of a block at index i
        // that is `k` steps away from any boundary.
        // This is equivalent to finding the minimum number of operations for each block.
        // A block at (x, y) is destroyed in `k` operations if `k` is the minimum of:
        // y + 1 (distance to top)
        // x + 1 (distance to left edge)
        // (n-1-x) + 1 (distance to right edge)
        // (y - h[x-1]) + 1 (distance to left adjacent shorter tower)
        // (y - h[x+1]) + 1 (distance to right adjacent shorter tower)

        // This is a min-max problem. The number of operations for a block is `min(dist_to_any_boundary)`.
        // The number of operations for the entire structure is `max(min(dist_to_any_boundary))`.
        // This is equivalent to finding the maximum `k` such that there exists at least one block
        // that is `k` steps away from all boundaries.

        // Let `d[i]` be the maximum `k` such that a block at `(i, k-1)` exists and is `k` steps away from the left boundary.
        // `d[i] = min(h[i], d[i-1] + 1)`
        // This is not quite right. `d[i]` should be the maximum height `k` such that a block at `(i, k-1)`
        // is `k` steps away from the left edge OR a shorter tower to its left.
        // This is `min(h[i], i + 1)` for the left edge.
        // And `min(h[i], (n-1-i) + 1)` for the right edge.

        // Let `L[i]` be the maximum height `k` such that a block at `(i, k-1)` is `k` steps away from the left boundary
        // (either the actual left edge of the whole structure, or a shorter tower to its left).
        // `L[i] = min(h[i], L[i-1] + 1)` if `i > 0`. `L[0] = h[0]`.
        // This is wrong. `L[i]` should be `min(h[i], L[i-1] + 1)` if `h[i] > L[i-1]`.
        // No, `L[i]` is the maximum `k` such that a block at `(i, k-1)` is `k` steps away from the left boundary.
        // This means `k <= h[i]`.
        // And `k <= k_prev + 1` where `k_prev` is the max `k` for `i-1`.
        // So `L[i] = min(h[i], L[i-1] + 1)` for `i > 0`. `L[0] = h[0]`.
        // This is the standard "water trapping" approach.
        // `L[i]` is the maximum height a block at `i` can have if it's supported by the left side.
        // `L[i]` is `min(h[i], L[i-1] + 1)` for `i > 0`. `L[0] = 1`.
        // No, `L[i]` is the maximum `k` such that a block at `(i, k-1)` is `k` steps away from the left boundary.
        // This means `k <= h[i]`.
        // And `k <= k_prev + 1` where `k_prev` is the max `k` for `i-1`.
        // So `L[i] = min(h[i], L[i-1] + 1)` for `i > 0`. `L[0] = 1`.
        // This is the distance from the left edge.
        // `L[i]` = `min(h[i], i + 1)`
