#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now cured

        long long current_v_cry = children[i].v;
        long long d_cry_sum = 0; // Accumulates d_j cries from children leaving due to chain reaction

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry_sum first
            children[j].p -= d_cry_sum;

            // Apply current_v_cry from the child in the doctor's office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // The effect decreases for subsequent children
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_cry_sum += children[j].d; // Add this child's d_j to the sum for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Calculate the total delta applied to each element by type 1 operations
    // that occur *before* any type 2 operation.
    // This is not quite right. We need the delta *at the time of the query*.
    // Let's rephrase:
    // For each element a_j, let a_0[j] be its initial value.
    // After k operations, its value is a_0[j] + sum(d_i for type 1 ops i <= k that affect j).
    // Let D_k[j] be sum(d_i for type 1 ops i <= k that affect j).
    // Then a_k[j] = a_0[j] + D_k[j].
    // For a type 2 op (l, r, m) at step k:
    // max_{j=l..r} (a_0[j] + D_k[j]) = m.
    // This implies for all j in [l, r]: a_0[j] + D_k[j] <= m
    // So, a_0[j] <= m - D_k[j].
    // We want to maximize a_0[j] to satisfy the equality condition later.
    // So, for each j, a_0[j] <= min(m - D_k[j]) over all type 2 ops (l, r, m) where j is in [l, r].

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max()); // a_0[j] upper bounds
    std::vector<long long> current_deltas(n, 0); // D_k[j]

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // If no type 2 operation constrained an element, its upper bound is still max_long_long.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> test_a = initial_a;
    std::fill(current_deltas.begin(), current_deltas.end(), 0); // Reset current_deltas for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                test_a[j] += ops[i].val;
                current_deltas[j] += ops[i].val; // Keep track of deltas for the next step
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_deltas[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int j = 0; j < n; ++j) {
        if (std::abs(initial_a[j]) > 1000000000LL) {
            // This case should ideally not be reached if m_i is within 5*10^7 and d_i within 10^4
            // and n, m <= 5000.
            // Max possible D_k[j] is 5000 * 10^4 = 5*10^7.
            // So m - D_k[j] would be around 5*10^7 - (-5*10^7) = 10^8 or -5*10^7 - 5*10^7 = -10^8.
            // These values are within 10^9.
            // However, if initial_a[j] was not constrained by any type 2 op, it could be 0.
            // So this check is mostly for robustness, but should pass.
            std::cout << "NO\n"; // Should not happen based on constraints
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

