    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long min_goodness = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> best_partition(n, 1); // Default to all 1s

    // Case 2: Try to put a[0] in one subsequence and the rest in another.
    // This is the strategy where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // Or a[0] is in S2, and a[1]...a[n-1] are in S1.
    // The logic is symmetric, so let's assume a[0] is in S1, others in S2.
    //
    // Possible f values:
    // 1. a[i] + a[j] for i,j in {1, ..., n-1} (both in S2)
    //    Min: a[1].value + a[2].value
    //    Max: a[n-2].value + a[n-1].value
    // 2. a[0].value + a[i].value + h for i in {1, ..., n-1} (a[0] in S1, a[i] in S2)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // Overall min_f: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max_f: max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // This strategy is only relevant if n >= 3. If n=2, this is the same as Case 1.
    if (n >= 3) {
        long long current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        long long current_max_f = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition.assign(n, 2); // All 2s
            best_partition[a[0].original_index] = 1; // a[0] is 1
        }
    }

    // Case 3: Try to put a[n-1] in one subsequence and the rest in another.
    // This is the strategy where a[n-1] is in S1, and a[0]...a[n-2] are in S2.
    // Or a[n-1] is in S2, and a[0]...a[n-2] are in S1.
    // The logic is symmetric, so let's assume a[n-1] is in S1, others in S2.
    //
    // Possible f values:
    // 1. a[i] + a[j] for i,j in {0, ..., n-2} (both in S2)
    //    Min: a[0].value + a[1].value
    //    Max: a[n-3].value + a[n-2].value
    // 2. a[n-1].value + a[i].value + h for i in {0, ..., n-2} (a[n-1] in S1, a[i] in S2)
    //    Min: a[n-1].value + a[0].value + h
    //    Max: a[n-1].value + a[n-2].value + h
    //
    // Overall min_f: min(a[0].value + a[1].value, a[n-1].value + a[0].value + h)
    // Overall max_f: max(a[n-3].value + a[n-2].value, a[n-1].value + a[n-2].value + h)
    //
    // This strategy is only relevant if n >= 3. If n=2, this is the same as Case 1.
    if (n >= 3) {
        long long current_min_f = std::min(a[0].value + a[1].value, a[n - 1].value + a[0].value + h);
        long long current_max_f = std::max(a[n - 3].value + a[n - 2].value, a[n - 1].value + a[n - 2].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition.assign(n, 1); // All 1s
            best_partition[a[n - 1].original_index] = 2; // a[n-1] is 2
        }
    }

    // Case 4: Put a[0] and a[n-1] in one subsequence, and the rest in another.
    // This is the strategy where a[0], a[n-1] are in S1, and a[1]...a[n-2] are in S2.
    //
    // Possible f values:
    // 1. a[i] + a[j] for i,j in {1, ..., n-2} (both in S2)
    //    Min: a[1].value + a[2].value
    //    Max: a[n-3].value + a[n-2].value
    // 2. a[0].value + a[n-1].value (both in S1)
    // 3. a[0].value + a[i].value + h for i in {1, ..., n-2} (a[0] in S1, a[i] in S2)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-2].value + h
    // 4. a[n-1].value + a[i].value + h for i in {1, ..., n-2} (a[n-1] in S1, a[i] in S2)
    //    Min: a[n-1].value + a[1].value + h
    //    Max: a[n-1].value + a[n-2].value + h
    //
    // Overall min_f: min(a[1].value + a[2].value, a[0].value + a[1].value + h, a[n-1].value + a[1].value + h, a[0].value + a[n-1].value)
    // Overall max_f: max(a[n-3].value + a[n-2].value, a[0].value + a[n-2].value + h, a[n-1].value + a[n-2].value + h, a[0].value + a[n-1].value)
    //
    // This strategy is only relevant if n >= 4. If n=2 or n=3, this is covered by previous cases or not applicable.
    if (n >= 4) {
        long long current_min_f = std::min({a[1].value + a[2].value,
                                            a[0].value + a[1].value + h,
                                            a[n - 1].value + a[1].value + h,
                                            a[0].value + a[n - 1].value});
        long long current_max_f = std::max({a[n - 3].value + a[n - 2].value,
                                            a[0].value + a[n - 2].value + h,
                                            a[n - 1].value + a[n - 2].value + h,
                                            a[0].value + a[n - 1].value});
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition.assign(n, 2); // All 2s
            best_partition[a[0].original_index] = 1; // a[0] is 1
            best_partition[a[n - 1].original_index] = 1; // a[n-1] is 1
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
