// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    while (p_idx < m && h_idx < n) {
        // Find the first target track that can be covered by the current head h_idx
        // A head h_idx can cover tracks in [h[h_idx] - t, h[h_idx] + t]
        // If p[p_idx] is already to the right of h[h_idx] + t, this head cannot cover p[p_idx]
        // and any subsequent p_j (since p is sorted). So we move to the next head.
        if (p[p_idx] > h[h_idx] + t) {
            h_idx++;
            continue;
        }

        // If p[p_idx] is to the left of h[h_idx] - t, this head cannot cover p[p_idx].
        // Since h is sorted, this head also cannot cover any p_j to its left.
        // We need to find a head that can cover p[p_idx].
        // This head h_idx might be able to cover p[p_idx] if p[p_idx] >= h[h_idx] - t.
        // If p[p_idx] < h[h_idx] - t, then h_idx cannot cover p[p_idx].
        // We must advance p_idx to find a track that h_idx can cover, or advance h_idx.
        // However, the greedy strategy is to use the current head h_idx to cover as many
        // tracks as possible starting from p[p_idx].
        // So, if p[p_idx] < h[h_idx] - t, this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // The current head h_idx is too far right for p[p_idx].
        // This means h[h_idx] - t > p[p_idx].
        // We should advance h_idx to find a head that is further left or can cover p[p_idx].
        // But the problem is that we are trying to cover p[p_idx] with h[h_idx].
        // If h[h_idx] is too far right, it means h[h_idx] - t > p[p_idx].
        // This implies that h[h_idx] is not suitable for p[p_idx].
        // We should try the next head h_idx+1.
        // This is incorrect. The greedy strategy is to use the current head h_idx to cover p[p_idx]
        // if it can. If it can't, it means p[p_idx] is too far left for h[h_idx].
        // So we need to find a head that can cover p[p_idx].
        // The current head h_idx can cover tracks in [h[h_idx] - t, h[h_idx] + t].
        // If p[p_idx] is within this range, we use h[h_idx] to cover p[p_idx] and subsequent tracks.
        // If p[p_idx] < h[h_idx] - t, then h[h_idx] cannot cover p[p_idx].
        // Since h is sorted, h[h_idx+1], h[h_idx+2], etc. will also be too far right.
        // This means p[p_idx] cannot be covered by any head. This is a contradiction.
        // The logic should be:
        // If p[p_idx] is covered by h[h_idx]:
        //   Find the rightmost track p_k that h[h_idx] can cover.
        //   Advance p_idx to k+1.
        //   Advance h_idx to h_idx+1.
        // Else (p[p_idx] is not covered by h[h_idx]):
        //   If p[p_idx] < h[h_idx] - t: This means p[p_idx] is too far left for h[h_idx].
        //     This implies that p[p_idx] cannot be covered by any head h_j where j >= h_idx,
        //     because h_j - t will be even larger or equal to h[h_idx] - t.
        //     This means p[p_idx] cannot be covered. So return false.
        //   If p[p_idx] > h[h_idx] + t: This means p[p_idx] is too far right for h[h_idx].
        //     This head h[h_idx] cannot cover p[p_idx]. We need to try the next head.
        //     Advance h_idx.

        // Correct greedy approach:
        // For each head h[h_idx], it can cover a range [h[h_idx] - t, h[h_idx] + t].
        // We want to cover p[p_idx], p[p_idx+1], ...
        // If the current head h[h_idx] cannot even reach p[p_idx] (i.e., p[p_idx] > h[h_idx] + t),
        // then this head is useless for p[p_idx] and any subsequent p_j. So we move to the next head.
        if (p[p_idx] > h[h_idx] + t) {
            h_idx++;
            continue;
        }

        // If the current head h[h_idx] is too far right for p[p_idx] (i.e., p[p_idx] < h[h_idx] - t),
        // then p[p_idx] cannot be covered by h[h_idx] or any subsequent head (since h is sorted).
        // This means it's impossible to cover p[p_idx].
        if (p[p_idx] < h[h_idx] - t) {
            return false;
        }

        // At this point, h[h_idx] can cover p[p_idx].
        // Use h[h_idx] to cover p[p_idx] and as many subsequent tracks as possible.
        long long current_head_reach_right = h[h_idx] + t;
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }
        h_idx++; // Move to the next head
    }

    // If all target tracks are covered (p_idx reaches m), return true.
    return p_idx == m;
}

