    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: distance between furthest p and furthest h, plus some buffer.
    // A safe upper bound is max(p_i) - min(h_i) or max(h_i) - min(p_i).
    // Or simply max(p_m-1, h_n-1) - min(p_0, h_0).
    // A very loose upper bound is 2 * 10^10, which is (10^10 - 1) + (10^10 - 1).
    // A tighter upper bound: max(p[m-1], h[n-1]) - min(p[0], h[0])
    // The maximum possible coordinate is 10^10. So max diff is 10^10.
    // If n=1, m=1, h={1}, p={10^10}, time is 10^10 - 1.
    // So 10^10 is a good upper bound.
    long long high = 20000000000LL; // 2 * 10^10, a safe upper bound for time
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

