int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> result;
        int current_num = 4 * n;
        while (result.size() < n) {
            if (current_num % 2 == 0) { // Only consider even numbers
                result.push_back(current_num);
            }
            current_num -= 2; // Decrement by 2 to get the next even number
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

