        } else { // type == 2
            total_packets_b += 10;
            successful_packets_b += x;
        }
    }
    if (successful_packets_a * 2 >= total_packets_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }
    if (successful_packets_b * 2 >= total_packets_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }
    return 0;
}

