    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed: k for crafting + k*y for buying coal
        // Each torch needs 1 stick and 1 coal.
        // To get k coal, we need k * y sticks. This takes k trades.
        // So, total sticks required = k (for crafting) + k * y (for coal)
        long long total_sticks_required = k * y + k;

        // We start with 1 stick. We need to acquire (total_sticks_required - 1) more sticks.
        // Each stick trade (1 stick -> x sticks) gives us (x - 1) net sticks.
        // Number of stick trades needed = ceil((total_sticks_required - 1) / (x - 1))
        // Using integer division: (A + B - 1) / B for ceil(A/B)
        long long stick_trades = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = stick trades + coal trades
        // Coal trades = k (one trade per coal)
        long long total_trades = stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

