#include <iostream>
#include <string>
#include <vector>
#include <numeric> // For std::iota (not strictly needed for this problem, but good practice for char sets)
#include <set>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If s and t are already equal, it's possible.
    if (s == t) {
        std::cout << "YES\n";
        return;
    }

    // The core idea is that if a character exists anywhere in a string,
    // it can be propagated to any other position in that string.
    // This means if we want to make s and t equal to some common string U,
    // then every character in U must be present in s, and every character in U must be present in t.
    //
    // More simply, if there is at least one common character between s and t,
    // say 'x', then we can transform s into a string of all 'x's (e.g., "xxx...x")
    // and t into a string of all 'x's ("xxx...x").
    // This is because 'x' can propagate from its original position to all other positions
    // in its respective string.
    //
    // For example, if s = "abc" and t = "xby", 'b' is common.
    // In s: "abc" -> "bbc" (s[1]=s[0]) -> "bbb" (s[2]=s[1])
    // In t: "xby" -> "bby" (t[0]=t[1]) -> "bbb" (t[2]=t[1])
    // Both can become "bbb".
    //
    // If there is no common character, then no such transformation is possible.
    // For example, s = "a", t = "z". No common character. Cannot make them equal.

    std::set<char> s_chars;
    for (char c : s) {
        s_chars.insert(c);
    }

    bool common_char_found = false;
    for (char c : t) {
        if (s_chars.count(c)) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

