int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (r - l + 1 >= 4) { // If the range is large enough to contain at least 4 numbers
                          // (e.g., 2, 3, 4, 5 or 3, 4, 5, 6), then 2 will always be the answer.
                          // This is because any range of 4 consecutive integers will contain
                          // at least two even numbers.
                          // For example, in [N, N+3]:
                          // If N is even: N, N+2 are even.
                          // If N is odd: N+1, N+3 are even.
                          // So, there are at least 2 multiples of 2.
                          // For any other number x > 2, the count of its multiples will be
                          // floor(r/x) - floor((l-1)/x).
                          // For x=3, count is at most floor(r/3) - floor((l-1)/3).
                          // For x=2, count is floor(r/2) - floor((l-1)/2).
                          // If r-l+1 >= 4, then floor(r/2) - floor((l-1)/2) >= 2.
                          // For x=3, the count can be 1 or 2.
                          // For x=4, the count can be 1.
                          // For x > r/2, the count can be at most 1.
                          // The only case where 2 might not be the answer is if the range is very small.
                          // For example, [3, 6]: 2 appears 2 times (4, 6), 3 appears 2 times (3, 6).
                          // In this case, 3 is a valid answer.
                          // The problem states "If there are multiple answers, print any of them."
                          // So 2 is always a safe bet for larger ranges.
                          // The threshold 4 is chosen because it guarantees at least two multiples of 2.
                          // For example, [2, 5] -> 2, 4 (count 2 for 2)
                          // [3, 6] -> 4, 6 (count 2 for 2)
                          // [4, 7] -> 4, 6 (count 2 for 2)
                          // For x=3, in [3, 6], count is 2 (3, 6).
                          // In [2, 5], count is 1 (3).
                          // In [4, 7], count is 1 (6).
                          // So, if r-l+1 >= 4, 2 is always a valid answer.
        std::cout << 2 << std::endl;
    } else { // r - l + 1 < 4, meaning the range has 1, 2, or 3 numbers.
             // Possible ranges: [N, N], [N, N+1], [N, N+2]
        if (l == r) { // Range has 1 number: [l, l]
            std::cout << l << std::endl; // The only divisor > 1 is l itself (if l > 1).
                                         // Since l >= 2, l is always the answer.
        } else if (l + 1 == r) { // Range has 2 numbers: [l, l+1]
            // Example: [19, 20]. Divisors > 1: 19, 2, 4, 5, 10, 20.
            // 19 appears once, 2 appears once, etc.
            // Any of them is a valid answer. 2 is the simplest.
            std::cout << 2 << std::endl;
        } else { // l + 2 == r, Range has 3 numbers: [l, l+1, l+2]
            // Example: [3, 5]. Numbers are 3, 4, 5.
            // Divisors > 1:
            // For 3: {3}
            // For 4: {2, 4}
            // For 5: {5}
            // Count for 2: 1 (from 4)
            // Count for 3: 1 (from 3)
            // Count for 4: 1 (from 4)
            // Count for 5: 1 (from 5)
            // Any of them is a valid answer. 2 is the simplest.
            // Example: [4, 6]. Numbers are 4, 5, 6.
            // Divisors > 1:
            // For 4: {2, 4}
            // For 5: {5}
            // For 6: {2, 3, 6}
            // Count for 2: 2 (from 4, 6)
            // Count for 3: 1 (from 6)
            // Count for 4: 1 (from 4)
            // Count for 5: 1 (from 5)
            // Count for 6: 1 (from 6)
            // Here, 2 is the answer.
            std::cout << 2 << std::endl;
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one and has_neg_one for elements to the left
        // This is crucial: an element a[i] can only be used to modify a[j] where j > i.
        // So, when we are checking a[i], the values of a[k] for k < i are fixed
        // and their presence (1 or -1) determines what operations are possible for a[i].
        // The current a[i] value (which is a[i] from the input) is what matters for future operations.
        // The problem states "Add a_i to a_j". This means the original a_i value.
        // However, the example implies that a_i can be changed.
        // "In the first test-case we can choose (i, j)=(2, 3) twice and after that choose (i, j)=(1, 2) twice too.
        // These operations will transform [1, -1, 0] -> [1, -1, -2] -> [1, 1, -2]"
        // Here, a_2 (which is -1) is added to a_3. Then a_1 (which is 1) is added to a_2.
        // This means a_i itself is not changed by operations where it is the source.
        // It can only be changed if it is the destination.
        // The problem statement "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // This implies that a_i is the original value.
        // The example "transform [1, -1, 0] -> [1, -1, -2] -> [1, 1, -2]"
        // Step 1: (2,3) twice. a_3 = a_3 + 2*a_2 = 0 + 2*(-1) = -2. Array becomes [1, -1, -2].
        // Step 2: (1,2) twice. a_2 = a_2 + 2*a_1 = -1 + 2*(1) = 1. Array becomes [1, 1, -2].
        // This confirms that a_i (the source) is its original value.
        // So, the `has_pos_one` and `has_neg_one` flags should be based on the original `a` array.
        // The loop should iterate from left to right, or the flags should be precomputed for the entire array.
        // Let's re-evaluate.
        // If we iterate from right to left, for a[i], we need to know if there's a 1 or -1 at an index k < i.
        // This means `has_pos_one` and `has_neg_one` should track elements in `a[0...i-1]`.

        // The current logic for `has_pos_one` and `has_neg_one` is for the entire array `a`.
        // This is incorrect. For `a[i]` to be modified, it must be `a_j` in the operation `a_j = a_j + a_k` where `k < j`.
        // So, for `a[i]` to be modified, we need `a_k` where `k < i`.
        // The flags `has_pos_one` and `has_neg_one` should reflect the presence of 1s and -1s in `a[0...i-1]`.
    }

    // Let's restart the logic with correct understanding of flags.
    // We need to check each b[i] against a[i].
    // For a[i] to become b[i], we can add a_k to a_i for any k < i.
    // So, for each i, we need to know if there's a 1 or -1 in a[0...i-1].

    has_pos_one = false;
    has_neg_one = false;
    possible = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // If a[i] is 1 or -1, it contributes to future has_pos_one/has_neg_one
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
            continue;
        }

        // If a[i] != b[i], we need to modify a[i].
        // This modification must come from a[k] where k < i.
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // No 1 available from a[0...i-1]
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) { // No -1 available from a[0...i-1]
                possible = false;
                break;
            }
        }

        // After checking, update flags for the next iteration (i+1)
        // The original a[i] value is what matters for future operations (a[i] as source).
        // But for the flags, we are interested in what values are available as sources for a[j] where j > i.
        // So, a[i] itself contributes to the flags for elements a[i+1], a[i+2], ...
        if (a[i] == 1) has_pos_one = true;
        if (a[i] == -1) has_neg_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

