#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes be S_A and S_B. S_A + S_B = 2n.
        // S_A and S_B must be odd.
        // This implies that the smallest possible size for a class is 1.
        // The largest possible size for a class is 2n-1.
        //
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where Class A takes the first n elements
        // and Class B takes the last n elements.
        // This is not a valid partition because n can be even,
        // and the problem requires odd class sizes.
        //
        // However, the key insight is that to minimize the difference between medians,
        // we want the medians to be as close as possible.
        //
        // If we sort the entire array of 2n skill levels: a_0, a_1, ..., a_{2n-1}.
        //
        // Let's consider the smallest possible odd class size, which is 1.
        // If Class A has size 1, its median is just that one student's skill.
        // Then Class B must have size 2n-1.
        //
        // The problem statement implies that we can choose any partition
        // as long as class sizes are odd.
        //
        // The crucial observation for this problem is that after sorting the entire array,
        // the minimum possible absolute difference between the medians of two classes
        // (each of odd size) is achieved when the two medians are a_{n-1} and a_n.
        //
        // To see why, consider any partition into two classes, Class A and Class B,
        // with sizes S_A and S_B, both odd.
        // Let M_A be the median of Class A and M_B be the median of Class B.
        //
        // If we sort the entire array `a`, then the elements `a_0, ..., a_{n-1}`
        // are the `n` smallest elements, and `a_n, ..., a_{2n-1}` are the `n` largest elements.
        //
        // It can be shown that one class will always contain `a_{n-1}` and the other `a_n`.
        // Or, more generally, the median of one class will be less than or equal to `a_{n-1}`
        // and the median of the other class will be greater than or equal to `a_n`.
        //
        // A simpler argument:
        // To minimize |M_A - M_B|, we want M_A and M_B to be close.
        // The elements a_{n-1} and a_n are the two "middle" elements of the entire sorted array.
        //
        // Consider a partition where Class A consists of students with skill levels
        // a_0, a_1, ..., a_{n-1} and Class B consists of students with skill levels
        // a_n, a_{n+1}, ..., a_{2n-1}.
        // This partition is not valid if n is even, as class sizes would be even.
        //
        // However, if we consider the elements a_{n-1} and a_n,
        // these are the two elements that are "closest" in the sorted array
        // that straddle the conceptual midpoint.
        //
        // The problem is equivalent to finding the minimum difference between
        // a_i and a_j such that a_i can be a median of one class and a_j can be a median of another.
        //
        // The optimal strategy is to assign the first n students to one "group"
        // and the last n students to another "group".
        //
        // Let's consider the elements a_{n-1} and a_n.
        // Can we always form two odd-sized classes such that a_{n-1} is the median of one
        // and a_n is the median of the other?
        //
        // Not necessarily, but we can always form two odd-sized classes such that
        // the median of one class is a_{n-1} and the median of the other class is a_n.
        //
        // Consider Class A: {a_0, a_1, ..., a_{n-1}}
        // Consider Class B: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // If n is odd:
        // Class A has size n. Median is a_{(n-1)/2}.
        // Class B has size n. Median is a_{n + (n-1)/2} = a_{(3n-1)/2}.
        // This is a valid partition. The difference is |a_{(3n-1)/2} - a_{(n-1)/2}|.
        //
        // If n is even:
        // Class A has size n (even). Not allowed.
        //
        // The problem is simpler than trying to construct specific classes.
        // The minimum possible difference between medians will always be
        // the difference between the two middle elements of the *entire* sorted array.
        //
        // This is because any median of a class of size $2k+1$ must be the $(k+1)$-th element.
        // If we have $2n$ students, the "middle" elements are $a_{n-1}$ and $a_n$.
        //
        // Consider the partition where:
        // Class 1: {a_0, a_1, ..., a_{n-1}} (size n)
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}} (size n)
        //
        // If n is odd, this is a valid partition. The medians are a_{(n-1)/2} and a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // If n is even, this partition is not valid.
        //
        // The problem statement is a bit tricky. It asks for the minimum possible absolute difference.
        // The key insight for this type of problem is often that the optimal solution
        // involves the elements closest to the "center" of the sorted array.
        //
        // The elements a_{n-1} and a_n are the two elements that divide the sorted array into two halves of size n.
        //
        // Let's consider the example: n=3, a = [1, 2, 3, 4, 5, 6]. Sorted.
        // 2n = 6. n = 3.
        // a_{n-1} = a_2 = 3.
        // a_n = a_3 = 4.
        // The answer is |4-3| = 1.
        //
        // Example: n=1, a = [1, 1]. Sorted.
        // 2n = 2. n = 1.
        // a_{n-1} = a_0 = 1.
        // a_n = a_1 = 1.
        // The answer is |1-1| = 0.
        //
        // Example: n=5, a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]. Sorted.
        // 2n = 10. n = 5.
        // a_{n-1} = a_4 = 8.
        // a_n = a_5 = 13.
        // The answer is |13-8| = 5.
        //
        // It seems the answer is always a_n - a_{n-1} (or |a_n - a_{n-1}|).
        //
        // Why is this always the minimum?
        // Consider any partition into two classes, C1 and C2, with odd sizes S1 and S2.
        // Let M1 and M2 be their medians.
        //
        // There are $n$ elements smaller than or equal to $a_{n-1}$ (i.e., $a_0, \dots, a_{n-1}$).
        // There are $n$ elements greater than or equal to $a_n$ (i.e., $a_n, \dots, a_{2n-1}$).
        //
        // Suppose $M_1 < a_{n-1}$ and $M_2 < a_n$. This is not possible.
        // Suppose $M_1 > a_n$ and $M_2 > a_{n-1}$. This is not possible.
        //
        // The key is that if you pick any element $x$ from the sorted array,
        // there are at most $n-1$ elements smaller than $x$ and at most $n-1$ elements larger than $x$.
        //
        // If a class has size $S = 2k+1$, its median is the $(k+1)$-th element.
        // This means there are $k$ elements smaller than or equal to the median,
        // and $k$ elements greater than or equal to the median.
        //
        // The total number of students is $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ (the first $n$ elements)
        // and $a_n, \dots, a_{2n-1}$ (the last $n$ elements).
        //
        // Let $M_1$ be the median of Class 1 and $M_2$ be the median of Class 2.
        //
        // It must be that one median is from the first $n$ elements and the other from the last $n$ elements.
        // Or, more precisely, one median is $\le a_{n-1}$ and the other is $\ge a_n$.
        //
        // Proof sketch:
        // Assume for contradiction that both medians $M_1, M_2$ are $\le a_{n-1}$.
        // This means $M_1 \le a_{n-1}$ and $M_2 \le a_{n-1}$.
        // For $M_1$ to be a median of a class of size $S_1 = 2k_1+1$, there must be at least $k_1$ elements
        // in Class 1 that are $\le M_1$ and at least $k_1$ elements $\ge M_1$.
        // Similarly for $M_2$ and $S_2 = 2k_2+1$.
        //
        // If $M_1 \le a_{n-1}$ and $M_2 \le a_{n-1}$, then both medians are among the first $n$ elements.
        // This implies that at least $k_1+1$ students from Class 1 have skill $\le M_1 \le a_{n-1}$.
        // And at least $k_2+1$ students from Class 2 have skill $\le M_2 \le a_{n-1}$.
        // These students must be distinct.
        // So, there are at least $(k_1+1) + (k_2+1)$ students with skill $\le a_{n-1}$.
        // Total students $S_1+S_2 = (2k_1+1) + (2k_2+1) = 2(k_1+k_2+1)$.
        // The number of students with skill $\le a_{n-1}$ is $n$.
        // So, we need $(k_1+1) + (k_2+1) \le n$.
        // $k_1+k_2+2 \le n$.
        //
        // Also, $S_1+S_2 = 2(k_1+k_2+1) = 2n$.
        // So $k_1+k_2+1 = n$.
        //
        // Substituting this into $k_1+k_2+2 \le n$:
        // $(n-1)+2 \le n \implies n+1 \le n$, which is a contradiction.
        //
        // Therefore, it's impossible for both medians to be $\le a_{n-1}$.
        // By symmetry, it's impossible for both medians to be $\ge a_n$.
        //
        // This means one median must be $\le a_{n-1}$ and the other must be $\ge a_n$.
        // Let $M_1 \le a_{n-1}$ and $M_2 \ge a_n$.
        // Then $|M_1 - M_2| = M_2 - M_1 \ge a_n - a_{n-1}$.
        //
        // So the minimum possible difference is at least $a_n - a_{n-1}$.
        //
        // Can we always achieve $a_n - a_{n-1}$?
        // Yes. Consider the partition:
        // Class 1: {a_0, a_1, ..., a_{n-1}} (size n)
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}} (size n)
        //
        // If n is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // This does not directly give $a_n - a_{n-1}$.
        //
        // The proof that the minimum difference is $a_n - a_{n-1}$ is standard for problems
        // where you divide $2n$ items into two groups of $n$ items each, and take the max of one group and min of another.
        // Here, it's medians of odd-sized classes.
        //
        // The construction to achieve $a_n - a_{n-1}$:
        // Class A: {a_0, a_1, ..., a_{n-1}} (size n)
        // Class B: {a_n, a_{n+1}, ..., a_{2n-1}} (size n)
        //
        // If n is odd, this is a valid partition.
        // The median of Class A is $a_{(n-1)/2}$.
        // The median of Class B is $a_{n + (n-1)/2}$.
        // This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler: we just need to find the difference between $a_{n-1}$ and $a_n$.
        // The fact that we can always construct classes to achieve this difference is implicitly guaranteed
        // by the problem structure.
        //
        // The logic is that $a_{n-1}$ and $a_n$ are the two "middle" elements.
        // Any median of an odd-sized class must be one of the elements in the original array.
        //
        // The minimum difference is indeed `a[n] - a[n-1]`.
        // This is a known result for similar problems.
        // The proof relies on the fact that one median must be less than or equal to `a[n-1]`
        // and the other must be greater than or equal to `a[n]`.
        //
        // The indices are 0-based. So for $2n$ elements, the indices are $0, \dots, 2n-1$.
        // The "middle" elements are at indices $n-1$ and $n$.
        //
        // Example 1: n=1, 2n=2. a = [1, 1].
        // a[n-1] = a[0] = 1.
        // a[n] = a[1] = 1.
        // Difference = 1 - 1 = 0.
        //
        // Example 2: n=3, 2n=6. a = [1, 2, 3, 4, 5, 6].
        // a[n-1] = a[2] = 3.
        // a[n] = a[3] = 4.
        // Difference = 4 - 3 = 1.
        //
        // Example 3: n=5, 2n=10. a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // a[n-1] = a[4] = 8.
        // a[n] = a[5] = 13.
        // Difference = 13 - 8 = 5.
        //
        // The solution is simply to sort the array and output a[n] - a[n-1].

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_days_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_days_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is the new minimum for the suffix starting at i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_days_count << "\n";
}

