#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But as a safety check
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number x such that x < q_i and x is not yet used.
            // To maximize chances, pick the smallest available number.
            int current_val = 1;
            while (current_val < q[i] && used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // No available number less than q_i
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

