#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int current_state = 0; // 0: a[i]==b[i], 1: a[i]!=b[i] and a[i+1]!=b[i+1]
                           //    and a[i]!=a[i+1] (i.e., a[i]=b[i+1] and a[i+1]=b[i])

    for (int i = 0; i < n; ++i) {
        if (current_state == 1) {
            // We were in a state where a[i-1] and a[i] were candidates for a swap.
            // This means a[i-1] != b[i-1] and a[i] != b[i] and a[i-1] != a[i].
            // We already processed this pair, so we just continue.
            current_state = 0; // Reset state for the next iteration
            continue;
        }

        if (a[i] != b[i]) {
            // Mismatch at current position i
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Mismatch at i+1 AND a[i] and a[i+1] are different
                // This implies a[i] == b[i+1] and a[i+1] == b[i]
                // We can swap a[i] and a[i+1] with cost 1.
                total_cost += 1;
                current_state = 1; // Mark that we've used a[i+1] for a swap
            } else {
                // Mismatch at i, but cannot perform a cheap swap with i+1
                // (either i+1 is out of bounds, or a[i+1] == b[i+1], or a[i] == a[i+1])
                // In this case, we must flip a[i]. Cost 1.
                total_cost += 1;
                current_state = 0; // No special state for next iteration
            }
        } else {
            // Match at current position i
            current_state = 0; // No special state for next iteration
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

