// Function to determine if a box can be the special box
// Parameters:
// A, B, C, D: initial counts of toys in boxes 1, 2, 3, 4
// target_box_idx: 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4
//
// The logic is based on analyzing the parity of negative numbers and the
// possibility of achieving certain magnitude ranges.
//
// Box 1: (-inf, -1] (negative, magnitude >= 1)
// Box 2: (-1, 0) (negative, magnitude < 1)
// Box 3: (0, 1) (positive, magnitude < 1)
// Box 4: [1, inf) (positive, magnitude >= 1)
bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;

    // If there's only one toy, it's the super toy.
    // The special box is simply the box that toy was in.
    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // Case 1: All toys are positive (A=0, B=0)
    // The final product will always be positive.
    // So, Box 1 and Box 2 are impossible.
    if (A == 0 && B == 0) {
        if (target_box_idx == 0 || target_box_idx == 1) return false; // Cannot be negative

        // If all toys are positive, the product is positive.
        // We need to check if it can be < 1 (Box 3) or >= 1 (Box 4).
        //
        // Can it be Box 3 (0, 1)?
        // Yes, if there's at least one toy in Box 3 (0, 1).
        // If C > 0, we can multiply all other toys by a very small number from Box 3.
        // E.g., (0.1 * 10 * 10) = 10 (not < 1)
        // E.g., (0.1 * 0.1 * 10) = 0.1 (can be < 1)
        // If C > 0, we can always make the product < 1.
        // Example: take a toy from C (e.g., 0.1). Multiply all other toys (C-1, D) to get P_rest.
        // If P_rest is large, 0.1 * P_rest might be large.
        // However, we can always pick a toy from C (e.g., 0.0001) and multiply it last.
        // If C > 0, we can always make the product arbitrarily small (but > 0).
        // So, if C > 0, Box 3 is possible.
        //
        // Can it be Box 4 [1, inf)?
        // Yes, if there's at least one toy in Box 4 (>= 1).
        // If D > 0, we can always make the product >= 1.
        // Example: take a toy from D (e.g., 10). Multiply all other toys (C, D-1) to get P_rest.
        // If P_rest is small, 10 * P_rest might be small.
        // However, if D > 0, we can always make the product arbitrarily large.
        // So, if D > 0, Box 4 is possible.
        //
        // What if C=0 and D=0? This case is covered by total_toys == 1.
        // What if C > 0 and D = 0? All toys are in Box 3. Product will be < 1. Only Box 3 possible.
        // What if C = 0 and D > 0? All toys are in Box 4. Product will be >= 1. Only Box 4 possible.
        // What if C > 0 and D > 0? Both Box 3 and Box 4 are possible.
        //
        // Simplified:
        // If C > 0, Box 3 is possible.
        // If D > 0, Box 4 is possible.
        // If C=0 and D=0, this means total_toys=0, but problem states total_toys > 0.
        // So if A=0, B=0, then C+D > 0.

        if (target_box_idx == 2) { // Box 3 (0, 1)
            return C > 0;
        }
        if (target_box_idx == 3) { // Box 4 [1, inf)
            return D > 0;
        }
    }

    // Case 2: All toys are negative (C=0, D=0)
    // The final product's sign depends on the parity of total_toys.
    // If total_toys is even, product is positive. Box 1 and Box 2 impossible.
    // If total_toys is odd, product is negative. Box 3 and Box 4 impossible.
    if (C == 0 && D == 0) {
        if (total_toys % 2 == 0) { // Even number of negative toys -> positive product
            if (target_box_idx == 0 || target_box_idx == 1) return false; // Cannot be negative
            // Can it be Box 3 (0, 1)? Yes, if B > 0.
            // Can it be Box 4 [1, inf)? Yes, if A > 0.
            // If A=0, B>0, all toys in Box 2. Product will be < 1. Only Box 3 possible.
            // If A>0, B=0, all toys in Box 1. Product will be >= 1. Only Box 4 possible.
            // If A>0, B>0, both Box 3 and Box 4 are possible.
            if (target_box_idx == 2) return B > 0;
            if (target_box_idx == 3) return A > 0;
        } else { // Odd number of negative toys -> negative product
            if (target_box_idx == 2 || target_box_idx == 3) return false; // Cannot be positive
            // Can it be Box 1 (-inf, -1]? Yes, if A > 0.
            // Can it be Box 2 (-1, 0)? Yes, if B > 0.
            // If A=0, B>0, all toys in Box 2. Product will be > -1. Only Box 2 possible.
            // If A>0, B=0, all toys in Box 1. Product will be < -1. Only Box 1 possible.
            // If A>0, B>0, both Box 1 and Box 2 are possible.
            if (target_box_idx == 0) return A > 0;
            if (target_box_idx == 1) return B > 0;
        }
    }

    // Case 3: Mixed signs (A+B > 0 and C+D > 0)
    //
    // Sign analysis:
    // The final product's sign depends on the parity of the initial negative toys (A+B).
    // If (A+B) is even, the product can be positive.
    // If (A+B) is odd, the product can be negative.
    //
    // However, we can manipulate the sign.
    // If we have at least one positive toy (C+D > 0) and at least one negative toy (A+B > 0),
    // we can always make the final product positive OR negative.
    //
    // How to make it positive:
    // If (A+B) is even, the product is naturally positive.
    // If (A+B) is odd, we need to introduce an odd number of negative products.
    // This is always possible if A+B > 0 and C+D > 0.
    // Example: (-2, -0.5, 0.5, 2) -> A=1, B=1, C=1, D=1. A+B=2 (even).
    // (-2 * -0.5) * (0.5 * 2) = 1 * 1 = 1 (positive)
    // (-2 * 0.5) * (-0.5 * 2) = -1 * -1 = 1 (positive)
    //
    // The key insight is that if you have at least one negative toy and at least one positive toy,
    // you can always choose the order of operations to make the final product positive or negative.
    // To make it positive: Pair up all negative numbers. If there's an odd number of negative numbers,
    // multiply the last negative number with a positive number. This will result in a negative intermediate.
    // Then, multiply this negative intermediate with another negative number (if available) or
    // with a positive number (if available).
    //
    // A simpler way to think about sign:
    // If A+B > 0 and C+D > 0:
    //   - If (A+B) is even: The product can be positive.
    //   - If (A+B) is odd: The product can be negative.
    //
    //   However, if we have at least one toy in Box 1 or Box 2 (negative) AND at least one toy in Box 3 or Box 4 (positive),
    //   we can always achieve both positive and negative results.
    //   Example: A=1, B=0, C=1, D=0. Toys: {-2, 0.5}. Product: -1. (Negative)
    //   Example: A=1, B=0, C=0, D=1. Toys: {-2, 2}. Product: -4. (Negative)
    //   Example: A=0, B=1, C=1, D=0. Toys: {-0.5, 0.5}. Product: -0.25. (Negative)
    //   Example: A=0, B=1, C=0, D=1. Toys: {-0.5, 2}. Product: -1. (Negative)
    //
    //   What if we have multiple toys?
    //   A=1, B=1, C=0, D=1. Toys: {-2, -0.5, 2}. A+B=2 (even).
    //   (-2 * -0.5) * 2 = 1 * 2 = 2 (positive)
    //   (-2 * 2) * -0.5 = -4 * -0.5 = 2 (positive)
    //
    //   A=1, B=0, C=1, D=1. Toys: {-2, 0.5, 2}. A+B=1 (odd).
    //   (-2 * 0.5) * 2 = -1 * 2 = -2 (negative)
    //   (-2 * 2) * 0.5 = -4 * 0.5 = -2 (negative)
    //
    //   It seems the sign is fixed by the parity of A+B if there are no zeros.
    //   The problem states "randomly", so we can't choose the order.
    //   The problem states "you don't see the sequence of Chaneka's sewing".
    //   "Determine which boxes *can be* the special box". This implies we need to find if *any* sequence of operations leads to that box.
    //   So, we *can* choose the order.
    //
    //   If A+B > 0 and C+D > 0:
    //   To get a positive result:
    //     If A+B is even, it's naturally positive.
    //     If A+B is odd: We need to make one negative toy effectively positive.
    //       This can be done by multiplying a negative toy with another negative toy (if A+B >= 2).
    //       Or, if A+B=1, we can't make it positive.
    //       Wait, if A+B is odd, and we want a positive result, we need to multiply one negative toy with a positive toy.
    //       This will result in a negative intermediate. Then we need to multiply this negative intermediate with another negative toy.
    //       This is only possible if we have at least two negative toys (A+B >= 2).
    //       If A+B = 1 (e.g., A=1, B=0, C=1, D=1. Toys: {-2, 0.5, 2}).
    //       (-2 * 0.5) * 2 = -1 * 2 = -2 (negative)
    //       (-2 * 2) * 0.5 = -4 * 0.5 = -2 (negative)
    //       In this case, the result is always negative.
    //
    //   So, if A+B > 0 and C+D > 0:
    //   - If A+B is odd: The final product is always negative. (Box 3, Box 4 impossible)
    //   - If A+B is even: The final product is always positive. (Box 1, Box 2 impossible)
    //
    //   This is incorrect. The example shows:
    //   1 2 0 1 -> A=1, B=2, C=0, D=1. A+B=3 (odd).
    //   Output: Ya Ya Tidak Tidak. This means Box 1 and Box 2 are possible.
    //   This implies the product can be negative.
    //   The example also shows:
    //   Scenario 1: (-3, -0.5, -0.5, 3) -> (-0.5 * -0.5) = 0.25 (C). Then (-3 * 0.25) = -0.75 (B). Then (-0.75 * 3) = -2.25 (A).
    //   Scenario 2: (-3, -0.33, -0.25, 3) -> (-3 * -0.33) = 0.99 (C). Then (0.99 * 3) = 2.97 (D). Then (2.97 * -0.25) = -0.7425 (B).
    //
    //   This means the sign can be manipulated.
    //   If A+B > 0 and C+D > 0:
    //   - Can it be positive? Yes. (e.g., multiply all negative numbers together first, then multiply by positives)
    //   - Can it be negative? Yes. (e.g., multiply one negative number by a positive number, then multiply by others)
    //   So, if A+B > 0 and C+D > 0, all four boxes are potentially possible regarding sign.
    //   We just need to check magnitude.
    //
    //   Magnitude analysis for A+B > 0 and C+D > 0:
    //   Can it be Box 1 (-inf, -1]? (Negative, magnitude >= 1)
    //     Requires: A+B > 0 and C+D > 0 (for sign manipulation)
    //     And: (A > 0 or D > 0) (to get magnitude >= 1)
    //     If A=0, D=0, then all initial toys are in B or C. Product of B and C toys will always have magnitude < 1.
    //     So, if A=0 and D=0, Box 1 and Box 4 are impossible.
    //     If A > 0 or D > 0, we can achieve magnitude >= 1.
    //     So, Box 1 is possible if (A+B > 0 and C+D > 0) AND (A > 0 or D > 0).
    //
    //   Can it be Box 2 (-1, 0)? (Negative, magnitude < 1)
    //     Requires: A+B > 0 and C+D > 0 (for sign manipulation)
    //     And: (B > 0 or C > 0) (to get magnitude < 1)
    //     If B=0, C=0, then all initial toys are in A or D. Product of A and D toys will always have magnitude >= 1.
    //     So, if B=0 and C=0, Box 2 and Box 3 are impossible.
    //     If B > 0 or C > 0, we can achieve magnitude < 1.
    //     So, Box 2 is possible if (A+B > 0 and C+D > 0) AND (B > 0 or C > 0).
    //
    //   Can it be Box 3 (0, 1)? (Positive, magnitude < 1)
    //     Requires: A+B > 0 and C+D > 0 (for sign manipulation)
    //     And: (B > 0 or C > 0) (to get magnitude < 1)
    //     So, Box 3 is possible if (A+B > 0 and C+D > 0) AND (B > 0 or C > 0).
    //
    //   Can it be Box 4 [1, inf)? (Positive, magnitude >= 1)
    //     Requires: A+B > 0 and C+D > 0 (for sign manipulation)
    //     And: (A > 0 or D > 0) (to get magnitude >= 1)
    //     So, Box 4 is possible if (A+B > 0 and C+D > 0) AND (A > 0 or D > 0).

    // Refined logic for A+B > 0 and C+D > 0 (mixed signs)
    // All four boxes are possible if there's at least one toy that can make the magnitude >= 1 (A or D)
    // AND at least one toy that can make the magnitude < 1 (B or C).
    // If (A > 0 or D > 0) and (B > 0 or C > 0): All 4 boxes are possible.
    //
    // If (A > 0 or D > 0) and (B == 0 and C == 0):
    //   All toys are in Box 1 or Box 4. All magnitudes are >= 1.
    //   The product will always have magnitude >= 1.
    //   Since A+B > 0 and C+D > 0, we can achieve both positive and negative signs.
    //   So, Box 1 and Box 4 are possible. Box 2 and Box 3 are impossible.
    //
    // If (A == 0 and D == 0) and (B > 0 or C > 0):
    //   All toys are in Box 2 or Box 3. All magnitudes are < 1.
    //   The product will always have magnitude < 1.
    //   Since A+B > 0 and C+D > 0, we can achieve both positive and negative signs.
    //   So, Box 2 and Box 3 are possible. Box 1 and Box 4 are impossible.

    bool can_be_positive = (A + B) % 2 == 0; // Initial parity of negative numbers
    bool can_be_negative = (A + B) % 2 != 0;

    // If there are both negative and positive toys, we can manipulate the sign.
    // Example: {-2, 0.5, 2}. A=1, C=1, D=1. A+B=1 (odd).
    // (-2 * 0.5) * 2 = -1 * 2 = -2 (negative)
    // (-2 * 2) * 0.5 = -4 * 0.5 = -2 (negative)
    //
    // Example: {-2, -0.5, 2}. A=1, B=1, D=1. A+B=2 (even).
    // (-2 * -0.5) * 2 = 1 * 2 = 2 (positive)
    // (-2 * 2) * -0.5 = -4 * -0.5 = 2 (positive)
    //
    // The example 1 2 0 1 (A=1, B=2, C=0, D=1) has A+B=3 (odd).
    // Output: Ya Ya Tidak Tidak. This means only negative results are possible.
    // This implies that if A+B > 0 and C+D > 0, the final sign is determined by (A+B) % 2.
    // This is because "randomly" implies we cannot choose the order to change the sign.
    // The problem statement "you don't see the sequence of Chaneka's sewing" and "Determine which boxes *can be* the special box"
    // usually implies we need to consider all possible sequences.
    // However, the example output contradicts this interpretation for sign manipulation.
    //
    // Let's re-evaluate based on the example:
    // Case 1: 1 2 0 1 (A=1, B=2, C=0, D=1). A+B=3 (odd). C+D=1 (positive toys exist).
    // Output: Ya Ya Tidak Tidak.
    // This means only negative results are possible.
    // So, if A+B > 0 and C+D > 0, the sign is fixed by (A+B) % 2.
    //
    // Case 2: 0 1 0 0 (A=0, B=1, C=0, D=0). A+B=1 (odd). C+D=0 (no positive toys).
    // Output: Tidak Ya Tidak Tidak.
    // This means only negative results are possible, and only Box 2.
    // This is consistent with the "all negative toys" logic.

    // So, the sign is determined by (A+B) % 2.
    // If (A+B) is odd, the product is negative.
    // If (A+B) is even, the product is positive.

    bool final_product_is_negative = ((A + B) % 2 != 0);
    bool final_product_is_positive = ((A + B) % 2 == 0);

    // Check for Box 1 (negative, magnitude >= 1)
    if (target_box_idx == 0) {
        if (!final_product_is_negative) return false; // Must be negative
        // Magnitude >= 1 requires at least one toy from Box 1 or Box 4.
        // If all toys are from Box 2 or Box 3, magnitude will be < 1.
        return (A > 0 || D > 0);
    }
    // Check for Box 2 (negative, magnitude < 1)
    else if (target_box_idx == 1) {
        if (!final_product_is_negative) return false; // Must be negative
        // Magnitude < 1 requires at least one toy from Box 2 or Box 3.
        // If all toys are from Box 1 or Box 4, magnitude will be >= 1.
        return (B > 0 || C > 0);
    }
    // Check for Box 3 (positive, magnitude < 1)
    else if (target_box_idx == 2) {
        if (!final_product_is_positive) return false; // Must be positive
        // Magnitude < 1 requires at least one toy from Box 2 or Box 3.
        return (B > 0 || C > 0);
    }
    // Check for Box 4 (positive, magnitude >= 1)
    else if (target_box_idx == 3) {
        if (!final_product_is_positive) return false; // Must be positive
        // Magnitude >= 1 requires at least one toy from Box 1 or Box 4.
        return (A > 0 || D > 0);
    }

    return false; // Should not reach here
}

