}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it for subsequent checks

    // 2. Ensure elements to the left of median are <= s
    // These elements are at indices 0 to median_idx-1
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // No need to actually change, just count cost
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These elements are at indices median_idx+1 to n-1
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // No need to actually change, just count cost
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile 'i', we can add 'min_val' to it
        // as many times as possible without exceeding 'k'.
        // The current value of pile 'i' is a[i].
        // We want to find max_x such that a[i] + x * min_val <= k.
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, x = floor((k - a[i]) / min_val)
        if (a[i] < k) { // Only if there's room to add
            operations += (k - a[i]) / min_val;
        }
    }
    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

