                            // If we form `k` ones, we use `k` 'o's, `k` 'n's, `k` 'e's.
                            // The remaining letters will be used for zeros.
                            // The number of 'n's directly determines the number of '1's because 'n' is only used in "one".

    // Count how many '0's can be formed
    // Each "zero" requires one 'z', one 'e', one 'r', one 'o'.
    // The number of 'z's directly determines the number of '0's because 'z' is only used in "zero".
    int num_zeros = count_z;

    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // This implies that the counts of 'o', 'e', 'r' will be consistent with `num_ones` and `num_zeros`.
    // For example, total 'o's needed = num_ones + num_zeros.
    // total 'e's needed = num_ones + num_zeros.
    // total 'r's needed = num_zeros.
    // total 'n's needed = num_ones.
    // total 'z's needed = num_zeros.
    // Since we want to maximize the number, we prioritize '1's.
    // The number of 'n's directly gives us the number of '1's.
    // The number of 'z's directly gives us the number of '0's.

    // Print all '1's first
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    // Then print all '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b.begin(), b.end(), std::greater<long long>());

    // Create pairs (F(A_i, B_j), original_index_of_A_i)
    // F(n, k) = n / (k+1)
    // We want to maximize sum(A'_i / (B_i + 1))
    // To do this, we pair the largest A_i with the smallest (B_i + 1)
    // which means largest A_i with smallest B_i.
    // Since B is sorted descending, b[0] is largest, b[m-1] is smallest.
    // So we pair a_elements[0] (smallest A) with b[m-1] (smallest B)
    // a_elements[1] with b[m-2], ..., a_elements[m-1] with b[0].
    // This is equivalent to pairing sorted A (ascending) with sorted B (ascending).
    // Or sorted A (ascending) with sorted B (descending) but then reversing the B indices.

    // Let's re-evaluate the pairing.
    // We have A_1 <= A_2 <= ... <= A_m
    // We have B_1 >= B_2 >= ... >= B_m
    // We want to maximize sum(A'_i / (B_i + 1)).
    // This is a rearrangement inequality problem.
    // To maximize sum(x_i * y_i), if x is sorted ascending, y should be sorted ascending.
    // Here, we have A_i and 1/(B_i + 1).
    // A_i is sorted ascending.
    // 1/(B_i + 1) should be sorted ascending.
    // Since B_i is sorted descending, B_i + 1 is sorted descending.
    // Therefore, 1/(B_i + 1) is sorted ascending.
    // So, we should pair A_i (sorted ascending) with 1/(B_i + 1) (sorted ascending).
    // This means a_elements[0] (smallest A) should be paired with b[m-1] (smallest B, largest 1/(B+1)).
    // a_elements[1] with b[m-2], and so on.
    // a_elements[i] should be paired with b[m-1-i].

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        result[a_elements[i].original_index] = a_elements[i].value;
    }

    // The problem asks to output A' which is a permutation of A.
    // The pairing logic is:
    // The smallest A value should be assigned to the B value that makes its F value largest.
    // F(A, B) = A / (B+1).
    // To maximize sum(A'_i / (B_i + 1)), we should pair the largest A_j with the largest 1/(B_k + 1).
    // Largest 1/(B_k + 1) corresponds to smallest B_k.
    // So, sort A ascending: A_1 <= A_2 <= ... <= A_m
    // Sort B ascending: B_1 <= B_2 <= ... <= B_m
    // Then pair A_i with B_i.
    // In our code, A is sorted ascending (a_elements).
    // B is sorted descending.
    // So, a_elements[0] (smallest A) should be paired with b[m-1] (smallest B).
    // a_elements[1] should be paired with b[m-2].
    // ...
    // a_elements[i] should be paired with b[m-1-i].
    // The output array A' should have its elements at positions corresponding to the original B array.
    // The problem asks for A'_1, A'_2, ..., A'_m such that sum F(A'_i, B_i) is maximized.
    // This means we need to find a permutation P of {1, ..., m} such that sum F(A_{P_i}, B_i) is maximized.
    // Let A_sorted be the sorted version of A.
    // Let B_sorted be the sorted version of B.
    // To maximize sum(A_sorted[i] / (B_sorted[i] + 1)), we sort A ascending and B ascending.
    // Our `a_elements` is sorted ascending.
    // Our `b` is sorted descending.
    // So, we need to pair `a_elements[i]` with `b[m-1-i]`.
    // The `result` array should store the `A'` values at their original `B` positions.
    // The `a_elements[i].original_index` tells us where `a_elements[i].value` came from in the original `A`.
    // We need to output `A'` such that `A'_j` is paired with `B_j`.
    // The `j`-th element of the output array `A'` should be `a_elements[k].value` where `a_elements[k]` is paired with `B_j`.
    // This means we need to know the original index of `B_j` after sorting `B`.
    // This is getting complicated. Let's simplify.

    // We have `m` pairs `(A_i, B_i)`. We want to reorder `A` to `A'` to maximize `sum F(A'_i, B_i)`.
    // This is equivalent to finding a permutation `p` of `A` such that `sum A_p[i] / (B_i + 1)` is maximized.
    // Let `X_i = A_i` and `Y_i = 1 / (B_i + 1)`. We want to maximize `sum X_{p[i]} * Y_i`.
    // By rearrangement inequality, this sum is maximized when `X` and `Y` are sorted in the same order.
    // So, we sort `A` in ascending order.
    // We sort `1/(B_i + 1)` in ascending order. This means sorting `B_i + 1` in descending order, or `B_i` in descending order.
    // Let `A_sorted` be `A` sorted ascending.
    // Let `B_desc` be `B` sorted descending.
    // Then the optimal pairing is `A_sorted[i]` with `B_desc[i]`.
    // The problem asks for the output array `A'`.
    // The `i`-th element of the output `A'` should be the `A` value that is paired with the `i`-th element of the *original* `B` array.

    // Let's store original indices for B as well.
    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        b_elements[i].value = b[i];
        b_elements[i].original_index = i;
    }

    // Sort A ascending
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B descending (to get 1/(B+1) ascending)
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Now, a_elements[i].value should be paired with b_elements[i].value.
    // The result array `ans` will store the final permutation of A.
    // `ans[b_elements[i].original_index]` should be `a_elements[i].value`.
    std::vector<long long> ans(m);
    for (int i = 0; i < m; ++i) {
        ans[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << ans[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins + k == 0) { // All games are L and k=0, or all games are L and k=0. No wins possible.
            std::cout << 0 << "\n";
            continue;
        }

        if (wins + k >= n) { // Can make all games W
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // Find the first and last 'W'
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        // If there are no 'W's initially, we must convert k 'L's to 'W's.
        // The best way is to make them consecutive to maximize score.
        // e.g., LLLLL, k=3 -> WWWLL. Score = 1+2 = 3.
        // If k=0, score is 0.
        // If k>0, score is 2*k-1.
        if (first_w == -1) { // No 'W's initially
            std::cout << 2 * k - 1 << "\n";
            continue;
        }

        // Collect lengths of 'L' segments between 'W's
        std::vector<int> gap_lengths;
        int current_gap = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        int current_k = k;
        int score_increase_from_gaps = 0;
        for (int gap_len : gap_lengths) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                score_increase_from_gaps += (2 * gap_len + 1); // Each L becomes W, connects two Ws, adds 2*L_len + 1 points
            } else {
                break;
            }
        }

        // Calculate total score after filling gaps
        int final_score = initial_score + score_increase_from_gaps;

        // Remaining k can be used to convert 'L's at the ends
        // Each 'L' converted at the end (or within a filled gap) adds 2 points if it extends a 'W' block.
        // The number of additional 'W's we can create is current_k.
        final_score += 2 * current_k;

        std::cout << final_score << "\n";
    }
    return 0;
}

