#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to 'len' are present exactly once.
// This is equivalent to checking if the maximum element is 'len'
// and all elements are distinct.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
    if (len > arr.size() - start_idx) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // All elements must be present, and max must be len
}

// Optimized check for permutation using prefix/suffix properties
// This function precomputes prefix/suffix permutation validity
// `is_perm[i]` will be true if `arr[0...i-1]` is a permutation of length `i`.
// `is_perm_rev[i]` will be true if `arr[n-i...n-1]` is a permutation of length `i`.
void precompute_permutations(const std::vector<int>& arr, int n, std::vector<bool>& is_perm, std::vector<bool>& is_perm_rev) {
    is_perm.assign(n + 1, false);
    is_perm_rev.assign(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix = 0;
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        int val = arr[i];
        if (val <= 0 || val > n) { // Value out of range for any permutation up to length n
            // If current value is invalid, no further prefix can be a permutation
            break; 
        }
        if (!seen_prefix[val]) {
            seen_prefix[val] = true;
            distinct_count_prefix++;
        } else {
            // Duplicate found, no further prefix can be a permutation
            break;
        }
        if (val > max_prefix) {
            max_prefix = val;
        }
        if (distinct_count_prefix == i + 1 && max_prefix == i + 1) {
            is_perm[i + 1] = true;
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix = 0;
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        int val = arr[i];
        int len = n - i; // Length of current suffix
        if (val <= 0 || val > n) { // Value out of range for any permutation up to length n
            break;
        }
        if (!seen_suffix[val]) {
            seen_suffix[val] = true;
            distinct_count_suffix++;
        } else {
            break;
        }
        if (val > max_suffix) {
            max_suffix = val;
        }
        if (distinct_count_suffix == len && max_suffix == len) {
            is_perm_rev[len] = true;
        }
    }
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::vector<bool> is_perm_prefix;
        std::vector<bool> is_perm_suffix;
        precompute_permutations(a, n, is_perm_prefix, is_perm_suffix);

        std::vector<std::pair<int, int>> results;
        for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1
            int l2 = n - l1;
            if (is_perm_prefix[l1] && is_perm_suffix[l2]) {
                results.push_back({l1, l2});
            }
        }

        std::cout << results.size() << "\n";
        for (const auto& p : results) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1
            } else if ((n / 2) % 2 != 0) { // N is even, N/2 is odd
                // If Chanek takes N/2, remaining N/2 is odd. Opponent takes 1.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // Taking N/2 is better for Chanek.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even, N/2 is even
                // If Chanek takes N/2, remaining N/2 is even. Opponent can take (N/2)/2.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // Taking 1 is better for Chanek.
                chanek_coins += 1;
                n -= 1;
            }
        }
        // Opponent's turn logic (implicitly handled by the optimal choice for Chanek)
        // If n becomes 0, game ends.
        // If n > 0, opponent will take coins.
        // Opponent will always try to maximize their own coins.
        // If n is odd, opponent takes 1. n becomes n-1.
        // If n is even, opponent takes n/2. n becomes n/2.
        // This is because if n/2 is even, opponent takes n/2. If n/2 is odd, opponent takes n/2.
        // The only exception is n=2, opponent takes 1.
        // So, if n > 0 after Chanek's move, opponent will reduce n.
        // If n is odd, opponent takes 1.
        // If n is even, opponent takes n/2.
        // This is equivalent to: if n > 0, n = (n % 2 != 0 || n == 2) ? n - 1 : n / 2;
        if (n > 0) {
            if (n % 2 != 0) { // Opponent's turn, N is odd
                n -= 1;
            } else { // Opponent's turn, N is even
                n /= 2;
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1 get two copies of the largest available numbers.
    // These are the k_one largest numbers from 'a'.
    // Since w is sorted ascending, w[0]...w[k_one-1] will be 1s.
    // We assign a[n-1], a[n-2], ... to these friends.
    // The largest numbers are at the end of sorted 'a'.
    // The friends with w_i = 1 are at the beginning of sorted 'w'.
    int a_ptr = n - 1; // Pointer to the largest available number in 'a'
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr];
            a_ptr--;
        } else {
            // All remaining w_i will be > 1. Break and handle them.
            break;
        }
    }

    // Friends with w_i > 1.
    // They get one largest available number (from a_ptr down) and one smallest available number.
    // The largest available numbers are assigned to be their max_val.
    // The smallest available numbers are assigned to be their min_val.
    // To maximize sum, we pair the largest remaining w_i with the largest remaining a[a_ptr]
    // and the smallest remaining w_i with the smallest remaining a[a_ptr_min].
    // This is handled by iterating w in descending order for max_val,
    // and iterating w in descending order for min_val, using a_ptr_min for min_val.

    int a_ptr_min = 0; // Pointer to the smallest available number in 'a'
    // Iterate w in descending order for friends with w_i > 1
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr]; // Assign largest available as max_val
            a_ptr--;

            // Assign smallest available as min_val
            total_happiness += a[a_ptr_min];
            a_ptr_min += (w[i] - 1); // Skip w[i]-1 smallest numbers for this friend
        } else {
            // All remaining w_i are 1s, which have been handled.
            break;
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

