    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            // We need to append elements b1, b2, ... such that
            // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

            // Let's try to append two elements.
            // Let the first element be X = current_xor_sum.
            // New XOR sum becomes current_xor_sum ^ X = current_xor_sum ^ current_xor_sum = 0.
            // New sum becomes current_sum + X.
            // The condition becomes (current_sum + X) = 2 * 0 = 0.
            // This is generally not true, as current_sum + X > 0.

            // Let's try to append two elements: X and current_sum + X.
            // This is the strategy derived from the problem analysis.
            // Let b1 = current_xor_sum.
            // Let b2 = current_sum + current_xor_sum.
            // New XOR sum: current_xor_sum ^ b1 ^ b2
            //             = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
            //             = 0 ^ (current_sum + current_xor_sum)
            //             = current_sum + current_xor_sum
            // New sum: current_sum + b1 + b2
            //          = current_sum + current_xor_sum + (current_sum + current_xor_sum)
            //          = 2 * (current_sum + current_xor_sum)
            //
            // Check condition: New sum = 2 * New XOR sum
            // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
            // This holds true.

            // So we append two elements: current_xor_sum and current_sum + current_xor_sum.
            // The problem states that we can append at most 3 elements.
            // This strategy uses 2 elements.

            long long b1 = current_xor_sum;
            long long b2 = current_sum + current_xor_sum;

            std::cout << 2 << "\n";
            std::cout << b1 << " " << b2 << "\n";
        }
    }
    return 0;
}

