    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just p[pos[1]], which has min 1, max 1, length 1.
        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'. The element 'm' is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This means its length must be exactly 'm'.
        // The minimum value in this segment is 1 (because current_min_idx covers pos[1]).
        // The maximum value in this segment is m (because current_max_idx covers pos[m]).
        // So, we only need to check if the length is 'm'.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

