#include <vector>
#include <cmath>

// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // This means we need to remove some prime factors from p such that it's no longer divisible by q,
        // but we want to remove as few as possible (or rather, make the resulting number as large as possible).

        // Get prime factors of q
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 0;

        // Iterate through each prime factor of q
        for (const auto& q_factor_pair : q_factors) {
            long long prime_factor = q_factor_pair.first;
            // int q_exponent = q_factor_pair.second; // Not directly used, but conceptually important

            // Calculate the current p_copy to find how many times prime_factor divides p
            long long p_copy = p;
            long long current_prime_power_in_p = 1;
            while (p_copy > 0 && p_copy % prime_factor == 0) {
                p_copy /= prime_factor;
                current_prime_power_in_p *= prime_factor;
            }

            // We need to reduce the power of prime_factor in p such that p is no longer divisible by q.
            // The smallest reduction that breaks divisibility by q for this prime factor
            // is to divide p by prime_factor until its exponent is less than the exponent of prime_factor in q.
            // A simpler way is to just divide p by one more power of prime_factor than it has in q.
            // Or, more generally, divide p by prime_factor until it's no longer divisible by q.
            // The largest x will be p / (prime_factor ^ k) where k is the smallest integer such that
            // (p / (prime_factor ^ k)) % q != 0.
            // This is equivalent to finding the largest divisor of p that has a smaller exponent of `prime_factor`
            // than `q` has, for *this specific prime factor*.

            // Let's find the largest divisor of p that is not divisible by q, considering only this prime_factor.
            // We want to remove just enough prime_factor from p to break its divisibility by q.
            // The number of times prime_factor divides q is q_exponent.
            // The number of times prime_factor divides p is p_exponent.
            // If p_exponent >= q_exponent, we need to reduce p_exponent.
            // The largest x will be p / (prime_factor ^ (p_exponent - q_exponent + 1)).
            // This is equivalent to p / (current_prime_power_in_p / (prime_factor ^ (q_exponent - 1)))
            // Or simply, p / (prime_factor ^ (count_of_prime_factor_in_p - count_of_prime_factor_in_q + 1))
            // A more direct way:
            // We have p. We want to find x = p / (prime_factor ^ k) such that x % q != 0.
            // The smallest k that makes x not divisible by q (for this prime factor) is when
            // the exponent of prime_factor in x is less than its exponent in q.
            // So, we divide p by prime_factor until p is no longer divisible by q.
            // The resulting value is a candidate for x.

            long long current_x_candidate = p;
            while (current_x_candidate % q == 0) {
                current_x_candidate /= prime_factor;
            }
            max_x = std::max(max_x, current_x_candidate);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

