int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x[right_ptr] such that x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d or right_ptr reaches end
        while (right_ptr < n && x[right_ptr] - x[left_ptr] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1] satisfy the condition with x[left_ptr].
        // We need to choose two more points from the range (left_ptr, right_ptr - 1].
        // The number of available points in this range is (right_ptr - 1) - (left_ptr + 1) + 1 = right_ptr - 1 - left_ptr.
        // Let m = right_ptr - 1 - left_ptr. These are the points x[left_ptr+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = static_cast<long long>(right_ptr - 1) - left_ptr;

        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

