    // Step 1: Propagate known characters based on s[i] == s[i+k] property
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] == '?') {
            s[i+k] = s[i];
        } else if (s[i] == '?' && s[i+k] != '?') {
            s[i] = s[i+k];
        } else if (s[i] != '?' && s[i+k] != '?' && s[i] != s[i+k]) {
            std::cout << "NO\n";
            return;
        }
    }

    // Step 2: Check the first k characters for consistency and fill '?'
    // For each i from 0 to k-1, all s[i], s[i+k], s[i+2k], ... must be the same.
    // We already propagated this, so now we just need to ensure they are consistent
    // and fill any remaining '?'s in the first k positions.
    // If s[i] is '?', it means s[i], s[i+k], s[i+2k], ... are all '?'
    // We don't need to fill them yet, as they can be anything.
    // The crucial part is that if s[i] is '0' or '1', then s[i+k], s[i+2k], ... must be the same.
    // This was handled in Step 1.

    // Step 3: Check the first k characters for balance
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else { // s[i] == '?'
            count_q++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means the first k characters can be made k/2 zeros and k/2 ones.
    // The remaining '?'s in the first k positions can be filled to achieve this balance.
    // Since all s[i], s[i+k], s[i+2k], ... are forced to be the same,
    // if the first k characters can be balanced, then all subsequent k-length blocks
    // will also be balanced with the same pattern.

    std::cout << "YES\n";
}

