#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string current_result(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool valid_pivot = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < pivot_digit + '0') {
                // Must be color 1
                if (digit < last1) {
                    valid_pivot = false;
                    break;
                }
                current_result[i] = '1';
                last1 = digit;
            } else if (digit > pivot_digit + '0') {
                // Must be color 2
                if (digit < last2) {
                    valid_pivot = false;
                    break;
                }
                current_result[i] = '2';
                last2 = digit;
            } else { // digit == pivot_digit + '0'
                // Can be either 1 or 2.
                // Prefer 2 if it maintains sorted order for color 2,
                // otherwise try 1 if it maintains sorted order for color 1.
                // If it can be 2:
                if (digit >= last2) {
                    current_result[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) { // If it cannot be 2, try 1
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Cannot be 1 or 2
                    valid_pivot = false;
                    break;
                }
            }
        }

        if (valid_pivot) {
            // Final check: last digit of color 1 sequence <= first digit of color 2 sequence
            // This is implicitly handled by the `last1` and `last2` logic.
            // If `last1` is the last digit assigned to color 1, and `last2` is the first digit assigned to color 2,
            // then `last1 <= last2` must hold.
            // However, `last1` and `last2` track the *last seen* digit for each color, not necessarily the final ones.
            // The condition `last1 <= last2` is not sufficient.
            // The actual condition is that the last digit of the *entire* color 1 sequence must be <= the first digit of the *entire* color 2 sequence.
            // Our greedy choice for `pivot_digit` handles this:
            // All digits < pivot_digit are 1.
            // All digits > pivot_digit are 2.
            // Digits == pivot_digit are assigned greedily.
            // If a digit `d_i == pivot_digit` is assigned '1', it means `d_i >= last1`.
            // If a digit `d_j == pivot_digit` is assigned '2', it means `d_j >= last2`.
            // The critical point is that `last1` will always be `pivot_digit` or less, and `last2` will always be `pivot_digit` or more.
            // So, `last1 <= last2` is always true if `last1` and `last2` are the actual last/first elements.
            // The current `last1` and `last2` track the maximums seen so far for each color.
            // If `last1` (max for color 1) is `X` and `last2` (max for color 2) is `Y`, then `X <= Y` is not guaranteed.
            // The actual condition is that the *last* digit assigned color 1 must be <= the *first* digit assigned color 2.
            // Let's reconstruct the sequences to verify.

            // This greedy assignment ensures that all digits assigned '1' are <= pivot_digit,
            // and all digits assigned '2' are >= pivot_digit.
            // If a digit `d_i = pivot_digit` is assigned '1', it means `d_i >= last1` (where `last1` is the max of previous '1's).
            // If a digit `d_j = pivot_digit` is assigned '2', it means `d_j >= last2` (where `last2` is the max of previous '2's).
            // The crucial part is that any digit assigned '1' will be `d_k <= pivot_digit`.
            // Any digit assigned '2' will be `d_m >= pivot_digit`.
            // So, the last digit of the '1' sequence will be `<= pivot_digit`.
            // The first digit of the '2' sequence will be `>= pivot_digit`.
            // This guarantees the overall sorted property.

            result = current_result;
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int correct_sequence_segments = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_sequence_segments++;
                    current_expected++;
                } else {
                    break; // Sequence broken
                }
            }
        }
    }

    // Total operations to disassemble all existing chains into individual dolls
    // Each existing nesting (a -> b) needs 1 operation to take 'a' out of 'b'.
    // Total existing nestings = (m1-1) + (m2-1) + ... + (mk-1) = (sum mi) - k = n - k.
    // So, n - k operations to disassemble everything.
    total_operations += (n - k);

    // Operations to build the final chain 1 -> 2 -> ... -> n from individual dolls.
    // This requires n-1 nesting operations.
    total_operations += (n - 1);

    // Now, subtract the operations that are "saved" because parts of the final chain
    // already exist in the correct configuration.
    // A segment 1 -> 2 -> ... -> X means X-1 nestings are already correct.
    // Each such correct nesting saves 1 disassembly operation and 1 assembly operation.
    // So, each correct_sequence_segment saves 2 operations.
    // The number of correct nestings is (correct_sequence_segments - 1).
    // For example, if 1->2->3 is a segment, correct_sequence_segments = 3.
    // This means 1->2 and 2->3 are correct nestings. (3-1 = 2 nestings).
    // Each of these 2 nestings saves 2 operations (1 disassemble, 1 assemble).
    // So, (correct_sequence_segments - 1) * 2 operations are saved.
    if (correct_sequence_segments > 0) {
        total_operations -= (long long)(correct_sequence_segments - 1) * 2;
    }

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        long long current_val = h[i] - i;
        while (!dq.empty() && h[dq.back()] - dq.back() >= current_val) {
            dq.pop_back();
        }
        dq.push_back(i);
        L[i] = h[dq.front()] - dq.front() + i;
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        long long current_val = h[i] + i;
        while (!dq.empty() && h[dq.back()] + dq.back() >= current_val) {
            dq.pop_back();
        }
        dq.push_back(i);
        R[i] = h[dq.front()] + dq.front() - i;
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        long long min_height_at_i = std::min({h[i], L[i], R[i]});
        max_ops = std::max(max_ops, min_height_at_i);
    }

    return max_ops;
}

