int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val = (b - 1);
    sum_r_val = (sum_r_val * b) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_k_val
    // sum_{k=1 to a} (k * b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_val_term1 = (a * (a + 1)) % MOD;
    sum_k_val_term1 = (sum_k_val_term1 * inv2) % MOD;
    sum_k_val_term1 = (sum_k_val_term1 * b) % MOD;

    long long sum_k_val_term2 = a % MOD;

    long long sum_k_val = (sum_k_val_term1 + sum_k_val_term2) % MOD;

    // Total sum = (sum_r_val * sum_k_val) % MOD
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

