        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now we have the final state for an input of 0 and an input of 1023.
    // Let f(0) = current_val_0 and f(1023) = current_val_1023.
    // We need to find a short sequence of operations that transforms
    // 0 -> current_val_0 and 1023 -> current_val_1023.

    // For each bit position i (0 to 9):
    // Let x_i be the i-th bit of the input.
    // Let c0_i be the i-th bit of current_val_0.
    // Let c1_i be the i-th bit of current_val_1023.

    // If x_i = 0, the output bit is c0_i.
    // If x_i = 1, the output bit is c1_i.

    // We can determine the required operations for each bit.
    // Let's find the combined constants for AND, OR, XOR operations.
    int and_const = 1023; // Initialize with all 1s
    int or_const = 0;    // Initialize with all 0s
    int xor_const = 0;   // Initialize with all 0s

    for (int i = 0; i < 10; ++i) {
        int bit_mask = (1 << i);
        int c0_i = (current_val_0 & bit_mask) >> i;
        int c1_i = (current_val_1023 & bit_mask) >> i;

        // Case 1: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 0
        // This means the output bit is always 0, regardless of input.
        // This can be achieved by `& 0` for this bit.
        if (c0_i == 0 && c1_i == 0) {
            and_const &= ~bit_mask; // Set this bit to 0 in and_const
        }
        // Case 2: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 1
        // This means the output bit is always 1, regardless of input.
        // This can be achieved by `| 1` for this bit.
        else if (c0_i == 1 && c1_i == 1) {
            or_const |= bit_mask; // Set this bit to 1 in or_const
        }
        // Case 3: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 1
        // This means the output bit is the same as the input bit.
        // This can be achieved by `& 1` and `| 0` and `^ 0` for this bit.
        // No change needed for and_const, or_const, xor_const for this bit.
        else if (c0_i == 0 && c1_i == 1) {
            // and_const remains 1 for this bit
            // or_const remains 0 for this bit
            // xor_const remains 0 for this bit
        }
        // Case 4: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 0
        // This means the output bit is the inverse of the input bit.
        // This can be achieved by `^ 1` for this bit.
        else if (c0_i == 1 && c1_i == 0) {
            xor_const |= bit_mask; // Set this bit to 1 in xor_const
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters. A common canonical form is:
    // (x & A) | B ^ C
    // Or, more generally, we can combine them.
    // Let's try to construct the operations.
    // The final value for an input `x` should be `(x & and_const) | or_const ^ xor_const`.
    // This is equivalent to `(x ^ xor_const) & and_const | or_const`.
    // Or `(x | or_const) & and_const ^ xor_const`.

    // Let's use the form: `(x & A) | B ^ C`
    // The `and_const` determines which bits can be 0.
    // The `or_const` determines which bits must be 1.
    // The `xor_const` determines which bits are flipped.

    // A single AND operation can set bits to 0.
    // A single OR operation can set bits to 1.
    // A single XOR operation can flip bits.

    // The problem states "no more than 5 lines".
    // The canonical form `(x & A) | B ^ C` uses at most 3 operations.
    // We need to find the A, B, C that match our derived `and_const`, `or_const`, `xor_const`.

    // Let's consider the effect of `& A`, `| B`, `^ C` on the two test values 0 and 1023.
    // Initial state: x_0 = 0, x_1 = 1023
    // After `& A`: x_0' = 0 & A = 0, x_1' = 1023 & A = A
    // After `| B`: x_0'' = 0 | B = B, x_1'' = A | B
    // After `^ C`: x_0''' = B ^ C, x_1''' = (A | B) ^ C

