#include <iostream>
#include <algorithm> // For std::min and std::max

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings in a string of length n
    long long total_substrings = n * (n + 1) / 2;

    // Number of zeros
    long long num_zeros = n - m;

    // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
    // This is achieved by distributing the zeros as evenly as possible among the 'm' ones.
    // This means we want to break the 'num_zeros' into 'm+1' blocks (before the first '1',
    // between '1's, and after the last '1').
    // However, the problem states "exactly m symbols equal to '1'".
    // The optimal strategy is to place '1's such that the blocks of '0's are as small as possible.
    // This means distributing the 'num_zeros' as evenly as possible into 'm+1' groups.
    // For example, if s = "01010", n=5, m=2. num_zeros = 3.
    // The '1's divide the string into 3 potential blocks of zeros:
    // _ 1 _ 1 _
    // The zeros are distributed as 1, 1, 1.
    // The number of blocks of zeros is m+1.
    // Let k be the number of zeros in each of the smaller blocks.
    // Let k+1 be the number of zeros in each of the larger blocks.
    // num_zeros = q * (k+1) + r * k, where q is the number of larger blocks, r is the number of smaller blocks.
    // More simply, if we divide num_zeros by (m+1), we get:
    // num_zeros = (m+1) * k + remainder
    // So, there are 'remainder' blocks of size (k+1) and (m+1 - remainder) blocks of size k.
    // Here, k = num_zeros / (m+1) (integer division)
    // remainder = num_zeros % (m+1)

    // Number of blocks of zeros that will have size k+1
    long long num_larger_zero_blocks = num_zeros % (m + 1);
    // Number of blocks of zeros that will have size k
    long long num_smaller_zero_blocks = (m + 1) - num_larger_zero_blocks;

    // Size of the smaller zero blocks
    long long k = num_zeros / (m + 1);

    // Calculate the number of substrings consisting only of zeros
    long long substrings_of_zeros = 0;
    // Contribution from smaller blocks of size k
    substrings_of_zeros += num_smaller_zero_blocks * (k * (k + 1) / 2);
    // Contribution from larger blocks of size k+1
    substrings_of_zeros += num_larger_zero_blocks * ((k + 1) * (k + 2) / 2);

    return total_substrings - substrings_of_zeros;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

