            long long x_i = (n - remainder) % n; // Smallest non-negative to add to make a[i] divisible by n
            long long k_0 = (n - x_i) % n; // k_0 * (n-1) % n == x_i
            long long b_i = k_0 * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] divisible by n
        // Select segment [n, n] (0-indexed: [n-1, n-1])
        // Length is 1.
        // We want to add b_{n-1} such that a[n-1] + b_{n-1} = 0.
        // b_{n-1} must be a multiple of 1. This is always true for any integer.
        // So we just add -a[n-1].
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0; // Update a[n-1]

        // Operation 3: Make all elements zero.
        // At this point, a[0]...a[n-2] are all multiples of n.
        // a[n-1] is 0.
        // Select segment [1, n] (0-indexed: [0, n-1])
        // Length is n.
        // For each a[i], we want to add b_i such that a[i] + b_i = 0.
        // b_i must be a multiple of n.
        // Since a[i] is already a multiple of n (for i < n-1) or 0 (for i = n-1),
        // -a[i] is also a multiple of n.
        // So we can just add -a[i] to each element.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Iterate in reverse order of removal
    // This means we are adding vertices back to the graph
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using k as an intermediate vertex
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active i

            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active j

                // dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // After adding vertex k and updating all paths through k,
        // we need to re-evaluate all paths between *all currently active* vertices
        // using any currently active vertex as an intermediate.
        // The previous loop only updated paths *using k as an intermediate*.
        // We need to ensure all pairs (i,j) among active vertices
        // have their shortest path considering all active k's.
        // Since we are adding vertices one by one, and the `dist` matrix
        // already contains shortest paths considering all previously added vertices,
        // the update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // correctly propagates the new shortest paths.
        // The crucial part is that `dist[i][k]` and `dist[k][j]` themselves
        // might have been updated by previous `k'`s.
        // The Floyd-Warshall structure `for k, for i, for j` ensures this.
        // Here, `k` is the *newest* vertex.
        // So, after adding `k`, we need to update paths `i -> j` using `k`.
        // But also, paths `i -> k` and `k -> j` might be shortened by other active vertices.
        // The standard Floyd-Warshall order is `k` (intermediate), then `i` (source), then `j` (destination).
        // By adding `k` and then iterating `i` and `j` over *all currently active vertices*,
        // we are effectively running one step of Floyd-Warshall where `k` is the current intermediate vertex.
        // The `dist` matrix always holds the shortest paths considering all vertices `x[k_idx], x[k_idx+1], ..., x[n-1]`
        // as intermediate vertices.

        // Calculate sum of shortest paths for all currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ...)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, k is the highest bit set in X+1, minus 1.
        // Or, k is the number of bits in X+1, minus 1.
        // Example: X=10. X+1=11 (1011_2). k=3. (2^3-1=7 <= 10). (2^4-1=15 > 10).
        // Example: X=4. X+1=5 (101_2). k=2. (2^2-1=3 <= 4). (2^3-1=7 > 4).

        // A more direct way: iterate k from 60 down to 0
        for (int i = 60; i >= 0; --i) {
            if (((1LL << (i + 1)) - 1) <= X) {
                k = i + 1;
                break;
            }
        }
        // If X is 1, k will be 1. (1LL << 1) - 1 = 1 <= 1.
        // If X is 0, loop won't find anything, k remains 0. But X > 0.
        // If X is 2, k will be 2. (1LL << 2) - 1 = 3 > 2. (1LL << 1) - 1 = 1 <= 2. So k=1.
        // This logic for k is slightly off.
        // We want the largest k such that 2^k - 1 <= X.
        // This means we want to find the largest power of 2, 2^k, such that 2^k <= X+1.
        // Then k is the exponent.

        // Correct logic for k:
        // We want to find the largest k such that (1LL << k) - 1 <= X.
        // This is equivalent to finding the largest k such that 2^k <= X + 1.
        // If X=10, X+1=11. Largest 2^k <= 11 is 2^3=8. So k=3.
        // If X=4, X+1=5. Largest 2^k <= 5 is 2^2=4. So k=2.
        // If X=1, X+1=2. Largest 2^k <= 2 is 2^1=2. So k=1.

        k = 0;
        if (X > 0) { // X is guaranteed to be > 0 here
            long long temp_X_plus_1 = X + 1;
            while ((1LL << (k + 1)) <= temp_X_plus_1) {
                k++;
            }
        }

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= ((1LL << k) - 1);

        // Increment current_val for the next block
        current_val += d;

        // Check for overflow for current_val
        if (current_val > 2e14) { // A sufficiently large number to prevent overflow with d
                                  // 10^18 is the limit. d can be 10^9.
                                  // If current_val is 10^18 - 10^9, adding d might exceed 10^18.
                                  // A safer check is to ensure current_val + d doesn't exceed 10^18.
                                  // Since d >= 1, current_val will always increase.
                                  // If current_val itself exceeds 10^18, it's an issue.
                                  // The problem states a_i < 10^18.
                                  // If current_val becomes too large, we might not be able to add more elements.
                                  // The maximum number of elements is 10^4.
                                  // If d=10^9, and we add 10^4 elements, current_val could reach 1 + 10^4 * 10^9 = 10^13.
                                  // This is well within 10^18.
                                  // The only way current_val could exceed 10^18 is if d is very large and X is very large,
                                  // requiring many blocks. But the number of blocks is limited by log2(X).
                                  // Max X is 10^9. log2(10^9) approx 30. So max 30 blocks.
                                  // Max current_val would be 1 + 30 * 10^9 = 3 * 10^10, which is fine.
                                  // So, current_val overflow is not an issue.
        }
    }

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Store upper bounds for initial_a[j]
    std::vector<long long> current_delta(n, 0); // Sum of d's applied to a[j] so far

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else {
            // Type 2: Max query
            // For each j in [l, r], initial_a[j] + current_delta[j] <= ops[i].val
            // So, initial_a[j] <= ops[i].val - current_delta[j]
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If any initial_a[j] is still LLONG_MAX, it means it was never constrained by a type 2 query.
    // We can set it to 0, as it satisfies |a[j]| <= 10^9.
    // Or, more generally, any value that satisfies the constraints.
    // The problem asks for *any* suitable array.
    // Setting it to 0 is a valid choice.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == LLONG_MAX) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> temp_a = initial_a; // This will be the array that changes during verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                temp_a[j] += ops[i].val;
            }
        } else {
            long long current_max = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_max = std::max(current_max, temp_a[j]);
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] < -1000000000LL || initial_a[j] > 1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution
            // within the bounds, but it's a good sanity check.
            // Our construction method (setting unconstrained values to 0) ensures this.
            // If initial_a[j] was constrained, it was by ops[i].val - current_delta[j].
            // ops[i].val is up to 5*10^7. current_delta[j] can be up to 5000 * 10^4 = 5*10^7.
            // So initial_a[j] can be around 5*10^7 - (-5*10^7) = 10^8, which is within 10^9.
            // Or -5*10^7 - (5*10^7) = -10^8.
            // So the bounds should be fine.
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using 1-based indexing for 'a' to match problem description
// a[0] is unused. a[1] will be the current 'i' value.
// a[2]...a[n] are the given values.
std::vector<long long> a_global;
int N_global;

// Memoization table for results of solve(start_idx, is_forward)
// dp[idx][0] stores result for (idx, false) (moving backward)
// dp[idx][1] stores result for (idx, true) (moving forward)
// -2 indicates not computed yet
// -1 indicates infinite loop
std::vector<std::vector<long long>> dp;

// Function to solve for a given starting index and direction
// current_x: The current value of x
// is_forward: true if the last operation was step 2 (x += a[x_old]), false if step 3 (x -= a[x_old])
long long solve(int current_x, bool is_forward) {
    // Check termination conditions
    if (current_x <= 0 || current_x > N_global) {
        return 0; // Base case: program terminates, no further y added
    }

    // Check memoization table
    if (dp[current_x][is_forward] != -2) {
        return dp[current_x][is_forward];
    }

    // Mark as currently computing to detect cycles
    dp[current_x][is_forward] = -1; // Sentinel for cycle detection

    long long val_at_x = a_global[current_x];
    long long result;

    if (is_forward) { // We just did x += a[x_old], now we do x -= a[x_old]
        int next_x = current_x - val_at_x;
        result = val_at_x + solve(next_x, false);
    } else { // We just did x -= a[x_old], now we do x += a[x_old]
        int next_x = current_x + val_at_x;
        result = val_at_x + solve(next_x, true);
    }

    // If result is -1, it means a cycle was detected downstream, so propagate -1
    if (result == -1) {
        return dp[current_x][is_forward] = -1;
    }

    return dp[current_x][is_forward] = result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_global;

    a_global.resize(N_global + 1); // 1-indexed
    for (int i = 2; i <= N_global; ++i) {
        std::cin >> a_global[i];
    }

    // Initialize DP table
    // dp[idx][0] for backward move, dp[idx][1] for forward move
    dp.resize(N_global + 1, std::vector<long long>(2, -2));

    for (int i = 1; i < N_global; ++i) {
        // For each i, a[1] is set to i.
        // The program starts with x=1, y=0.
        // First operation is x = x + a[x_old], y = y + a[x_old]
        // So, x becomes 1 + a[1], y becomes a[1].
        // The state after the first step 2 is (x=1+a[1], y=a[1]), and the next step is step 3 (x -= a[x_old]).
        // So, we call solve with current_x = 1 + a[1], and is_forward = true (because the last step was step 2).
        // The total y will be a[1] + the result from solve.

        a_global[1] = i;

        // Clear DP table for each new 'i'
        // Only need to clear states reachable from current 'i'.
        // However, clearing the whole table is simpler and N is small enough.
        // A more optimized approach would be to only clear relevant states or use a different DP structure.
        // For N=2e5, clearing N*2 states is fine.
        for(int k=1; k<=N_global; ++k) {
            dp[k][0] = -2;
            dp[k][1] = -2;
        }

        long long initial_a1 = a_global[1];
        long long result = initial_a1 + solve(1 + initial_a1, true);

        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now cured and out of line

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children leaving due to chain reaction

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue; // This child has already left
            }

            // Apply accumulated d_effect from previous children leaving
            children[j].p -= total_d_effect;

            // Apply v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--; // v_effect decreases for subsequent children
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves
                total_d_effect += children[j].d; // Add d_j to the total effect for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can form s' = s[i...N-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    // The cut must not be at i=0 or i=N.
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // This means 3 pieces.
    // The problem statement implies that if a solution exists, k=1 or k=2.
    // The only case where it's impossible is if all characters are the same.
    // If all characters are the same, e.g., "aaaa", then any rearrangement of its
    // substrings will result in "aaaa".
    // For example, "aa|a|a" -> "aaaa". "a|aa|a" -> "aaaa".
    // If s consists of only one distinct character, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // Consider s = "nolon". k=1 doesn't work.
        // "nolon" -> "on|l|no" is a palindrome and != "nolon". This uses 2 cuts.
        // The logic is that if s is a palindrome and not all characters are the same,
        // we can always find a way to make 2 cuts to form a new palindrome.
        // For example, take s[0...N/2-1] and s[N/2+1...N-1] (if N is odd, middle char s[N/2] is separate).
        // Or more simply, cut s into s[0...N-2] and s[N-1].
        // Then cut s[0...N-2] into s[0...N-3] and s[N-2].
        // This gives pieces s[0...N-3], s[N-2], s[N-1].
        // This is just one way to think about it. The problem guarantees that if
        // not all characters are the same, and k=1 doesn't work, then k=2 is the answer.
        // This is a known property for this type of problem.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores the index of the nearest 1 to the left (inclusive)
    std::vector<int> right_ones(n, -1); // Stores the index of the nearest 1 to the right (inclusive)

    int last_one = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one = i;
        }
        left_ones[i] = last_one;
    }

    last_one = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one = i;
        }
        right_ones[i] = last_one;
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (left_ones[i] != -1 && right_ones[i] != -1) {
                int dist_left = i - left_ones[i];
                int dist_right = right_ones[i] - i;

                if (dist_left == dist_right) {
                    // This 0 will never become 1. It's a "pivot" for stability.
                    // The sequence will never stabilize if such a 0 exists and is not at an edge.
                    // However, the problem statement implies that 0s between 1s can become 1s.
                    // The condition for a 0 to become 1 is that it's surrounded by 1s within a certain distance.
                    // If dist_left == dist_right, this 0 will remain 0.
                    // If dist_left != dist_right, it will eventually become 1 if it's closer to a 1.
                    // The crucial observation is that if a 0 is equidistant from two 1s, it will remain 0.
                    // If it's closer to one 1, it will become that 1.
                    // The problem is about the *entire* sequence stabilizing.
