                // So, we can update min_r_with_3ap[x] = min(min_r_with_3ap[x], x + 2k).
                // Then, propagate this minimum backwards:
                // min_r_with_3ap[i] = min(min_r_with_3ap[i], min_r_with_3ap[i+1]) for i from x-1 down to 0.
                // This propagation is done after all 3-APs are found.

                // For now, just store the minimum r_prime for each possible starting x.
                // This is min_r_with_3ap[x] = min(min_r_with_3ap[x], x + 2k).
                // This is not quite right. min_r_with_3ap[l] is the minimum r for substring s[l...r].
                // The current 3-AP is s[x...x+2k].
                // So for l=x, the minimum r is x+2k.
                // For l=x-1, the minimum r is also x+2k (if this is the first 3-AP found for l=x-1).
                // So, min_r_with_3ap[l] should be updated for all l <= x.
                // The smallest r for s[l...r] is x+2k.
                // So, min_r_with_3ap[l] = min(min_r_with_3ap[l], x+2k).
                // This is the correct logic.
                // The loop for k can go up to k=7 for N=300000.
                // If k is large, x+2k will be large, so it's less likely to be the minimum r.
                // The maximum k we need to check is small.
                // If k > 7, then 2k > 14.
                // If we have a 3-AP (x, x+k, x+2k) and another (x', x'+k', x'+2k')
                // such that x' <= x and x'+2k' <= x+2k, then the first one is redundant.
                // We are looking for the smallest r for each l.
                // The maximum k we need to consider is 7.
                // If k > 7, then x+2k > x+14.
                // If there is a 3-AP (x, x+k, x+2k) with k > 7,
                // and there is another 3-AP (x', x'+k', x'+2k') with x' <= x and x'+2k' <= x+14,
                // then the (x, k) 3-AP is not the one that determines min_r_with_3ap[l] for l <= x.
                // The problem states $1 \leq k \leq n$.
                // However, if $k$ is large, $x+2k$ will be large.
                // The maximum $k$ that can possibly be relevant for finding the *minimum* $r$ for a given $l$
                // is small.
                // Consider $l$. We are looking for $x, k$ such that $l \le x < x+2k \le r$.
                // We want to find the smallest $r$.
                // This means we want to find the smallest $x+2k$ for any $x \ge l$.
                // If $k$ is large, $x+2k$ will be large.
                // For example, if $k=8$, then $x+2k = x+16$.
                // If there is a 3-AP with $k=1$, $x+2k = x+2$.
                // If there is a 3-AP with $k=2$, $x+2k = x+4$.
                // If there is a 3-AP with $k=3$, $x+2k = x+6$.
                // If there is a 3-AP with $k=4$, $x+2k = x+8$.
                // If there is a 3-AP with $k=5$, $x+2k = x+10$.
                // If there is a 3-AP with $k=6$, $x+2k = x+12$.
                // If there is a 3-AP with $k=7$, $x+2k = x+14$.
                // If $k \ge 8$, then $x+2k \ge x+16$.
                // If we find a 3-AP $(x, k)$ with $k \ge 8$, its end point is $x+2k$.
                // If there is *any* 3-AP $(x', k')$ with $x' \le x$ and $x'+2k' \le x+14$,
                // then $x+2k$ is not the minimum $r$ for $l \le x$.
                // It is known that if a string of length $N$ contains a 3-AP, it must contain one with $k \le \log N$.
                // For $N=300000$, $\log_2 300000 \approx 18$.
                // However, a tighter bound is $k \le 7$.
                // This is a known result for "avoiding 3-APs" in binary strings.
                // If a binary string of length $L$ contains a 3-AP, it must contain one with $k \le 7$.
                // This means we only need to check $k$ from $1$ to $7$.
                // This optimization makes the inner loop constant time.
                if (k > 7) break; // Optimization: only check k up to 7

                int current_r_prime = x + 2 * k;
                // Update min_r_with_3ap[l] for all l from 0 to x.
                // This is done by setting min_r_with_3ap[x] and then propagating.
                min_r_with_3ap[x] = std::min(min_r_with_3ap[x], current_r_prime);
            }
        }
    }

    // Propagate the minimum r_prime backwards.
    // If s[i...r] contains a 3-AP, then s[i-1...r] also contains it.
    // So, min_r_with_3ap[i-1] <= min_r_with_3ap[i].
    // We need to ensure min_r_with_3ap[i-1] is the minimum of its current value
    // and min_r_with_3ap[i].
    for (int i = n - 1; i >= 0; --i) {
        min_r_with_3ap[i] = std::min(min_r_with_3ap[i], min_r_with_3ap[i + 1]);
    }

    // Calculate bad_pairs
    for (int l = 0; l < n; ++l) {
        // For a fixed l, all r such that l <= r < min_r_with_3ap[l]
        // form a bad pair (l, r).
        // The number of such r values is (min_r_with_3ap[l] - 1) - l + 1
        // = min_r_with_3ap[l] - l.
        // If min_r_with_3ap[l] == n, it means no 3-AP was found for this l,
        // so all r from l to n-1 are bad. Number of such r is n - l.
        // The formula min_r_with_3ap[l] - l works for both cases.
        // Example: if min_r_with_3ap[l] = n, then n - l bad pairs.
        // Example: if min_r_with_3ap[l] = 5, l=0, then r=0,1,2,3,4 are bad. 5-0=5 pairs.
        bad_pairs += (min_r_with_3ap[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s - count of 2s) in jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s - count of 2s) in jars 2n-k+1 to 2n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars eaten from the left to achieve a certain diff_L value
    // map: diff_L_value -> k (number of jars eaten from left)
    std::map<int, int> left_diff_to_k;
    for (int k = 0; k <= n; ++k) {
        // If we eat k jars from the left, the remaining jars are from index k to n-1.
        // The difference in these *eaten* jars is diff_L[k].
        // We are interested in the difference of the *remaining* jars.
        // The problem statement says "Karlsson initially stands between jars n and n+1".
        // This means jars 1..n are left, jars n+1..2n are right.
        // If he eats k jars from the left, he eats jars 1..k.
        // The remaining jars on the left are k+1..n.
        // The difference of jars 1..k is diff_L[k].
        // We need to find the difference of the *remaining* jars.
        // Let's re-evaluate the meaning of diff_L[k].
        // diff_L[k] is the balance of the first k jars (a[0]...a[k-1]).
        // If we eat k jars from the left, the balance of the eaten jars is diff_L[k].
        // The balance of the remaining jars (from index k to 2n-1) is initial_diff - diff_L[k].
        // We want to find a state where the balance of remaining jars is 0.
        // So, we need initial_diff - diff_L[k] - diff_R[j] = 0 for some k, j.
        // This means diff_L[k] + diff_R[j] = initial_diff.
        // Or, diff_L[k] = initial_diff - diff_R[j].

        // Let's store the balance of the *eaten* jars from the left.
        // If we eat k jars from the left (a[0]...a[k-1]), their balance is diff_L[k].
        // We want to find the minimum k+j such that the balance of remaining jars is 0.
        // The balance of all jars is initial_diff.
        // If we eat k jars from left and j jars from right, the balance of eaten jars is diff_L[k] + diff_R[j].
        // The balance of remaining jars is initial_diff - (diff_L[k] + diff_R[j]).
        // We want this to be 0. So, diff_L[k] + diff_R[j] = initial_diff.

        // Store the number of jars eaten from the left (k) for each possible balance (diff_L[k]).
        // We want the minimum k for each balance.
        if (left_diff_to_k.find(diff_L[k]) == left_diff_to_k.end()) {
            left_diff_to_k[diff_L[k]] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible number of jars eaten from the right (j)
    for (int j = 0; j <= n; ++j) {
        // If we eat j jars from the right (a[2n-j]...a[2n-1]), their balance is diff_R[j].
        // We need to find a k such that diff_L[k] + diff_R[j] = initial_diff.
        // This means diff_L[k] = initial_diff - diff_R[j].
        int target_diff_L = initial_diff - diff_R[j];

        if (left_diff_to_k.count(target_diff_L)) {
            int k = left_diff_to_k[target_diff_L];
            min_jars_eaten = std::min(min_jars_eaten, k + j);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_ptr = 0; // Pointer for target tracks
    int h_ptr = 0; // Pointer for heads

    while (p_ptr < m) {
        if (h_ptr >= n) {
            return false; // No more heads to cover remaining tracks
        }

        long long current_p = p[p_ptr];
        long long current_h = h[h_ptr];

        // If the current head cannot reach the current target track, move to the next head
        if (current_h + T < current_p) {
            h_ptr++;
            continue;
        }

        // If the current head can reach the current target track,
        // it can cover a range [current_p, current_h + T].
        // We need to find how many subsequent target tracks can be covered by this head.
        long long max_reach_left = current_h - T;
        long long max_reach_right = current_h + T;

        // Case 1: The head is to the left of the current target track.
        // It must move right to cover current_p.
        // The effective range it can cover is [current_p, current_h + T].
        // The time taken to reach current_p is current_p - current_h.
        // Remaining time for leftward movement from current_p is T - (current_p - current_h).
        // So, it can cover tracks up to current_p + (T - (current_p - current_h)) = current_h + T.
        // This is simply max_reach_right.
        // The tracks covered are from current_p to max_reach_right.

        // Case 2: The head is to the right of the current target track.
        // It must move left to cover current_p.
        // The effective range it can cover is [current_h - T, current_p].
        // The time taken to reach current_p is current_h - current_p.
        // Remaining time for rightward movement from current_p is T - (current_h - current_p).
        // So, it can cover tracks up to current_p + (T - (current_h - current_p)) = current_p + T - current_h + current_p = 2*current_p + T - current_h.
        // This is not correct.
        // If a head at `h_i` covers `p_j`, it takes `abs(h_i - p_j)` time.
        // The remaining time is `T - abs(h_i - p_j)`.
        // With this remaining time, it can cover tracks in the range `[p_j - (T - abs(h_i - p_j)), p_j + (T - abs(h_i - p_j))]`.
        // The total range covered by head `h_i` if it covers `p_j` is
        // `[min(h_i - T, p_j - (T - abs(h_i - p_j))), max(h_i + T, p_j + (T - abs(h_i - p_j)))]`.
        // This is complicated. Let's simplify.

        // A head at `h_i` can cover any track `x` such that `abs(h_i - x) <= T`.
        // If we use head `h_ptr` to cover `p_ptr`, then `abs(h[h_ptr] - p[p_ptr]) <= T` must hold.
        // If this condition is met, the head `h[h_ptr]` can cover a range of tracks.
        // The crucial observation is that if `h[h_ptr]` covers `p[p_ptr]`, it should also cover as many subsequent `p` tracks as possible.
        // To do this, it should move to the leftmost possible track it can cover, which is `p[p_ptr]`.
        // The time taken to reach `p[p_ptr]` is `p[p_ptr] - h[h_ptr]`.
        // The remaining time for movement is `T - (p[p_ptr] - h[h_ptr])`.
        // From `p[p_ptr]`, it can then move further right by this remaining time.
        // So, the rightmost track it can cover is `p[p_ptr] + (T - (p[p_ptr] - h[h_ptr])) = h[h_ptr] + T`.
        // This is valid if `h[h_ptr] <= p[p_ptr]`.

        // If `h[h_ptr] > p[p_ptr]`:
        // The time taken to reach `p[p_ptr]` is `h[h_ptr] - p[p_ptr]`.
        // The remaining time for movement is `T - (h[h_ptr] - p[p_ptr])`.
        // From `p[p_ptr]`, it can then move further right by this remaining time.
        // So, the rightmost track it can cover is `p[p_ptr] + (T - (h[h_ptr] - p[p_ptr])) = 2 * p[p_ptr] + T - h[h_ptr]`.
        // This is the correct logic.

        long long current_head_right_reach;
        if (current_h <= current_p) {
            // Head is to the left or at the target. Move right to cover current_p.
            // Time taken: current_p - current_h.
            // Remaining time: T - (current_p - current_h).
            // Max right reach from current_p: current_p + (T - (current_p - current_h)) = current_h + T.
            current_head_right_reach = current_h + T;
        } else { // current_h > current_p
            // Head is to the right of the target. Move left to cover current_p.
            // Time taken: current_h - current_p.
            // Remaining time: T - (current_h - current_p).
            // Max right reach from current_p: current_p + (T - (current_h - current_p)) = 2 * current_p + T - current_h.
            current_head_right_reach = 2 * current_p + T - current_h;
        }

        // Now, advance p_ptr as long as tracks are covered by the current head
        while (p_ptr < m && p[p_ptr] <= current_head_right_reach) {
            p_ptr++;
        }
        h_ptr++; // Move to the next head
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_val_sum = elements[0].value + elements[1].value;
    long long max_val_sum = elements[n - 1].value + elements[n - 2].value;

    long long best_goodness;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a'_1 + a'_2
    // max_f = a'_{n-1} + a'_n
    // Goodness = (a'_{n-1} + a'_n) - (a'_1 + a'_2)
    best_goodness = max_val_sum - min_val_sum;
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Case 2: At least one element in each subsequence.
    // min_f can be a'_1 + a'_2 (same subsequence) or a'_1 + a'_2 + h (different subsequences)
    // max_f can be a'_{n-1} + a'_n (same subsequence) or a'_{n-1} + a'_n + h (different subsequences)

    // The minimum possible value of f is always a'_1 + a'_2.
    // This is because we can always put a'_1 and a'_2 in the same subsequence.
    // If we put them in different subsequences, f(a'_1, a'_2) = a'_1 + a'_2 + h, which is larger.
    // So, min_f = a'_1 + a'_2.

    // The maximum possible value of f is always a'_{n-1} + a'_n + h.
    // This is because we can always put a'_{n-1} and a'_n in different subsequences.
    // If we put them in the same subsequence, f(a'_{n-1}, a'_n) = a'_{n-1} + a'_n, which is smaller.
    // So, max_f = a'_{n-1} + a'_n + h.

    // Goodness = (a'_{n-1} + a'_n + h) - (a'_1 + a'_2)
    // This is the goodness if we ensure that a'_1 and a'_2 are in the same group,
    // and a'_{n-1} and a'_n are in different groups.
    // This strategy is always possible if n >= 2.
    long long goodness_mixed = max_val_sum + h - min_val_sum;

    // Consider a specific partition strategy for mixed case:
    // Put elements[0] (a'_1) into group 1.
    // Put elements[1] (a'_2) into group 1.
    // Put elements[n-1] (a'_n) into group 2.
    // Put elements[n-2] (a'_{n-1}) into group 2.
    // For all other elements, put them into group 1.
    // This ensures a'_1, a'_2 are in same group (1).
    // This ensures a'_{n-1}, a'_n are in same group (2).
    // This ensures a'_1 and a'_n are in different groups.
    // This ensures a'_2 and a'_{n-1} are in different groups.

    // With this strategy:
    // min_f = a'_1 + a'_2 (from group 1)
    // max_f = max( (a'_{n-1} + a'_n), (a'_1 + a'_{n-1} + h), (a'_1 + a'_n + h), (a'_2 + a'_{n-1} + h), (a'_2 + a'_n + h) )
    // The largest sum of two elements in the same group is a'_{n-1} + a'_n.
    // The largest sum of two elements in different groups is a'_1 + a'_n + h.
    // So, max_f = std::max(a'_{n-1} + a'_n, a'_1 + a'_n + h).
    // This is not quite right. The max_f could be a'_1 + a'_{n-1} + h or a'_2 + a'_n + h.
    // The maximum possible sum of two elements is a'_{n-1} + a'_n.
    // The maximum possible sum of two elements plus h is a'_{n-1} + a'_n + h.
    // So, if we have elements in different groups, the max_f will be at least a'_{n-1} + a'_n + h.
    // If we have elements in the same group, the max_f will be at least a'_{n-1} + a'_n.

    // Let's re-evaluate the two main scenarios:
    // Scenario A: All elements in one group.
    // min_f = a'_1 + a'_2
    // max_f = a'_{n-1} + a'_n
    // Goodness = (a'_{n-1} + a'_n) - (a'_1 + a'_2)

    // Scenario B: Elements in both groups.
    // In this case, there must be at least one pair (a_i, a_j) such that a_i is in group 1 and a_j is in group 2.
    // This means f(a_i, a_j) = a_i + a_j + h will be present.
    // The minimum possible value of f is a'_1 + a'_2. This can be achieved by putting a'_1 and a'_2 in the same group.
    // The maximum possible value of f is a'_{n-1} + a'_n + h. This can be achieved by putting a'_{n-1} and a'_n in different groups.
    // So, if we can achieve both of these, the goodness is (a'_{n-1} + a'_n + h) - (a'_1 + a'_2).

    // The question is, can we always achieve min_f = a'_1 + a'_2 AND max_f = a'_{n-1} + a'_n + h?
    // Yes, for example:
    // Put a'_1, a'_2, ..., a'_{n-1} in group 1.
    // Put a'_n in group 2.
    // Then f(a'_1, a'_2) = a'_1 + a'_2 (same group).
    // And f(a'_{n-1}, a'_n) = a'_{n-1} + a'_n + h (different groups).
    // In this partition:
    // min_f = a'_1 + a'_2 (from group 1)
    // max_f = max( (a'_{n-2} + a'_{n-1}), (a'_1 + a'_n + h) )
    // This is not necessarily a'_{n-1} + a'_n + h.
    // It could be a'_{n-2} + a'_{n-1} if h is very small.

    // Let's consider the actual values that can appear.
    // The set of all possible sums is {a_i + a_j} U {a_i + a_j + h}.
    // The minimum possible sum is always a'_1 + a'_2.
    // The maximum possible sum is always a'_{n-1} + a'_n + h.

    // If we put all elements in one group, min_f = a'_1 + a'_2, max_f = a'_{n-1} + a'_n. Goodness = max_val_sum - min_val_sum.
    // This is the current `best_goodness`.

    // If we put elements in two groups, then there will be at least one pair (x, y) with x in group 1 and y in group 2.
    // So, values of type `A + B + h` will appear.
    // The minimum value of `f` will be `min( (min_same_group_sum), (min_diff_group_sum + h) )`.
    // The maximum value of `f` will be `max( (max_same_group_sum), (max_diff_group_sum + h) )`.

    // The key insight is that the minimum possible value of f is always a'_1 + a'_2.
    // We can always put a'_1 and a'_2 in the same group.
    // The maximum possible value of f is always a'_{n-1} + a'_n + h.
    // We can always put a'_{n-1} and a'_n in different groups.

    // So, if we have a partition where both types of sums (same group and different group) exist,
    // then the range of f values will span from a'_1 + a'_2 to a'_{n-1} + a'_n + h.
    // The goodness would be (a'_{n-1} + a'_n + h) - (a'_1 + a'_2).
    // This is true IF we can ensure that a'_1 and a'_2 are in the same group AND a'_{n-1} and a'_n are in different groups.
    // This is possible: put a'_1, a'_2, ..., a'_{n-1} in group 1, and a'_n in group 2.
    // Then min_f = a'_1 + a'_2 (from group 1).
    // And max_f = max( (a'_{n-2} + a'_{n-1}), (a'_1 + a'_n + h) ).
    // This is the crucial part. The max_f is NOT necessarily a'_{n-1} + a'_n + h.

    // Let's consider the two main candidates for optimal partition:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = a'_1 + a'_2
    //    max_f = a'_{n-1} + a'_n
    //    Goodness = (a'_{n-1} + a'_n) - (a'_1 + a'_2)
    //    This is already calculated as `best_goodness`.

    // 2. Elements in two groups.
    //    To minimize goodness, we want to make the range of f values as small as possible.
    //    This means we want to make min_f as large as possible and max_f as small as possible.
    //    However, the problem is about the difference.
    //    The smallest possible value for f is `a'_1 + a'_2`.
    //    The largest possible value for f is `a'_{n-1} + a'_n + h`.
    //    If we can construct a partition where these two values are the min and max f,
    //    then the goodness is `(a'_{n-1} + a'_n + h) - (a'_1 + a'_2)`.

    //    Consider the partition where:
    //    elements[0] (a'_1) is in group 1.
    //    elements[1] (a'_2) is in group 2.
    //    elements[n-1] (a'_n) is in group 1.
    //    elements[n-2] (a'_{n-1}) is in group 2.
    //    All other elements (if n > 4) can be put in group 1.
    //    This ensures a'_1 and a'_2 are in different groups.
    //    This ensures a'_{n-1} and a'_n are in different groups.
    //    This ensures a'_1 and a'_n are in the same group.
    //    This ensures a'_2 and a'_{n-1} are in the same group.

    //    This is getting complicated. Let's simplify.
    //    The minimum possible value of `a_i + a_j` is `elements[0].value + elements[1].value`.
    //    The maximum possible value of `a_i + a_j` is `elements[n-1].value + elements[n-2].value`.

    //    If h is very large, it's usually better to put all elements in one group to avoid the `+h` penalty.
    //    If h is small, it might be better to use two groups.

    //    Let's consider the partition where `elements[0]` is in group 1, and all other elements are in group 2.
    //    min_f: `elements[1].value + elements[2].value` (from group 2) OR `elements[0].value + elements[1].value + h` (diff groups).
    //           So, `min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)`.
    //           This is not right. The minimum f is always `elements[0].value + elements[1].value` if they are in the same group.
