    //     Pairs in G2: (elements[1], elements[2]) -> elements[1].value + elements[2].value.
    //     Pairs across G1/G2: (elements[0], elements[1]) -> elements[0].value + elements[1].value + h.
    //                          (elements[0], elements[2]) -> elements[0].value + elements[2].value + h.
    //     min_f = elements[1].value + elements[2].value.
    //     max_f = elements[0].value + elements[2].value + h.
    //     Goodness = (elements[0].value + elements[2].value + h) - (elements[1].value + elements[2].value)
    //              = elements[0].value - elements[1].value + h.
    //     This is a candidate for `best_goodness`.
    //     Let's call this `goodness_strategy_2`.
    //     `goodness_strategy_2 = elements[0].value + h - elements[1].value`.
    //     This is only valid if `elements[1].value + elements[2].value` is indeed the minimum.
    //     This is true if `elements[1].value + elements[2].value <= elements[0].value + elements[1].value + h`.
    //     Which simplifies to `elements[2].value <= elements[0].value + h`. This is generally true.
    //     And `elements[0].value + elements[2].value + h` is indeed the maximum.
    //     This is true if `elements[0].value + elements[2].value + h >= elements[1].value + elements[2].value`.
    //     Which simplifies to `elements[0].value + h >= elements[1].value`. This is generally true.

    // So, for n >= 3, a partition of {a'_1} and {a'_2, ..., a'_n} gives goodness `a'_1 + h - a'_2`.
    // Let's check this against the first sample:
    // n=3, h=2, a = {1, 2, 3}. Sorted: {1, 2, 3}.
    // Strategy 1 (all 1s):
    //   min_f = 1+2 = 3
    //   max_f = 2+3 = 5
    //   Goodness = 5 - 3 = 2.
    // Strategy 2 (1 in G1, 2,3 in G2):
    //   G1={1}, G2={2,3}
    //   Pairs in G2: (2,3) -> 2+3 = 5.
    //   Pairs across G1/G2: (1,2) -> 1+2+2 = 5. (1,3) -> 1+3+2 = 6.
    //   min_f = 5.
    //   max_f = 6.
    //   Goodness = 6 - 5 = 1.
    // This matches the sample output (goodness 1, partition 1 2 2).
    // So, `elements[0].value + h - elements[1].value` is a strong candidate for the optimal goodness.

    // Let's compare `best_goodness` (from all 1s) with `elements[0].value + h - elements[1].value`.
    // If `elements[0].value + h - elements[1].value` is smaller, update `best_goodness` and `best_partition`.

    // The partition for `elements[0].value + h - elements[1].value` is:
    // `elements[0]` gets group 1.
    // All other elements `elements[1]` to `elements[n-1]` get group 2.
    // This is the partition `1 2 2 ... 2`.

    // What if n=2?
    // a = {a'_1, a'_2}.
    // Strategy 1 (all 1s): G1={a'_1, a'_2}. min_f = a'_1+a'_2, max_f = a'_1+a'_2. Goodness = 0.
    // Strategy 2 (a'_1 in G1, a'_2 in G2): G1={a'_1}, G2={a'_2}. min_f = a'_1+a'_2+h, max_f = a'_1+a'_2+h. Goodness = 0.
    // So for n=2, goodness is always 0. The initial `best_goodness` calculation handles this.
    // `elements[0].value + h - elements[1].value` would be `a'_1 + h - a'_2`. This is not necessarily 0.
    // So this strategy is only for n >= 3.

    if (n >= 3) {
        long long current_goodness = elements[0].value + h - elements[1].value;
        if (current_goodness < best_goodness) {
            best_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << best_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

