        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for consistent logic
        if (n > m) {
            std::swap(n, m);
        }

        // Minimum moves required to reach (n, m) is m (by making n diagonal moves and m-n straight moves)
        // If k < m, it's impossible.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        long long parity_diff = (k - m) % 2;

        if (parity_diff == 0) {
            // If k and m have the same parity, we can reach (n, m) in k moves.
            // The maximum number of diagonal moves is k.
            // We can make n diagonal moves to reach (n, n).
            // Then m-n straight moves to reach (n, m).
            // Total moves so far: n + (m-n) = m.
            // Remaining moves: k - m.
            // Since (k-m) is even, we can use (k-m)/2 pairs of (1,0) and (-1,0) moves
            // or (0,1) and (0,-1) moves, which are non-diagonal.
            // Each such pair uses 2 moves and changes position by (0,0).
            // So, all k moves can be used, and the maximum diagonal moves is k.
            ans = k;
