int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // int count_e = 0; // 'e' is used by both, but 'n' and 'z' are unique indicators
    // int count_r = 0;
    // int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
        // No need to count 'e', 'r', 'o' explicitly for determining max 'one's and 'zero's
        // because 'n' is unique to "one" and 'z' is unique to "zero".
        // The problem guarantees that it's possible to form words.
    }

    // To maximize the binary number, we want as many '1's as possible,
    // and they should come first.
    // The number of '1's is limited by the count of 'n's.
    // The number of '0's is limited by the count of 'z's.

    // Print all '1's first
    for (int i = 0; i < count_n; ++i) {
        std::cout << 1 << (i == count_n - 1 && count_z == 0 ? "" : " ");
    }

    // Then print all '0's
    for (int i = 0; i < count_z; ++i) {
        std::cout << 0 << (i == count_z - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
