int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0, so a[i] is not the smallest),
            // we can add min_val to it as many times as possible.
            // The number of times min_val can be added to a[i] is
            // floor((k - a[i]) / min_val).
            if (a[i] < k) { // Only if a[i] itself is not already k or more
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

