#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed for k torches:
        // k sticks for the torches themselves
        // k * y sticks to buy k coal
        // Total = k + k * y = k * (1 + y)
        long long total_sticks_needed = k * (1 + y);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) additional sticks.
        // Each "1 stick for x sticks" trade gives a net gain of (x - 1) sticks.
        // Number of stick trades = ceil((total_sticks_needed - 1) / (x - 1))
        long long num_stick_trades = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades (to get enough sticks)
        //              + k (to buy k coal, each costing y sticks)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

