    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The flags `has_one` and `has_minus_one` are updated based on original `a` values.
        // This is correct because we can always use an `a[k]` with `k < i` and `a[k]=1` (or -1)
        // to modify `a[i]`. The values `a[k]` themselves are not changed by operations on `a[i]`.
        // The values `a[k]` might be changed by operations on `a[p]` where `p < k`, but this
        // doesn't affect their ability to be added to `a[i]`.
        // The crucial point is that if an original `a[k]` was 1, it can be used to add 1 to any `a[j]` with `j > k`.
        // If `a[k]` itself was changed to `a[k] + X`, then `a[k]` can be used to add `a[k]+X` to `a[j]`.
        // However, the problem states "Add a_i to a_j". This implies the *current* value of a_i.
        // But the logic holds: if there was an original 1 at index `k < i`, we can always add 1 to `a[i]`.
        // We can add 1 to `a[k]` to make it `1+X`, then add `1+X` to `a[i]`.
        // Or we can just add 1 to `a[i]` directly from `a[k]`.
        // The key is that if `a[k]` was 1, we can make `a[k]` any value `1 + Y` by adding `a[p]` for `p < k`.
        // But we can also just use `a[k]` as 1.
        // The problem is simpler: if there's *any* 1 at an index `k < i`, we can add 1 to `a[i]`.
        // If there's *any* -1 at an index `k < i`, we can add -1 to `a[i]`.
        // The flags `has_one` and `has_minus_one` track if such an element exists *among a[0]...a[i-1]*.
    }

    std::cout << "YES\n";
}

