    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a[i][j]);
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any element in p is n-1. If so, it means n was not used.
    // This happens if the actual maximum value in the permutation is n.
    // For example, if p = {1, 2, ..., n-1, n}, then for the element n,
    // max_{j!=k} min(p_k, p_j) = max_{j!=k} min(n, p_j) = max_{j!=k} p_j = n-1.
    // So, if n is present in the permutation, its reconstructed value will be n-1.
    // We need to find if n is missing from the reconstructed values.
    bool n_is_missing = true;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_is_missing = false;
            break;
        }
    }

    if (n_is_missing) {
        // If n is not present in the reconstructed values, it means
        // one of the elements that was originally n was reconstructed as n-1.
        // We need to find one such element (any one will do) and change its value to n.
        // The problem guarantees a solution exists, so there will be at least one
        // element whose reconstructed value is n-1.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

