#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 is always q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is greater than q_{i-1}, then p_i must be q_i
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be a new maximum
                // But as a safety check
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some unused number less than q_i
            // We need to find the smallest available number that is not used yet
            // and is less than q_i.
            // The numbers 1 to q_i-1 are candidates.
            // We need to find the smallest positive integer not in used_numbers.
            // This can be done by iterating from 1 or by using a set difference approach.
            // A more efficient way is to keep track of available numbers.
            // For now, let's find the smallest available number.
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) { // q[i] is q_{i-1} here
                // If the smallest available number is not less than q_i,
                // then we cannot satisfy the condition p_i <= q_i.
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers 1 to n are used exactly once
        // and all p_i are within [1, n].
        // This is implicitly handled by the construction if possible is true.
        // The used_numbers set will contain n distinct numbers.
        // Since we always pick the smallest available, and q_i <= n,
        // all p_i will be <= n.
        // The only remaining check is if any p_i is 0 or negative, but we start from 1.

        // One final check: if any q_i is greater than n, it's impossible.
        // The problem statement guarantees 1 <= q_i <= n.

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

