#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If such a `p` exists, then a[p-1] > a[p].
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-decreasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // If such a `q` exists, then a[q-1] < a[q].
    int q = p - 1;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }

    // The prefix to remove is a[0...q-1].
    // The length of this prefix is `q`.
    std::cout << q << std::endl;
}

