#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <string>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // The segment is [pos[1], pos[1]], length 1. min=1, max=1.
        // This is a permutation of {1}.

        // For m > 1, we consider the number 'm'.
        // We need to expand the current segment [min_idx, max_idx]
        // to include 'm'.
        // The new segment must contain all numbers from 1 to m.
        // This means it must contain 1, 2, ..., m-1 (which are already in [min_idx, max_idx])
        // AND it must contain 'm'.
        // So, the new segment must span from min(current min_idx, pos[m]) to max(current max_idx, pos[m]).

        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // After updating min_idx and max_idx to include 'm',
        // the segment p[min_idx ... max_idx] now contains all numbers from 1 to m.
        // Its length is (max_idx - min_idx + 1).
        // Its minimum value is 1 (because min_idx was updated to include pos[1] and never decreased below it).
        // Its maximum value is m (because max_idx was updated to include pos[m] and never increased above it for values > m).
        // For this segment to be a permutation of {1, ..., m}, its length must be exactly m.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

