    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> s;
    s.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a local maximum if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a local minimum if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_local_max = (p[i-1] < p[i] && p[i] > p[i+1]);
        bool is_local_min = (p[i-1] > p[i] && p[i] < p[i+1]);

        if (is_local_max || is_local_min) {
            s.push_back(p[i]);
        }
    }
    s.push_back(p[n-1]);

    std::cout << s.size() << "\n";
    for (size_t i = 0; i < s.size(); ++i) {
        std::cout << s[i] << (i == s.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

