#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition x[right_ptr] <= x[left_ptr] + d is equivalent to x[right_ptr] - x[left_ptr] <= d.
        while (right_ptr < n && x[right_ptr] <= x[left_ptr] + d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr+1] to x[right_ptr-1]
        // are within distance d from x[left_ptr].
        // The number of such points is (right_ptr - 1) - (left_ptr + 1) + 1 = right_ptr - 1 - left_ptr.
        // Let k = right_ptr - 1 - left_ptr.
        // These k points are candidates for x_j and x_k.
        // We need to choose 2 points from these k points.
        // The number of ways to choose 2 points from k is k * (k - 1) / 2.

        long long num_eligible_points = right_ptr - 1 - left_ptr;

        if (num_eligible_points >= 2) {
            count += num_eligible_points * (num_eligible_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // (n-1)/2 for 0-indexed

    // Cost for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    // If an element is > s, it must be decreased to s.
    // The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    // If an element is < s, it must be increased to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

