void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (A == 1) std::cout << "Ya Tidak Tidak Tidak\n";
        else if (B == 1) std::cout << "Tidak Ya Tidak Tidak\n";
        else if (C == 1) std::cout << "Tidak Tidak Ya Tidak\n";
        else std::cout << "Tidak Tidak Tidak Ya\n";
        return;
    }

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Box 1: (-inf, -1]
    // Final product must be negative and <= -1.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.
    // A toy in Box 1 can be formed if:
    // 1. There's an odd number of negative toys (A+B is odd).
    // 2. The magnitude can be made >= 1.
    //    This is always possible if A+D > 0 or (A+B+C+D > 1 and B+C > 0).
    //    More precisely, if we can make a product with magnitude >= 1.
    //    If A+D > 0, we can always make a product >= 1 or <= -1.
    //    If A+D == 0, then all initial toys are in B or C.
    //    If all toys are in B or C, the final product will be in (0,1).
    //    So, if A+D == 0, Box 1 is impossible.
    //    If A+D > 0, we can always achieve magnitude >= 1.
    //    So, Box 1 is possible if (A+B) is odd AND (A+D > 0).
    //    What if A+D > 0 but A+B is even?
    //    Example: A=0, B=2, C=0, D=1. Total 3. (A+B)=2 (even).
    //    (-0.5)*(-0.5) = 0.25 (Box 3). Then 0.25*3 = 0.75 (Box 3). Final in Box 3.
    //    Example: A=1, B=1, C=0, D=1. Total 3. (A+B)=2 (even).
    //    (-2)*(-0.5) = 1 (Box 4). Then 1*3 = 3 (Box 4). Final in Box 4.
    //    Example: A=1, B=0, C=0, D=1. Total 2. (A+B)=1 (odd).
    //    (-2)*3 = -6 (Box 1). Final in Box 1.
    //
    // The condition for magnitude >= 1 is that not all toys are in B and C.
    // If A+D > 0, we can always ensure the final magnitude is >= 1.
    // If A+D == 0, then all toys are in B or C. The product of any number of toys from B and C will always be in (0,1).
    // So, if A+D == 0, Box 1 and Box 4 are impossible.
    //
    // Box 1: Requires odd number of negative factors (A+B is odd) AND (A+D > 0).
    if (((A + B) % 2 != 0) && (A + D > 0)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Final product must be negative and in (-1, 0).
    // This requires an odd number of negative factors (A+B is odd).
    // The magnitude must be in (0, 1).
    // This is always possible if B+C > 0.
    // If B+C == 0, then all toys are in A or D. The product will be in Box 1 or Box 4.
    // So, if B+C == 0, Box 2 and Box 3 are impossible.
    // If B+C > 0, we can always achieve magnitude in (0,1).
    // So, Box 2 is possible if (A+B) is odd AND (B+C > 0).
    if (((A + B) % 2 != 0) && (B + C > 0)) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Final product must be positive and in (0, 1).
    // This requires an even number of negative factors (A+B is even).
    // The magnitude must be in (0, 1).
    // This is always possible if B+C > 0.
    // So, Box 3 is possible if (A+B) is even AND (B+C > 0).
    if (((A + B) % 2 == 0) && (B + C > 0)) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Final product must be positive and >= 1.
    // This requires an even number of negative factors (A+B is even).
    // The magnitude must be >= 1.
    // This is always possible if A+D > 0.
    // So, Box 4 is possible if (A+B) is even AND (A+D > 0).
    if (((A + B) % 2 == 0) && (A + D > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

