#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value > b.value; // Sort A in descending order
}

struct BElement {
    long long value;
    int original_index;
};

bool compareB(const BElement& a, const BElement& b) {
    return a.value < b.value; // Sort B in ascending order
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<BElement> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in descending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order, keeping original indices
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Assign elements: largest A_i' to smallest B_j, second largest A_i' to second smallest B_j, etc.
    // This means a_elements[k] (k-th largest A value) should be assigned to b_elements[k] (k-th smallest B value).
    // The k-th smallest B value (b_elements[k]) needs its original index to place the A value.
    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a sub-array is a permutation of its length
// This version uses a frequency array and checks max element.
// It's optimized for checking prefixes/suffixes by passing max_val.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len, int max_val) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (max_val != len) return false; // Max element must be equal to length

    std::vector<bool> seen(len + 1, false);
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool current_prefix_valid = true;

    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > i + 1 || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        seen_prefix[val] = true;
        current_max_prefix = std::max(current_max_prefix, val);
        prefix_max[i] = current_max_prefix;

        if (current_prefix_valid && current_max_prefix == (i + 1)) {
            prefix_is_perm[i] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool current_suffix_valid = true;

    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int suffix_len = n - i;
        if (val < 1 || val > suffix_len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        seen_suffix[val] = true;
        current_max_suffix = std::max(current_max_suffix, val);
        suffix_max[i] = current_max_suffix;

        if (current_suffix_valid && current_max_suffix == suffix_len) {
            suffix_is_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1 - 1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (initial_wins + k == 0) { // No wins possible even after changes
            std::cout << 0 << "\n";
            continue;
        }

        // Case 1: No initial wins, but we can make some wins
        if (initial_wins == 0) {
            // We can change k 'L's to 'W's.
            // To maximize score, we want to make them consecutive.
            // The best we can do is make k 'W's.
            // If k=0, score is 0.
            // If k=1, score is 1.
            // If k>1, score is 1 (first W) + (k-1)*2 (subsequent Ws) = 1 + 2k - 2 = 2k - 1.
            // This can be simplified to max(0, 2*k - 1).
            std::cout << std::max(0, 2 * k - 1) << "\n";
            continue;
        }

        // Case 2: There are initial wins.
        // We want to fill 'L' gaps between 'W's first, then convert 'L's at ends.
        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect gaps between Ws
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int changes_made = 0;
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                changes_made += gap_len;
                current_score += 2 * gap_len; // Each L in gap becomes W, connecting two Ws, adding 2 points per L
            } else {
                break;
            }
        }

        // Now k is remaining changes.
        // We can use remaining k to convert 'L's at the beginning or end.
        // Each such conversion adds 2 points (1 for the W itself, 1 for connecting to an existing W).
        // Or, if it's the first W, it adds 1 point.
        // The logic for current_score already accounts for the 1 point for the W itself.
        // So, converting an L to W at the ends adds 2 points if it connects to an existing W.
        // If it's an isolated W, it adds 1 point.
        // But since we already have initial wins, any new W at the ends will connect to an existing W.
        // Example: LLLWWL, k=1. Change first L to W. WWLWWL. Score increases by 2.
        // Example: LLLWWL, k=1. Change last L to W. LLLWWW. Score increases by 2.
        // The number of L's before first_W is first_W.
        // The number of L's after last_W is n - 1 - last_W.

        // Maximize changes at ends
        int changes_at_ends = std::min(k, first_W + (n - 1 - last_W));
        current_score += 2 * changes_at_ends;
        k -= changes_at_ends;

        // If k is still positive, it means we have converted all L's to W's.
        // This scenario is covered by the initial_wins + k == 0 check if all were L.
        // If there were initial W's, and we converted all L's, then k would be 0.
        // The only way k is still positive is if we converted all L's to W's,
        // and we still have k left. This means we have a string of all W's.
        // The score for all W's is 1 + 2*(n-1) = 2n-1.
        // Our current_score calculation:
        // initial_wins + 2*changes_made + 2*changes_at_ends.
        // This is equivalent to 1 (for first W) + 2*(total_wins - 1).
        // Total wins = initial_wins + changes_made + changes_at_ends.
        // So, current_score = 1 + 2 * (initial_wins + changes_made + changes_at_ends - 1).
        // This is correct.

        std::cout << current_score << "\n";
    }
    return 0;
}

