        // n=4, a="0101", b="0011"
        // i=0: a[0]='0', b[0]='0'. Match. cost=0.
        //      (current_diff_01=0, current_diff_10=0)
        // i=1: a[1]='1', b[1]='0'. No pending 0->1. current_diff_10 becomes 1. cost=0.
