        // If a[i] != b[i]:
        //   If a[i] = '0' and b[i] = '1':
        //     If current_diff_10 > 0: // We have a '1' from a previous 1->0 mismatch
        //       cost += 1; // This is a swap of adjacent differing bits, cost 1.
