            total_happiness += a[a_ptr_right] * 2;
            a_ptr_right--;
        } else {
            // All remaining friends have w_i > 1.
            // Break the loop as w is sorted.
            break;
        }
    }

    // Friends with w_i > 1.
    // These are the friends at the beginning of the w array.
    // They get one largest remaining number (for max_val) and one smallest remaining number (for min_val).
    // The remaining w_i - 2 numbers are taken from the smallest available numbers.
    for (int i = 0; i < k; ++i) {
