                opponent_max_score = temp_n - (m - 1) / 2;
                break; // We found the optimal score for the opponent starting with temp_n
            }
        }

        // Now we have `opponent_max_score` which is `max_first_player_coins(N/2)`.
        // Chanek's score for Option 2 (take N/2): N/2 + (N/2 - opponent_max_score) = N - opponent_max_score.
        long long chanek_score_option1 = n / 2; // If Chanek takes 1, then N-1 is odd. Opponent gets N/2. Chanek gets (N-2)/2. Total 1 + (N-2)/2 = N/2.
        long long chanek_score_option2_val = n - opponent_max_score;

        return std::max(chanek_score_option1, chanek_score_option2_val);
    }
}

