long long solve() {
    long long n;
    std::cin >> n;

    if (n % 2 != 0) {
        // If N is odd, Mr. Chanek must take 1 coin.
        // Remaining N-1 coins (even).
        // The opponent will then play optimally on N-1 coins.
        // For any even number M, the first player can always ensure they get M/2 coins
        // and the second player gets M/2 coins. This is achieved by always taking M/2
        // if M is even, or 1 if M is odd (which leads to an even number for the opponent).
        // More precisely, if the first player faces an even number M, they can take M/2.
        // The second player then faces M/2. This continues until an odd number is faced.
        // The player who faces an odd number `m` will take `(m+1)/2` coins.
        // The other player will take `(m-1)/2` coins.
        // The total coins taken by the first player from an even number `M` is `M - (m-1)/2`,
        // where `m` is the largest odd divisor of `M`.
        // The total coins taken by the second player from an even number `M` is `(m-1)/2`.
        //
        // In this case, after Chanek takes 1, N-1 coins remain.
        // Opponent is the first player for N-1 coins.
        // N-1 is even. Let M = N-1.
        // The largest odd divisor of M is M itself (since M is even, this is wrong).
        // The largest odd divisor of M (even) is found by repeatedly dividing by 2.
        // Let m_prime be the largest odd divisor of N-1.
        // Opponent gets (N-1) - (m_prime - 1)/2 coins.
        // Chanek gets (m_prime - 1)/2 coins from the N-1 subgame.
        // Chanek's total: 1 + (m_prime - 1)/2.
        //
        // However, for an odd N, the simplest strategy for Chanek is to take 1.
        // N-1 coins remain. Opponent plays on N-1.
        // The opponent will take (N-1)/2 coins, and Chanek will take (N-1)/2 coins.
        // This is because for any even number M, the first player can always ensure they get M/2 coins
        // and the second player gets M/2 coins. This is achieved by always taking M/2 if M is even,
        // or 1 if M is odd (which leads to an even number for the opponent).
        // So, if N-1 is even, the opponent takes (N-1)/2 and Chanek takes (N-1)/2.
        // Chanek's total: 1 + (N-1)/2 = (N+1)/2.
        return (n + 1) / 2;
    } else {
        // If N is even, Mr. Chanek has two choices:
        // 1. Take 1 coin. Remaining N-1 (odd).
        //    Now it's Opponent's turn with N-1 coins.
        //    Opponent takes 1. Remaining N-2 (even).
        //    Opponent gets 1 + (N-2)/2 = N/2 coins.
        //    Chanek gets (N-2)/2 coins from the N-2 subgame.
        //    Chanek's total: 1 (initial) + (N-2)/2 = N/2.
        long long chanek_score_option1 = n / 2;

        // 2. Take N/2 coins. Remaining N/2.
        //    Now it's Opponent's turn with N/2 coins.
        //    Opponent will play optimally to maximize their own score.
        //    Let `max_first_player_score(k)` be the maximum coins the first player can get from `k` coins.
        //    If `k` is odd: `max_first_player_score(k) = (k+1)/2`.
        //    If `k` is even: `max_first_player_score(k) = k - (m-1)/2`, where `m` is the largest odd divisor of `k`.
        //    (This is derived from the strategy: keep taking `k/2` until an odd number `m` is reached,
        //    then the player facing `m` takes `(m+1)/2` and the other player gets `(m-1)/2`.
        //    The total coins taken by the first player is `k - (m-1)/2`).
        //
        //    Opponent will get `max_first_player_score(N/2)` coins from the subgame.
        //    Chanek will get `N/2 - max_first_player_score(N/2)` coins from the subgame.
        //    Chanek's total: N/2 (initial) + (N/2 - max_first_player_score(N/2)) = N - max_first_player_score(N/2).

        long long temp_n_for_opponent = n / 2;
        long long opponent_max_score_from_subgame;

        if (temp_n_for_opponent % 2 != 0) {
            // N/2 is odd. Opponent takes 1.
            opponent_max_score_from_subgame = (temp_n_for_opponent + 1) / 2;
        } else {
            // N/2 is even. Find its largest odd divisor `m`.
            long long m = temp_n_for_opponent;
            while (m % 2 == 0) {
                m /= 2;
            }
            opponent_max_score_from_subgame = temp_n_for_opponent - (m - 1) / 2;
        }

        long long chanek_score_option2 = n - opponent_max_score_from_subgame;

        return std::max(chanek_score_option1, chanek_score_option2);
    }
}

