// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means we need to remove some factors from p such that it's no longer divisible by q.
        // To maximize x, we should remove as few factors as possible, or factors that are as small as possible.

        // Get prime factors of q
        std::map<long long, int> q_factors = get_prime_factors(q);

        long long max_x = 1;

        // Iterate through each prime factor of q
        for (auto const& [prime_factor, q_exponent] : q_factors) {
            // Calculate the current p_copy to find its prime_factor exponent
            long long p_copy = p;
            int p_exponent = 0;
            while (p_copy > 0 && p_copy % prime_factor == 0) {
                p_exponent++;
                p_copy /= prime_factor;
            }

            // If p_exponent is less than q_exponent, it means p is not divisible by q_prime_factor^q_exponent.
            // This case should not happen if p % q == 0, unless q_prime_factor^q_exponent is not a factor of q.
            // But q_prime_factor^q_exponent is a factor of q by definition.
            // So p_exponent must be >= q_exponent.

            // We need to reduce the exponent of prime_factor in p such that it's less than q_exponent.
            // The largest such divisor of p would be p / (prime_factor ^ (p_exponent - q_exponent + 1)).
            // This ensures that the new exponent of prime_factor in x is q_exponent - 1,
            // making x not divisible by prime_factor^q_exponent, and thus not divisible by q.

            long long current_x = p;
            for (int i = 0; i < p_exponent - q_exponent + 1; ++i) {
                current_x /= prime_factor;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

