void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?');

    // Step 1: Propagate known characters within each k-group
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_chars[i % k] == '?') {
                fixed_chars[i % k] = s[i];
            } else if (fixed_chars[i % k] != s[i]) {
                // Conflict: s[i] is '0' but fixed_chars[i%k] is '1', or vice versa
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Apply fixed_chars back to s (conceptually, not modifying s itself)
    // and check the k-balance condition for the first k characters.
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    // Check if it's possible to make the first k characters k-balanced
    // We need k/2 zeros and k/2 ones.
    // We have count0 fixed zeros, count1 fixed ones, and count_q '?'s.
    // We need (k/2 - count0) more zeros and (k/2 - count1) more ones.
    // These must come from the '?'s.
    // The number of '?'s available is count_q.
    // The number of '?'s needed is (k/2 - count0) + (k/2 - count1).
    // This sum must be equal to count_q.
    // Also, (k/2 - count0) must be non-negative, and (k/2 - count1) must be non-negative.

    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    int needed0 = k / 2 - count0;
    int needed1 = k / 2 - count1;

    if (needed0 + needed1 == count_q) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

