int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] multiples of n
    // Segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add x_i such that (a[i] + x_i) % n == 0.
    // x_i must be a multiple of (n-1).
    // (a[i] + k * (n-1)) % n == 0
    // (a[i] + k * (-1)) % n == 0
    // (a[i] - k) % n == 0
    // k % n == a[i] % n
    // We can choose k = (a[i] % n + n) % n.
    // Then x_i = k * (n-1).
    // Note: a[i] can be negative, so (a[i] % n + n) % n ensures a positive remainder.
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n;
        long long add_val = remainder * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] a multiple of n
    // Segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // For a[n-1], we want to add x such that (a[n-1] + x) % n == 0.
    // x must be a multiple of 1.
    // We can choose x = -a[n-1]. This makes a[n-1] zero.
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0; // Update a[n-1]

    // Operation 3: Make a[0]...a[n-2] zero
    // Segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // For each a[i], we want to add x_i such that (a[i] + x_i) == 0.
    // x_i must be a multiple of n.
    // From Operation 1, a[0]...a[n-2] are now multiples of n.
    // So we can choose x_i = -a[i].
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

