int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: 0 and 1023 (all 1s for 10 bits)
    // We track how these two specific inputs transform through the operations.
    // Since operations are bitwise and constants are <= 1023, we only care about 10 bits.
    // Any input x can be represented as a combination of bits.
    // If we know how 0 and 1023 transform, we can deduce the final operation.
    // Let f(x) be the final function.
    // f(0) will tell us the constant part (bits that become 1 regardless of input).
    // f(1023) will tell us how bits are flipped or forced to 0.
    // Specifically, for each bit j:
    // Let x_j be the j-th bit of input x.
    // Let f_j(x_j) be the j-th bit of f(x).
    // We know f_j(0) and f_j(1).
    // Case 1: f_j(0) = 0, f_j(1) = 0  => f_j(x_j) = 0 (bit is forced to 0)
    // Case 2: f_j(0) = 0, f_j(1) = 1  => f_j(x_j) = x_j (bit is unchanged)
    // Case 3: f_j(0) = 1, f_j(1) = 0  => f_j(x_j) = !x_j (bit is flipped)
    // Case 4: f_j(0) = 1, f_j(1) = 1  => f_j(x_j) = 1 (bit is forced to 1)

    int val0 = 0;    // Represents the transformation of input 0
    int val1023 = 1023; // Represents the transformation of input 1023 (all 1s for 10 bits)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, val0 is f(0) and val1023 is f(1023).
    // We need to find a sequence of at most 5 operations that achieves this.
    // A single AND, OR, XOR operation can be represented as:
    // x' = (x & A) | B ^ C
    // where A, B, C are constants.
