    // Let x_j be the j-th bit of input.
    // Let v0_j be the j-th bit of val0.
    // Let v1_j be the j-th bit of val1023.

    // We want to find constants for a minimal set of operations.
    // Let's try to construct the final state using at most 3 operations:
    // 1. An OR operation to set bits that are 1 when input is 0.
    // 2. An AND operation to clear bits that are 0 when input is 1.
    // 3. An XOR operation to flip bits that are 1 when input is 1 and 0 when input is 0.

    int final_or_const = 0;  // Bits that are 1 in val0 (f(0))
    int final_and_const = 1023; // Bits that are 0 in val1023 (f(1023))
    int final_xor_const = 0; // Bits that are flipped (f(0) != f(1))

    for (int j = 0; j < 10; ++j) { // Iterate through bits 0 to 9
        int v0_j = (val0 >> j) & 1;
        int v1_j = (val1023 >> j) & 1;

        if (v0_j == 0 && v1_j == 0) { // Bit j is always 0
            // This bit must be forced to 0. An AND with 0 will do this.
            final_and_const &= ~(1 << j); // Set j-th bit of AND constant to 0
        } else if (v0_j == 0 && v1_j == 1) { // Bit j is unchanged (x_j)
            // This bit should pass through. AND with 1, OR with 0, XOR with 0.
            // No change needed for AND/OR/XOR constants for this bit.
        } else if (v0_j == 1 && v1_j == 0) { // Bit j is flipped (!x_j)
            // This bit needs to be flipped. An XOR with 1 will do this.
            final_xor_const |= (1 << j); // Set j-th bit of XOR constant to 1
            // Also, if it's flipped, it means it's 1 when input is 0, so OR with 1.
            final_or_const |= (1 << j);
            // And it's 0 when input is 1, so AND with 0.
            final_and_const &= ~(1 << j);
        } else if (v0_j == 1 && v1_j == 1) { // Bit j is always 1
            // This bit must be forced to 1. An OR with 1 will do this.
            final_or_const |= (1 << j); // Set j-th bit of OR constant to 1
        }
