    //
    // Consider the bits:
    // 1. Bits that are always 0 (v0_j=0, v1_j=0): Must be forced to 0. This is handled by `final_and_const`.
    // 2. Bits that are always 1 (v0_j=1, v1_j=1): Must be forced to 1. This is handled by `final_or_const`.
    // 3. Bits that are `x_j` (v0_j=0, v1_j=1): Pass through.
    // 4. Bits that are `!x_j` (v0_j=1, v1_j=0): Flipped. This is handled by `final_xor_const`.

    // The strategy is:
    // 1. Apply an OR operation to set bits that are 1 in val0.
    // 2. Apply an AND operation to clear bits that are 0 in val1023.
    // 3. Apply an XOR operation to flip bits where val0 != val1023.

    // Let's re-evaluate the constants for a sequence of operations:
    // (x | OR_C) & AND_C ^ XOR_C
    //
    // For each bit j:
    // If (v0_j == 0 && v1_j == 0):
    //   (x_j | 0) & 0 ^ 0 = 0. So OR_C_j=0, AND_C_j=0, XOR_C_j=0.
    // If (v0_j == 0 && v1_j == 1):
    //   (x_j | 0) & 1 ^ 0 = x_j. So OR_C_j=0, AND_C_j=1, XOR_C_j=0.
    // If (v0_j == 1 && v1_j == 0):
    //   (x_j | 1) & 0 ^ 0 = 0. This is not !x_j.
    //   (x_j | 0) & 1 ^ 1 = !x_j. So OR_C_j=0, AND_C_j=1, XOR_C_j=1.
    // If (v0_j == 1 && v1_j == 1):
    //   (x_j | 1) & 1 ^ 0 = 1. So OR_C_j=1, AND_C_j=1, XOR_C_j=0.

    // Let's define the constants for (x | OR_C) & AND_C ^ XOR_C
    int OR_C = 0;
    int AND_C = 1023;
    int XOR_C = 0;

    for (int j = 0; j < 10; ++j) {
        int v0_j = (val0 >> j) & 1;
        int v1_j = (val1023 >> j) & 1;

        if (v0_j == 0 && v1_j == 0) { // Target: 0
            // (x_j | 0) & 0 ^ 0 = 0
            AND_C &= ~(1 << j); // Set j-th bit of AND_C to 0
        } else if (v0_j == 0 && v1_j == 1) { // Target: x_j
            // (x_j | 0) & 1 ^ 0 = x_j
            // OR_C_j=0, AND_C_j=1, XOR_C_j=0 (default values)
        } else if (v0_j == 1 && v1_j == 0) { // Target: !x_j
            // (x_j | 0) & 1 ^ 1 = !x_j
            XOR_C |= (1 << j); // Set j-th bit of XOR_C to 1
        } else if (v0_j == 1 && v1_j == 1) { // Target: 1
            // (x_j | 1) & 1 ^ 0 = 1
            OR_C |= (1 << j); // Set j-th bit of OR_C to 1
        }
    }

    if (OR_C != 0) {
        result_ops.push_back({'|', OR_C});
    }
    if (AND_C != 1023) { // If AND_C is not all 1s, it means some bits are forced to 0
        result_ops.push_back({'&', AND_C});
    }
    if (XOR_C != 0) {
        result_ops.push_back({'^', XOR_C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

