void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for balance (1 for strawberry, -1 for blueberry)
    // For jars 1 to n (left side), calculate balance from right to left
    // For jars n+1 to 2n (right side), calculate balance from left to right

    // Balances for the left side (jars 1 to n)
    // `left_balances[i]` stores the balance of jars from `i` to `n-1` (0-indexed)
    // This means if we remove `i` jars from the left, the balance of remaining jars on the left is `left_balances[i]`
    // `left_balances[0]` is balance of jars 0 to n-1
    // `left_balances[k]` is balance of jars k to n-1
    std::vector<int> left_balances(n + 1, 0);
    int current_balance = 0;
    for (int i = n - 1; i >= 0; --i) {
        current_balance += (a[i] == 1 ? 1 : -1);
        left_balances[n - 1 - i] = current_balance; // left_balances[k] is balance of jars from k to n-1
    }

    // Balances for the right side (jars n+1 to 2n)
    // `right_balances[i]` stores the balance of jars from `n` to `n+i-1` (0-indexed)
    // This means if we remove `i` jars from the right, the balance of remaining jars on the right is `right_balances[i]`
    // `right_balances[0]` is balance of jars n to 2n-1
    // `right_balances[k]` is balance of jars n to 2n-1-k
    std::vector<int> right_balances(n + 1, 0);
    current_balance = 0;
    for (int i = n; i < 2 * n; ++i) {
        current_balance += (a[i] == 1 ? 1 : -1);
        right_balances[i - n] = current_balance; // right_balances[k] is balance of jars from n to n+k-1
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance.
    // `left_balance_to_removed_count[balance]` = `k` means removing `k` jars from the left
    // results in a balance of `balance` for the remaining jars on the left.
    // The `k` here is the number of jars removed from the left, which is `n - (n-k)`
    // No, it's simpler: `k` jars removed from left means jars `0` to `k-1` are removed.
    // The remaining jars on the left are `k` to `n-1`.
    // The balance of these remaining jars is `left_balances[k]`.
    std::map<int, int> left_balance_to_removed_count;
    left_balance_to_removed_count[0] = 0; // 0 jars removed from left, balance 0 (if n=0, or if all jars cancel out)
                                          // This means if we remove all n jars from the left, the balance of remaining left jars is 0.
                                          // This is for the case where we remove all jars from the left.
                                          // The balance of jars 0 to n-1 is `left_balances[0]` (if we consider it as removing 0 jars from left)
                                          // No, `left_balances[k]` is the balance of jars `k` to `n-1`.
                                          // So, if we remove `k` jars from the left, the balance is `left_balances[k]`.
                                          // The number of jars removed is `k`.

    // Iterate through possible number of jars removed from the left (0 to n)
    // `k_left` is the number of jars removed from the left (jars 0 to k_left-1)
    // The remaining jars on the left are from index `k_left` to `n-1`.
    // Their balance is `left_balances[k_left]`.
    for (int k_left = 0; k_left <= n; ++k_left) {
        int balance_of_remaining_left_jars;
        if (k_left == n) { // All jars on the left are removed
            balance_of_remaining_left_jars = 0;
        } else {
            balance_of_remaining_left_jars = left_balances[k_left];
        }
        // Store the minimum k_left for this balance
        if (left_balance_to_removed_count.find(balance_of_remaining_left_jars) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[balance_of_remaining_left_jars] = k_left;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from the right (0 to n)
    // `k_right` is the number of jars removed from the right (jars 2n-k_right to 2n-1)
    // The remaining jars on the right are from index `n` to `2n-1-k_right`.
    // Their balance is `right_balances[n - k_right - 1]` if we consider `right_balances` as prefix sums from `n`.
    // Let's re-evaluate `right_balances`.
    // `right_balances[k]` is the balance of jars `n` to `n+k-1`.
    // If we remove `k_right` jars from the right, the remaining jars on the right are `n` to `2n-1-k_right`.
    // The number of remaining jars on the right is `(2n-1-k_right) - n + 1 = n - k_right`.
    // So, the balance of these remaining jars is `right_balances[n - k_right]`.
    for (int k_right = 0; k_right <= n; ++k_right) {
        int balance_of_remaining_right_jars;
        if (k_right == n) { // All jars on the right are removed
            balance_of_remaining_right_jars = 0;
        } else {
            balance_of_remaining_right_jars = right_balances[n - k_right];
        }

        // We need total balance to be 0.
        // So, `balance_of_remaining_left_jars + balance_of_remaining_right_jars = 0`.
        // This means `balance_of_remaining_left_jars = -balance_of_remaining_right_jars`.
        int target_left_balance = -balance_of_remaining_right_jars;

        if (left_balance_to_removed_count.count(target_left_balance)) {
            int k_left = left_balance_to_removed_count[target_left_balance];
            min_removed_jars = std::min(min_removed_jars, k_left + k_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

