#include <iostream>
#include <algorithm>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    long long num_zeros = n - m;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible among m+1 potential blocks.
    // The '1's act as separators. If there are m '1's, they can create at most m+1 blocks of '0's.
    // For example, "0010100" has m=2 ones, and 3 blocks of zeros.
    // The number of blocks of zeros is m+1.
    // We want to distribute num_zeros into m+1 blocks as evenly as possible.

    // Let k be the number of '1's.
    // The '1's divide the string into k+1 segments of '0's.
    // For example, 10101 has k=3 ones, and 4 segments of zeros (some might be empty).
    // The number of '0's is n-m.
    // We want to distribute n-m zeros into m+1 blocks.
    // Let q be the quotient and r be the remainder when (n-m) is divided by (m+1).
    // This means r blocks will have (q+1) zeros, and (m+1-r) blocks will have q zeros.

    long long num_blocks_of_zeros = m + 1;
    long long q = num_zeros / num_blocks_of_zeros; // base number of zeros in a block
    long long r = num_zeros % num_blocks_of_zeros; // number of blocks with one extra zero

    long long sum_zero_substrings = 0;

    // r blocks have (q+1) zeros
    sum_zero_substrings += r * (q + 1) * (q + 2) / 2;

    // (num_blocks_of_zeros - r) blocks have q zeros
    sum_zero_substrings += (num_blocks_of_zeros - r) * q * (q + 1) / 2;

    return total_substrings - sum_zero_substrings;
}

