int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b1=a1, bn=an, no middle elements)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores the index of the nearest 1 to the left (inclusive)
    std::vector<int> right_ones(n, n); // Stores the index of the nearest 1 to the right (inclusive)

    int last_one = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one = i;
        }
        left_ones[i] = last_one;
    }

    last_one = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one = i;
        }
        right_ones[i] = last_one;
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == n) ? n : (right_ones[i] - i);

            if (dist_left == n && dist_right == n) { // All zeros
                max_dist = 0; // Already stable
                break;
            }

            if (dist_left == n) { // Only ones to the right
                max_dist = std::max(max_dist, dist_right);
            } else if (dist_right == n) { // Only ones to the left
                max_dist = std::max(max_dist, dist_left);
            } else { // Ones on both sides
                max_dist = std::max(max_dist, std::min(dist_left, dist_right));
            }
        }
    }

    int k = (max_dist + 1) / 2;

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == n) ? n : (right_ones[i] - i);

            if (dist_left <= k && dist_right <= k) {
                final_a[i] = 1;
            } else {
                final_a[i] = 0;
            }
        }
    }

    std::cout << k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

