bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // Cut s into s1 and s2: s = s1s2
    // New string s' = s2s1
    // We need s' to be a palindrome and s' != s
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2
    // This is always possible unless all characters in s are the same.
    // If all characters are the same, e.g., "aaaa", then any rearrangement
    // of substrings will result in "aaaa" again.
    // For example, "a|a|aa" -> "a|aa|a" -> "aaaa".
    // So, if all characters are the same, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" which is "onlno" (palindrome)
        // This works because if not all characters are the same, there must be
        // at least two distinct characters. Since s is a palindrome, it must
        // have at least two distinct characters if n > 1.
        // If n=1, e.g., "a", then all_same is true, and it's impossible.
        // If n > 1 and not all_same, then there's a character s[j] != s[0].
        // Consider cutting s into s[0...j-1], s[j], s[j+1...n-1].
        // Or more simply, cut s into s[0...n/2-1], s[n/2], s[n/2+1...n-1] (if n is odd)
        // or s[0...n/2-1], s[n/2...n-1] (if n is even).
        // The problem statement guarantees that if not all characters are the same,
        // a solution with k=2 exists.
        std::cout << 2 << std::endl;
    }

    return 0;
}

