            last_valid_r[x] = std::min(last_valid_r[x], x + 1);
        }
        // For k=2: (x, x+2, x+4)
        if (x + 4 < n && s[x] == s[x + 2] && s[x + 2] == s[x + 4]) {
            last_valid_r[x] = std::min(last_valid_r[x], x + 3);
        }
        // For k=3: (x, x+3, x+6)
        if (x + 6 < n && s[x] == s[x + 3] && s[x + 3] == s[x + 6]) {
            last_valid_r[x] = std::min(last_valid_r[x], x + 5);
        }
        // For k=4: (x, x+4, x+8)
        if (x + 8 < n && s[x] == s[x + 4] && s[x + 4] == s[x + 8]) {
            last_valid_r[x] = std::min(last_valid_r[x], x + 7);
        }

        // The maximum r (0-indexed) for which s[x...r] is "good" is last_valid_r[x].
        // The number of "good" substrings starting at x is (last_valid_r[x] - x + 1).
        // These are (x,x), (x,x+1), ..., (x, last_valid_r[x]).
        bad_pairs_count += (last_valid_r[x] - x + 1);
    }

    std::cout << total_pairs - bad_pairs_count << std::endl;

    return 0;
}

