            // If `x >= h[h_idx]`, `f(x) = x + T - (x - h[h_idx]) = h[h_idx] + T`.
            // If `x < h[h_idx]`, `f(x) = x + T - (h[h_idx] - x) = 2*x - h[h_idx] + T`.
            // So, the maximum right reach for the current head is `max(h[h_idx] + T, 2*p_k - h[h_idx] + T)` for any `p_k < h[h_idx]` that is reachable.
            // To maximize `2*p_k - h[h_idx] + T`, we need to maximize `p_k`.
            // So, we find the rightmost `p_k` such that `p_k < h[h_idx]` and `abs(p_k - h[h_idx]) <= T`.
            // Let this be `p_max_left`.
            // The effective right reach of the current head is `max(h[h_idx] + T, 2*p_max_left - h[h_idx] + T)`.
            // If no such `p_max_left` exists, then it's just `h[h_idx] + T`.

            // Let's simplify. The current head `h[h_idx]` can cover a range `[h[h_idx] - T, h[h_idx] + T]`.
            // If it covers a track `p_k` within this range, it can then extend its reach.
            // The total range covered by this head is `[min(h[h_idx] - T, p_k - (T - abs(p_k - h[h_idx]))), max(h[h_idx] + T, p_k + (T - abs(p_k - h[h_idx])))]`.
            // We are interested in the rightmost point it can reach.
            // This is `max(h[h_idx] + T, p_k + (T - abs(p_k - h[h_idx])))`.
            // To cover all `p_i`, we need to ensure that `p[p_idx]` is covered.
            // The current head `h[h_idx]` must cover `p[p_idx]`.
            // This means `abs(p[p_idx] - h[h_idx]) <= T`.
            // If this condition is not met, then `p[p_idx]` cannot be covered by `h[h_idx]`.
            // Since `p` is sorted, if `p[p_idx]` cannot be covered, then `p[p_idx]` cannot be covered by any `h_j` where `j < h_idx` (because `h_j` are smaller).
            // So, if `abs(p[p_idx] - h[h_idx]) > T`, it's impossible.
            // This is the core check.
            // If `abs(p[p_idx] - h[h_idx]) <= T`, then `h[h_idx]` can cover `p[p_idx]`.
            // After covering `p[p_idx]`, the head has `T_rem = T - abs(p[p_idx] - h[h_idx])` time remaining.
            // It can then move `T_rem` steps further right from `p[p_idx]`.
            // So, the effective rightmost point it can reach is `p[p_idx] + T_rem`.
            // We update `p_idx` to the first track that is beyond this effective rightmost point.

            if (std::abs(p[p_idx] - h[h_idx]) > T) {
                return false; // Current head cannot reach the leftmost required track
            }

            long long current_head_max_reach = p[p_idx] + (T - std::abs(p[p_idx] - h[h_idx]));

            // Advance p_idx past all tracks covered by this head
            while (p_idx < m && p[p_idx] <= current_head_max_reach) {
                p_idx++;
            }
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}
